window.HADITH_CACHE["bukhari_2"] = {"1001":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَانْكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghoilan] berkata, telah telah menceritakan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari [Yunus] dari [Al Hasan] dari [Abu Bakrah radliallahu 'anhu] berkata: \"Telah pernah terjadi gerhana matahari pada zaman Rasulullah shallallahu 'alaihi wasallam, kemudian Beliau mendirikan shalat dua raka'at\"."},"1002":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ قَالَخَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ يَجُرُّ رِدَاءَهُ حَتَّى انْتَهَى إِلَى الْمَسْجِدِ وَثَابَ النَّاسُ إِلَيْهِ فَصَلَّى بِهِمْ رَكْعَتَيْنِ فَانْجَلَتْ الشَّمْسُ فَقَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ وَإِنَّهُمَا لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَإِذَا كَانَ ذَاكَ فَصَلُّوا وَ��دْعُوا حَتَّى يُكْشَفَ مَا بِكُمْوَذَاكَ أَنَّ ابْنًا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاتَ يُقَالُ لَهُ إِبْرَاهِيمُ فَقَالَ النَّاسُ فِي ذَاكَ","id":"Telah menceritakan kepada kami [Abu Ma'mar] berkata, telah telah menceritakan kepada kami ['Abdul Warits] berkata, telah menceritakan kepada kami [Yunus] dari [Al Hasan] dari [Abu Bakrah] berkata: \"Telah terjadi gerhana matahari pada zaman Rasulullah shallallahu 'alaihi wasallam lalu Beliau keluar dengan menyingsingkan selendangnya hingga tiba di masjid. Maka orang-orang berkumpul mengelilingi Beliau. Lalu Beliau memimpin shalat bersama mereka dua raka'at hingga matahari kembali nampak. Kemudian Beliau bersabda: \"Matahari dan bulan adalah dua tanda dari tanda-tanda kebesaran Allah dan keduanya tidak akan mengalami gerhana disebabkan karena kematian seseorang. Jika terjadi gerhana, maka dirikanlah shalat dan banyaklah berdo'a hingga selesai gerhana yang terjadi pada kalian\". Peristiwa ini berkenaan ketika putra Nabi shallallahu 'alaihi wasallam yang bernama Ibrahim wafat yang manusia kemudian memperbincangkannya\"."},"1003":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو أَحْمَدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى عَنْ عَمْرَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِهِمْ فِي كُسُوفِ الشَّمْسِ أَرْبَعَ رَكَعَاتٍ فِي سَجْدَتَيْنِ الْأَوَّلُ الْأَوَّلُ أَطْوَلُ","id":"Telah menceritakan kepada kami [Mahmud bin Ghoilan] berkata, telah menceritakan kepada kami [Abu Ahmad] berkata, telah menceritakan kepada kami [Sufyan] dari [Yahya] dari ['Amrah] dari ['Aisyah radliallahu 'anha] bahwa Nabi shallallahu 'alaihi wasallam shalat bersama mereka (para sahabat) ketika terjadi gerhana matahari dengan empat ruku' dalam dua kali sujud, dan rakaat yang pertama lebih panjang\"."},"1004":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مِهْرَانَ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ أَخْبَرَنَا ابْنُ نَمِرٍ سَمِعَ ابْنَ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاجَهَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةِ الْخُسُوفِ بِقِرَاءَتِهِ فَإِذَا فَرَغَ مِنْ قِرَاءَتِهِ كَبَّرَ فَرَكَعَ وَإِذَا رَفَعَ مِنْ الرَّكْعَةِ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ ثُمَّ يُعَاوِدُ الْقِرَاءَةَ فِي صَلَاةِ الْكُسُوفِ أَرْبَعَ رَكَعَاتٍ فِي رَكْعَتَيْنِ وَأَرْبَعَ سَجَدَاتٍوَقَالَ الْأَوْزَاعِيُّ وَغَيْرُهُ سَمِعْتُ الزُّهْرِيَّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّ الشَّمْسَ خَسَفَتْ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَ مُنَادِيًا بُ الصَّلَاةُ جَامِعَةٌ فَتَقَدَّمَ فَصَلَّى أَرْبَعَ رَكَعَاتٍ فِي رَكْعَتَيْنِ وَأَرْبَعَ سَجَدَاتٍ وَأَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ نَمِرٍ سَمِعَ ابْنَ شِهَابٍ مِثْلَهُ قَالَ الزُّهْرِيُّ فَقُلْتُ مَا صَنَعَ أَخُوكَ ذَلِكَ عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ مَا صَلَّى إِلَّا رَكْعَتَيْنِ مِثْلَ الصُّبْحِ إِذْ صَلَّى بِالْمَدِينَةِ قَالَ أَجَلْ إِنَّهُ أَخْطَأَ السُّنَّةَ تَابَعَهُ سُفْيَانُ بْنُ حُسَيْنٍ وَسُلَيْمَانُ بْنُ كَثِيرٍ عَنْ الزُّهْرِيِّ فِي الْجَهْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Mihran] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah mengabarkan kepada kami [Ibnu Namir], dia mendengar [Ibnu Syihab] dari ['Urwah] dari ['Aisyah radliallahu 'anha]: \"Nabi shallallahu 'alaihi wasallam mengeraskan bacaan dalam shalat gerhana. Jika selesai dari bacaan Beliau membaca takbir kemudian ruku'. Jika mengangkat kepalanya dari ruku' Beliau membaca \"sami'allahu liman hamidah Rabbanaa lakal hamd\". Kemudian Beliau mengulang bacaannya dalam shalat gerhana dengan empat kali ruku' dalam dua raka'at dan empat kali sujud\". Berkata, [Al Awza'iy] dan selainnya aku mendengar [Az Zuhriy] dari ['Urwah] dari ['Aisyah radliallahu 'anha] bahwa pernah terjadi gerhana matahari pada zaman Rasulullah shallallahu 'alaihi wasallam, maka Beliau mengutus seorang mu'adzin untuk menyerukan \"Ashalaatul Jaami'ah\". Maka kemudian Beliau maju dan shalat dengan empat kali ruku' dalam dua raka'at dan empat kali sujud\". Dan telah mengabarkan kepada saya ['Abdurrahman bin Namir] bahwasanya dia mendengar [Ibnu Syihab] seperti ini. Berkata, [Az Zuhriy]; Aku bertanya: \"Apa alasan saudaramu 'Abdullah bin Az Zubair yang tidak melaksanakan shalat (gerhana) kecuali dengan dua raka'at seperti shalat Shubuh ketika shalat di Madinah?\" Dia menjawab: \"Benar begitu adanya dan itu adalah menyalahi sunnah\". Riwayat ini juga diikuti oleh [Sufyan bin Husain], [Sulaiman bin Katsir] dari [Az Zuhri] dalam (shalat) jahar (shalat yang bacaan alfatihah dan surat sesudahnya dibaca terang) \"."},"1005":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا غُنْدَرٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ الْأَسْوَدَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَرَأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّجْمَ بِمَكَّةَ فَسَجَدَ فِيهَا وَسَجَدَ مَنْ مَعَهُ غَيْرَ شَيْخٍ أَخَذَ كَفًّا مِنْ حَصًى أَوْ تُرَابٍ فَرَفَعَهُ إِلَى جَبْهَتِهِ وَقَالَ يَكْفِينِي هَذَا فَرَأَيْتُهُ بَعْدَ ذَلِكَ قُتِلَ كَافِرًا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ghundar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] berkata; aku mendengar [Al Aswad] dari ['Abdullah radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam membaca surah An-Najm ketika berada di Makkah. Maka Beliau sujud tilawah begitu juga orang-orang yang bersama Beliau. Kecuali ada seorang yang tua, dia hanya mengambil segenggam kerikil atau tanah lalu menempelkannya pada mukanya seraya berkata; \"bagiku cukup begini\". Di kemudian hari aku melihat orang itu terbunuh dalam kekafiran\"."},"1006":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْجُمُعَةِ فِي صَلَاةِ الْفَجْرِ الم تَنْزِيلُ السَّجْدَةُ وَهَلْ أَتَى عَلَى الْإِنْسَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Sa'ad bin Ibrahim] dari ['Abdurrahman] dari [Abu Hurairah radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam membaca pada shalat Shubuh hari Jum'at surah As-Sajadah dan Al Insan\"."},"1007":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَأَبُو النُّعْمَانِ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَص لَيْسَ مِنْ عَزَائِمِ السُّجُودِ وَقَدْ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْجُدُ فِيهَا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] dan [Abu an-Nu'man] keduanya berkata,, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: Pada surat Shad tidak ada kewajiban untuk sujud tilawah, namun aku melihat Nabi shallallahu 'alaihi wasallam melaksanakan sujud ketika membacanya\"."},"1008":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ سُورَةَ النَّجْمِ فَسَجَدَ بِهَا فَمَا بَقِيَ أَحَدٌ مِنْ الْقَوْمِ إِلَّا سَجَدَ فَأَخَذَ رَجُلٌ مِنْ الْقَوْمِ كَفًّا مِنْ حَصًى أَوْ تُرَابٍ فَرَفَعَهُ إِلَى وَجْهِهِ وَقَالَ يَكْفِينِي هَذَا قَالَ عَبْدُ اللَّهِ فَلَقَدْ رَأَيْتُهُ بَعْدُ قُتِلَ كَافِرًا","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Aswad] dari ['Abdullah radliallahu 'anhu] berkata: \"Bahwa Nabi shallallahu 'alaihi wasallam membaca surah An-Najm lalu Beliau sujud dan tidak ada seorang pun dari kaum saat itu melainkan mengikuti beliau untuk sujud. Kecuali ada seseorang dari mereka yang ia hanya mengambil segenggam kerikil atau tanah lalu menempelkannya pada mukanya seraya berkata; \"bagiku cukup begini\". Berkata, 'Abdullah: Di kemudian hari aku melihat orang itu terbunuh dalam kekafiran\"."},"1009":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ بِالنَّجْمِ وَسَجَدَ مَعَهُ الْمُسْلِمُونَ وَالْمُشْرِكُونَ وَالْجِنُّ وَالْإِنْسُوَرَوَاهُ إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ أَيُّوبَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami ['Abdul Warits] berkata, telah menceritakan kepada kami [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma]: \"Bahwa Nabi shallallahu 'alaihi wasallam melakukan sujud tilawah ketika membaca surah An-Najm. Begitu juga ikut sujud bersama Beliau dari kalangan Kaum Muslimin, Musyrikin, bangsa jin dan manusia. Hadits ini juga diriwayatkan oleh [Ibrahim bin Thahman] dari [Ayyub]."},"1010":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ أَبُو الرَّبِيعِ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ قَالَ أَخْبَرَنَا يَزِيدُ بْنُ خُصَيْفَةَ عَنْ ابْنِ قُسَيْطٍ عَنْ عَطَاءِ بْنِ يَسَارٍ أَنَّهُ أَخْبَرَهُ أَنَّهُ سَأَلَ زَيْدَ بْنَ ثَابِتٍ رَضِيَ اللَّهُ عَنْهُ فَزَعَمَأَنَّهُ قَرَأَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّجْمِ فَلَمْ يَسْجُدْ فِيهَا","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Abu Ar-Rabi'] berkata, telah menceritakan kepada kami [Isma'il bin Ja'far] berkata, telah mengabarkan kepada kami [Yazid bin Khushaifah] dari [Ibnu Qusaith] dari ['Atho' bin Basar] bahwa dia mengabarkannya, bahwa dia pernah bertanya kepada [Zaid bin Tsabit radliallahu 'anhu] (tentang sujud tilawah pada surah An-Najm). Maka dia menceritakan bahwa dia pernah membaca surah An-Najm untuk Nabi shallallahu 'alaihi wasallam namun Beliau tidak melakukan sujud tilawah padanya\"."},"1011":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَقَرَأْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّجْمِ فَلَمْ يَسْجُدْ فِيهَا","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] berkata, telah menceritakan kepada kami [Ibnu Abu Dza'bi] berkata, telah menceritakan kepada kami [Yazid bin 'Abdullah bin Qusaith] dari ['Atho' bin Basar] dari [Zaid bin Tsabit radliallahu 'anhu] berkata: \"Aku pernah membaca surah An-Najm untuk Nabi shallallahu 'alaihi wasallam dan Beliau tidak melakukan sujud tilawah padanya\"."},"1012":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْ��َاهِيمَ وَمُعَاذُ بْنُ فَضَالَةَ قَالَا أَخْبَرَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ قَالَ رَأَيْتُ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُقَرَأَ إِذَا السَّمَاءُ انْشَقَّتْ فَسَجَدَ بِهَا فَقُلْتُ يَا أَبَا هُرَيْرَةَ أَلَمْ أَرَكَ تَسْجُدُ قَالَ لَوْ لَمْ أَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْجُدُ لَمْ أَسْجُدْ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] dan [Mu'adz bin Fadhalah] keduanya berkata, telah mengabarkan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] berkata; \"Aku melihat [Abu Hurairah radliallahu 'anhu] membaca idzas samaa-unsyaqqat (QS Al Insyiqaq) lalu dia sujud tilawah. Kemudian aku bertanya kepadanya: \"Wahai Abu Hurairah mengapa anda melakukan sujud?\" Maka dia menjawab: \"Seandainya aku tidak melihat Nabi shallallahu 'alaihi wasallam sujud, tentu aku tidak akan sujud\"."},"1013":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى حَدَّثَنَا عُبَيْدُ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ عَلَيْنَا السُّورَةَ فِيهَا السَّجْدَةُ فَيَسْجُدُ وَنَسْجُدُ حَتَّى مَا يَجِدُ أَحَدُنَا مَوْضِعَ جَبْهَتِهِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami ['Ubaidullah] berkata, telah menceritakan kepada saya [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] berkata; \"Nabi shallallahu 'alaihi wasallam pernah membacakan untuk kami satu surat yang berisi ayat sajadah. Kemudian Beliau sujud. Lalu kami pun sujud hingga ada seorang diantara kami yang tidak mendapatkan tempat untuk meletakkan keningnya\"."},"1014":{"ar":"حَدَّثَنَا بِشْرُ بْنُ آدَمَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ قَالَ أَخْبَرَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ السَّجْدَةَ وَنَحْنُ عِنْدَهُ فَيَسْجُدُ وَنَسْجُدُ مَعَهُ فَنَزْدَحِمُ حَتَّى مَا يَجِدُ أَحَدُنَا لِجَبْهَتِهِ مَوْضِعًا يَسْجُدُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Bisyir bin Adam] berkata, telah menceritakan kepada kami ['Ali bin Mushir] berkata, telah mengabarkan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] berkata; \"Nabi shallallahu 'alaihi wasallam pernah membaca ayat sajadah. Saat itu kami sedang berkumpul bersama Beliau. Maka Beliau pun sujud. Lalu kami pun sujud bersama Beliau dengan berebut berdesakan, hingga ada seorang diantara kami yang tidak mendapatkan tempat untuk keningnya untuk bersujud.\" "},"1015":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى قَالَ أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي أَبُو بَكْرِ بْنُ أَبِي مُلَيْكَةَ عَنْ عُثْمَانَ بْنِ عَبْدِ الرَّحْمَنِ التَّيْمِيِّ عَنْ رَبِيعَةَ بْنِ عَبْدِ اللَّهِ بْنِ الْهُدَيْرِ التَّيْمِيِّ قَالَ أَبُو بَكْرٍ وَكَانَ رَبِيعَةُ مِنْ خِيَارِ النَّاسِ عَمَّا حَضَرَ رَبِيعَةُ مِنْ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُقَرَأَ يَوْمَ الْجُمُعَةِ عَلَى الْمِنْبَرِ بِسُورَةِ النَّحْلِ حَتَّى إِذَا جَاءَ السَّجْدَةَ نَزَلَ فَسَجَدَ وَسَجَدَ النَّاسُ حَتَّى إِذَا كَانَتْ الْجُمُعَةُ الْقَابِلَةُ قَرَأَ بِهَا حَتَّى إِذَا جَاءَ السَّجْدَةَ قَالَ يَا أَيُّهَا النَّاسُ إِنَّا نَمُرُّ بِالسُّجُودِ فَمَنْ سَجَدَ فَقَدْ أَصَابَ وَمَنْ لَمْ يَسْجُدْ فَلَا إِثْمَ عَلَيْهِ وَلَمْ يَسْجُدْ عُمَرُ رَضِيَ اللَّهُ عَنْهُوَزَادَ نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا إِنَّ اللَّهَ لَمْ يَفْرِضْ السُّجُودَ إِلَّا أَنْ نَشَاءَ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] berkata, telah mengabarkan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] mengabarkan mereka katanya telah mengabarkan kepada saya [Abu Bakar bin Abu Mulaikah] dari ['Utsman bin 'Abdurrahman At-Taimiy] dari [Rabi'ah bin 'Abdullah Al Hudair At-Taimiy]. Berkata, Abu Bakar; \"Rabi'ah adalah orang yang paling baik dalam mengisahkan segala hal yang berasal dari majelis ['Umar bin Al Khaththob radliallahu 'anhu], saat hari Jum'at, 'Umar bin Al Khaththab radliallahu 'anhu membaca surah An-Nahl dari atas mimbar hingga ketika sampai pada ayat sajadah, dia turun dari mimbar lalu melakukan sujud tilawah. Maka orang-orang pun turut melakukan sujud. Kemudian pada waktu shalat Jum'at berikutnya dia membaca surat yang sama hingga ketika sampai pada ayat sajadah dia berkata: \"Wahai sekalian manusia, kita telah membaca dan melewati ayat sajadah. Maka barangsiapa yang sujud, benarlah dia. Namun yang tidak melakukan sujud tidak ada dosa baginya. Dan 'Umar bin Al Khaththab radliallahu 'anhu tidak melakukan sujud\". [Nafi'] menambahkan dari [Ibnu 'Umar radliallahu 'anhuma]: \"Allah subhanahu wata'ala tidaklah mewajibkan sujud tilawah. Kecuali siapa yang mau silakan melakukannya\"."},"1016":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي قَالَ حَدَّثَنِي بَكْرٌ عَنْ أَبِي رَافِعٍ قَالَصَلَّيْتُ مَعَ أَبِي هُرَيْرَةَ الْعَتَمَةَ فَقَرَأَ إِذَا السَّمَاءُ انْشَقَّتْ فَسَجَدَ فَقُلْتُ مَا هَذِهِ قَالَ سَجَدْتُ بِهَا خَلْفَ أَبِي الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَزَالُ أَسْجُدُ فِيهَا حَتَّى أَلْقَاهُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Mu'tamir] berkata; aku mendengar [bapakku] berkata, telah menceritakan kepada saya [Bakar] dari [Abu Rafi'] berkata: \"Aku pernah shalat 'Atmah ('Isya di penghujung malam) bersama [Abu Hurairah radliallahu 'anhu]. Dia membaca idzas samaa-unsyaqqat (QS Al Insyiqaq) lalu dia sujud tilawah. Kemudian aku bertanya kepadanya: \"Mengapa anda melakukan ini?\" Maka dia menjawab: \"Aku pernah sujud di belakang Abul Qasim shallallahu 'alaihi wasallam. Dan senantiasa aku melakukan sujud ketika membacanya sampai akhir hayatku\"."},"1017":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ قَالَ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ السُّورَةَ الَّتِي فِيهَا السَّجْدَةُ فَيَسْجُدُ وَنَسْجُدُ مَعَهُ حَتَّى مَا يَجِدُ أَحَدُنَا مَكَانًا لِمَوْضِعِ جَبْهَتِهِ","id":"Telah menceritakan kepada kami [Shadaqah bin Al Fadhal] berkata, telah mengabarkan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] berkata; \"Nabi shallallahu 'alaihi wasallam pernah membaca satu surat yang berisi ayat sajadah. Kemudian Beliau sujud. Lalu kami pun sujud bersama Beliau, hingga ada seorang diantara kami yang tidak mendapatkan tempat untuk meletakkan keningnya\"."},"1018":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَاصِمٍ وَحُصَيْنٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِسْعَةَ عَشَرَ يَقْصُرُ فَنَحْنُ إِذَا سَافَرْنَا تِسْعَةَ عَشَرَ قَصَرْنَا وَإِنْ زِدْنَا أَتْمَمْنَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Abu 'Awanah] dari ['Ashim] dari [Hushain] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Nabi shallallahu 'alaihi wasallam pernah menetap (dalam bepergian) selama sembilan belas hari dengan mengqashar (meringkas) shalat. Maka kami bila bepergian selama sembilan belas hari mengqashar solat. Bila lebih dari itu, kami menyempurnakan shalat\"."},"1019":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ أَنَسًا يَقُولُخَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمَدِينَةِ إِلَى مَكَّةَ فَكَانَ يُصَلِّي رَكْعَتَيْنِ رَكْعَتَيْنِ حَتَّى رَجَعْنَا إِلَى الْمَدِينَةِ قُلْتُ أَقَمْتُمْ بِمَكَّةَ شَيْئًا قَالَ أَقَمْنَا بِهَا عَشْرًا","id":"Telah menceritakan kepada kami [Abu Ma'mar] berkata, telah menceritakan kepada kami ['Abdul Warits] berkata, telah menceritakan kepada kami [Yahya bin Abu Ishaq] berkata; Aku mendengar [Anas radliallahu 'anhu] berkata: \"Kami pernah bepergian bersama Nabi shallallahu 'alaihi wasallam dari kota Madinah menuju kota Makkah, selama kepergian itu Beliau melaksanakan shalat dua raka'at dua raka'at hingga kami kembali ke Madinah. Aku tanyakan: 'Berapa lama kalian menetap di Makkah?\" Dia menjawab: \"Kami menetap disana selama sepuluh hari\"."},"1020":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى رَكْعَتَيْنِ وَأَبِي بَكْرٍ وَعُمَرَ وَمَعَ عُثْمَانَ صَدْرًا مِنْ إِمَارَتِهِ ثُمَّ أَتَمَّهَا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] berkata, telah mengabarkan kepada saya [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhuma] berkata: \"Aku pernah shalat bersama Nabi shallallahu 'alaihi wasallam di kota Mina dua raka'at. Begitu juga ketika aku shalat bersama Abu Bakar, 'Umar dan juga bersama 'Utsman pada awal pemerintahannya. Namun beliau di kemudian hari menyempurnakannya (empat raka'at)."},"1021":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ أَنْبَأَنَا أَبُو إِسْحَاقَ قَالَ سَمِعْتُ حَارِثَةَ بْنَ وَهْبٍ قَالَصَلَّى بِنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آمَنَ مَا كَانَ بِمِنًى رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] telah memberitakan kepada kami [Abu Ishaq] berkata; Aku mendengar [Haritsah bin Wahb] berkata: \"Nabi shallallahu 'alaihi wasallam shalat bersama kami, sebagaimana Beliau selalu lakukan seperti saat di Mina hanya dua raka'at\"."},"1022":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ عَنْ الْأَعْمَشِ قَالَ حَدَّثَنَا إِبْرَاهِيمُ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَزِيدَ يَقُولُصَلَّى بِنَا عُثْمَانُ بْنُ عَفَّانَ رَضِيَ اللَّهُ عَنْهُ بِمِنًى أَرْبَعَ رَكَعَاتٍ فَقِيلَ ذَلِكَ لِعَبْدِ اللَّهِ بْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ فَاسْتَرْجَعَ ثُمَّ قَالَ صَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى رَكْعَتَيْنِ وَصَلَّيْتُ مَعَ أَبِي بَكْرٍ الصِّدِّيقِ رَضِيَ اللَّهُ عَنْهُ بِمِنًى رَكْعَتَيْنِ وَصَلَّيْتُ مَعَ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ بِمِنًى رَكْعَتَيْنِ فَلَيْتَ حَظِّي مِنْ أَرْبَعِ رَكَعَاتٍ رَكْعَتَانِ مُتَقَبَّلَتَانِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami ['Abdul Wahid bin Ziyad] dari [Al A'masy] berkata, telah menceritakan kepada kami [Ibrahim] berkata; Aku mendengar ['Abdurrahman bin Yazid] berkata; 'Usman bin 'Affan radliallahu 'anhu pernah shalat bersama kami di Mina sebanyak empat raka'at. Kemudian hal ini disampaikan kepada [Ibnu Mas'ud radliallahu 'anhu] maka dia mengucapkan istirja' (innaa lillahi wa innaa ilahi raji'un) kemudian berkata: \"Sungguh aku selalu shalat bersama Rasulullah shallallahu 'alaihi wasallam di Mina sebanyak dua raka'at. Begitu juga aku shalat bersama Abu Bakat Ash-Shiddiq radliallahu 'anhu di Mina sebanyak dua raka'at. Juga aku pernah shalat 'Umar bin Al Khaththob radliallahu 'anhu di Mina sebanyak dua raka'at. Namun aku berharap shalat yang empat raka'at maupun dua raka'at keduanya diterima\"."},"1023":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي الْعَالِيَةِ الْبَرَّاءِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ لِصُبْحِ رَابِعَةٍ يُلَبُّونَ بِالْحَجِّ فَأَمَرَهُمْ أَنْ يَجْعَلُوهَا عُمْرَةً إِلَّا مَنْ مَعَهُ الْهَدْيُتَابَعَهُ عَطَاءٌ عَنْ جَابِرٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Wuhaib] berkata, telah menceritakan kepada kami [Ayyub] dari [Abu Al 'Aliyah Al Barra'] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Pernah Nabi shallallahu 'alaihi wasallam dan para sahabatnya datang pada shubuh keempat yang ketika itu mereka niyatkan untuk haji, lantas Beliau memerintahkan mereka agar menjadikannya sebagai 'umrah kecuali bagi siapa yang membawa hewan sembelihan\". Hadits ini juga diikuti oleh ['Atho'] dari [Jabir]."},"1024":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ قَالَ قُلْتُ لِأَبِي أُسَامَةَ حَدَّثَكُمْ عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُسَافِرْ الْمَرْأَةُ ثَلَاثَةَ أَيَّامٍ إِلَّا مَعَ ذِي مَحْرَمٍ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzholah] berkata; Aku berkata, kepada [Abu Usamah] apakah ['Ubaidullah] telah menceritakan kepada kalian dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Seorang wanita tidak boleh mengadakan perjalanan diatas tiga hari kecuali bersama mahramnya\"."},"1025":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُسَافِرْ الْمَرْأَةُ ثَلَاثًا إِلَّا مَعَ ذِي مَحْرَمٍتَابَعَهُ أَحْمَدُ عَنْ ابْنِ الْمُبَارَكِ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] telah mengabarkan kepada saya [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Seorang wanita tidak boleh mengadakan perjalanan diatas tiga hari kecuali bersama mahramnya\". Hadits ini diikuti pula oleh [Ahmad] dari [Ibnu Al Mubarak] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam."},"1026":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ قَالَ حَدَّثَنَا سَعِيدٌ الْمَقْبُرِيُّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ تُسَافِرَ مَسِيرَةَ يَوْمٍ وَلَيْلَةٍ لَيْسَ مَعَهَا حُرْمَةٌتَابَعَهُ يَحْيَى بْنُ أَبِي كَثِيرٍ وَسُهَيْلٌ وَمَالِكٌ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Ibnu Abu Dza'bi] berkata, [Said Al Maqbariy] dari [bapaknya] dari [Abu Hurairah radliallahu 'anhu a] berkata; Telah bersabda Nabi shallallahu 'alaihi wasallam; \"Tidak halal seorang wanita yang beriman kepada Allah dan hari akhir untuk mengadakan perjalanan selama satu hari satu tanpa didampingi mahramnya\". Hadits ini diikuti pula oleh [Yahya bin Abu Katsir], [Suhail] dan [Malik] dari [Al Maqburiy] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam."},"1027":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ وَإِبْرَاهِيمَ بْنِ مَيْسَرَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّيْتُ الظُّهْرَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ أَرْبَعًا وَبِذِي الْحُلَيْفَةِ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Al Munkadir] dan [Ibrahim bin Maisarah] dari [Anas bin Malik radliallahu 'anhu] berkata: \"Aku shalat Zhuhur bersama Nabi shallallahu 'alaihi wasallam di Madinah sebanyak empat raka'at sedangkan ketika di Dzul Hulaifah dua raka'at\"."},"1028":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْالصَّلَاةُ أَوَّلُ مَا فُرِضَتْ رَكْعَتَيْنِ فَأُقِرَّتْ صَلَاةُ السَّفَرِ وَأُتِمَّتْ صَلَاةُ الْحَضَرِقَالَ الزُّهْرِيُّ فَقُلْتُ لِعُرْوَةَ مَا بَالُ عَائِشَةَ تُتِمُّ قَالَ تَأَوَّلَتْ مَا تَأَوَّلَ عُثْمَانُ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] berkata, telah menceritakan kepada kami [Sufyan] dari [Az Zuhriy] dari ['Urwah] dari ['Aisyah radliallahu 'anha] berkata: \"Awal mula diwajibkannya shalat sebanyak dua raka'at. Kemudian ketentuan ini ditetapkan untuk shalat safar (dalam bepergian) dan disempurnakan bagi shalat di tempat tinggal (mukim) \". Berkata, Az Zuhriy: \"Aku bertanya kepada 'Urwah: \"Mengapa 'Aisyah radliallahu 'anha menyempurnakan?\" 'Urwah menjawab: \"Dia mengikuti seperti yang dilakukan 'Utsman\"."},"1029":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَعْجَلَهُ السَّيْرُ فِي السَّفَرِ يُؤَخِّرُ الْمَغْرِبَ حَتَّى يَجْمَعَ بَيْنَهَا وَبَيْنَ الْعِشَاءِقَالَ سَالِمٌ وَكَانَ عَبْدُ اللَّهِ بْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَفْعَلُهُ إِذَا أَعْجَلَهُ السَّيْرُ وَزَادَ اللَّيْثُ قَالَ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ سَالِمٌ كَانَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَجْمَعُ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ بِالْمُزْدَلِفَةِ قَالَ سَالِمٌ وَأَخَّرَ ابْنُ عُمَرَ الْمَغْرِبَ وَكَانَ اسْتُصْرِخَ عَلَى امْرَأَتِهِ صَفِيَّةَ بِنْتِ أَبِي عُبَيْدٍ فَقُلْتُ لَهُ الصَّلَاةَ فَقَالَ سِرْ فَقُلْتُ الصَّلَاةَ فَقَالَ سِرْ حَتَّى سَارَ مِيلَيْنِ أَوْ ثَلَاثَةً ثُمَّ نَزَلَ فَصَلَّى ثُمَّ قَالَ هَكَذَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي إِذَا أَعْجَلَهُ السَّيْرُ وَقَالَ عَبْدُ اللَّهِ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَعْجَلَهُ السَّيْرُ يُؤَخِّرُ الْمَغْرِبَ فَيُصَلِّيهَا ثَلَاثًا ثُمَّ يُسَلِّمُ ثُمَّ قَلَّمَا يَلْبَثُ حَتَّى يُقِيمَ الْعِشَاءَ فَيُصَلِّيهَا رَكْعَتَيْنِ ثُمَّ يُسَلِّمُ وَلَا يُسَبِّحُ بَعْدَ الْعِشَاءِ حَتَّى يَقُومَ مِنْ جَوْفِ اللَّيْلِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya [Salim] dari ['Abdullah bin 'Umar radliallahu 'anhu] berkata: \"Aku melihat Rasulullah shallallahu 'alaihi wasallam jika perjalanan mendesak, Beliau menangguhkan shalat Maghrib dan menggabungkannya bersama shalat 'Isya'\". Berkata, Salim: \"Dan 'Abdullah bin 'Umar radliallahu 'anhu mengerjakannya juga bila terdesak (tergesa-gesa) dalam perjalanan\". [Al Laits] menambahkan dan berkata, telah menceritakan kepada saya [Yunus] dari [Ibnu Syihab]; [Salim] berkata: [Ibnu 'Umar radliallahu 'anhuma] menggabungkan antara shalat Maghrib dan 'Isya' saat berada di Muzdalifah. Salim berkata, lagi; \"Ibnu 'Umar radliallahu 'anhuma mengakhirkan shalat Maghrib karena hendak menolong isterinya Shafiyah binti Abu 'Ubaid (yang sedang sakit). Aku katakan kepadanya; \"Mari kita dirikan shalat?!\". Dia menjawab: \"Terus saja berjalan\". Aku katakan lagi; \" Mari kita dirikan shalat?!\". Dia menjawab: \"Terus saja berjalan\". Hingga ketika perjalanan sudah mencapai dua atau tiga mil, dia turun lalu mendirikan shalat. Setelah selesai dia berkata: \"Beginilah, aku pernah melihat Nabi shallallahu 'alaihi wasallam melaksanakan shalat bila dalam keadaan terdesak dalam perjalanannya\". Dan berkata, 'Abdullah bin 'Umar radliallahu 'anhu: \"Aku melihat Nabi shallallahu 'alaihi wasallam jika perjalanan mendesak, Beliau menangguhkan shalat Maghrib, kemudian Beliau mengerjakan tiga raka'at lalu salam. Kemudian diam sejenak lalu mengerjakan shalat 'Isya' dengan dua raka'at lalu salam. Beliau tidak bertasbih (mengerjakan shalat sunnah) setelah shalat 'Isya' hingga Beliau bangun di penghujung malam\"."},"1030":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ عَنْ أَبِيهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى رَاحِلَتِهِ حَيْثُ تَوَجَّهَتْ بِهِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami ['Abdul 'Abdullah'laa] berkata, telah menceritakan kepada kami [Ma'mar] dari [Az Zuhriy] dari ['Abdullah bin 'Amir bin Rabi'ah] dari [bapaknya] berkata; \"Aku melihat Nabi shallallahu 'alaihi wasallam shalat diatas hewan tunggangannya kearah mana saja hewan tunggangannya berjalan\"."},"1031":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ أَخْبَرَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي التَّطَوُّعَ وَهُوَ رَاكِبٌ فِي غَيْرِ الْقِبْلَةِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Muhammad bin 'Abdurrahman] bahwa [Jabir bin 'Abdullah] telah mengabarkan kepadanya bahwa Nabi shallallahu 'alaihi wasallam mendirikan shalat sunnat sambil mengendarai hewan tunggangannya dalam keadaan tidak menghadap qiblat\"."},"1032":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ قَالَ وَكَانَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَايُصَلِّي عَلَى رَاحِلَتِهِ وَيُوتِرُ عَلَيْهَا وَيُخْبِرُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَفْعَلُهُ","id":"Telah menceritakan kepada kami ['Abdul 'a'laa bin Hammad] berkata, telah menceritakan kepada kami [Wuhaib] berkata, telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Nafi'] berkata; \" [Ibnu 'Umar radliallahu 'anhumaa] pernah mengerjakan shalat diatas hewan tunggangannya dan juga shalat witir dan dia mengabarkan bahwa Nabi shallallahu 'alaihi wasallam mengerjakannya pula\"."},"1033":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ قَالَ كَانَ عَبْدُ اللَّهِ بْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَايُصَلِّي فِي السَّفَرِ عَلَى رَاحِلَتِهِ أَيْنَمَا تَوَجَّهَتْ يُومِئُ وَذَكَرَ عَبْدُ اللَّهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَفْعَلُهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami ['Abdul 'Aziz bin Muslim] berkata, telah menceritakan kepada kami ['Abdullah bin Dinar] berkata: ['Abdullah bin 'Umar radliallahu 'anhu] pernah mengerjakan shalat dalam safarnya diatas hewan tunggangannya kearah manapun ia menghadap dengan cara memberi isyarat. Dan dia memberitakan bahwa Nabi shallallahu 'alaihi wasallam juga pernah mengerjakan seperti itu."},"1034":{"ar":"حَدَّثَنَا يَحْيَى بْن بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ أَنَّ عَامِرَ بْنَ رَبِيعَةَ أَخْبَرَهُ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الرَّاحِلَةِ يُسَبِّحُ يُومِئُ بِرَأْسِهِ قِبَلَ أَيِّ وَجْهٍ تَوَجَّهَ وَلَمْ يَكُنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ ذَلِكَ فِي الصَّلَاةِ الْمَكْتُوبَةِوَقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ قَالَ سَالِمٌ كَانَ عَبْدُ اللَّهِ بْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يُصَلِّي عَلَى دَابَّتِهِ مِنْ اللَّيْلِ وَهُوَ مُسَافِرٌ مَا يُبَالِي حَيْثُ مَا كَانَ وَجْهُهُ قَالَ ابْنُ عُمَرَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَبِّحُ عَلَى الرَّاحِلَةِ قِبَلَ أَيِّ وَجْهٍ تَوَجَّهَ وَيُوتِرُ عَلَيْهَا غَيْرَ أَنَّهُ لَا يُصَلِّي عَلَيْهَا الْمَكْتُوبَةَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Abdullah bin 'Amir bin Rabi'ah] bahwa ['Amir bin Rabi'ah] mengabarkannya berkata: \"Aku melihat Rasulullah shallallahu 'alaihi wasallam di atas hewan tunggangannya bertasbih dengan memberi isyarat dengan kepala beliau kearah mana saja hewan tunggangannya menghadap. Rasulullah shallallahu 'alaihi wasallam tidak pernah melakukan seperti ini untuk shalat-shalat wajib\". Dan berkata, [Al Laits] telah menceritakan kepada saya [Yunus] dari [Ibnu Syihab] berkata; Telah berkata, [Salim]: ['Abdullah bin 'Umar radliallahu 'anhua] ketika bepergian pernah shalat malam diatas tunggangannya ke arah mana saja tunggangannya menghadap. berkata, Ibnu 'Umar radliallahu 'anhuma: \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat sunnat diatas tunggangan Beliau ke arah mana saja menghadap dan juga melaksanakan shalat witir di atasnya. Hanya saja Beliau tidak melaksanakan yang demikian untuk shalat wajib\"."},"1035":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبانَ قَالَ حَدَّثَنِي جَابِرُ بْنُ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي عَلَى رَاحِلَتِهِ نَحْوَ الْمَشْرِقِ فَإِذَا أَرَادَ أَنْ يُصَلِّيَ الْمَكْتُوبَةَ نَزَلَ فَاسْتَقْبَلَ الْقِبْلَةَ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadhalah] berkata, telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Muhammad bin 'Abdurrahman bin Tsauban] berkata, telah menceritakan kepada saya [Jabir bin 'Abdullah], bahwa Nabi shallallahu 'alaihi wasallam mendirikan shalat diatas hewan tunggangannya menghadap ke Timur. Jika Beliau hendak melaksanakan shalat wajib, maka Beliau turun dan melaksanakannya dengan menghadap qiblat\"."},"1036":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَبَّانُ قَالَ حَدَّثَنَا هَمَّامٌ قَالَ حَدَّثَنَا أَنَسُ بْنُ سِيرِينَ قَالَ اسْتَقْبَلْنَا أَنَسَ بْنَ مَالِكٍحِينَ قَدِمَ مِنْ الشَّأْمِ فَلَقِينَاهُ بِعَيْنِ التَّمْرِ فَرَأَيْتُهُ يُصَلِّي عَلَى حِمَارٍ وَوَجْهُهُ مِنْ ذَا الْجَانِبِ يَعْنِي عَنْ يَسَارِ الْقِبْلَةِ فَقُلْتُ رَأَيْتُكَ تُصَلِّي لِغَيْرِ الْقِبْلَةِ فَقَالَ لَوْلَا أَنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَهُ لَمْ أَفْعَلْهُرَوَاهُ إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ حَجَّاجٍ عَنْ أَنَسِ بْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id] berkata, telah menceritakan kepada kami [Habban] berkata, [Hammam] berkata, telah menceritakan kepada kami [Anas bin Sirin] berkata: \"Kami menemui [Anas bin Malik radliallahu 'anhu] sekembalinya dia dari negeri Syam di daerah 'Ainu Tamar. Aku melihat dia sedang shalat di atas keledai dan menghadap ke samping yaitu sebelah kiri arah qiblat. Maka aku tanyakan kepadanya: \"Aku melihat anda shalat tidak menghadap qiblat?\" Maka dia menjawab: \"Seandainya aku tidak melihat Rasulullah shallallahu 'alaihi wasallam mengerjakan seperti itu pasti aku pun tidak akan mengerjakannya\". Dan diriwayatkan oleh [Ibrahim bin Thahman] dari [Hajjaj] dari [Anas bin Sirin] dari [Anas bin Malik radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam."},"1037":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ قَالَ حَدَّثَنِي عُمَرُ بْنُ مُحَمَّدٍ أَنَّ حَفْصَ بْنَ عَاصِمٍ حَدَّثَهُ قَالَ سَافَرَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا فَقَالَصَحِبْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ أَرَهُ يُسَبِّحُ فِي السَّفَرِ وَقَالَ اللَّهُ جَلَّ ذِكْرُهُ{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ إِسْوَةٌ حَسَنَةٌ }","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] berkata, telah menceritakan kepada saya [Ibnu Wahb] berkata, telah menceritakan kepada saya ['Umar bin Muhammad] bahwa [Hafsh bin 'Ashim] menceritakan kepadanya berkata; \" [Ibnu 'Umar radliallahu 'anhumaa] mengadakan perjalanan lalu berkata: \"Aku pernah menemani Nabi shallallahu 'alaihi wasallam dan aku tidak melihat Beliau melaksanakan shalat sunnah dalam safarnya\". Dan Allah subhanahu wata'ala telah berfirman: \"Sungguh telah ada pada (diri) Rasulullah itu suri teladan yang baik bagimu\". (QS. Ahzab 21)."},"1038":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ عِيسَى بْنِ حَفْصِ بْنِ عَاصِمٍ قَالَ حَدَّثَنِي أَبِي أَنَّهُ سَمِعَ ابْنَ عُمَرَ يَقُولُصَحِبْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ لَا يَزِيدُ فِي السَّفَرِ عَلَى رَكْعَتَيْنِ وَأَبَا بَكْرٍ وَعُمَرَ وَعُثْمَانَ كَذَلِكَ رَضِيَ اللَّهُ عَنْهُمْ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari ['Isa bin Hafsh bin 'Ashim] berkata, telah menceritakan kepada saya [Bapakku] bahwasanya dia mendengar [Ibnu 'Umar radliallahu 'anhuma] berkata: \"Aku pernah menemani Rasulullah shallallahu 'alaihi wasallam ketika safar (bepergian), selama kepergian itu Beliau tidak lebih melaksanakan shalat kecuali dua raka'at. Begitu juga dengan Abu Bakar, 'Umar dan 'Utsman radliallahu 'anhum."},"1039":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ ابْنِ أَبِي لَيْلَى قَالَمَا أَخْبَرَنَا أَحَدٌ أَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الضُّحَى غَيْرُ أُمِّ هَانِئٍ ذَكَرَتْ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ اغْتَسَلَ فِي بَيْتِهَا فَصَلَّى ثَمَانِيَ رَكَعَاتٍ فَمَا رَأَيْتُهُ صَلَّى صَلَاةً أَخَفَّ مِنْهَا غَيْرَ أَنَّهُ يُتِمُّ الرُّكُوعَ وَالسُّجُودَوَقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ رَبِيعَةَ أَنَّ أَبَاهُ أَخْبَرَهُ أَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى السُّبْحَةَ بِاللَّيْلِ فِي السَّفَرِ عَلَى ظَهْرِ رَاحِلَتِهِ حَيْثُ تَوَجَّهَتْ بِهِ","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Ibnu Abu Laila] berkata, telah mengabarkan kepada kami seseorang bahwasanya dia melihat Nabi shallallahu 'alaihi wasallam mengerjakan shalat dhuha. Sedangkan [Ummu Hani'] menceritakan bahwa Nabi shallallahu 'alaihi wasallam saat hari Penaklukan Makkah, Beliau mandi di rumahnya kemudian shalat delapan raka'at. (Katanya): \"Aku belum pernah sekalipun melihat Beliau melaksanakan shalat yang lebih ringan dari pada saat itu, namun Beliau tetap menyempurnakan ruku' dan sujudnya\". Berkata, Al Laits telah menceritakan kepada saya Yunus dari Ibnu Syihab berkata, telah menceritakan kepada saya 'Abdullah bin 'Amir bin Rabi'ah bahwa bapaknya mengabarkan kepadanya bahwa dia melihat Nabi shallallahu 'alaihi wasallam mengerjakan shalat sunnat dalam perjalanan (safarnya) di atas punggung hewan tunggangannya ke mana saja arah menghadapnya.\""},"1040":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُسَبِّحُ عَلَى ظَهْرِ رَاحِلَتِهِ حَيْثُ كَانَ وَجْهُهُ يُومِئُ بِرَأْسِهِوَكَانَ ابْنُ عُمَرَ يَفْعَلُهُ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya [Salim bin 'Abdullah] dari [Ibnu 'Umar radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat sunnah diatas punggung hewan tunggangannya ke arah manapun ia menghadap dengan cara memberi isyarat dengan kepala Beliau\". Dan Ibnu 'Umar radliallahu 'anhuma juga melakukan hal yang demikian itu."},"1041":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ الزُّهْرِيَّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْمَعُ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ إِذَا جَدَّ بِهِ السَّيْرُوَقَالَ إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ الْحُسَيْنِ الْمُعَلِّمِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْمَعُ بَيْنَ صَلَاةِ الظُّهْرِ وَالْعَصْرِ إِذَا كَانَ عَلَى ظَهْرِ سَيْرٍ وَيَجْمَعُ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ وَعَنْ حُسَيْنٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ حَفْصِ بْنِ عُبَيْدِ اللَّهِ بْنِ أَنَسٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْمَعُ بَيْنَ صَلَاةِ الْمَغْرِبِ وَالْعِشَاءِ فِي السَّفَرِ وَتَابَعَهُ عَلِيُّ بْنُ الْمُبَارَكِ وَحَرْبٌ عَنْ يَحْيَى عَنْ حَفْصٍ عَنْ أَنَسٍ جَمَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Sufyan] berkata, Aku mendengar [Az Zuhriy] dari [Salim] dari [bapaknya] berkata: \"Nabi shallallahu 'alaihi wasallam pernah menggabungkan (menjama') shalat Maghrib dan shalat 'Isya' bila terdesak (tergesa-gesa) dalam perjalanan\". Dan berkata, [Ibrahim bin Thohman] dari [Al Husain Al Mu'alim] dari [Yahya bin Abu Katsir] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Nabi shallallahu 'alaihi wasallam pernah menggabungkan shalat Zhuhur dan shalat 'Ashar bila sedang dalam perjalanan dan menggabungkan shalat Maghrib dan shalat 'Isya'. Dan dari [Husain] dari [Yahya bin Abu Katsir] dari [Hafsh bin 'Ubaidullah bin Anas] dari [Anas bin Malik radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam pernah menggabungkan shalat Maghrib dan shalat 'Isya' dalam perjalanan\". Hadits ini diikuti pula oleh ['Ali bin Al Mubarak] dan [Harb] dari [Yahya] dari [Hafsh] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam menjama'."},"1042":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَعْجَلَهُ السَّيْرُ فِي السَّفَرِ يُؤَخِّرُ صَلَاةَ الْمَغْرِبِ حَتَّى يَجْمَعَ بَيْنَهَا وَبَيْنَ الْعِشَاءِقَالَ سَالِمٌ وَكَانَ عَبْدُ اللَّهِ بْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَفْعَلُهُ إِذَا أَعْجَلَهُ السَّيْرُ وَيُقِيمُ الْمَغْرِبَ فَيُصَلِّيهَا ثَلَاثًا ثُمَّ يُسَلِّمُ ثُمَّ قَلَّمَا يَلْبَثُ حَتَّى يُقِيمَ الْعِشَاءَ فَيُصَلِّيهَا رَكْعَتَيْنِ ثُمَّ يُسَلِّمُ وَلَا يُسَبِّحُ بَيْنَهُمَا بِرَكْعَةٍ وَلَا بَعْدَ الْعِشَاءِ بِسَجْدَةٍ حَتَّى يَقُومَ مِنْ جَوْفِ اللَّيْلِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya [Salim] dari ['Abdullah bin 'Umar radliallahu 'anhu] berkata: \"Aku melihat Rasulullah shallallahu 'alaihi wasallam jika perjalanan mendesak, Beliau menangguhkan shalat Maghrib dan menggabungkannya bersama shalat 'Isya'\". Berkata, Salim: \"Dan 'Abdullah bin 'Umar radliallahu 'anhu mengerjakannya juga bila terdesak (tergesa-gesa) dalam perjalanan. Beliau hanya melaksanakan shalat Maghrib sebanyak tiga raka'at lalu salam. Kemudian berdiam sejenak lalu melaksanakan shalat 'Isya' sebanyak dua raka'at dan dia tidak menyelingi diantara keduanya dengan shalat sunnah satu raka'atpun dan juga tidak sesudahnya hingga Beliau bangun di penghujung malam (untuk shalat malam)."},"1043":{"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا حَرْبٌ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنِي حَفْصُ بْنُ عُبَيْدِ اللَّهِ بْنِ أَنَسٍ أَنَّ أَنَسًا رَضِيَ اللَّهُ عَنْهُ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَجْمَعُ بَيْنَ هَاتَيْنِ الصَّلَاتَيْنِ فِي السَّفَرِ يَعْنِي الْمَغْرِبَ وَالْعِشَاءَ","id":"Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami ['Abdush Shamad bin 'Abdul Warits] telah menceritakan kepada kami [Harb] telah menceritakan kepada kami [Yahya] berkata, telah menceritakan kepada saya [Hafsh bin 'Ubaidullah bin Anas] bahwa [Anas radliallahu 'anhu] menceritakan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam menjama' (menggabungkan) dua shalat ini ketika dalam perjalanan, yaitu shalat Maghrib dan 'Isya'."},"1044":{"ar":"حَدَّثَنَا حَسَّانُ الْوَاسِطِيُّ قَالَ حَدَّثَنَا الْمُفَضَّلُ بْنُ فَضَالَةَ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ارْتَحَلَ قَبْلَ أَنْ تَزِيغَ الشَّمْسُ أَخَّرَ الظُّهْرَ إِلَى وَقْتِ الْعَصْرِ ثُمَّ يَجْمَعُ بَيْنَهُمَا وَإِذَا زَاغَتْ صَلَّى الظُّهْرَ ثُمَّ رَكِبَ","id":"Telah menceritakan kepada kami [Hassan Al Waasithiy] berkata, telah menceritakan kepada kami [Al Mufadhdhal bin Fadhalah] dari ['Uqail] dari [Ibnu Syihab] dari [Anas bin Malik radliallahu 'anhu] berkata; \"Nabi shallallahu 'alaihi wasallam bila berangkat bepergian sebelum matahari condong, Beliau shallallahu 'alaihi wasallam mengakhirkan pelaksanaan shalat zhuhur hingga waktu shalat 'Ashar lalu menggabungkan (jama') keduanya. Dan bila berangkat setelah matahari condong, Beliau laksanakan shalat Zhuhur terlebih dahulu kemudian setelah itu berangkat\"."},"1045":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا الْمُفَضَّلُ بْنُ فَضَالَةَ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ارْتَحَلَ قَبْلَ أَنْ تَزِيغَ الشَّمْسُ أَخَّرَ الظُّهْرَ إِلَى وَقْتِ الْعَصْرِ ثُمَّ نَزَلَ فَجَمَعَ بَيْنَهُمَا فَإِنْ زَاغَتْ الشَّمْسُ قَبْلَ أَنْ يَرْتَحِلَ صَلَّى الظُّهْرَ ثُمَّ رَكِبَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Al Mufadhdhal bin Fadhalah] dari ['Uqail] dari [Ibnu Syihab] dari [Anas bin Malik radliallahu 'anhu] berkata; \"Rasulullah shallallahu 'alaihi wasallam bila berangkat bepergian sebelum matahari condong, Beliau shallallahu 'alaihi wasallam mengakhirkan pelaksanaan shalat zhuhur hingga waktu shalat 'Ashar, lantas beliau singgah lalu menggabungkan (jama') keduanya. Dan bila matahari condong sebelum berangkat, Beliau laksanakan shalat Zhuhur terlebih dahulu kemudian setelah itu berangkat\"."},"1046":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِهِ وَهُوَ شَاكٍ فَصَلَّى جَالِسًا وَصَلَّى وَرَاءَهُ قَوْمٌ قِيَامًا فَأَشَارَ إِلَيْهِمْ أَنْ اجْلِسُوا فَلَمَّا انْصَرَفَ قَالَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا رَفَعَ فَارْفَعُوا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha] berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah shalat di rumahnya ketika Belliau sedang sakit hingga shalat dengan duduk. Saat itu di belakang Beliau ada orang-orang mengikuti shalat dengan berdiri. Maka Beliau memnberi isyarat kepada mereka agar shalat dengan duduk. Setelah selesai Beliau bersabda: \"Sesungguhnya imam diangkat untuk diikuti. Maka bila dia ruku', ruku'lah kalian dan bila dia mengangkat (kepala), maka angkatlah (kepala) kalian\"."},"1047":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَسَقَطَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ فَرَسٍ فَخُدِشَ أَوْ فَجُحِشَ شِقُّهُ الْأَيْمَنُ فَدَخَلْنَا عَلَيْهِ نَعُودُهُ فَحَضَرَتْ الصَّلَاةُ فَصَلَّى قَاعِدًا فَصَلَّيْنَا قُعُودًا وَقَالَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا رَفَعَ فَارْفَعُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا وَلَكَ الْحَمْدُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhriy] dari [Anas bin Malik radliallahu 'anhu] berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah terjatuh dari kudanya dan mengalami cedera pada bagian kanan badan Beliau. Saat kami datang menjemput Beliau, tiba-tiba masuk waktu shalat. Maka Beliau melaksanakan shalat dengan duduk, maka kami pun turut shalat dengan duduk. Maka Beliau bersabda: \"Sesungguhnya imam diangkat untuk diikuti. Bila ia telah membaca takbir maka bertakbirlah kalian dan bila ia telah ruku', ruku'lah kalian dan bila dia telah bangkit berdiri, bangkitlah kalian dan bila ia berkata, sami'allahu liman hamidah, ucapkanlah oleh kalian: rabbanaa wa lakal hamdu\"."},"1048":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ قَالَ أَخْبَرَنَا رَوْحُ بْنُ عُبَادَةَ أَخْبَرَنَا حُسَيْنٌ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ سَأَلَ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَ أَخْبَرَنَا إِسْحَاقُ قَالَ أَخْبَرَنَا عَبْدُ الصَّمَدِ قَالَ سَمِعْتُ أَبِي قَالَ حَدَّثَنَا الْحُسَيْنُ عَنْ أَبِي بُرَيْدَةَ قَالَ حَدَّثَنِي عِمْرَانُ بْنُ حُصَيْنٍ وَكَانَ مَبْسُورًا قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ الرَّجُلِ قَاعِدًا فَقَالَ إِنْ صَلَّى قَائِمًا فَهُوَ أَفْضَلُ وَمَنْ صَلَّى قَاعِدًا فَلَهُ نِصْفُ أَجْرِ الْقَائِمِ وَمَنْ صَلَّى نَائِمًا فَلَهُ نِصْفُ أَجْرِ الْقَاعِدِ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah mengabarkan kepada kami [Rauh bin 'Ubadah] telah mengabarkan kepada kami [Husain] dari ['Abdullah bin Buraidah] dari ['Imran bin Hushain radliallahu 'anhu] bahwa dia pernah bertanya kepada Nabi shallallahu 'alaihi wasallam, dan telah mengabarkan kepada kami [Ishaq] berkata, telah mengabarkan kepada kami ['Abdush Shamad] berkata; Aku mendengar [Bapakku] berkata, telah menceritakan kepada kami [Al husain] dari [Abu Buraidah] berkata, telah menceritakan kepada saya ['Imran bin Hushain radliallahu 'anhu] yang saat itu sedang menderita sakit wasir berkata; Aku pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang seseorang yang melaksanakan shalat dengan duduk. Maka Beliau shallallahu 'alaihi wasallam menjawab: \"Jika ia shalat dengan berdiri maka itu lebih utama. Dan siapa yang melaksanakan shalat dengan duduk maka baginya setengah pahala dari orang yang shalat dengan berdiri dan siapa yang shalat dengan tidur (berbaring) maka baginya setengah pahala orang yang shalat dengan duduk\"."},"1049":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ أَنَّ عِمْرَانَ بْنَ حُصَيْنٍ وَكَانَ رَجُلًا مَبْسُورًا وَقَالَ أَبُو مَعْمَرٍ مَرَّةً عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ الرَّجُلِ وَهُوَ قَاعِدٌ فَقَالَ مَنْ صَلَّى قَائِمًا فَهُوَ أَفْضَلُ وَمَنْ صَلَّى قَاعِدًا فَلَهُ نِصْفُ أَجْرِ الْقَائِمِ وَمَنْ صَلَّى نَائِمًا فَلَهُ نِصْفُ أَجْرِ الْقَاعِدِقَالَ أَبُو عَبْد اللَّهِ نَائِمًا عِنْدِي مُضْطَجِعًا هَا هُنَا","id":"Telah menceritakan kepada kami [Abu Ma'mar] berkata, telah menceritakan kepada kami [\"Abdul Warits] berkata, telah menceritakan kepada kami [Husain Al Mu'alim] dari ['Abdullah bin Buraidah] bahwa ['Imran bin Hushain radliallahu 'anhu] adalah seorang yang pernah menderita sakit wasir. Dan suatu kali Abu Ma'mar berkata, dari Hushain yang berkata; Aku pernah bertanya kepada Nabi shallallahu 'alaihi wasallam tentang seseorang yang melaksanakan shalat dengan duduk. Maka Beliau shallallahu 'alaihi wasallam menjawab: \"Siapa yang shalat dengan berdiri maka itu lebih utama. Dan siapa yang melaksanakan shalat dengan duduk maka baginya setengah pahala dari orang yang shalat dengan berdiri dan siapa yang shalat dengan tidur (berbaring) maka baginya setengah pahala orang yang shalat dengan duduk\". Berkata, Abu 'Abdullah; \"Menurutku yang dimaksud dengan tidur adalah berbaring.\""},"1050":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ عَبْدِ اللَّهِ عَنْ إِبْرَاهِيمَ بْنِ طَهْمَانَ قَالَ حَدَّثَنِي الْحُسَيْنُ الْمُكْتِبُ عَنْ ابْنِ بُرَيْدَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَتْ بِي بَوَاسِيرُ فَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّلَاةِ فَقَالَ صَلِّ قَائِمًا فَإِنْ لَمْ تَسْتَطِعْ فَقَاعِدًا فَإِنْ لَمْ تَسْتَطِعْ فَعَلَى جَنْبٍ","id":"Telah menceritakan kepada kami ['Abdan] dari ['Abdullah] dari [Ibrahim bin Thohman] berkata, telah menceritakan kepada saya [Al Husain Al Muktib] dari [Abu Buraidah] dari ['Imrah bin Hushain radliallahu 'anhu] berkata: \"Suatu kali aku menderita sakit wasir lalu aku tanyakan kepada Nabi shallallahu 'alaihi wasallam tentang cara shalat. Maka Beliau shallallahu 'alaihi wasallam menjawab: \"Shalatlah dengan berdiri, jika kamu tidak sanggup lakukanlah dengan duduk dan bila tidak sanggup juga lakukanlah dengan berbaring pada salah satu sisi badan\"."},"1051":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أُمِّ الْمُؤْمِنِينَ أَنَّهَا أَخْبَرَتْهُأَنَّهَا لَمْ تَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي صَلَاةَ اللَّيْلِ قَاعِدًا قَطُّ حَتَّى أَسَنَّ فَكَانَ يَقْرَأُ قَاعِدًا حَتَّى إِذَا أَرَادَ أَنْ يَرْكَعَ قَامَ فَقَرَأَ نَحْوًا مِنْ ثَلَاثِينَ آيَةً أَوْ أَرْبَعِينَ آيَةً ثُمَّ رَكَعَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah radliallahu 'anha] Ummul Mukminin bahwasanya ia mengabarinya bahwa ia tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam sekalipun mendirikan shalat malam dengan duduk hingga beliau beranjak tua. Saat tua itulah Beliau membaca surat dengan duduk, hingga jika Beliau akan ruku' maka Beliau berdiri dan Beliau baca sekitar tiga puluh atau empat puluh ayat kemudian Beliau ruku'."},"1052":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ وَأَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي جَالِسًا فَيَقْرَأُ وَهُوَ جَالِسٌ فَإِذَا بَقِيَ مِنْ قِرَاءَتِهِ نَحْوٌ مِنْ ثَلَاثِينَ أَوْ أَرْبَعِينَ آيَةً قَامَ فَقَرَأَهَا وَهُوَ قَائِمٌ ثُمَّ يَرْكَعُ ثُمَّ سَجَدَ يَفْعَلُ فِي الرَّكْعَةِ الثَّانِيَةِ مِثْلَ ذَلِكَ فَإِذَا قَضَى صَلَاتَهُ نَظَرَ فَإِنْ كُنْتُ يَقْظَى تَحَدَّثَ مَعِي وَإِنْ كُنْتُ نَائِمَةً اضْطَجَعَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari ['Abdullah bin Yazid] dan [Abu An-Nadhir] sahaya 'Umar bin 'Ubaidullah dari [Abu Salamah bin 'Abdurrahman] dari ['Aisyah Ummul Mukminin radliallahu 'anha] bahwa Rasulullah shallallahu 'alaihi wasallam pernah melaksanakan shalat dengan duduk dan Beliau membaca surat sambil duduk. Bila sedikit tersisa dari bacaannya sekitar tiga puluh atau empat puluh ayat, maka Beliau berdiri dan melanjutkan bacaannya itu dengan berdiri. Kemudian Beliau ruku' lalu sujud', Kemudian Beliau melakukan seperti itu pada raka'at kedua. Bila Beliau telah menyelesaikan shalatnya, Beliau melihat (kepadaku). Bila aku telah bangun maka Beliau mengajak aku berbincang dan bila aku masih tidur, maka Beliau berbaring\"."},"1053":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ أَبِي مُسْلِمٍ عَنْ طَاوُسٍ سَمِعَ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ مِنْ اللَّيْلِ يَتَهَجَّدُ قَالَ اللَّهُمَّ لَكَ الْحَمْدُ أَنْتَ قَيِّمُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ وَلَكَ الْحَمْدُ لَكَ مُلْكُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ وَلَكَ الْحَمْدُ أَنْتَ نُورُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ وَلَكَ الْحَمْدُ أَنْتَ مَلِكُ السَّمَوَاتِ وَالْأَرْضِ وَلَكَ الْحَمْدُ أَنْتَ الْحَقُّ وَوَعْدُكَ الْحَقُّ وَلِقَاؤُكَ حَقٌّ وَقَوْلُكَ حَقٌّ وَالْجَنَّةُ حَقٌّ وَالنَّارُ حَقٌّ وَالنَّبِيُّونَ حَقٌّ وَمُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَقٌّ وَالسَّاعَةُ حَقٌّ اللَّهُمَّ لَكَ أَسْلَمْتُ وَبِكَ آمَنْتُ وَعَلَيْكَ تَوَكَّلْتُ وَإِلَيْكَ أَنَبْتُ وَبِكَ خَا��َمْتُ وَإِلَيْكَ حَاكَمْتُ فَاغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ وَمَا أَسْرَرْتُ وَمَا أَعْلَنْتُ أَنْتَ الْمُقَدِّمُ وَأَنْتَ الْمُؤَخِّرُ لَا إِلَهَ إِلَّا أَنْتَ أَوْ لَا إِلَهَ غَيْرُكَقَالَ سُفْيَانُ وَزَادَ عَبْدُ الْكَرِيمِ أَبُو أُمَيَّةَ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ قَالَ سُفْيَانُ قَالَ سُلَيْمَانُ بْنُ أَبِي مُسْلِمٍ سَمِعَهُ مِنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepada kami [Sulaiman bin Abu Muslim] dari [Thawus] bahwa dia mendengar [Ibnu 'Abbas radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam bila berdiri melaksanakan shalat malam, Beliau memulainya dengan membaca doa (istiftah: \"Allahumma lakal hamdu. Anta qayyumus samaawaati wal ardhi wa man fiihinna. Wa lakal hamdu lakal mulkus samaawaati wal ardhi wa man fiihinna. Wa lakal hamdu anta nuurus samaawaati wal ardhi wa man fiihinna. Wa lakal hamdu anta malikus samaawaati wal ardhi. Wa lakal hamdu antal haqq wa wa'dukal haqq wa liqao-ukal haqq wa qaulukal haqq wal jannatul haqq wan naarul haqq wan nabiyyuuna haqq wa muhammadun shallallhu wa salam haqq was saa'atu haq. Allahumma laka aslamtu wa bika aamantu wa 'alaika tawakkaltu wa ilaika anabtu wa bika khashamtu wa ilaika haakamtu, faghfirlii maa qaddamtu wa maa akhkhartu wa maa asrartu wa maa 'Abdullah'lantu antal muqaddimu wa antal mu'akhiru laa ilaaha illaa anta\" aw \"laa ilaaha ghoiruka\". (\"Ya Allah bagiMulah segala pujian. Engkaulah Yang Maha Memelihara langit dan bumi serta apa yang ada pada keduanya. Dan bagiMulah segala pujian, milikMu kerajaan langit dan bumi serta apa yang ada pada keduanya. Dan bagiMu segala pujian, Engkau cahaya langit dan bumi dan apa yang ada pada keduanya. Dan bagiMu segala pujian, Engkaulah raja di langit dan di bumi serta apa yang ada pada keduanya. Dan bagiMulah segala puian, Engkaulah Al Haq (Yang Maha Benar), dan janjiMu haq (benar adanya), dan perjumpaan dengaMu adalah benar, firmanMu benar, surga adalah benar, neraka adalah benar, dan para nabiMu benar, Muhammad shallallahu 'alaihi wasallam benar dan hari qiyamat benar. Ya Allah, kepadaMulah aku berserah diri, kepadaMulah aku beriman, kepadaMu lah aku bertawakal, kepadaMulah aku bertaubat (kembali), karena hujah yang Kau berikan kepadaku aku memusuhi siapapun yang menentang (syareat-Mu) dan kepadaMu aku berhukum. Ampunilah aku dari dosa yang lalu maupun yang akan datang, yang aku sembunyikan atau yang aku tampakkan. Engkaulah yang Awal dan yang Akhir dan tidak ada ilah yang berhaq disembah selain Engkau atau tidak ada ilah selainMu\" Berkata, [Sufyan]; Dan ditambahkan oleh ['Abdul Karim Abu Umayah]: \"Wa laa haula wa laa quwwata illaa billah\" (Tidak ada daya dan upaya kecuali Engkau). Berkata, [Sufyan] dari [Sulaiman bin Abu Muslim] dia mendengarnya dari [Thawus] dari [Ibnu 'Abbas radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam."},"1054":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا هِشَامٌ قَالَ أَخْبَرَنَا مَعْمَرٌ ح و حَدَّثَنِي مَحْمُودٌ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ الرَّجُلُ فِي حَيَاةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَى رُؤْيَا قَصَّهَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَمَنَّيْتُ أَنْ أَرَى رُؤْيَا فَأَقُصَّهَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكُنْتُ غُلَامًا شَابًّا وَكُنْتُ أَنَامُ فِي الْمَسْجِدِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَأَيْتُ فِي النَّوْمِ كَأَنَّ مَلَكَيْنِ أَخَذَانِي فَذَهَبَا بِي إِلَى النَّارِ فَإِذَا هِيَ مَطْوِيَّةٌ كَطَيِّ الْبِئْرِ وَإِذَا لَهَا قَرْنَانِ وَإِذَا فِيهَا أُنَاسٌ قَدْ عَرَفْتُهُمْ فَجَعَلْتُ أَقُولُ أَعُوذُ بِاللَّهِ مِنْ النَّارِ قَالَ فَلَقِيَنَا مَلَكٌ آخَرُ فَقَالَ لِي لَمْ تُرَعْ فَقَصَصْتُهَا عَلَى حَفْصَةَ فَقَصَّتْهَا حَفْصَةُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ نِعْمَ الرَّجُلُ عَبْدُ اللَّهِ لَوْ كَانَ يُصَلِّي مِنْ اللَّيْلِ فَكَانَ بَعْدُ لَا يَنَامُ مِنْ اللَّيْلِ إِلَّا قَلِيلًا","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] berkata, telah menceritakan kepada kami [Hisyam] berkata, telah mengabarkan kepada kami [Ma'mar]. Dan diceritakan juga, telah menceritakan kepada saya [Mahmud] berkata, telah menceritakan kepada kami ['Abdur Razaaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhriy] dari [Salim] dari [Bapaknya radliallahu 'anhu] berkata; \"Sudah menjadi kebiasaan seseorang pada masa hidup Nabi shallallahu 'alaihi wasallam bila bermimpi, biasanya dia menceritakannya kepada Rasulullah shallallahu 'alaihi wasallam. Aku pun berharap bermimpi hingga aku dapat mengisahkannya kepada Rasulullah shallallahu 'alaihi wasallam. Saat itu aku masih remaja. Pada suatu hari di jaman Rasulullah shallallahu 'alaihi wasallam aku tidur di masjid lalu aku bermimpi ada dua malaikat memegangku lalu membawaku ke dalam neraka, aku melihat neraka yang ternyata adalah lubang besar bagaikan lubang sumur (atau jurang). Neraka itu memiliki dua emperan dan aku melihat di dalamnya ada orang-orang yang sebelumnya aku sudah mengenal mereka. Dengan melihat mereka, membuat aku berkata,; \"Aku berlindung kepada Allah dari neraka\" Dia berkata,; \"Kemudian kami berjumpa dengan malaikat lain lalu dia berkata, kepadaku; \"Janganlah kamu takut\". Kemudian aku ceritakan mimpiku itu kepada [Hafshah], lalu Hafshah menceritakannya kepada Rasulullah shallallahu 'alaihi wasallam. Maka Beliau pun bersabda: \"Sungguh 'Abdullah (bin \"Umar) adalah seorang yang beruntung (bahagia) bila dia mendirikan shalat malam\". Setelah peristiwa ini 'Abdullah bin 'Umar tidak tidur malam kecuali sedikit\"."},"1055":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي إِحْدَى عَشْرَةَ رَكْعَةً كَانَتْ تِلْكَ صَلَاتَهُ يَسْجُدُ السَّجْدَةَ مِنْ ذَلِكَ قَدْرَ مَا يَقْرَأُ أَحَدُكُمْ خَمْسِينَ آيَةً قَبْلَ أَنْ يَرْفَعَ رَأْسَهُ وَيَرْكَعُ رَكْعَتَيْنِ قَبْلَ صَلَاةِ الْفَجْرِ ثُمَّ يَضْطَجِعُ عَلَى شِقِّهِ الْأَيْمَنِ حَتَّى يَأْتِيَهُ الْمُنَادِي لِلصَّلَاةِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya ['Urwah] bahwa ['Aisyah radliallahu 'anha] mengabarkannya bahwa Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat sebelas raka'at, satu sujud shalat Beliau lamanya sepanjang bacaan lima puluh ayat dari kalian sebelum Beliau mengangkat kepalanya, dan beliau melakukan ruku' dua raka'at (shalat sunnah) sebelum shalat Subuh kemudian Beliau berbaring pada sebelah kanan badan Beliau hingga datang mu'adzin menyerukan shalat\"."},"1056":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَسْوَدِ قَالَ سَمِعْتُ جُنْدَبًا يَقُولُاشْتَكَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَقُمْ لَيْلَةً أَوْ لَيْلَتَيْنِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Sufyan] dari [Al Aswad] berkata; Aku mendengar [Jundab] berkata: \"Nabi shallallahu 'alaihi wasallam pernah menderita sakit hingga Beliau tidak mendirikan shalat malam selama satu atau dua malam\"."},"1057":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ قَالَ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ جُنْدَبِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَاحْتَبَسَ جِبْرِيلُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ امْرَأَةٌ مِنْ قُرَيْشٍ أَبْطَأَ عَلَيْهِ شَيْطَانُهُ فَنَزَلَتْ{ وَالضُّحَى وَاللَّيْلِ إِذَا سَجَى مَا وَدَّعَكَ رَبُّكَ وَمَا قَلَى }","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah mengabarkan kepada kami [Sufyan] dari [Al Aswad bin Qais] dari [Jundab bin 'Abdullah radliallahu 'anhu] berkata; \"Malaikat Jibril Alaihissalam sekian lama tidak datang menyampaikan wahyu kepada Nabi shallallahu 'alaihi wasallam hingga kemudian ada seorang wanita Quraisy berkata; \"Syetannya telah meninggalkannya\". Maka turunlah surah Adh-Dhuha: \"Wadh dhuhaa wal laili idza sajaa. Maa wadda'aka rabbuka wa qalaa\" (Demi waktu dhuha (matahari sepenggalahan naik) dan demi malam apabila telah sunyi (gelap). Rabbmu tiada meninggalkan kamu dan tiada (pula) benci kepadamu\") (QS. Adhdhuha 1-3)."},"1058":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ هِنْدٍ بِنْتِ الْحَارِثِ عَنْ أُمِّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَيْقَظَ لَيْلَةً فَقَالَ سُبْحَانَ اللَّهِ مَاذَا أُنْزِلَ اللَّيْلَةَ مِنْ الْفِتْنَةِ مَاذَا أُنْزِلَ مِنْ الْخَزَائِنِ مَنْ يُوقِظُ صَوَاحِبَ الْحُجُرَاتِ يَا رُبَّ كَاسِيَةٍ فِي الدُّنْيَا عَارِيَةٍ فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Hind binti Al Harits] dari [Ummu Salamah radliallahu 'anha] bahwa pada suatu malam Nabi Nabi shallallahu 'alaihi wasallam terbangun lalu bersabda: \"Subhaanallah (Maha suci Allah), fitnah apakah yang diturunkan pada malam ini? Dan apa yang diturunkan pada dua perbendaharaan/kekayaan (Ramawi dan Parsi)?\" Siapa yang membangunkan orang-orang yang ada di kamar-kamar (maksudnya isteri-isterinya)?, karena betapa banyak orang hidup menikmati nikmat-nikmat dari Allah di dunia ini namun akan telanjang nanti di akhirat (tidak mendapatkan kebaikan) \"."},"1059":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عَلِيُّ بْنُ حُسَيْنٍ أَنَّ حُسَيْنَ بْنَ عَلِيٍّ أَخْبَرَهُ أَنَّ عَلِيَّ بْنَ أَبِي طَالِبٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَرَقَهُ وَفَاطِمَةَ بِنْتَ النَّبِيِّ عَلَيْهِ السَّلَام لَيْلَةً فَقَالَ أَلَا تُصَلِّيَانِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَنْفُسُنَا بِيَدِ اللَّهِ فَإِذَا شَاءَ أَنْ يَبْعَثَنَا بَعَثَنَا فَانْصَرَفَ حِينَ قُلْنَا ذَلِكَ وَلَمْ يَرْجِعْ إِلَيَّ شَيْئًا ثُمَّ سَمِعْتُهُ وَهُوَ مُوَلٍّ يَضْرِبُ فَخِذَهُ وَهُوَ يَقُولُ{ وَكَانَ الْإِنْسَانُ أَكْثَرَ شَيْءٍ جَدَلًا }","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya ['Ali bin Husain] bahwa [Husain bin 'Ali] mengabarkannya bahwa ['Ali bin Abu Tholib radliallahu 'anhu] menceritakan kepadanya bahwa pada suatu malam Rasulullah shallallahu 'alaihi wasallam membangunkan dia dan Fathimah putri Nabi shallallahu 'alaihi wasallam lalu berkata: \"Mengapa kalian tidak shalat malam? Maka aku (Ali) menjawab: \"Wahai Rasulullah, jiwa-jiwa kami ada di tangan Allah, jika Dia menghendaki membangunkan kami pasti kami akan bangun juga\". Maka Beliau shallallahu 'alaihi wasallam berpaling pergi ketika kami mengatakan seperti itu dan Beliau tidak berkata sepatah katapun. Kemudian aku mendengar ketika Beliau pergi sambil memukul pahanya berkata: \"Memang manusia adalah makhluk yang paling banyak membantah. (QS Al Kahfi: 54)."},"1060":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْإِنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَدَعُ الْعَمَلَ وَهُوَ يُحِبُّ أَنْ يَعْمَلَ بِهِ خَشْيَةَ أَنْ يَعْمَلَ بِهِ النَّاسُ فَيُفْرَضَ عَلَيْهِمْ وَمَا سَبَّحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُبْحَةَ الضُّحَى قَطُّ وَإِنِّي لَأُسَبِّحُهَا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah radliallahu 'anha] berkata; \"Tidaklah Rasulullah shallallahu 'alaihi wasallam meninggalkan suatu amal padahal Beliau mencintai amal tersebut melainkan karena Beliau khawatir nanti orang-orang akan ikut mengamalkannya sehingga diwajibkan buat mereka. Dan tidaklah Beliau melaksanakan shalat Dhuha sekalipun kecuali pasti aku ikut melaksanakannya\"."},"1061":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ رَضِيَ اللَّهُ عَن��هَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى ذَاتَ لَيْلَةٍ فِي الْمَسْجِدِ فَصَلَّى بِصَلَاتِهِ نَاسٌ ثُمَّ صَلَّى مِنْ الْقَابِلَةِ فَكَثُرَ النَّاسُ ثُمَّ اجْتَمَعُوا مِنْ اللَّيْلَةِ الثَّالِثَةِ أَوْ الرَّابِعَةِ فَلَمْ يَخْرُجْ إِلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا أَصْبَحَ قَالَ قَدْ رَأَيْتُ الَّذِي صَنَعْتُمْ وَلَمْ يَمْنَعْنِي مِنْ الْخُرُوجِ إِلَيْكُمْ إِلَّا أَنِّي خَشِيتُ أَنْ تُفْرَضَ عَلَيْكُمْ وَذَلِكَ فِي رَمَضَانَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari ['Aisyah Ummul Mu'minin radliallahu 'anha] berkata; \"Pada suatu malam Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat di masjid, maka orang-oang mengikuti shalat Beliau. Pada malam berikutnya Beliau kembali melaksanakan shalat di masjid dan orang-orang yang mengikuti bertambah banyak. Pada malam ketiga atau keempat, orang-orang banyak sudah berkumpul namun Rasulullah shallallahu 'alaihi wasallam tidak keluar untuk shalat bersama mereka. Ketika pagi harinya, Beliau bersabda: \"Sungguh aku mengetahui apa yang kalian lakukan tadi malam dan tidak ada yang menghalangi aku untuk keluar shalat bersama kalian. Hanya saja aku khawatir nanti diwajibkan atas kalian\". Kejadian ini di bulan Ramadhan."},"1062":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا مِسْعَرٌ عَنْ زِيَادٍ قَالَ سَمِعْتُ الْمُغِيرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُإِنْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَقُومُ لِيُصَلِّيَ حَتَّى تَرِمُ قَدَمَاهُ أَوْ سَاقَاهُ فَيُقَالُ لَهُ فَيَقُولُ أَفَلَا أَكُونُ عَبْدًا شَكُورًا","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Mis'ar] dari [Ziyad] berkata; aku mendengar [Al Mughirah radliallahu 'anhu] berkata; \"Ketika Nabi shallallahu 'alaihi wasallam bangun untuk mendirikan shalat (malam) hingga tampak bengkak pada kaki atau betis, Beliau dimintai keterangan tentangnya. Maka Beliau menjawab: \"Apakah memang tidak sepatutnya aku menjadi hamba yang bersyukur?\""},"1063":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ أَنَّ عَمْرَو بْنَ أَوْسٍ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ أَحَبُّ الصَّلَاةِ إِلَى اللَّهِ صَلَاةُ دَاوُدَ عَلَيْهِ السَّلَام وَأَحَبُّ الصِّيَامِ إِلَى اللَّهِ صِيَامُ دَاوُدَ وَكَانَ يَنَامُ نِصْفَ اللَّيْلِ وَيَقُومُ ثُلُثَهُ وَيَنَامُ سُدُسَهُ وَيَصُومُ يَوْمًا وَيُفْطِرُ يَوْمًا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami ['Amru bin Dinar] bahwa ['Amru bin Aus] mengabarkannya bahwa ['Abdullah bin 'Amru bin Al 'Ash radliallahu 'anhu'anhuma] mengabarkannya bahwa Rasulullah shallallahu 'alaihi wasallam pernah berkata kepadanya: \"Shalat yang paling Allah cintai adalah shalatnya Nabi Daud Alaihissalam dan shaum (puasa) yang paling Allah cintai adalah shaumnya Nabi Daud alaihissalam. Nabi Daud Alaihissalam tidur hingga pertengahan malam lalu shalat pada sepertiganya kemudian tidur kembali pada seperenam akhir malamnya. Dan Nabi Daud Alaihissalam shaum sehari dan berbuka sehari\"."},"1064":{"ar":"حَدَّثَنِي عَبْدَانُ قَالَ أَخْبَرَنِي أَبِي عَنْ شُعْبَةَ عَنْ أَشْعَثَ سَمِعْتُ أَبِي قَالَ سَمِعْتُ مَسْرُوقًا قَالَ سَأَلْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَيُّ الْعَمَلِ كَانَ أَحَبَّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ الدَّائِمُ قُلْتُ مَتَى كَانَ يَقُومُ قَالَتْ كَانَ يَقُومُ إِذَا سَمِعَ الصَّارِخَحَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ قَالَ أَخْبَرَنَا أَبُو الْأَحْوَصِ عَنْ الْأَشْعَثِ قَالَ إِذَا سَمِعَ الصَّارِخَ قَامَ فَصَلَّى","id":"Telah menceritakan kepada saya ['Abdan] berkata, telah mengabarkan kepada saya [Bapakku] dari [Syu'bah] dari [Asy'ats]; Aku mendengar [Bapakku] berkata; Aku mendengar [Masruq] berkata; \"Aku pernah bertanya kepada ['Aisyah radliallahu 'anha], amal apakah yang paling disukai oleh Nabi shallallahu 'alaihi wasallam? 'Aisyah radliallahu 'anha menjawab: \"Amal yang ditekuni secara terus menerus\". Aku bertanya lagi: \"Kapan Beliau bangun malam?\" 'Aisyah radliallahu 'anha menjawab: \"Beliau bangun malam bila mendengar suara kokok ayam\". Telah menceritakan kepada kami [Muhammad bin Salam] berkata, telah mengabarkan kepada kami [Abu Al Ahwash] dari [Al 'Asy'ats] berkata: \"Jika Beliau mendengar suara kokok ayam Beliau bangun lalu shalat\"."},"1065":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ قَالَ ذَكَرَ أَبِي عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَا أَلْفَاهُ السَّحَرُ عِنْدِي إِلَّا نَائِمًا تَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'ad] berkata, [bapakku] menceritakan dari [Abu Salamah] dari ['Aisyah radliallahu 'anha] berkata: \"Tidaklah aku mendapatkan dia di sampingku saat datang waktu sahar (akhir malam menjelang Shubuh) kecuali dia dalam keadaan tidur\". Yang dimaksud oleh 'Aisyah radliallahu 'anha adalah Nabi shallallahu 'alaihi wasallam."},"1066":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَزَيْدَ بْنَ ثَابِتٍ رَضِيَ اللَّهُ عَنْهُ تَسَحَّرَا فَلَمَّا فَرَغَا مِنْ سَحُورِهِمَا قَامَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الصَّلَاةِ فَصَلَّى فَقُلْنَا لِأَنَسٍ كَمْ كَانَ بَيْنَ فَرَاغِهِمَا مِنْ سَحُورِهِمَا وَدُخُولِهِمَا فِي الصَّلَاةِ قَالَ كَقَدْرِ مَا يَقْرَأُ الرَّجُلُ خَمْسِينَ آيَةً","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] berkata, telah menceritakan kepada [Rauh] berkata, telah menceritakan kepada kami [Sa'id bin Abu 'Urubah] dari [Qatadah] dari [Anas bin Malik radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam dan Zaid bin Tsabit radliallahu 'anhu makan sahur bersama. Setelah keduanya selesai makan sahurnya, maka Nabi shallallahu 'alaihi wasallam bangkit untuk segera melaksanakan shalat, lalu Beliau mendirikan shalat\". Kami bertanya kepada Anas radliallahu 'anhu: \"Berapa tenggang waktu antara selesai makan sahur keduanya dengan awal shalatnya? Anas bin Malik radliallahu 'anhu berkata,: \"Kira-kira selama seorang membaca lima puluh ayat\"."},"1067":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً فَلَمْ يَزَلْ قَائِمًا حَتَّى هَمَمْتُ بِأَمْرِ سَوْءٍ قُلْنَا وَمَا هَمَمْتَ قَالَ هَمَمْتُ أَنْ أَقْعُدَ وَأَذَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Syu'bah] dari [Al A'masy] dari [Abu Wa'il] dari ['Abdullah bin Mas'ud radliallahu 'anhu] berkata: Pada suatu malam aku pernah shalat malam bersama Nabi shallallahu 'alaihi wasallam. Saat shalat itu Beliau terus saja berdiri hingga aku terbetik perasaan yang jelek\". Kami tanyakan: \"Apa perasaan jelekmu itu?\" Dia menjawab: \"Aku berkeinginan untuk duduk dan meninggalkan Nabi shallallahu 'alaihi wasallam \"."},"1068":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ قَالَ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ حُصَيْنٍ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا قَامَ لِلتَّهَجُّدِ مِنْ اللَّيْلِ يَشُوصُ فَاهُ بِالسِّوَاكِ","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] berkata, telah menceritakan kepada kami [Khalid bin 'Abdullah] dari [Hushain] dari [Abu Wa'il] dari [Hudzaifah radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam apabila bangun malam untuk shalat tahajjud, Beliau menggosok dan membersihkan mulut Beliau dengan siwak\"."},"1069":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَإِنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ كَيْفَ صَلَاةُ اللَّيْلِ قَالَ مَثْنَى مَثْنَى فَإِذَا خِفْتَ الصُّبْحَ فَأَوْتِرْ بِوَاحِدَةٍ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya [Salim bin 'Abdullah] bahwa ['Abdullah bin 'Umar radliallahu 'anhu] berkata; Ada seseorang bertanya: \"Wahai Rasulullah shallallahu 'alaihi wasallam, bagaimana cara shalat malam?\" Beliau shallallahu 'alaihi wasallam menjawab: \" Dua dua (raka'at) dan jika kamu khawatir masuk waktu Shubuh witirlah dengan satu raka'at\"."},"1070":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ قَالَ حَدَّثَنِي أَبُو جَمْرَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَتْ صَلَاةُ ال��َّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَ عَشْرَةَ رَكْعَةً يَعْنِي بِاللَّيْلِ","id":"Telah menceritakan kepada kami [Musadad] berkata, telah menceritakan kepada kami [Yahya] dari [Syu'bah] berkata, telah menceritakan kepada saya [Abu Jamrah] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; \"Shalat Nabi shallallahu 'alaihi wasallam adalah tiga belas raka'at, yaitu shalat malamnya\"."},"1071":{"ar":"حَدَّثَنَا إِسْحَاقُ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ أَخْبَرَنَا إِسْرَائِيلُ عَنْ أَبِي حَصِينٍ عَنْ يَحْيَى بْنِ وَثَّابٍ عَنْ مَسْرُوقٍ قَالَ سَأَلْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاعَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ فَقَالَتْ سَبْعٌ وَتِسْعٌ وَإِحْدَى عَشْرَةَ سِوَى رَكْعَتِي الْفَجْرِ","id":"Telah menceritakan kepada kami [Ishaq] berkata, telah menceritakan kepada kami ['Ubaidullah bin Musa] berkata, telah mengabarkan kepada kami [Isra'il] dari [Abu Hushain] dari [Yahya bin Watstsab] dari [Masruq] berkata; Aku bertanya kepada ['Aisyah radliallahu 'anha] tentang shalat Rasulullah shallallahu 'alaihi wasallam di waktu malam. Maka dia radliallahu 'anhu menjawab: \"Tujuh atau sembilan atau sebelas raka'at selain dua raka'at sunnat Fajar\"."},"1072":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ أَخْبَرَنَا حَنْظَلَةُ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ ثَلَاثَ عَشْرَةَ رَكْعَةً مِنْهَا الْوِتْرُ وَرَكْعَتَا الْفَجْرِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] berkata, telah mengabarkan kepada kami [Hanzholah] dari [Al Qasim bin Muhammad] dari ['Aisyah radliallahu 'anha] berkata: \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat malamnya sebanyak tiga belas raka'at, termasuk witir dan dua raka'at sunnat Fajar\"."},"1073":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ حُمَيْدٍ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُفْطِرُ مِنْ الشَّهْرِ حَتَّى نَظُنَّ أَنْ لَا يَصُومَ مِنْهُ وَيَصُومُ حَتَّى نَظُنَّ أَنْ لَا يُفْطِرَ مِنْهُ شَيْئًا وَكَانَ لَا تَشَاءُ أَنْ تَرَاهُ مِنْ اللَّيْلِ مُصَلِّيًا إِلَّا رَأَيْتَهُ وَلَا نَائِمًا إِلَّا رَأَيْتَهُتَابَعَهُ سُلَيْمَانُ وَأَبُو خَالِدٍ الْأَحْمَرُ عَنْ حُمَيْدٍ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] berkata, telah menceritakan kepada saya [Muhammad bin Ja'far] dari [Humaid] bahwasanya dia mendengar [Anas bin Malik radliallahu 'anhu] berkata: \"Rasulullah shallallahu 'alaihi wasallam biasa berbuka (tidak shaum sunnah) selama satu bulan hingga kami menduganya Beliau tidak pernah shaum selama itu, dan bila shaum seakan Beliau terus menerus shaum hingga kami menduganya Beliau tidak pernah berbuka sekalipun dalam bulan itu. Dan jika kamu hendak melihat Beliau pada suatu malam dalam keadaan shalat maka pasti kamu akan melihatnya dan tidak pula dalam posisi tertidur melainkan pasti kalian akan melihatnya pula dalam keadaan tertidur\". Hadits ini diikuti pula oleh [Sulaiman] dan [Abu Khalid Al Ahmar] dari [Humaid]."},"1074":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّه صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَعْقِدُ الشَّيْطَانُ عَلَى قَافِيَةِ رَأْسِ أَحَدِكُمْ إِذَا هُوَ نَامَ ثَلَاثَ عُقَدٍ يَضْرِبُ كُلَّ عُقْدَةٍ عَلَيْكَ لَيْلٌ طَوِيلٌ فَارْقُدْ فَإِنْ اسْتَيْقَظَ فَذَكَرَ اللَّهَ انْحَلَّتْ عُقْدَةٌ فَإِنْ تَوَضَّأَ انْحَلَّتْ عُقْدَةٌ فَإِنْ صَلَّى انْحَلَّتْ عُقْدَةٌ فَأَصْبَحَ نَشِيطًا طَيِّبَ النَّفْسِ وَإِلَّا أَصْبَحَ خَبِيثَ النَّفْسِ كَسْلَانَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setan mengikat tengkuk kepala seseorang dari kalian saat dia tidur dengan tiga tali ikatan dan syaitan mengikatkannya sedemikian rupa sehingga setiap ikatan diletakkan pada tempatnya lalu (dikatakan) kamu akan melewati malam yang sangat panjang maka tidurlah dengan nyenyak. Jika dia bangun dan mengingat Allah maka lepaslah satu tali ikatan. Jika kemudian dia berwudhu' maka lepaslah tali yang lainnya dan bila ia mendirikan shalat lepaslah seluruh tali ikatan dan pada pagi harinya ia akan merasakan semangat dan kesegaran yang menenteramkan jiwa. Namun bila dia tidak melakukan seperti itu, maka pagi harinya jiwanya merasa tidak segar dan menjadi malas beraktifitas\"."},"1075":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ هِشَامٍ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عُلَيَّةَ قَالَ حَدَّثَنَا عَوْفٌ قَالَ حَدَّثَنَا أَبُو رَجَاءٍ قَالَ حَدَّثَنَا سَمُرَةُ بْنُ جُنْدَبٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الرُّؤْيَا قَالَ أَمَّا الَّذِي يُثْلَغُ رَأْسُهُ بِالْحَجَرِ فَإِنَّهُ يَأْخُذُ الْقُرْآنَ فَيَرْفِضُهُ وَيَنَامُ عَنْ الصَّلَاةِ الْمَكْتُوبَةِ","id":"Telah menceritakan kepada kami [Mu'ammal bin Hisyam] berkata, telah menceritakan kepada kami [Isma'il bin 'Ulayyah] berkata, telah menceritakan kepada kami ['Auf] berkata, telah menceritakan kepada kami [Abu Raja'] berkata, telah menceritakan kepada kami [Samurah bin Jundab radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam tentang masalah mimpi. Beliau shallallahu 'alaihi wasallam bersabda: \"Adapun ta'wil mimpi seseorang yang memecahkan kepalanya dengan batu adalah dia mengambil Al Qur'an lalu ditinggalkannya kemudian dia tidur sehingga melalaikan shalat wajib\"."},"1076":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ قَالَ حَدَّثَنَا مَنْصُورٌ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَذُكِرَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَقِيلَ مَا زَالَ نَائِمًا حَتَّى أَصْبَحَ مَا قَامَ إِلَى الصَّلَاةِ فَقَالَ بَالَ الشَّيْطَانُ فِي أُذُنِهِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abu Al Ahwash] berkata, telah menceritakan kepada kami [Manshur] dari [Abu Wa'il] dari ['Abdullah radliallahu 'anhu] berkata: Diceritakan kepada Nabi shallallahu 'alaihi wasallam tentang seseorang yang dia terus tertidur sampai pagi hari hingga tidak mengerjakan shalat. Maka Beliau shallallahu 'alaihi wasallam bersabda: \"Syaitan telah mengencingi orang itu pada telinganya\"."},"1077":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ وَأَبِي عَبْدِ اللَّهِ الْأَغَرِّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَنْزِلُ رَبُّنَا تَبَارَكَ وَتَعَالَى كُلَّ لَيْلَةٍ إِلَى السَّمَاءِ الدُّنْيَا حِينَ يَبْقَى ثُلُثُ اللَّيْلِ الْآخِرُ يَقُولُ مَنْ يَدْعُونِي فَأَسْتَجِيبَ لَهُ مَنْ يَسْأَلُنِي فَأُعْطِيَهُ مَنْ يَسْتَغْفِرُنِي فَأَغْفِرَ لَهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Abu Salamah] dan [Abu 'Abdullah Al Aghor] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rabb Tabaaraka wa Ta'ala kita turun di setiap malam ke langit dunia pada sepertiga malam terakhir dan berfirman: \"Siapa yang berdo'a kepadaKu pasti Aku kabulkan dan siapa yang meminta kepadaKu pasti Aku penuhi dan siapa yang memohon ampun kepadaKu pasti Aku ampuni\"."},"1078":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنِي سُلَيْمَانُ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ عَنْ الْأَسْوَدِ قَالَ سَأَلْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاكَيْفَ كَانَتْ صَلَاةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ قَالَتْ كَانَ يَنَامُ أَوَّلَهُ وَيَقُومُ آخِرَهُ فَيُصَلِّي ثُمَّ يَرْجِعُ إِلَى فِرَاشِهِ فَإِذَا أَذَّنَ الْمُؤَذِّنُ وَثَبَ فَإِنْ كَانَ بِهِ حَاجَةٌ اغْتَسَلَ وَإِلَّا تَوَضَّأَ وَخَرَجَ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dan diriwayatkan pula telah menceritakan kepada saya [Sulaiman] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Aswad] berkata; \"Aku bertanya kepada ['Aisyah radliallahu 'anha] tentang cara Nabi shallallahu 'alaihi wasallam melaksanakan shalat malam\". 'Aisyah radliallahu 'anha menjawab: \"Beliau tidur di awal malam dan bangun untuk shalat di akhir malam dan shalat, lalu beliau kembali ke tempat tidurnya. Bila mu'adzin sudah mengumandangkan adzan, maka Beliau bersegera. Bila saat itu Beliau punya hajat (kepada isterinya), maka Beliau mandi. Bila tidak, maka Beliau hanya berwudhu' lalu keluar untuk shalat\"."},"1079":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُ أَخْبَرَهُ أَنَّهُ سَأَلَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاكَيْفَ كَانَتْ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَمَضَانَ فَقَالَتْ مَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَزِيدُ فِي رَمَضَانَ وَلَا فِي غَيْرِهِ عَلَى إِحْدَى عَشْرَةَ رَكْعَةً يُصَلِّي أَرْبَعًا فَلَا تَسَلْ عَنْ حُسْنِهِنَّ وَطُولِهِنَّ ثُمَّ يُصَلِّي أَرْبَعًا فَلَا تَسَلْ عَنْ حُسْنِهِنَّ وَطُولِهِنَّ ثُمَّ يُصَلِّي ثَلَاثًا قَالَتْ عَائِشَةُ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتَنَامُ قَبْلَ أَنْ تُوتِرَ فَقَالَ يَا عَائِشَةُ إِنَّ عَيْنَيَّ تَنَامَانِ وَلَا يَنَامُ قَلْبِي","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Sa'id bin Abu Sa'id Al Maqbariy] dari [Abu Salamah bin 'Abdurrahman] bahwasanya dia mengabarkan kepadanya bahwa dia pernah bertanya kepada ['Aisyah radliallahu 'anha] tentang cara shalat Rasulullah shallallahu 'alaihi wasallam di bulan Ramadhan. Maka 'Aisyah radliallahu 'anha menjawab: \"Tidaklah Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat malam di bulan Ramadhan dan di bulan-bulan lainnya lebih dari sebelas raka'at, Beliau shalat empat raka'at, dan jangan kamu tanya tentang bagus dan panjangnya kemudian Beliau shalat empat raka'at lagi dan jangan kamu tanya tentang bagus dan panjangnya kemudian Beliau shalat tiga raka'at\". 'Aisyah radliallahu 'anha berkata; Aku bertanya: \"Wahai Rasulullah, apakah anda tidur sebelum melaksanakan witir?\" Beliau menjawab: \"Wahai 'Aisyah, kedua mataku tidur, namun hatiku tidaklah tidur\"."},"1080":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي شَيْءٍ مِنْ صَلَاةِ اللَّيْلِ جَالِسًا حَتَّى إِذَا كَبِرَ قَرَأَ جَالِسًا فَإِذَا بَقِيَ عَلَيْهِ مِنْ السُّورَةِ ثَلَاثُونَ أَوْ أَرْبَعُونَ آيَةً قَامَ فَقَرَأَهُنَّ ثُمَّ رَكَعَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam] berkata, [bapakku] telah mengabarkan kepadaku dari ['Aisyah radliallahu 'anha] berkata: \"Tidak pernah aku melihat Nabi shallallahu 'alaihi wasallam membaca surat dalam shalat malam dalam keadaan duduk kecuali ketika Beliau sudah berusia lanjut, ketika usia tua itu Beliau membaca dalam keadaan duduk. Namun bila surat yang dibacanya tinggal tersisa sekitar tiga puluh atau empat puluh ayat, maka Beliau berdiri dan melanjutkan bacaannya itu dengan berdiri. Kemudian Beliau ruku'\"."},"1081":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ أَبِي حَيَّانَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِبِلَالٍ عِنْدَ صَلَاةِ الْفَجْرِ يَا بِلَالُ حَدِّثْنِي بِأَرْجَى عَمَلٍ عَمِلْتَهُ فِي الْإِسْلَامِ فَإِنِّي سَمِعْتُ دَفَّ نَعْلَيْكَ بَيْنَ يَدَيَّ فِي الْجَنَّةِ قَالَ مَا عَمِلْتُ عَمَلًا أَرْجَى عِنْدِي أَنِّي لَمْ أَتَطَهَّرْ طَهُورًا فِي سَاعَةِ لَيْلٍ أَوْ نَهَارٍ إِلَّا صَلَّيْتُ بِذَلِكَ الطُّهُورِ مَا كُتِبَ لِي أَنْ أُصَلِّيَقَالَ أَبُو عَبْد اللَّهِ دَفَّ نَعْلَيْكَ يَعْنِي تَحْرِيكَ","id":"Telah menceritakan kepada kami [Ishaq bin Nashr] telah menceritakan kepada kami [Abu Usamah] dari [Abu Hayyan] dari [Abu Zur'ah] dari [Abu Hurairah radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam berkata, kepada Bilal radliallahu 'anhu ketika shalat Fajar (Shubuh): \"Wahai Bilal, ceritakan kepadaku amal yang paling utama yang sudah kamu amalkan dalam Islam, sebab aku mendengar di hadapanku suara sandalmu dalam surga\". Bilal berkata; \"Tidak ada amal yang utama yang aku sudah amalkan kecuali bahwa jika aku bersuci (berwudhu') pada suatu kesempatan malam ataupun siang melainkan aku selalu shalat dengan wudhu' tersebut disamping shalat wajib\". Berkata, (Abu 'Abdullah): Istilah \"Daffa na'laika maksudnya gerakan sandal\"."},"1082":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا حَبْلٌ مَمْدُودٌ بَيْنَ السَّارِيَتَيْنِ فَقَالَ مَا هَذَا الْحَبْلُ قَالُوا هَذَا حَبْلٌ لِزَيْنَبَ فَإِذَا فَتَرَتْ تَعَلَّقَتْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حُلُّوهُ لِيُصَلِّ أَحَدُكُمْ نَشَاطَهُ فَإِذَا فَتَرَ فَلْيَقْعُدْ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami ['Abdul 'Aziz bin Shuhaib] dari [Anas bin Malik radliallahu 'anhu] berkata: \"Pada suatu hari Nabi shallallahu 'alaihi wasallam masuk (ke masjid), kemudian Beliau mendapati tali yang diikatkan dua tiang. Kemudian Beliau berkata: \"Apa ini?\" Orang-orang menjawab: \"Tali ini milik Zainab, bila dia shalat dengan berdiri lalu merasa letih, dia berpegangan tali tersebut\". Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Jangan ia lakukan sedemikian itu. Hendaklah seseorang dari kalian tekun dalam ibadah shalatnya dan apabila dia merasa letih, shalatlah sambil duduk\"."},"1083":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَتْ عِنْدِي امْرَأَةٌ مِنْ بَنِي أَسَدٍ فَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ هَذِهِ قُلْتُ فُلَانَةُ لَا تَنَامُ بِاللَّيْلِ فَذُكِرَ مِنْ صَلَاتِهَا فَقَالَ مَهْ عَلَيْكُمْ مَا تُطِيقُونَ مِنْ الْأَعْمَالِ فَإِنَّ اللَّهَ لَا يَمَلُّ حَتَّى تَمَلُّوا","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah radliallahu 'anhu] berkata: \"Suatu hari seorang wanita dari Bani Asad bersamaku saat Rasulullah shallallahu 'alaihi wasallam mendatangiku. Lalu Beliau bertanya: \"Siapa dia?\" Aku jawab: \"Si anu, orang yang tidak tidur di waktu malam\". Lantas diberitakan kepada Beliau tentang shalat wanita tersebut. Kemudian Beliau shallallahu 'alaihi wasallam bersabda: \"Celakalah kalian, mengapa kalian memaksakan amalan yang kalian tidak mampu? Sungguh Allah tidak bosan (memberi ganjaran) hingga kalian merasa bosan sendiri (jika terlalu memaksakan diri) \"."},"1084":{"ar":"حَدَّثَنَا عَبَّاسُ بْنُ الْحُسَيْنِ حَدَّثَنَا مُبَشِّرُ بْنُ إِسْمَاعِيلَ عَنْ الْأَوْزَاعِيِّ ح و حَدَّثَنِي مُحَمَّدُ بْنُ مُقَاتِلٍ أَبُو الْحَسَنِ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ الْعَاصِ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبْدَ اللَّهِ لَا تَكُنْ مِثْلَ فُلَانٍ كَانَ يَقُومُ اللَّيْلَ فَتَرَكَ قِيَامَ اللَّيْلِوَقَالَ هِشَامٌ حَدَّثَنَا ابْنُ أَبِي الْعِشْرِينَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى عَنْ عُمَرَ بْنِ الْحَكَمِ بْنِ ثَوْبَانَ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ مِثْلَهُ وَتَابَعَهُ عَمْرُو بْنُ أَبِي سَلَمَةَ عَنْ الْأَوْزَاعِيِّ","id":"Telah menceritakan kepada kami ['Abbas bin Al Husain] telah menceritakan kepada kami [Mubasysyir bin Isma'il] dari [Al Awza'iy] dan diriwayatkan telah menceritakan kepada saya [Muhammad bin Muqatil Abu Al Hasan] berkata, telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Al Awza'iy] berkata, telah menceritakan kepada saya [Yahya bin Abu Katsir] berkata, telah menceritakan kepada saya [Abu Salamah bin 'Abdurrahman] berkata, telah menceritakan kepada saya ['Abdullah bin 'Amru bin Al 'Ash radliallahu 'anhuma] berkata; Rasulullah shallallahu 'alaihi wasallam telah bersabda kepadaku: \" Wahai 'Abdullah, janganlah kamu seperti fulan, yang dia biasa mendirikan shalat malam namun kemudian meninggalkan shalat malam\". Dan berkata, [Hisyam] telah menceritakan kepada kami [Ibnu Abi Al 'Isyrin] telah menceritakan kepada kami [Al Awza'iy] berkata, telah menceritakan kepada saya [Yahya] dari ['Umar bin Al Hakam bin Tsauban] telah menceritakan kepada saya [Abu Salamah] seperti ini juga. Dan diikuti pula oleh ['Amru bin Abu Salamah] dari [Al Awza'iy]."},"1085":{"ar":"بَاب حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ أَبِي الْعَبَّاسِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو رَضِيَ اللَّهُ عَنْهُمَاقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَمْ أُخْبَرْ أَنَّكَ تَقُومُ اللَّيْلَ وَتَصُومُ النَّهَارَ قُلْتُ إِنِّي أَفْعَلُ ذَلِكَ قَالَ فَإِنَّكَ إِذَا فَعَلْتَ ذَلِكَ هَجَمَتْ عَيْنُكَ وَنَفِهَتْ نَفْسُكَ وَإِنَّ لِنَفْسِكَ حَقًّا وَلِأَهْلِكَ حَقًّا فَصُمْ وَأَفْطِرْ وَقُمْ وَنَمْ","id":"Bab telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Abu Al 'Abbas] berkata; Aku mendengar ['Abdullah bin 'Amru radliallahu 'anhuma] berkata: \"Nabi shallallahu 'alaihi wasallam berkata, kepadaku: \"Benarkah kabar bahwa kamu selalu mendirikan shalat di malam hari dan shaum pada siang harinya? Aku jawab: 'Benar \". Beliau shallallahu 'alaihi wasallam bersabda: \"Sungguh jika kamu lakukan terus menerus maka nanti matamu letih dan jiwamu lemah. Sungguh untuk dirimu ada haknya, juga keluargamu punya hak, maka shaumlah dan juga berbukalah, bangun untuk shalat malam dan juga tidurlah\"."},"1086":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا الْوَلِيدُ هُوَ ابْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي عُمَيْرُ بْنُ هَانِئٍ قَالَ حَدَّثَنِي جُنَادَةُ بْنُ أَبِي أُمَيَّةَ حَدَّثَنِي عُبَادَةُ بْنُ الصَّامِتِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَعَارَّ مِنْ اللَّيْلِ فَقَالَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ الْحَمْدُ لِلَّهِ وَسُبْحَانَ اللَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ ثُمَّ قَالَ اللَّهُمَّ اغْفِرْ لِي أَوْ دَعَا اسْتُجِيبَ لَهُ فَإِنْ تَوَضَّأَ وَصَلَّى قُبِلَتْ صَلَاتُهُ","id":"Telah menceritakan kepada kami [Shadaqah bun AL Fadhal] telah mengabarkan kepada kami [Al Walid], dia adalah anak dari Muslim telah menceritakan kepada kami [Al Awza'iy] berkata, telah menceritakan kepada saya ['Umair bin Hani'] berkata, telah menceritakan kepada saya [Junadah bin Abu Umayyah] telah menceritakan kepada saya ['Ubadah bin Ash-Shamit] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang bangun di malam hari lalu membaca \"laa ilaaha illallah wahdahu laa syariika lahu, lahul mulku wa lahul hamdu wa huwa 'alaa kulli syai-in qadiir. Alhamdulillahi wa subhaanallah wa laa ilaaha illallah wallahu akbar wa laa jaula wa laa quwwata illa billah\" (Tidak ada ilah yang berhaq disembah kecuali Allah satu-satunya, tidak ada sekutu bagiNya. Dialah yang memiliki kerajaan dan baginNya segala pujian dan Dia berkuasa atas segala sesuatu. Segala puji bagi Allah dan Maha Suci Allah dan tidak ada ilah kecuali Allah dan Allah Maha Besar dan tidak ada daya dan upaya kecuali dengan Dia\") Kemudian dilanjutkan dengan membaca \"Allahummaghfirlii\" (\"Ya Allah ampunilah aku\") atau berdo'a, maka akan dikabulkan baginya. Jika dia berwudhu' lalu shalat maka shalatnya diterima\"."},"1087":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي الْهَيْثَمُ بْنُ أَبِي سِنَانٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ وَهُوَ يَقُصُّ فِي قَصَصِهِ وَهُوَ يَذْكُرُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَإِنَّ أَخًا لَكُمْ لَا يَقُولُ الرَّفَثَ يَعْنِي بِذَلِكَ عَبْدَ اللَّهِ بْنَ رَوَاحَةَ وَفِينَا رَسُولُ اللَّهِ يَتْلُو كِتَابَهُإِذَا انْشَقَّ مَعْرُوفٌ مِنْ الْفَجْرِ سَاطِعُأَرَانَا الْهُدَى بَعْدَ الْعَمَى فَقُلُوبُنَابِهِ مُوقِنَاتٌ أَنَّ مَا قَالَ وَاقِعُيَبِيتُ يُجَافِي جَنْبَهُ عَنْ فِرَاشِهِإِذَا اسْتَثْقَلَتْ بِالْمُشْرِكِينَ الْمَضَاجِعُتَابَعَهُ عُقَيْلٌ وَقَالَ الزُّبَيْدِيُّ أَخْبَرَنِي الزُّهْرِيُّ عَنْ سَعِيدٍ وَالْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Ibnu Syuihab] telah mengabarkan kepada saya [Al Haitsam bin Abu Sinan] bahwasanya dia mendengar [Abu Hurairah radliallahu 'anhu] mengisahkan pengalamannya, dia menyebutkan bahwa Rasulullah shallallahu 'alaihi wasallam berkata,: \"Sesungguhnya saudara kalian ini tidak pernah berkata, rafats (kotor) \". Yang dimaksud Beliau adalah 'Abdullah bin Rawahah yang penah bersya'ir: \"Bersama kita ada Rasulullah shallallahu 'alaihi wasallam yang membacacakan Al Qur'an, ketika fajar yang sudah dikenal itu menyingsing, Kita melihat petunjuk setelah sebelumnya kita buta, hati kita meyakini bahwa apa yang disabdakannya adalah benar adanya. Di malam hari Beliau menjauhkan diri dari tempat tidurnya, saat orang-orang musyrik tertidur lelap\". Hadits ini dikuatkan oleh ['Uqail] dan berkata, [Az Zubaidiy] telah mengabarkan kepada saya [Az Zuhriy] dari [Sa'id] dan [Al A'raj] dari [Abu Hurairah radliallahu 'anhu]."},"1088":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاقَالَ رَأَيْتُ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَأَنَّ بِيَدِي قِطْعَةَ إِسْتَبْرَقٍ فَكَأَنِّي لَا أُرِيدُ مَكَانًا مِنْ الْجَنَّةِ إِلَّا طَارَتْ إِلَيْهِ وَرَأَيْتُ كَأَنَّ اثْنَيْنِ أَتَيَانِي أَرَادَا أَنْ يَذْهَبَا بِي إِلَى النَّارِ فَتَلَقَّاهُمَا مَلَكٌ فَقَالَ لَمْ تُرَعْ خَلِّيَا عَنْهُ فَقَصَّتْ حَفْصَةُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِحْدَى رُؤْيَايَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِعْمَ الرَّجُلُ عَبْدُ اللَّهِ لَوْ كَانَ يُصَلِّي مِنْ اللَّيْلِ فَكَانَ عَبْدُ اللَّهِ رَضِيَ اللَّهُ عَنْهُ يُصَلِّي مِنْ اللَّيْلِ وَكَانُوا لَا يَزَالُونَ يَقُصُّونَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرُّؤْيَا أَنَّهَا فِي اللَّيْلَةِ السَّابِعَةِ مِنْ الْعَشْرِ الْأَوَاخِرِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَى رُؤْيَاكُمْ قَدْ تَوَاطَأَتْ فِي الْعَشْرِ الْأَوَاخِرِ فَمَنْ كَانَ مُتَحَرِّيهَا فَلْيَتَحَرَّهَا مِنْ الْعَشْرِ الْأَوَاخِرِ","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] berkata: \"Pada zaman Nabi shallallahu 'alaihi wasallam aku pernah bermimpi, ditanganku ada sehelai kain sutera dan seakan tidaklah aku menginginkan satu tempat di surga kecuali akan segera nampak buatku. Aku juga mengalami mimpi yang lain, aku melihat dua malaikat yang membawaku ke dalam neraka, disana keduanya ditemui oleh malaikat yang lain seraya berkata; \"Jangan kamu takut, tolong biarkan orang ini leluasa\". Kemudian [Hafshah] menceritakan salah satu mimpiku itu kepada Nabi shallallahu 'alaihi wasallam. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh 'Abdullah menjadi orang yang paling berbahagia jika mau shalat malam\". 'Abdullah radliallahu 'anhu adalah orang yang seantiasa mendirikan shalat malam sementara para sahabat selalu menceritakan kepada Nabi shallallahu 'alaihi wasallam tentang mimpi-mimpi mereka bahwa pelaksanaan Lailatul Qadar terjadi pada malam ketujuh dari sepuluh malam yang akhir, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh aku melihat bahwa mimpi kalian benar bahwa Lailatul Qadar terjadi pada sepuluh malam yang akhir. Maka siapa yang mau mencari Lailatul Qadar, carilah pada sepuluh malam yang akhir (dari Romadhan) \"."},"1089":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا سَعِيدٌ هُوَ ابْنُ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي جَعْفَرُ بْنُ رَبِيعَةَ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعِشَاءَ ثُمَّ صَلَّى ثَمَانِيَ رَكَعَاتٍ وَرَكْعَتَيْنِ جَالِسًا وَرَكْعَتَيْنِ بَيْنَ النِّدَاءَيْنِ وَلَمْ يَكُنْ يَدَعْهُمَا أَبَدًا","id":"Telah menceritakan kepada kami ['Abdullah bin Yazid] telah menceritakan kepada kami [Said] dia adalah anak dari Abu Ayyub berkata, telah menceritakan kepada saya [Ja'far bin Rabi'ah] dari ['Irak bin Malik] dari [Abu Salamah] dari ['Aisyah radliallahu 'anha] berkata: \"Nabi shallallahu 'alaihi wasallam senantiasa mengerjakan shalat 'Isya' kemudian shalat malam delapan raka'at dan dua raka'at dengan duduk dan dua raka'at antara dua adzan dan tidaklah Beliau pernah meninggalkannya\"."},"1090":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي أَبُو الْأَسْوَدِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى رَكْعَتَيْ الْفَجْرِ اضْطَجَعَ عَلَى شِقِّهِ الْأَيْمَنِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yazid] telah menceritakan kepada kami [Sa'id bin Abu Ayyub] berkata, telah menceritakan kepada saya [Abu Al Aswad] dari ['Urwah bin Az Zubair] dari ['Aisyah radliallahu 'anha] berkata: \"Nabi shallallahu 'alaihi wasallam bila selesai mendirikan dua raka'at shalat sunat Fajar, Beliau berbaring dengan dengan bertumpu pada sisi badannya yang sebelah kanan\"."},"1091":{"ar":"حَدَّثَنَا بِشْرُ بْنُ الْحَكَمِ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي سَالِمٌ أَبُو النَّضْرِ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا صَلَّى فَإِنْ كُنْتُ مُسْتَيْقِظَةً حَدَّثَنِي وَإِلَّا اضْطَجَعَ حَتَّى يُؤْذَنَ بِالصَّلَاةِ","id":"Telah menceritakan kepada kami [Bisyir bin Al Hakam] telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepada saya [Salim Abu An-Nadhir] dari [Abu Salamah] dari ['Aisyah radliallahu 'anha] bahwa Nabi shallallahu 'alaihi wasallam jika selesai dari shalat malam dan aku sudah terbangun Beliau mengajak aku berbincang-bincang dan jika tidak, Beliau akan berbaring hingga datang seruan untuk shalat (Shubuh) \"."},"1092":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ أَبُو النَّضْرِ حَ��َّثَنِي عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي رَكْعَتَيْنِ فَإِنْ كُنْتُ مُسْتَيْقِظَةً حَدَّثَنِي وَإِلَّا اضْطَجَعَقُلْتُ لِسُفْيَانَ فَإِنَّ بَعْضَهُمْ يَرْوِيهِ رَكْعَتَيْ الْفَجْرِ قَالَ سُفْيَانُ هُوَ ذَاكَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] berkata, [Abu An-Nadhir] telah menceritakan kepada saya [Abu Salamah] dari ['Aisyah radliallahu 'anha] bahwa Nabi shallallahu 'alaihi wasallam mengerjakan shalat dua raka'at. Jika aku sudah terbangun Beliau mengajak aku berbincang-bincang dan jika tidak, Beliau akan berbaring\". Aku ('Ali bin 'Abdullah) bertanya kepada Sufyan: \"Sebagaian orang meriwayatkan bahwa shalat yang dimaksud itu adalah dua raka'at Fajar?\" Sufyan berkata: \"Ya benar\"."},"1093":{"ar":"حَدَّثَنَا بَيَانُ بْنُ عَمْرٍو حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمْ يَكُنْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى شَيْءٍ مِنْ النَّوَافِلِ أَشَدَّ مِنْهُ تَعَاهُدًا عَلَى رَكْعَتَيْ الْفَجْرِ","id":"Telah menceritakan kepada kami [Bayan bin 'Amru] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Ibnu Juraij] dari ['Atho'] dari ['Ubaid bin 'Umair] dari ['Aisyah radliallahu 'anha] berkata: \"Tidak ada shalat sunnat yang lebih Nabi shallallahu 'alaihi wasallam tekuni daripada dua raka'at Fajar\"."},"1094":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِاللَّيْلِ ثَلَاثَ عَشْرَةَ رَكْعَةً ثُمَّ يُصَلِّي إِذَا سَمِعَ النِّدَاءَ بِالصُّبْحِ رَكْعَتَيْنِ خَفِيفَتَيْنِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha] berkata: \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat malam tiga belas raka'at kemudian bila sudah mendengar seruan adzan Shubuh Beliau mengerjakan dua raka'at shalat sunnat yang ringan\"."},"1095":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَمَّتِهِ عَمْرَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا يَحْيَى هُوَ ابْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَمْرَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَفِّفُ الرَّكْعَتَيْنِ اللَّتَيْنِ قَبْلَ صَلَاةِ الصُّبْحِ حَتَّى إِنِّي لَأَقُولُ هَلْ قَرَأَ بِأُمِّ الْكِتَابِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin 'Abdurrahman] dari bibinya ['Amrah] dari ['Aisyah radliallahu 'anhu] berkata: \"Adalah Nabi shallallahu 'alaihi wasallam \". -lewat jalur periwayatan lain--Hadits ini diriwayatkan pula oleh [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Yahya] dia adalah anak dari Sa'id dari [Muhammad bin 'Abdurrahman] dari ['Amrah] dari ['Aisyah radliallahu 'anha] berkata: \"Nabi shallallahu 'alaihi wasallam meringankan dua raka'at ini sebelum shalat Shubuh hingga aku bertanya: \"Apakah anda membaca Ummul Kitab (Al Fatihah)?\""},"1096":{"ar":"حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الْمَوَالِي عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا الِاسْتِخَارَةَ فِي الْأُمُورِ كُلِّهَا كَمَا يُعَلِّمُنَا السُّورَةَ مِنْ الْقُرْآنِ يَقُولُ إِذَا هَمَّ أَحَدُكُمْ بِالْأَمْرِ فَلْيَرْكَعْ رَكْعَتَيْنِ مِنْ غَيْرِ الْفَرِيضَةِ ثُمَّ لِيَقُلْ اللَّهُمَّ إِنِّي أَسْتَخِيرُكَ بِعِلْمِكَ وَأَسْتَقْدِرُكَ بِقُدْرَتِكَ وَأَسْأَلُكَ مِنْ فَضْلِكَ الْعَظِيمِ فَإِنَّكَ تَقْدِرُ وَلَا أَقْدِرُ وَتَعْلَمُ وَلَا أَعْلَمُ وَأَنْتَ عَلَّامُ الْغُيُوبِ اللَّهُمَّ إِنْ كُنْتَ تَعْلَمُ أَنَّ هَذَا الْأَمْرَ خَيْرٌ لِي فِي دِينِي وَمَعَاشِي وَعَاقِبَةِ أَمْرِي أَوْ قَالَ عَاجِلِ أَمْرِي وَآجِلِهِ فَاقْدُرْهُ لِي وَيَسِّرْهُ لِي ثُمَّ بَارِكْ لِي فِيهِ وَإِنْ كُنْتَ تَعْلَمُ أَنَّ هَذَا الْأَمْرَ شَرٌّ لِي فِي دِينِي وَمَعَاشِي وَعَاقِبَةِ أَمْرِي أَوْ قَالَ فِي عَاجِلِ أَمْرِي وَآجِلِهِ فَاصْرِفْهُ عَنِّي وَاصْرِفْنِي عَنْهُ وَاقْدُرْ لِي الْخَيْرَ حَيْثُ كَانَ ثُمَّ أَرْضِنِي قَالَ وَيُسَمِّي حَاجَتَهُ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami ['Abdurrahman bin Abu Al Mawaliy] dari [Muhammad bin Al Munkadir] dari [Jabir bin 'Abdullah radliallahu 'anhua] berkata: \"Rasulullah shallallahu 'alaihi wasallam mengajari kami shalat istikharah dalam setiap urusan yan kami hadapi sebagaimana Beliau mengajarkan kami AL Qur'an, yang Beliau shallallahu 'alaihi wasallam bersabda: \"Jika seorang dari kalian menghadapi masalah maka ruku'lah (shalat) dua raka'at yang bukan shalat wajib kemudian berdo'alah: \"Allahumma inniy astakhiiruka bi 'ilmika wa astaqdiruka biqudratika wa as-aluka min fadhlikal 'azhim, fainnaka taqdiru wa laa aqdiru wa ta'lamu wa laa 'Abdullah'lamu wa anta 'allaamul ghuyuub. Allahumma in kunta ta'lamu anna haadzal amru khairul liy fiy diiniy wa aku ma'aasyiy wa 'aafiyati amriy\" atau; 'Aajili amriy wa aajilihi faqdurhu liy wa yassirhu liy tsumma baarik liy fiihi. Wa in kunta ta'lamu anna haadzal amru syarrul liy fiy diiniy wa ma'aasyiy wa 'aafiyati amriy\" aw qaola; fiy 'aajili amriy wa aajilihi fashrifhu 'anniy washrifniy 'anhu waqdurliyl khaira haitsu kaana tsummar dhiniy\". Beliau bersabda: Dan sebutlah keperluannya\" (Ya Allah aku memohon pilihan kepadaMu dengan ilmuMu dan memohon kemampuan dengan kekuasaanMu dan memohon kepadaMu dengan karuniaMu yang Agung, karena Engkau Maha berkuasa sedang aku tidak berkuasa, Engkau Maha Mengetahui sedang aku tidak mengetahui karena Engkaulah yang Maha Mengetahui perkara yang ghoib. Ya Allah bila Engkau mengetahui bahwa urusan ini baik untukku, bagi agamaku, kehidupanku dan kesudahan urusanku ini atau Beliau bersabda; di waktu dekat atau di masa nanti maka takdirkanlah buatku dan mudahkanlah kemudian berikanlah berkah padanya. Namun sebaliknya, ya Allah bila Engkau mengetahui bahwa urusan ini buruk untukku, bagi agamaku, kehidupanku dan kesudahan urusanku ini atau Beliau bersabda; di waktu dekat atau di maa nanti maka jauhkanlah urusan dariku dan jauhkanlah aku darinya dan tetapkanlah buatku urusn yang baik saja dimanapun adanya kemudian paskanlah hatiku dengan ketepanMu itu\". Beliau bersabda: \"Dia sebutkan urusan yang sedang diminta pilihannya itu\"."},"1097":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدٍ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ الزُّرَقِيِّ سَمِعَ أَبَا قَتَادَةَ بْنَ رِبْعِيٍّ الْأنْصَارِيَّ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ أَحَدُكُمْ الْمَسْجِدَ فَلَا يَجْلِسْ حَتَّى يُصَلِّيَ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Al Makkiy bin Ibrahim] dari ['Abdullah bin Sa'id] dari ['Amir bin 'Abdullah bin Az Zubair] dari ['Amru bin Sulaim Az Zuraqiy] dia mendengar [Abu Qatadah bin Rib'iy Al Anshariy radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seorang dari kalian masuk ke dalam masjid maka janganlah dia duduk sebelum shalat dua raka'at\"."},"1098":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ ثُمَّ انْصَرَفَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ishaq bin 'Abdullah bin Abu Tholhah] dari [Anas bin Malik radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam memimpin shalat bersama kami dua raka'at lalu pergi berlalu\"."},"1099":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَالِمٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ قَبْلَ الظُّهْرِ وَرَكْعَتَيْنِ بَعْدَ الظُّهْرِ وَرَكْعَتَيْنِ بَعْدَ الْجُمُعَةِ وَرَكْعَتَيْنِ بَعْدَ الْمَغْرِبِ وَرَكْعَتَيْنِ بَعْدَ الْعِشَاءِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] berkata, telah mengabarkan kepada saya [Salim] dari ['Abdullah bin 'Umar radliallahu 'anhuma] berkata; \"Aku pernah shalat bersama Rasulullah shallallahu 'alaihi wasallam dua raka'at sebelum shalat Zhuhur, dua raka'at sesudah shalat Zhuhur, dua raka'at sesudah shalat Jum'at, dua raka'at sesudah shalat Maghrib dan dua raka'at sesudah shalat 'Isya'\"."},"1100":{"ar":"حَدَّثَنَا آدَمُ قَالَ أَخْبَرَنَا شُعْبَةُ أَخْبَرَنَا عَمْرُو بْنُ دِينَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَخْطُبُ إِذَا جَاءَ أَحَدُكُمْ وَالْإِمَامُ يَخْطُبُ أَوْ قَدْ خَرَجَ فَلْيُصَلِّ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Adam] berkata, telah mengabarkan kepada kami [Syu'bah] telah mengabarkan kepada kami ['Amru bin Dinar] berkata; Aku mendengar [Jabir bin 'Abdullah radliallahu 'anhua] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda ketika Beliau sedang menyampaikan khathbah: \"Jika seorang dari kalian memasuki masjid sedang imam sedang berkhuthbah atau dia telah keluar (kemudian masuk lagi) maka hendaklah dia shalat dua raka'at\"."},"1101":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سَيْفُ بْنُ سُلَيْمَانَ سَمِعْتُ مُجَاهِدًا يَقُولُأُتِيَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا فِي مَنْزِلِهِ فَقِيلَ لَهُ هَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ دَخَلَ الْكَعْبَةَ قَالَ فَأَقْبَلْتُ فَأَجِدُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ خَرَجَ وَأَجِدُ بِلَالًا عِنْدَ الْبَابِ قَائِمًا فَقُلْتُ يَا بِلَالُ أَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْكَعْبَةِ قَالَ نَعَمْ قُلْتُ فَأَيْنَ قَالَ بَيْنَ هَاتَيْنِ الْأُسْطُوَانَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى رَكْعَتَيْنِ فِي وَجْهِ الْكَعْبَةِقَالَ أَبُو عَبْد اللَّهِ قَالَ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ أَوْصَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَكْعَتَيْ الضُّحَى وَقَالَ عِتْبَانُ بْنُ مَالِكٍ غَدَا عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ بَعْدَ مَا امْتَدَّ النَّهَارُ وَصَفَفْنَا وَرَاءَهُ فَرَكَعَ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Sayf bin Sulaiman] aku mendengar [Mujahid] berkata, \" [Ibnu'Umar radliallahu 'anhuma] ditemui di rumahnya lalu dikatakan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam masuk Ka'bah\" Dia berkata: \"Maka aku susul Beliau namun Beliau sudah keluar dari dalam Ka'bah dan aku hanya mendapatkan Bilal sedang berdiri di depan pintu. Aku tanyakan kepadanya; \"Wahai Bilal, apakah Rasulullah shallallahu 'alaihi wasallam mendirikan shalat dalam Ka'bah?\" [Bilal] menjawab: Iya\". Aku berkata lagi; \"dimana beliau shalat?\" Dia menjawab: \"Diantara dua tiang, kemudian keluar dan mendirikan shalat dua raka'at di depan Ka'bah\". Berkata Abu 'Abdullah: berkata, Abu Hurairah radliallahu 'anhu: \"Nabi shallallahu 'alaihi wasallam telah mewasiatkan aku agar melaksanakan shalat Dhuha dua raka'at\". Dan berkata, 'Utban bin Malik: Aku pernah bersama Rasulullah shallallahu 'alaihi wasallam dan Abu Bakar radliallahu 'anhu di waktu pagi hari hingga siang mulai meninggi, lalu Beliau shallallahu 'alaihi wasallam membariskan kami di belakangnya kemudian shalat dua raka'at\"."},"1102":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنَا نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجْدَتَيْنِ قَبْلَ الظُّهْرِ وَسَجْدَتَيْنِ بَعْدَ الظُّهْرِ وَسَجْدَتَيْنِ بَعْدَ الْمَغْرِبِ وَسَجْدَتَيْنِ بَعْدَ الْعِشَاءِ وَسَجْدَتَيْنِ بَعْدَ الْجُمُعَةِ فَأَمَّا الْمَغْرِبُ وَالْعِشَاءُ فَفِي بَيْتِهِوَحَدَّثَتْنِي أُخْتِي حَفْصَةُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي رَكْعَتَيْنِ خَفِيفَتَيْنِ بَعْدَ مَا يَطْلُعُ الْفَجْرُ وَكَانَتْ سَاعَةً لَا أَدْخُلُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا وَقَال�� ابْنُ أَبِي الزِّنَادِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ بَعْدَ الْعِشَاءِ فِي أَهْلِهِ تَابَعَهُ كَثِيرُ بْنُ فَرْقَدٍ وَأَيُّوبُ عَنْ نَافِعٍ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] berkata, telah mengabarkan kepada kami [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] berkata: \"Aku pernah shalat bersama Nabi shallallahu 'alaihi wasallam dua sujud (raka'at) sebelum shalat Zhuhur dan dua raka'at sesudah shalat Zhuhur, dua raka'at sesudah shalat Maghrib, dua raka'at sesudah shalat 'Isya', dan dua raka'at sesudah shalat Jum'at. Adapun untuk Maghrib dan 'Isya' Beliau melaksanaannya di rumah Beliau\". Dan telah menceritakan kepadaku saudara perempuanku [Hafshah] bahwa Nabi shallallahu 'alaihi wasallam melaksanakan shalat dua raka'at dengan ringan setelah terbitnya fajar dan ketika itu aku tidak menemui Nabi shallallahu 'alaihi wasallam \". Dan berkata, [Ibnu Abu Az Zanad] dari [Musa bin 'Uqbah] dari [Nafi']: \"Beliau shallallahu 'alaihi wasallam mengerjakan shalat sunnat setelah 'Isya di rumah keluarganya\". Hadits ini diperkuat pula oleh [Katsir bin Farqad] dan [Ayyub] dari [Nafi']."},"1103":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو قَالَ سَمِعْتُ أبَا الشَّعْثَاءِ جَابِرًا قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَمَانِيًا جَمِيعًا وَسَبْعًا جَمِيعًا قُلْتُ يَا أَبَا الشَّعْثَاءِ أَظُنُّهُ أَخَّرَ الظُّهْرَ وَعَجَّلَ الْعَصْرَ وَعَجَّلَ الْعِشَاءَ وَأَخَّرَ الْمَغْرِبَ قَالَ وَأَنَا أَظُنُّهُ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Sufyan] dari ['Amru] berkata, Aku mendengar [Abu Asy-Sya'tsa' Jabir] berkata, Aku mendengar [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Aku pernah shalat bersama Rasulullah shallallahu 'alaihi wasallam delapan raka'at dengan dijamak dan tujuh raka'at dengan di jamak'\". Aku tanyakan: \"Wahai Abu Asy-Sya'tsa', dugaanku Beliau mengakhirkan Zhuhur dan menyegerakan 'Ashar (jama' takhir) dan menyegerakan 'Isya mengakhirkan Maghrib\" (jamak takhir). Dia berkata: \"Aku juga menduga begitu\"."},"1104":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ تَوْبَةَ عَنْ مُوَرِّقٍ قَالَ قُلْتُ لِابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَتُصَلِّي الضُّحَى قَالَ لَا قُلْتُ فَعُمَرُ قَالَ لَا قُلْتُ فَأَبُو بَكْرٍ قَالَ لَا قُلْتُ فَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا إِخَالُهُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Taubah] dari [Muwarriq] berkata; Aku bertanya kepada [Ibnu'Umar radliallahu 'anhuma]: \"Apakah anda melaksanakan shalat Dhuha?\" Dia menjawab: \"Tidak!\". Aku tanyakan lagi: \"Bagaimana dengan 'Umar?\" Dia menjawab: Tidak!\".\"Bagaimana dengan Abu Bakar?\" Dia menjawab: Tidak!\".\"Bagaimana dengan Nabi shallallahu 'alaihi wasallam?\" Dia menjawab: \"Juga tidak, menurut dugaanku!\"."},"1105":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَمْرُو بْنُ مُرَّةَ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ أَبِي لَيْلَى يَقُولُ مَا حَدَّثَنَا أَحَدٌ أَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الضُّحَى غَيْرُ أُمِّ هَانِئٍ فَإِنَّهَا قَالَتْإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ بَيْتَهَا يَوْمَ فَتْحِ مَكَّةَ فَاغْتَسَلَ وَصَلَّى ثَمَانِيَ رَكَعَاتٍ فَلَمْ أَرَ صَلَاةً قَطُّ أَخَفَّ مِنْهَا غَيْرَ أَنَّهُ يُتِمُّ الرُّكُوعَ وَالسُّجُودَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] Aku mendengar ['Abdurrahman bin Abu Laila] berkata: Tidak ada dari orang yang pernah menceritakan kepada kita bahwa dia melihat Nabi shallallahu 'alaihi wasallam melaksanakan shalat Dhuha kecuali [Ummu Hani'] yang dia menceritakan bahwa Nabi shallallahu 'alaihi wasallam pernah memasuki rumahnya pada saat penaklukan Makkah, kemudian Beliau shallallahu 'alaihi wasallam mandi lalu shalat delapan raka'at\" seraya menjelaskan: \"Aku belum pernah sekalipun melihat Beliau melaksanakan shalat yang lebih ringan dari pada saat itu, namun Beliau tetap menyempurnakan ruku' dan sujudnya\"."},"1106":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبَّحَ سُبْحَةَ الضُّحَى وَإِنِّي لَأُسَبِّحُهَا","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Ibnu Abu Dza'bi] dari [Az Zuhriy] dari ['Urwah] dari ['Aisyah radliallahu 'anha] berkata: \"Aku belum pernah melihat Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat sunnat Dhuha. Adapun aku mengerjakannya\"."},"1107":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا شُعْبَةُ حَدَّثَنَا عَبَّاسٌ الْجُرَيْرِيُّ هُوَ ابْنُ فَرُّوخَ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَأَوْصَانِي خَلِيلِي بِثَلَاثٍ لَا أَدَعُهُنَّ حَتَّى أَمُوتَ صَوْمِ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ وَصَلَاةِ الضُّحَى وَنَوْمٍ عَلَى وِتْرٍ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah mengabarkan kepada kami [Syu'bah] telah menceritakan kepada kami ['Abbas Al Jurairiy] dia adalah anak dari Farrukh dari [Abu 'Utsman An-Nahdiy] dari [Abu Hurairah radliallahu 'anhu] berkata: \"Kekasihku (Rasulullah shallallahu 'alaihi wasallam) telah berwasiat kepadaku dengan tiga perkara yang tidak akan pernah aku tinggalkan hingga aku meninggal dunia, yaitu shaum tiga hari pada setiap bulan, shalat Dhuha dan tidur dengan shalat witir terlebih dahulu\"."},"1108":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْجَعْدِ أَخْبَرَنَا شُعْبَةُ عَنْ أَنَسِ بْنِ سِيرِينَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ الْأَنْصَارِيَّ قَالَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ وَكَانَ ضَخْمًا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَا أَسْتَطِيعُ الصَّلَاةَ مَعَكَ فَصَنَعَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا فَدَعَاهُ إِلَى بَيْتِهِ وَنَضَحَ لَهُ طَرَفَ حَصِيرٍ بِمَاءٍ فَصَلَّى عَلَيْهِ رَكْعَتَيْنِ وَقَالَ فُلَانُ بْنُ فُلَانِ بْنِ جَارُودٍ لِأَنَسٍ رَضِيَ اللَّهُ عَنْهُ أَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الضُّحَى فَقَالَ مَا رَأَيْتُهُ صَلَّى غَيْرَ ذَلِكَ الْيَوْمِ","id":"Telah menceritakan kepada kami ['Ali bin Al Ja'di] telah mengabarkan kepada kami [Syu'bah] dari [Anas bin Sirin] berkata, aku mendengar [Anas bin Malik Al Anshariy radliallahu 'anhu] berkata; \"Ada seorang laki-laki yang berbadan besar dari Kaum Anshar berkata kepada Nabi shallallahu 'alaihi wasallam; \"Aku tidak dapat shalat bersama anda\". Kemudian ia menyiapkan makanan untuk Nabi shallallahu 'alaihi wasallam, lalu dia mengundang Beliau shallallahu 'alaihi wasallam ke rumahnya, kemudian Beliau memercikkan air pada sisi tikar lalu Beliau shallallahu 'alaihi wasallam shalat dua raka'at diatasnya\". Berkata fulan bin fulan bin Al Jarud kepada Anas bin Malik radliallahu 'anhu; \"Apakah Nabi shallallahu 'alaihi wasallam tadi melaksanakan shalat Dhuha'? Anas bin Malik radliallahu 'anhu menjawab: \"Aku belum pernah melihat Beliau mengerjakannya kecuali pada hari itu\"."},"1109":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَحَفِظْتُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشْرَ رَكَعَاتٍ رَكْعَتَيْنِ قَبْلَ الظُّهْرِ وَرَكْعَتَيْنِ بَعْدَهَا وَرَكْعَتَيْنِ بَعْدَ الْمَغْرِبِ فِي بَيْتِهِ وَرَكْعَتَيْنِ بَعْدَ الْعِشَاءِ فِي بَيْتِهِ وَرَكْعَتَيْنِ قَبْلَ صَلَاةِ الصُّبْحِ وَكَانَتْ سَاعَةً لَا يُدْخَلُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا حَدَّثَتْنِي حَفْصَةُ أَنَّهُ كَانَ إِذَا أَذَّنَ الْمُؤَذِّنُ وَطَلَعَ الْفَجْرُ صَلَّى رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhu] berkata; \"Aku menghafal sesuatu dari Nabi shallallahu 'alaihi wasallam berupa shalat sunnat sepuluh raka'at yaitu; dua raka'at sebelum shalat Zhuhur, dua raka'at sesudahnya, dua raka'at sesudah shalat Maghrib di rumah Beliau, dua raka'at sesudah shalat 'Isya' di rumah Beliau dan dua raka'at sebelum shalat Shubuh, dan pada pelaksanaan shalat ini tidak ada waktu senggang buat Nabi shallallahu 'alaihi wasallam \". Telah menceritakan kepada saya [Hafshah]: \"Bahwasanya bila mu'adzin sudah mengumandangkan adzan dan fajar sudah terbit, Beliau shalat dua raka'at\"."},"1110":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَدَعُ أَرْبَعًا قَبْلَ الظُّهْرِ وَرَكْعَتَيْنِ قَبْلَ الْغَدَاةِتَابَعَهُ ابْنُ أَبِي عَدِيٍّ وَعَمْرٌو عَنْ شُعْبَةَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Ibrahim bin Muhammad bin Al Muntasyir] dari [bapaknya] dari ['Aisyah radliallahu 'anha] bahwa \"Nabi shallallahu 'alaihi wasallam tidak pernah meninggalkan shalat sunnat empat reka'at sebelum Zhuhur dan dua raka'at sebelum shalat Shubuh\". Hadits ini diriwayatkan pula oleh [Ibnu Abu 'Adiy] dan ['Amru] dari [Syu'bah]."},"1111":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ الْحُسَيْنِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ الْمُزَنِيُّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلُّوا قَبْلَ صَلَاةِ الْمَغْرِبِ قَالَ فِي الثَّالِثَةِ لِمَنْ شَاءَ كَرَاهِيَةَ أَنْ يَتَّخِذَهَا النَّاسُ سُنَّةً","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami ['Abdul Warits] dari [Al Hasan] dari ['Abdullah bin Buraidah] berkata, telah menceritakan kepada saya ['Abdullah Al Muzaniy] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Shalatlah sebelum shalat Maghrib!\". Beliau berkata, pada kali ketiganya: \"Bagi siapa yang mau\". Hal ini Beliau sampaikan karena khawatir nanti orang-orang akan menjadikannya sebagai sunnah\"."},"1112":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ هُوَ الْمُقْرِئُ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ قَالَ سَمِعْتُ مَرْثَدَ بْنَ عَبْدِ اللَّهِ الْيَزَنِيَّ قَالَ أَتَيْتُ عُقْبَةَ بْنَ عَامِرٍ الْجُهَنِيَّ فَقُلْتُأَلَا أُعْجِبُكَ مِنْ أَبِي تَمِيمٍ يَرْكَعُ رَكْعَتَيْنِ قَبْلَ صَلَاةِ الْمَغْرِبِ فَقَالَ عُقْبَةُ إِنَّا كُنَّا نَفْعَلُهُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ فَمَا يَمْنَعُكَ الْآنَ قَالَ الشُّغْلُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yazid] -dia adalah Al Muqriy- berkata, telah menceritakan kepada kami [Sa'id bin Abu Ayyub] berkata, telah menceritakan kepada saya [Yazid bin Abu Habib] berkata; Aku mendengar [Martsad bin 'Abdullah Al Yazaniy] berkata; \"Aku menemui ['Uqbah bin 'Amir Al Juhaniy] lalu aku berkata kepadanya: \"Apakah kamu tidak heran terhadap Abu Tamim yang dia shalat dua raka'at sebelum shalat Maghrib? Maka ('Uqbah) menjawab: \"Kami dulu juga melakukannya pada masa hidup Rasulullah shallallahu 'alaihi wasallam \". Aku berkata: \"Lalu apa yang menghalangimu dari mengerjakannya sekarang?\" Dia menjawab: \"Kesibukan\"."},"1113":{"ar":"حَدَّثَنِي إِسْحَاقُ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي مَحْمُودُ بْنُ الرَّبِيعِ الْأَنْصَارِيُّ أَنَّهُ عَقَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَقَلَ مَجَّةً مَجَّهَا فِي وَجْهِهِ مِنْ بِئْرٍ كَانَتْ فِي دَارِهِمْ فَزَعَمَ مَحْمُودٌ أَنَّهُ سَمِعَ عِتْبَانَ بْنَ مَالِكٍ الْأَنْصارِيَّ رَضِيَ اللَّهُ عَنْهُ وَكَانَ مِمَّنْ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُكُنْتُ أُصَلِّي لِقَوْمِي بِبَنِي سَالِمٍ وَكَانَ يَحُولُ بَيْنِي وَبَيْنَهُمْ وَادٍ إِذَا ج��اءَتْ الْأَمْطَارُ فَيَشُقُّ عَلَيَّ اجْتِيَازُهُ قِبَلَ مَسْجِدِهِمْ فَجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَهُ إِنِّي أَنْكَرْتُ بَصَرِي وَإِنَّ الْوَادِيَ الَّذِي بَيْنِي وَبَيْنَ قَوْمِي يَسِيلُ إِذَا جَاءَتْ الْأَمْطَارُ فَيَشُقُّ عَلَيَّ اجْتِيَازُهُ فَوَدِدْتُ أَنَّكَ تَأْتِي فَتُصَلِّي مِنْ بَيْتِي مَكَانًا أَتَّخِذُهُ مُصَلًّى فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَفْعَلُ فَغَدَا عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ بَعْدَ مَا اشْتَدَّ النَّهَارُ فَاسْتَأْذَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَذِنْتُ لَهُ فَلَمْ يَجْلِسْ حَتَّى قَالَ أَيْنَ تُحِبُّ أَنْ أُصَلِّيَ مِنْ بَيْتِكَ فَأَشَرْتُ لَهُ إِلَى الْمَكَانِ الَّذِي أُحِبُّ أَنْ أُصَلِّيَ فِيهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَبَّرَ وَصَفَفْنَا وَرَاءَهُ فَصَلَّى رَكْعَتَيْنِ ثُمَّ سَلَّمَ وَسَلَّمْنَا حِينَ سَلَّمَ فَحَبَسْتُهُ عَلَى خَزِيرٍ يُصْنَعُ لَهُ فَسَمِعَ أَهْلُ الدَّارِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِي فَثَابَ رِجَالٌ مِنْهُمْ حَتَّى كَثُرَ الرِّجَالُ فِي الْبَيْتِ فَقَالَ رَجُلٌ مِنْهُمْ مَا فَعَلَ مَالِكٌ لَا أَرَاهُ فَقَالَ رَجُلٌ مِنْهُمْ ذَاكَ مُنَافِقٌ لَا يُحِبُّ اللَّهَ وَرَسُولَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُلْ ذَاكَ أَلَا تَرَاهُ قَالَ لَا إِلَهَ إِلَّا اللَّهُ يَبْتَغِي بِذَلِكَ وَجْهَ اللَّهِ فَقَالَ اللَّهُ وَرَسُولُهُ أَعْلَمُ أَمَّا نَحْنُ فَوَاللَّهِ لَا نَرَى وُدَّهُ وَلَا حَدِيثَهُ إِلَّا إِلَى الْمُنَافِقِينَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ اللَّهَ قَدْ حَرَّمَ عَلَى النَّارِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ يَبْتَغِي بِذَلِكَ وَجْهَ اللَّهِ قَالَ مَحْمُودُ بْنُ الرَّبِيعِ فَحَدَّثْتُهَا قَوْمًا فِيهِمْ أَبُو أَيُّوبَ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَتِهِ الَّتِي تُوُفِّيَ فِيهَا وَيَزِيدُ بْنُ مُعَاوِيَةَ عَلَيْهِمْ بِأَرْضِ الرُّومِ فَأَنْكَرَهَا عَلَيَّ أَبُو أَيُّوبَ قَالَ وَاللَّهِ مَا أَظُنُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا قُلْتَ قَطُّ فَكَبُرَ ذَلِكَ عَلَيَّ فَجَعَلْتُ لِلَّهِ عَلَيَّ إِنْ سَلَّمَنِي حَتَّى أَقْفُلَ مِنْ غَزْوَتِي أَنْ أَسْأَلَ عَنْهَا عِتْبَانَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ إِنْ وَجَدْتُهُ حَيًّا فِي مَسْجِدِ قَوْمِهِ فَقَفَلْتُ فَأَهْلَلْتُ بِحَجَّةٍ أَوْ بِعُمْرَةٍ ثُمَّ سِرْتُ حَتَّى قَدِمْتُ الْمَدِينَةَ فَأَتَيْتُ بَنِي سَالِمٍ فَإِذَا عِتْبَانُ شَيْخٌ أَعْمَى يُصَلِّي لِقَوْمِهِ فَلَمَّا سَلَّمَ مِنْ الصَّلَاةِ سَلَّمْتُ عَلَيْهِ وَأَخْبَرْتُهُ مَنْ أَنَا ثُمَّ سَأَلْتُهُ عَنْ ذَلِكَ الْحَدِيثِ فَحَدَّثَنِيهِ كَمَا حَدَّثَنِيهِ أَوَّلَ مَرَّةٍ","id":"Telah menceritakan kepada saya [Ishaq] telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [bapakku] dari [Ibnu Syihab] berkata, telah mengabarkan kepada saya [Mahmud bin Ar-Rab' Al Anshary] bahwasanya dia mengingat kejadian bersama Rasulullah shallallahu 'alaihi wasallam diantaranya Beliau shallallahu 'alaihi wasallam pernah menyemburkan air dari mulut Beliau kepadanya dari air yang ada di sumur yang berada di rumah mereka. Mahmud mengabarkan bahwa dia mendengar ['Itban bin Malik Al Anshariy radliallahu 'anhu] seorang shahabat yang pernah mengikuti perang Badar bersama Rasulullah shallallahu 'alaihi wasallam berkata: \"Aku sering memimpin shalat kaumku Bali Salim sedanglan tempat aku dan mereka dipisahkan oleh lembah yang apabila turun hujan akan menghalangi aku mengunjungi masjid mereka. Maka aku menemui Rasulullah shallallahu 'alaihi wasallam, dan aku berkata kepada Beliau: \"Pandanganku sudah buruk, sementara lembah yang ada antara aku dan kaumku saat turun hujan akan menghalangiku mengunjungi mereka. Maka aku menginginkan anda dapat mengunjungi aku lalu shalat di rumahku yang akan aku jadikan sebagai tempat shalat. Maka berkata, Rasulullah shallallahu 'alaihi wasallam: \"Akan saya penuhi\". Maka Rasulullah shallallahu 'alaihi wasallam dan Abu Bakar berangkat ketika siang hari lalu Rasulullah shallallahu 'alaihi wasallam meminta izin, maka aku izinkan. Beliau tidaklah duduk hingga Beliau berkata: \"Mana tempat yang kau sukai untuk aku shalat di rumahmu?\" Maka Beliau aku tunjukkan tempat yang aku sukai untuk aku shalat disana. Maka Nabi shallallahu 'alaihi wasallam berdiri lalu bertakbir. Dan kami pun berdiri membuat shaf di belakang Beliau, lalu Beliau shalat dua raka'at kemudian memberi salam dan kami pun memberi salam ketika Beliau memberi salam. Lalu aku tahan Beliau dengan menyuguhkan makanan dari daging yang kami masak untuk Beliau. Kemudian orang-orang mendengar kehadiran Rasulullah shallallahu 'alaihi wasallam di rumahku. Lalu ada seorang diantara mereka yang mengabarkan sehingga orang-orang bertambah banyak yang berkumpul di rumahku. Berkata seorang dari mereka: \"Apa yang dilakukan aku tidak setuju\". Lalu ada seorang dari mereka yang berkata: \"Inilah munafiq, yang tidak mencintai Allah dan RasulNya\". Maka Rasulullah shallallahu 'alaihi wasallam berkata.: \"Janganlah kamu ucapkan seperti itu. Bukankan kamu tahu dia telah mengucapkan laa ilaaha illallah dengan semata mengharap ridha Allah?\" Orang itu berkata: \"Allah dan RasulNya yang lebih tahu\". Adapun kami, demi Allah 'tidaklah kami melihat kecintaan dan ucapan Beliau ini kecuali untuk orang Munafiqin. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah telah mengharamkan neraka bagi orang yang mengucapkan laa ilaaha illallah dengan mengharap ridha Allah \". Berkata, Mahmud bin Ar-Rabi': \"Kemudian kisah ini aku ceritakan kepada kaum yang dikampung itu terdapat ada Abu Ayyub yang pernah menyertai Rasulullah shallallahu 'alaihi wasallam dalam perang yang Beliau lakukan yang ia menjadi wafat karenanya dan Yazid bin Mu'awiyah yang saat itu menjadi pemimpin mereka dibumi Rum. Maka Abu Ayyub mengingkari apa yang aku ceritakan seraya berkata: \"Demi Allah, aku tidak percaya bahwa Rasulullah shallallahu 'alaihi wasallam mengatakan seperti yang kamu ceritakan\". Pernyataan Abu Ayyub ini membuat aku sangat berat menerimanya sehingga aku serahkan diriku kepada Allah Ta'ala agar menyelamatkan aku sampai aku kembali dari perangku ini dengan tujuan agar aku bisa menanyakan hal ini kepada 'Itban bin Malik radliallahu 'anhu jika aku menjumpainya masih hidup di masjid kaumnya. Maka aku kembali lalu aku bertalbiyah (memulai) hajji dan 'umrah. Setelah itu aku pergi berjalan hingga sampai di kota Madinah. Kemudian aku mendatangi Bani Salim, disana aku jumpai 'Itban dalam kondisi yang sudah sangat tua dan telah buta matanya sedang shalat bersama kaumnya. Setelah selesai salam dari shalatnya aku memberi salam kepadanya lalu aku memberi tahu siapa aku lalu aku bertanya kepadanya tentang kisah yang aku maksud. Maka dia menceritakan kepadaku sebagaimana dia pernah menceritakan kali pertama dulu\"."},"1114":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ حَدَّثَنَا وُهَيْبٌ عَنْ أَيُّوبَ وَعُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْعَلُوا فِي بُيُوتِكُمْ مِنْ صَلَاتِكُمْ وَلَا تَتَّخِذُوهَا قُبُورًاتَابَعَهُ عَبْدُ الْوَهَّابِ عَنْ أَيُّوبَ","id":"Telah menceritakan kepada kami ['Abdul A'laa bin Hammad] telah menceritakan kepada kami [Wuhaib] dari [Ayyub] dan ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhumaa] berkata; Telah bersabda Rasulullah shallallahu 'alaihi wasallam: \"Kerjakanlah di rumah-rumah kalian diantara shalat-shalat yang ada, dan jangan kalian jadikan (rumah-rumah kalian) sebagai kuburan\". Hadits ini uga diperkuat oleh ['Abdul Wahhab] dari [Ayyub]. "},"1115":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ عَنْ قَزَعَةَ قَالَ سَمِعْتُ أَبَا سَعِيدٍ رَضِيَ اللَّهُ عَنْهُ أَرْبَعًا قَالَ سَمِعْتُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ غَزَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثِنْتَيْ عَشْرَةَ غَزْوَةً ح حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُشَدُّ الرِّحَالُ إِلَّا إِلَى ثَلَاثَةِ مَسَاجِدَ الْمَسْجِدِ الْحَرَامِ وَمَسْجِدِ الرَّسُولِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَسْجِدِ الْأَقْصَى","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] telah menceritakan kepada kami [Syu'bah] berkata, telah mengabarkan kepada saya ['Abdul Malik bin 'Umair] dari [Qaza'ah] berkata; Aku mendengar [Abu Sa'id radliallahu 'anhu] empat kali, berkata; Aku mendengar dari Nabi shallallahu 'alaihi wasallam. Dia (Abu Sa'id radliallahu 'anhu) pernah ikut berperang bersama Nabi shallallahu 'alaihi wasallam sebanyak dua belas kali peperangan. Dan diriwayatkan, telah menceritakan kepada kami ['Ali] telah menceritakan kepada kami [Sufyan] dari [Az Zuhriy] dari [Sa'id] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah ditekankan untuk berziarah kecuali untuk mengunjungi tiga masjid, Masjidil Haram, Masjid Rasul shallallahu 'alaihi wasallam dan Masjidil Aqsha\"."},"1116":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ زَيْدِ بْنِ رَبَاحٍ وَعُبَيْدِ اللَّهِ بْنِ أَبِي عَبْدِ اللَّهِ الْأَغَرِّ عَنْ أَبِي عَبْدِ اللَّهِ الْأَغَرِّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةٌ فِي مَسْجِدِي هَذَا خَيْرٌ مِنْ أَلْفِ صَلَاةٍ فِيمَا سِوَاهُ إِلَّا الْمَسْجِدَ الْحَرَامَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Zaid bin Rabah] dan ['Ubaidillah bin Abu 'Abdullah Al Ghorri] dari [Abu 'Abdullah Al Ghorri] dari [Abu Hurairah radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Shalat di masjidku ini nilainya seribu kali lebih baik dibandingkan pada masjid lain kecuali pada Al Masjidil Haram\"."},"1117":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ هُوَ الدَّوْرَقِيُّ حَدَّثَنَا ابْنُ عُلَيَّةَ أَخْبَرَنَا أَيُّوبُ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاكَانَ لَا يُصَلِّي مِنْ الضُّحَى إِلَّا فِي يَوْمَيْنِ يَوْمَ يَقْدَمُ بِمَكَّةَ فَإِنَّهُ كَانَ يَقْدَمُهَا ضُحًى فَيَطُوفُ بِالْبَيْتِ ثُمَّ يُصَلِّي رَكْعَتَيْنِ خَلْفَ الْمَقَامِ وَيَوْمَ يَأْتِي مَسْجِدَ قُبَاءٍ فَإِنَّهُ كَانَ يَأْتِيهِ كُلَّ سَبْتٍ فَإِذَا دَخَلَ الْمَسْجِدَ كَرِهَ أَنْ يَخْرُجَ مِنْهُ حَتَّى يُصَلِّيَ فِيهِ قَالَ وَكَانَ يُحَدِّثُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَزُورُهُ رَاكِبًا وَمَاشِيًا قَالَ وَكَانَ يَقُولُ إِنَّمَا أَصْنَعُ كَمَا رَأَيْتُ أَصْحَابِي يَصْنَعُونَ وَلَا أَمْنَعُ أَحَدًا أَنْ يُصَلِّيَ فِي أَيِّ سَاعَةٍ شَاءَ مِنْ لَيْلٍ أَوْ نَهَارٍ غَيْرَ أَنْ لَا تَتَحَرَّوْا طُلُوعَ الشَّمْسِ وَلَا غُرُوبَهَا","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] dia adalah Ad-Dawraqiy telah menceritakan kepada kami [Ibnu 'Ulayyah] telah mengabarkan kepada kami [Ayyub] dari [Nafi'] bahwa [Ibnu 'Umar radliallahu 'anhumaa] tidak pernah mengerjakan shalat Dhuha kecuali pada dua kali kesempatan (hari) yaitu hari ketika dia mengunjungi Makkah saat dia memasuki kota Makkah di waktu Dhuha lalu dia melakukan thawaf di Al Bait (Ka'bah) kemudian shalat dua raka'at di belakang Maqam (Ibrahim) dan satunya lagi saat dia mengunjungi masjid Quba', yang dia mendatanginya pada hari Sabtu. Bila dia sudah memasukinya, maka dia enggan untuk keluar darinya hingga dia shalat terlebih dahulu di dalamnya. Berkata, Nafi'; \"Dan Ibnu'Umar radliallahu 'anhuma menceritakan bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengunjungi (masjid Quba') baik dengan berkendaraan ataupun berjalan kaki\". Berkata, Nafi'; \"Dan Ibnu'Umar radliallahu 'anhuma berkata: \"Sesungguhnya aku mengerjakan yang demikian seperti aku melihat para sahabatku melakukannya, namun aku tidak melarang seseorangpun untuk mengerjakan shalat pada waktu kapanpun yang dia suka baik di waktu malam maupun siang hari, asalkan tidak bersamaan waktunya saat terbitnya matahari atau saat tenggelam\"."},"1118":{"ar":"حَدَّثَنَا مُوسَى بْنُ ��ِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِي مَسْجِدَ قُبَاءٍ كُلَّ سَبْتٍ مَاشِيًا وَرَاكِبًا وَكَانَ عَبْدُ اللَّهِ بْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَفْعَلُهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami ['Abdul 'Aziz bin Muslim] dari ['Abdullah bin Dinar] dari [Ibnu'Umar radliallahu 'anhuma] berkata: \"Rasulullah shallallahu 'alaihi wasallam pernah mengunjungi masjid Quba' pada setiap hari Sabtu, baik dengan berkendaraan ataupun berjalan kaki\". Dan Ibnu'Umar radliallahu 'anhuma juga melakukannya seperti itu."},"1119":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِي مَسْجِدَ قُبَاءٍ رَاكِبًا وَمَاشِيًازَادَ ابْنُ نُمَيْرٍ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ فَيُصَلِّي فِيهِ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] berkata, telah menceritakan kepada saya [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] berkata: \"Rasulullah shallallahu 'alaihi wasallam pernah mengunjungi masjid Quba' dengan berkendaraan ataupun berjalan kaki\". Dan [Ibnu Numair] menambahkan, telah menceritakan kepada kami ['Ubaidullah] dari [Nafi']: \"Maka Beliau mengerjakan shalat dua raka'at didalamnya\"."},"1120":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ الْمَازِنِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا بَيْنَ بَيْتِي وَمِنْبَرِي رَوْضَةٌ مِنْ رِيَاضِ الْجَنَّةِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari ['Abdullah bin Abu Bakar] dari ['Abbad bin Tamim] dari ['Abdullah bin Zaid Al Maaziniy radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tempat yang ada diantara rumahku dan mimbarku adalah raudhah (taman) diantara taman-taman surga\"."},"1121":{"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ قَالَ حَدَّثَنِي خُبَيْبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا بَيْنَ بَيْتِي وَمِنْبَرِي رَوْضَةٌ مِنْ رِيَاضِ الْجَنَّةِ وَمِنْبَرِي عَلَى حَوْضِي","id":"Telah menceritakan kepada kami [Musaddad] dari [Yahya] dari ['Ubaidullah bin 'Umar] berkata, telah menceritakan kepada saya [Khubaib bin 'Abdurrahman] dari [Hafsh bin 'Ashim] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Diantara rumahku dan mimbarku adalah raudhah (taman) diantara taman-taman surga dan mimbarku berada pada telagaku (di surga) \"."},"1122":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ سَمِعْتُ قَزَعَةَ مَوْلَى زِيَادٍ قَالَ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُيُحَدِّثُ بِأَرْبَعٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْجَبْنَنِي وَآنَقْنَنِي قَالَ لَا تُسَافِرْ الْمَرْأَةُ يَوْمَيْنِ إِلَّا مَعَهَا زَوْجُهَا أَوْ ذُو مَحْرَمٍ وَلَا صَوْمَ فِي يَوْمَيْنِ الْفِطْرِ وَالْأَضْحَى وَلَا صَلَاةَ بَعْدَ صَلَاتَيْنِ بَعْدَ الصُّبْحِ حَتَّى تَطْلُعَ الشَّمْسُ وَبَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ وَلَا تُشَدُّ الرِّحَالُ إِلَّا إِلَى ثَلَاثَةِ مَسَاجِدَ مَسْجِدِ الْحَرَامِ وَمَسْجِدِ الْأَقْصَى وَمَسْجِدِي","id":"Telah menceritakan kepada kami [Abu AL Walid] telah menceritakan kepada kami [Syu'bah] dari ['Abdul Malik] aku mendengar [Qaza'ah] sahayanya Ziyad berkata, Aku mendengar [Abu Sa'id Al Khudriy radliallahu 'anhu] menceritakan empat hal (kalimat) dari Nabi shallallahu 'alaihi wasallam yang menyebabkan aku ta'ajub dan kaget. Beliau shallallahu 'alaihi wasallam bersabda: \"Tidak boleh bepergian bagi wanita selama dua hari kecuali bersama suami atau mahramnya, dan tidak boleh shaum pada hari Raya 'Iedul Fithri dan 'Iedul Adhha, dan tidak boleh shalat setelah shalat Shubuh hingga matahari terbit dan setelah 'Ashar hingga terbenam (matahari), dan tidaklah ditekankan untuk berziarah kecuali untuk mengunjungi tiga masjid, Al Masjidil Haram, Masjid Rasul shallallahu 'alaihi wasallam dan Masjidil Aqsha\"."},"1123":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ أَنَّهُ أَخْبَرَهُ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ بَاتَ عِنْدَ مَيْمُونَةَ أُمِّ الْمُؤْمِنِينَ رَضِيَ اللَّهُ عَنْهَا وَهِيَ خَالَتُهُ قَالَ فَاضْطَجَعْتُ عَلَى عَرْضِ الْوِسَادَةِ وَاضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ فِي طُولِهَا فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى انْتَصَفَ اللَّيْلُ أَوْ قَبْلَهُ بِقَلِيلٍ أَوْ بَعْدَهُ بِقَلِيلٍ ثُمَّ اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَلَسَ فَمَسَحَ النَّوْمَ عَنْ وَجْهِهِ بِيَدِهِ ثُمَّ قَرَأَ الْعَشْرَ آيَاتٍ خَوَاتِيمَ سُورَةِ آلِ عِمْرَانَ ثُمَّ قَامَ إِلَى شَنٍّ مُعَلَّقَةٍ فَتَوَضَّأَ مِنْهَا فَأَحْسَنَ وُضُوءَهُ ثُمَّ قَامَ يُصَلِّي قَالَ عَبْدُ اللَّهِ بْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا فَقُمْتُ فَصَنَعْتُ مِثْلَ مَا صَنَعَ ثُمَّ ذَهَبْتُ فَقُمْتُ إِلَى جَنْبِهِ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ الْيُمْنَى عَلَى رَأْسِي وَأَخَذَ بِأُذُنِي الْيُمْنَى يَفْتِلُهَا بِيَدِهِ فَصَلَّى رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ ثُمَّ اضْطَجَعَ حَتَّى جَاءَهُ الْمُؤَذِّنُ فَقَامَ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى الصُّبْحَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Makhramah bin Sulaiman] dari [Kuraib] sahaya Ibnu 'Abbas radliallahu 'anhu bahwa dia mengabarkan dari ['Abdullah bin 'Abbas radliallahu 'anhuma] bahwa dia pada suatu malam bermalam di rumah Maimunah Ummul Mu'minin radliallahu 'anha, dia adalah bibinya, katanya: \"Maka aku berbaring di sisi bantal bagian lebar, sementara Nabi shallallahu 'alaihi wasallam dan keluarganya pada bagian panjang, lantas Rasulullah shallallahu 'alaihi wasallam tidur hingga pada tengah malam kurang sedikit atau lewat sedikit, Beliau shallallahu 'alaihi wasallam bangun lalu sambil duduk Beliau mengusap (sisa) tidur pada wajahnya dengan tangannya. Kemudian membaca sepuluh ayat terakhir dari Surah Ali 'Imran. Kemudian berdiri menuju tempat wudhu' lalu Beliau berwudhu' dengan sebaik-baiknya, kemudian shalat\". Berkata, Ibnu 'Abbas radliallahu 'anhu, \"Maka aku pun bangun dan aku lakukan seperti yang Beliau shallallahu 'alaihi wasallam lakukan. Lalu aku menuju kepadanya dan berdiri di sampingnya. Maka Beliau meletakkan tangan kanannya di kepalaku seraya memegang telingaku hingga menggeserku ke sebelah kanannya. Kemudian Beliau shalat dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian witir (ganjil) kemudian berbaring hingga datang kepadanya mu'adzin (mengumandangkan adzan). Maka Beliau shalat dua raka'at dengan ringan lalu keluar untuk menunaikan shalat Shubuh\"."},"1124":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا ابْنُ فُضَيْلٍ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا نُسَلِّمُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي الصَّلَاةِ فَيَرُدُّ عَلَيْنَا فَلَمَّا رَجَعْنَا مِنْ عِنْدِ النَّجَاشِيِّ سَلَّمْنَا عَلَيْهِ فَلَمْ يَرُدَّ عَلَيْنَا وَقَالَ إِنَّ فِي الصَّلَاةِ شُغْلًاحَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ السَّلُولِيُّ حَدَّثَنَا هُرَيْمُ بْنُ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Ibnu Fudhail] telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah radliallahu 'anhu] berkata: \"Kami pernah memberi salam kepada Nabi shallallahu 'alaihi wasallam ketika Beliau sedang shalat dan Beliau membalas salam kami. Ketika kami kembali dari (negeri) An-Najasyi kami memberi salam kembali kepada Beliau namun Beliau tidak membalas salam kami. Kemudian Beliau berkata: \"Sesungguhnya dalam shalat ada kesibukan\". Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Ishaq bin Manshur As-Saluliy] telah menceritakan kepada kami [Huraim bin Sufyan] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam yang seperti ini juga."},"1125":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا عِيسَى هُوَ ابْنُ يُونُسَ عَنْ إِسْمَاعِيلَ عَنْ الْحَارِثِ بْنِ شُبَيْلٍ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ قَالَ قَالَ لِي زَيْدُ بْنُ أَرْقَمَإِنْ كُنَّا لَنَتَكَلَّمُ فِي الصَّلَاةِ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَلِّمُ أَحَدُنَا صَاحِبَهُ بِحَاجَتِهِ حَتَّى نَزَلَتْ{ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى وَقُومُوا لِلَّهِ قَانِتِينَ }فَأُمِرْنَا بِالسُّكُوتِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami ['Isa] dia adalah putra Yunus dari [Isma'il] dari [Al Harits bin Syubail] dari [Abu 'Amru Asy Syaibaniy] berkata; [Zaid bin Arqam] berkata, kepadaku: \"Sungguh kami pernah berbicara ketika sedang shalat hingga ada seorang diantara kami yang berbicara dengan temannya tentang kebutuhannya sampai kemudian turun firman Allah Ta'ala (dalam surah Al Baqarah) \"Peliharalah seluruh shalat kalian dan shalat Al Wustha dan berdirilah (dalam shalat) untuk Allah dengan khusyu'\". (QS. Albaqarah, 238), Maka kami diperintah untuk diam\"."},"1126":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلِ بْنِ سَعْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصْلِحُ بَيْنَ بَنِي عَمْرِو بْنِ عَوْفِ بْنِ الْحَارِثِ وَحَانَتْ الصَّلَاةُ فَجَاءَ بِلَالٌ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا فَقَالَ حُبِسَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَؤُمُّ النَّاسَ قَالَ نَعَمْ إِنْ شِئْتُمْ فَأَقَامَ بِلَالٌ الصَّلَاةَ فَتَقَدَّمَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَصَلَّى فَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْشِي فِي الصُّفُوفِ يَشُقُّهَا شَقًّا حَتَّى قَامَ فِي الصَّفِّ الْأَوَّلِ فَأَخَذَ النَّاسُ بِالتَّصْفِيحِ قَالَ سَهْلٌ هَلْ تَدْرُونَ مَا التَّصْفِيحُ هُوَ التَّصْفِيقُ وَكَانَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ لَا يَلْتَفِتُ فِي صَلَاتِهِ فَلَمَّا أَكْثَرُوا الْتَفَتَ فَإِذَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّفِّ فَأَشَارَ إِلَيْهِ مَكَانَكَ فَرَفَعَ أَبُو بَكْرٍ يَدَيْهِ فَحَمِدَ اللَّهَ ثُمَّ رَجَعَ الْقَهْقَرَى وَرَاءَهُ وَتَقَدَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] telah menceritakan kepada kami ['Abdul 'Aziz bin Abu Hazim] dari [bapaknya] dari [Sahal bin Sa'ad radliallahu 'anhu] berkata; Suatu hari Rasulullah shallallahu 'alaihi wasallam keluar rumah untuk menyelesaikan masalah yang terjadi diantara suku Bani 'Amru bin 'Auf bin Al Harits kemudian tiba waktu shalat. Maka Bilal menemui Abu Bakar radliallahu 'anhuma seraya berkata: \"Nabi shallallahu 'alaihi wasallam sedang berhalangan, apakah engkau mau memimpin shalat berjama'ah? Dia (Abu Bakar) menjawab: \"Boleh, jika kalian menghenmdaki\". Maka Bilal membacakan iqamat shalat dan Abu Bakar maju memimpin shalat. Tak lama kemudian datang Nabi shallallahu 'alaihi wasallam berjalan menerobos tengah-tengan shaf membelah barisan hingga sampai di shaf pertama. Maka orang-orang memberi isyarat dengan bertepuk tangan. Sahal berkata: \"Apakah kalian tahu bahwa At-Tashfiih berbeda dengan At-Tashfiiq? Saat itu Abu Bakar tidak bereaksi dan tetap meneruskan shalatnya. Ketika suara tepukan semakin banyak, Abu Bakar berbalik dan ternyata dia melihat ada Nabi shallallahu 'alaihi wasallam dalam barisan. Maka Nabi shallallahu 'alaihi wasallam memberi isyarat kepadanya agar dia tetap pada posisinya. Abu Bakar mengangkat kedua tangannya lalu memuji Allah kemudian Abu Bakar mundur, lalu Nabi shallallahu 'alaihi wasallam maju untuk melanjutkan shalat. "},"1127":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عِيسَى حَدَّثَنَا أَبُو عَبْدِ الصَّمَدِ عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الصَّمَدِ حَدَّثَنَا حُصَيْنُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُقَالَ كُنَّا نَقُولُ التَّحِيَّةُ فِي الصَّلَاةِ وَنُسَمِّي وَيُسَلِّمُ بَعْضُنَا عَلَى بَعْضٍ فَسَمِعَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ قُولُوا التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ فَإِنَّكُمْ إِذَا فَعَلْتُمْ ذَلِكَ فَقَدْ سَلَّمْتُمْ عَلَى كُلِّ عَبْدٍ لِلَّهِ صَالِحٍ فِي السَّمَاءِ وَالْأَرْضِ","id":"Telah menceritakan kepada kami ['Amru bin 'Isa] telah menceritakan kepada kami [Abu 'Abdush Shamad 'Abdul 'Aziz bin 'Abdush Shamad] telah menceritakan kepada kami [Hushain bin 'Abdurrahman] dari [Abu Wa'il] dari ['Abdullah bin Mas'ud radliallahu 'anhu] berkata; \"Kami pernah membaca at-tahiyat dalam shalat, yang dalam tersebut kami menyebut nama dan memberi salam kepada beberapa diantara kami. Hal ini kemudian didengar oleh Rasulullah shallallahu 'alaihi wasallam hingga akhirnya Beliau bersabda: \"Bacalah: \"Attahiyyaatu lillahi washshalawaatu waththayyibaat. Assalaamu 'alaika ayyuhannabiyyu wa rahmatullohi wa barakaatuh. Assalaamu 'alainaa wa 'alaa 'ibaadillahish shaolihiin. Asyhadu allaa ilaaha illallah wa asyhadu anna Muhammadan 'abduhu wa rasuuluh\" \" (Segala penghormatan hanya milik Allah, juga segala pengagungan dan kebaikan. Semoga kesejahteraan terlimpahkan kepada engkau wahai Nabi dan juga rahmat dan berkahNya. Dan juga semoga kesejahteraan terlimpahkan kepada kami dan kepada hamba-hamba Allah yang shalih. Aku bersaksi tidak ada ilah yang berhaq disembah selain Allah dan aku bersaksi bahwa Muhammad adalah hamba dan utusanNya\"). Karena apabila kalian melakukan seperti ini, maka berarti kalian telah mengucapkan salam kepada seluruh hanba Allah yang shalih yang ada di langit dan bumi\"."},"1128":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ التَّسْبِيحُ لِلرِّجَالِ وَالتَّصْفِيقُ لِلنِّسَاءِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Az Zuhriy] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ucapan tasbih buat laki-laki sedangkan bertepuk tangan buat wanita\"."},"1129":{"ar":"حَدَّثَنَا يَحْيَى أَخْبَرَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّسْبِيحُ للرِّجَالِ وَالتَّصْفِيحُ لِلنِّسَاءِ","id":"Telah menceritakan kepada kami [Yahya] telah mengabarkan kepada kami [Waki'] dari [Sufyan] dari [Abu Hazim] dari [Sahal bin Sa'ad radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ucapan tasbih buat laki-laki sedangkan bertepuk tangan buat wanita\"."},"1130":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ يُونُسُ قَالَ الزُّهْرِيُّ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍأَنَّ الْمُسْلِمِينَ بَيْنَا هُمْ فِي الْفَجْرِ يَوْمَ الِاثْنَيْنِ وَأَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ يُصَلِّي بِهِمْ فَفَجِئَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ كَشَفَ سِتْرَ حُجْرَةِ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَنَظَرَ إِلَيْهِمْ وَهُمْ صُفُوفٌ فَتَبَسَّمَ يَضْحَكُ فَنَكَصَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ عَلَى عَقِبَيْهِ وَظَنَّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدُ أَنْ يَخْرُجَ إِلَى الصَّلَاةِ وَهَمَّ الْمُسْلِمُونَ أَنْ يَفْتَتِنُوا فِي صَلَاتِهِمْ فَرَحًا بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ رَأَوْهُ فَأَشَارَ بِيَدِهِ أَنْ أَتِمُّوا ثُمَّ دَخَلَ الْحُجْرَةَ وَأَرْخَى السِّتْرَ وَتُوُفِّيَ ذَلِكَ الْيَوْمَ","id":"Telah menceritakan kepada kami [Bisyir bin Muhammad] telah mengabarkan kepada kami ['Abdullah] berkata, [Yunus] berkata, [Az Zuhriy] telah mengabarkan kepada saya [Anas bin Malik Al Anshariy radliallahu 'anhu] bahwa; Ketika Kaum Muslimin sedang melaksanakan shalat Shubuh pada hari Senin yang dipimpin Abu Bakar radliallahu 'anhu, mereka dikejutkan oleh Nabi shallallahu 'alaihi wasallam yang menyingkap tabir kamar 'Aisyah radliallahu 'anha. Dari balik kamar itu Nabi shallallahu 'alaihi wasallam memandang mereka saat mereka berada dalam barisan shaf. Beliau tersenyum dan tertawa. Maka Abu Bakar berbalik untuk masuk kedalam barisan shaf karena menduga Nabi shallallahu 'alaihi wasallam akan keluar untuk shalat. Kaum Muslimin merasa terganggu dalam shalat mereka karena sangat gembiranya dapat melihat Nabi shallallahu 'alaihi wasallam. Ternyata Beliau shallallahu 'alaihi wasallam memberi isyarat dengan tangan Beliau agar mereka melanjutkan shalat. Kemudian Beliau masuk ke kamarnya dengan menutup tabir. Beliau shallallahu 'alaihi wasallam akhirnya wafat pada hari itu."},"1131":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ قَالَ حَدَّثَنِي مُعَيْقِيبٌأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الرَّجُلِ يُسَوِّي التُّرَابَ حَيْثُ يَسْجُدُ قَالَ إِنْ كُنْتَ فَاعِلًا فَوَاحِدَةً","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] berkata, telah menceritakan kepada saya [Mu'aiqib] bahwa Nabi shallallahu 'alaihi wasallam berkata tentang seseorang yang mengusapkan tanah ke mukanya ketika sedang sujud. Beliau bersabda: \"Jika kamu melakukannya, lakukanlah sekali saja\"."},"1132":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرٌ حَدَّثَنَا غَالِبٌ الْقَطَّانُ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا نُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شِدَّةِ الْحَرِّ فَإِذَا لَمْ يَسْتَطِعْ أَحَدُنَا أَنْ يُمَكِّنَ وَجْهَهُ مِنْ الْأَرْضِ بَسَطَ ثَوْبَهُ فَسَجَدَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyir] telah menceritakan kepada saya [Gholib Al Qaththan] dari [Bakar bin 'Abdullah] dari [Anas bin Malik radliallahu 'anhu] berkata: \"Kami pernah shalat bersama Nabi shallallahu 'alaihi wasallam saat udara sangat panas. Bila ada diantara kami yang tidak kuat meletakkan wajahnya di permukaan tanah, maka dia menghamparkan bajunya lalu sujud diatasnya."},"1133":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ عَنْ أَبِي النَّضْرِ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكُنْتُ أَمُدُّ رِجْلِي فِي قِبْلَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي فَإِذَا سَجَدَ غَمَزَنِي فَرَفَعْتُهَا فَإِذَا قَامَ مَدَدْتُهَا","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] telah menceritakan kepada kami [Malik] dari [Abu An-Nadhir] dari [Abu Salamah] dari ['Aisyah radliallahu 'anha] berkata: \"Aku menjulurkan kakiku pada arah qiblat Nabi shallallahu 'alaihi wasallam ketika Beliau sedang shalat. Bila Beliau sujud maka aku tarik kakiku dan aku angkat. Dan bila Beliau berdiri, kembali kakiku aku julurkan lagi\"."},"1134":{"ar":"حَدَّثَنَا مَحْمُودٌ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى صَلَاةً قَالَ إِنَّ الشَّيْطَانَ عَرَضَ لِي فَشَدَّ عَلَيَّ لِيَقْطَعَ الصَّلَاةَ عَلَيَّ فَأَمْكَنَنِي اللَّهُ مِنْهُ فَذَعَتُّهُ وَلَقَدْ هَمَمْتُ أَنْ أُوثِقَهُ إِلَى سَارِيَةٍ حَتَّى تُصْبِحُوا فَتَنْظُرُوا إِلَيْهِ فَذَكَرْتُ قَوْلَ سُلَيْمَانَ عَلَيْهِ السَّلَام رَبِّ{ هَبْ لِي مُلْكًا لَا يَنْبَغِي لِأَحَدٍ مِنْ بَعْدِي }فَرَدَّهُ اللَّهُ خَاسِيًاثُمَّ قَالَ النَّضْرُ بْنُ شُمَيْلٍ فَذَعَتُّهُ بِالذَّالِ أَيْ خَنَقْتُهُ وَفَدَعَّتُّهُ مِنْ قَوْلِ اللَّهِ{ يَوْمَ يُدَعُّونَ }أَيْ يُدْفَعُونَ وَالصَّوَابُ فَدَعَتُّهُ إِلَّا أَنَّهُ كَذَا قَالَ بِتَشْدِيدِ الْعَيْنِ وَالتَّاءِ","id":"Telah menceritakan kepada kami [Mahmud] telah mengabarkan kepada kami [Syababah] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Ziyad] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bahwasanya Beliau ketika selesai dari mengerjakan shalat berkata: \"Sesungguhnya setan menghampiriku lalu menggangguku untuk memutus shalatku tapi Allah memenangkan aku atasnya dan aku berkehendak untuk mengikatnya di salah satu tiang masjid sampai pagi hari sehingga kalian semuanya dapat melihatnya. Namun aku teringat ucapan Sulaiman Alaihissalam yang berdo'a: Ya Rabb, anugerahkanlah kepadaku kerajaan yang tidak akan dimiliki oleh seorangpun setelah aku\" telah memberitakan kepada kami (QS. Shad 35). Maka kemudian Allah mengusirnya\". Kemudian An Nadhir bin Syumail berkata: fadza'attuhu dengan huruf dzal, artinya; mencekiknya seperti firman Allah Ta'ala QS Ath-Thur 13 yang artinya digiring. Yang benar adalah fada'attuhu. Dengan ada tanda taydid pada huruf 'ain dan ta."},"1135":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا الْأَزْرَقُ بْنُ قَيْسٍ قَالَكُنَّا بِالْأَهْوَازِ نُقَاتِلُ الْحَرُورِيَّةَ فَبَيْنَا أَنَا عَلَى جُرُفِ نَهَرٍ إِذَا رَجُلٌ يُصَلِّي وَإِذَا لِجَامُ دَابَّتِهِ بِيَدِهِ فَجَعَلَتْ الدَّابَّةُ تُنَازِعُهُ وَجَعَلَ يَتْبَعُهَا قَالَ شُعْبَةُ هُوَ أَبُو بَرْزَةَ الْأَسْلَمِيُّ فَجَعَلَ رَجُلٌ مِنْ الْخَوَارِجِ يَقُولُ اللَّهُمَّ افْعَلْ بِهَذَا الشَّيْخِ فَلَمَّا انْصَرَفَ الشَّيْخُ قَالَ إِنِّي سَمِعْتُ قَوْلَكُمْ وَإِنِّي غَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِتَّ غَزَوَاتٍ أَوْ سَبْعَ غَزَوَاتٍ وَثَمَانِيَ وَشَهِدْتُ تَيْسِيرَهُ وَإِنِّي إِنْ كُنْتُ أَنْ أُرَاجِعَ مَعَ دَابَّتِي أَحَبُّ إِلَيَّ مِنْ أَنْ أَدَعَهَا تَرْجِعُ إِلَى مَأْلَفِهَا فَيَشُقُّ عَلَيَّ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Al Azraq bin Qais] berkata; \"Kami pernah berada di daerah Al Ahwaz ketika kami memerangi kelompok Haruriyyah. Ketika aku berada di tepian sungai ada seseorang yang sedang mengerjakan shalat sementara dia tetap memegang tali kekang tunggangannya. Maka hewan tunggangannya mengganggunya dengan bergerak kesana kemari hingga ia mengikuti kemana gerak hewannya itu\". Berkata, Syu'bah dia adalah [Abu Barzah Al Aslamiy]; Tiba-tiba seorang dari Khawarij berkata: \"Masya Allah, apa yang dilakukan orang ini?\" Ketika orang tadi selesai dari shalatnya, dia berkata; \"Sungguh aku mendengar percakapan kalian. Sungguh aku sudah pernah ikut berperang bersama Rasulullah shallallahu 'alaihi wasallam enam, tujuh atau hingga delapan kali peperangan dan aku menyaksikan kemudahan-kemudahan yang Beliau ajarkan. Bagiku mengikuti hewan tungganganku itu lebih aku sukai daripada aku memaksa kembali ke padang gembalaan tempat hewan itu biasa berkeliaraan, yang nanti pasti lebih menyulitkan aku\"."},"1136":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ قَالَ قَا��َتْ عَائِشَةُخَسَفَتْ الشَّمْسُ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَ سُورَةً طَوِيلَةً ثُمَّ رَكَعَ فَأَطَالَ ثُمَّ رَفَعَ رَأْسَهُ ثُمَّ اسْتَفْتَحَ بِسُورَةٍ أُخْرَى ثُمَّ رَكَعَ حَتَّى قَضَاهَا وَسَجَدَ ثُمَّ فَعَلَ ذَلِكَ فِي الثَّانِيَةِ ثُمَّ قَالَ إِنَّهُمَا آيَتَانِ مِنْ آيَاتِ اللَّهِ فَإِذَا رَأَيْتُمْ ذَلِكَ فَصَلُّوا حَتَّى يُفْرَجَ عَنْكُمْ لَقَدْ رَأَيْتُ فِي مَقَامِي هَذَا كُلَّ شَيْءٍ وُعِدْتُهُ حَتَّى لَقَدْ رَأَيْتُ أُرِيدُ أَنْ آخُذَ قِطْفًا مِنْ الْجَنَّةِ حِينَ رَأَيْتُمُونِي جَعَلْتُ أَتَقَدَّمُ وَلَقَدْ رَأَيْتُ جَهَنَّمَ يَحْطِمُ بَعْضُهَا بَعْضًا حِينَ رَأَيْتُمُونِي تَأَخَّرْتُ وَرَأَيْتُ فِيهَا عَمْرَو بْنَ لُحَيٍّ وَهُوَ الَّذِي سَيَّبَ السَّوَائِبَ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhriy] dari ['Urwah] berkata; Berkata, ['Aisyah radliallahu 'anha]: \"Ketika terjadi gerhana matahari Nabi shallallahu 'alaihi wasallam berdiri melaksanakan shalat, Beliau membaca bacaan yang panjang lalu Beliau ruku' dengan ruku' yang panjang lalu mengangkat kepala lalu memulai membaca surat yang lain, lalu ruku' kembali sampai menyempurnakannya dan kemudian sujud. Kemudian Beliau melakukan seperti itu lagi pada raka'at kedua kemudian setelah selesai Beliau bersabda: \"Keduanya adalah dua tanda dari tanda-tanda kebesaran Allah. Jika kalian melihat (gerhana) nya, maka dirikanlah shalat hingga menghilang gerhana itu dari kalian. Sungguh aku telah melihat segala sesuatu yang telah dijanjikan bagiku dengannya dari tempatku berdiri ini, sehingga aku ingin mengambil setandan anggur di dalam surga, itu terlihat saat kalian melihatku aku ingin bergerak ke depan. Dan sungguh aku melihat jahanam yang apinya saling membakar satu sama lain saat kalian melihatku aku bergerak mundur dan aku melihat didalamnya ada 'Amru bin Luhai dan dialah yang pertama-tama merumuskan saibah\". "},"1137":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى نُخَامَةً فِي قِبْلَةِ الْمَسْجِدِ فَتَغَيَّظَ عَلَى أَهْلِ الْمَسْجِدِ وَقَالَ إِنَّ اللَّهَ قِبَلَ أَحَدِكُمْ فَإِذَا كَانَ فِي صَلَاتِهِ فَلَا يَبْزُقَنَّ أَوْ قَالَ لَا يَتَنَخَّمَنَّ ثُمَّ نَزَلَ فَحَتَّهَا بِيَدِهِوَقَالَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا إِذَا بَزَقَ أَحَدُكُمْ فَلْيَبْزُقْ عَلَى يَسَارِهِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] bahwasanya Nabi shallallahu 'alaihi wasallam melihat ludah pada arah qiblat masjid. Spontan Beliau menampakkan kemarahannya kepada jama'ah masjid seraya bersabda: \"Sesungguhnya Allah berada dihadapan setiap orang dari kalian (saat shalat). Maka bila sedang shalat janganlah seseorang meludah\" atau sabdanya: \"janganlah dia membuang dahak\". Kemudian Beliau turun lalu menggosok ludah tersebut dengan tangannya. Dan berkata, Ibnu'Umar radliallahu 'anhuma: \"Jika seorang dari kalian meludah, maka meludahlah kearah kirinya\"."},"1138":{"ar":"حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ فِي الصَّلَاةِ فَإِنَّهُ يُنَاجِي رَبَّهُ فَلَا يَبْزُقَنَّ بَيْنَ يَدَيْهِ وَلَا عَنْ يَمِينِهِ وَلَكِنْ عَنْ شِمَالِهِ تَحْتَ قَدَمِهِ الْيُسْرَى","id":"Telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] berkata; Aku mendengar [Qatadah] dari [Anas bin Malik radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seseorang sedang berdiri shalat, sesungguhnya dia sedang berhadapan dengan Rabnya, maka janganlah dia meludah ke arah depannya dan jangan pula ke arah kanannya tetapi lakukanlah ke arah kirinya dibawah kaki (kirinya) \"."},"1139":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّاسُ يُصَلُّونَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمْ عَاقِدُو أُزْرِهِمْ مِنْ الصِّغَرِ عَلَى رِقَابِهِمْ فَقِيلَ لِلنِّسَاءِ لَا تَرْفَعْنَ رُءُوسَكُنَّ حَتَّى يَسْتَوِيَ الرِّجَالُ جُلُوسًا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Abu Hazim] dari [Sahal bin Sa'ad radliallahu 'anhu] berkata: \"Orang-orang shalat bersama Nabi shallallahu 'alaihi wasallam dengan mengikatkan kain mereka di leher-leher karena kainnya kecil. Dan dikatakan kepada Kaum Wanita: \"Janganlah kalian mengangkat kepala kalian hingga para laki-laki telah duduk\"."},"1140":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَكُنْتُ أُسَلِّمُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي الصَّلَاةِ فَيَرُدُّ عَلَيَّ فَلَمَّا رَجَعْنَا سَلَّمْتُ عَلَيْهِ فَلَمْ يَرُدَّ عَلَيَّ وَقَالَ إِنَّ فِي الصَّلَاةِ لَشُغْلًا","id":"Telah menceritakan kepada kami ['Abdullah bin Abu Syaibah] telah menceritakan kepada kami [Ibnu Fudhail] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah radliallahu 'anhu] berkata: \"Aku pernah memberi salam kepada Nabi shallallahu 'alaihi wasallam ketika Beliau sedang shalat maka Beliau membalas salamku. Ketika kami kembali (dari negeri An-Najasyi), aku memberi salam kembali kepada Beliau namun Beliau tidak membalas salamku. Kemudian Beliau berkata: \"Sesungguhnya dalam shalat terdapat kesibukan\"."},"1141":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا كَثِيرُ بْنُ شِنْظِيرٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَاجَةٍ لَهُ فَانْطَلَقْتُ ثُمَّ رَجَعْتُ وَقَدْ قَضَيْتُهَا فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمْتُ عَلَيْهِ فَلَمْ يَرُدَّ عَلَيَّ فَوَقَعَ فِي قَلْبِي مَا اللَّهُ أَعْلَمُ بِهِ فَقُلْتُ فِي نَفْسِي لَعَلَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَدَ عَلَيَّ أَنِّي أَبْطَأْتُ عَلَيْهِ ثُمَّ سَلَّمْتُ عَلَيْهِ فَلَمْ يَرُدَّ عَلَيَّ فَوَقَعَ فِي قَلْبِي أَشَدُّ مِنْ الْمَرَّةِ الْأُولَى ثُمَّ سَلَّمْتُ عَلَيْهِ فَرَدَّ عَلَيَّ فَقَالَ إِنَّمَا مَنَعَنِي أَنْ أَرُدَّ عَلَيْكَ أَنِّي كُنْتُ أُصَلِّي وَكَانَ عَلَى رَاحِلَتِهِ مُتَوَجِّهًا إِلَى غَيْرِ الْقِبْلَةِ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami [Katsir bin Syinzhir] dari ['Atha' bin Abu Rabah] dari [Jabir bin 'Abdullah radliallahu 'anhua] berkata; Rasulullah shallallahu 'alaihi wasallam mengutusku untuk menyelesaikan keperluan Beliau. Maka aku berangkat kemudian kembali setelah menuntaskan tugasku itu, lalu aku menemui Nabi shallallahu 'alaihi wasallam. Aku memberi salam kepada Beliau namun Beliau tidak membalas salamku. Kejadian itu menimbulkan kegusaran dalam hatiku yang hanya Allah sajalah yang lebih mengetahuinya. Kemudian aku berkata dalam hatiku, barangkali Rasulullah shallallahu 'alaihi wasallam menganggap aku terlambat menunaikan tugas dari Beliau. Kemudian aku memberi salam kembali dan lagi-lagi Beliau tidak membalasnya. Timbul lagi kegusaran dalam hatiku yang lebih besar dari yang pertama. Kemudian aku memberi salam lagi, lalu Beliau membalasnya seraya berkata: \"Sesungguhnya yang menghalangiku buat menjawab salammu adalah karena aku sedang melaksanakan shalat\". Saat itu Beliau sedang berada diatas hewan tunggangannya yang tidak menghadap ke arah qiblat."},"1142":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَبَلَغَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ بَنِي عَمْرِو بْنِ عَوْفٍ بِقُبَاءٍ كَانَ بَيْنَهُمْ شَيْءٌ فَخَرَجَ يُصْلِحُ بَيْنَهُمْ فِي أُنَاسٍ مِنْ أَصْحَابِهِ فَحُبِسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَانَتْ الصَّلَاةُ فَجَاءَ بِلَالٌ إِلَى أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا فَقَالَ يَا أَبَا بَكْرٍ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ حُبِسَ وَقَدْ حَانَتْ الصَّلَاةُ فَهَلْ لَكَ أَنْ تَؤُمَّ النَّاسَ قَالَ نَعَمْ إِنْ شِئْتَ فَأَقَامَ بِلَالٌ الصَّلَاةَ وَتَقَدَّمَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَكَبَّرَ لِلنَّاسِ وَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْشِي فِي الصُّفُوفِ يَشُقُّهَا شَقًّا حَتَّى قَامَ فِي الصَّفِّ فَأَخَذَ النَّاسُ فِي التَّصْفِيحِ قَالَ سَهْلٌ التَّصْفِيحُ هُوَ التَّصْفِيقُ قَالَ وَكَانَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ لَا يَلْتَفِتُ فِي صَلَاتِهِ فَلَمَّا أَكْثَرَ النَّاسُ الْتَفَتَ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَشَارَ إِلَيْهِ يَأْمُرُهُ أَنْ يُصَلِّيَ فَرَفَعَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ يَدَهُ فَحَمِدَ اللَّهَ ثُمَّ رَجَعَ الْقَهْقَرَى وَرَاءَهُ حَتَّى قَامَ فِي الصَّفِّ وَتَقَدَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى لِلنَّاسِ فَلَمَّا فَرَغَ أَقْبَلَ عَلَى النَّاسِ فَقَالَ يَا أَيُّهَا النَّاسُ مَا لَكُمْ حِينَ نَابَكُمْ شَيْءٌ فِي الصَّلَاةِ أَخَذْتُمْ بِالتَّصْفِيحِ إِنَّمَا التَّصْفِيحُ لِلنِّسَاءِ مَنْ نَابَهُ شَيْءٌ فِي صَلَاتِهِ فَلْيَقُلْ سُبْحَانَ اللَّهِ ثُمَّ الْتَفَتَ إِلَى أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَقَالَ يَا أَبَا بَكْرٍ مَا مَنَعَكَ أَنْ تُصَلِّيَ لِلنَّاسِ حِينَ أَشَرْتُ إِلَيْكَ قَالَ أَبُو بَكْرٍ مَا كَانَ يَنْبَغِي لِابْنِ أَبِي قُحَافَةَ أَنْ يُصَلِّيَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami ['Abdul 'Aziz] dari [Abu Hazim] dari [Sahal bin Sa'ad radliallahu 'anhu] berkata; Telah sampai kabar kepada Rasulullah shallallahu 'alaihi wasallam bahwa pada suku Bani 'Amru bin 'Auf bin Al Harits di Quba' timbul masalah diantara mereka. Maka Beliau bersama para sahabat Beliau berangkat kesana untuk menyelesaikan masalah. Ternyata Rasulullah shallallahu 'alaihi wasallam tertahan lama disana sedangkan waktu shalat sudah masuk. Maka Bilal menemui Abu Bakar radliallahu 'anhuma seraya berkata: \"Wahai Abu Bakar, Rasulullah shallallahu 'alaihi wasallam terlambat hadir sedangkan waktu shalat sudah masuk, apakah engkau bersedia memimpin shalat berjama'ah? Dia (Abu Bakar) menjawab: \"Ya bersedia, jika kamu menghendaki\". Maka Bilal membacakan iqamat shalat dan Abu Bakar maju dan memulai takbir memimpin shalat bersama orang banyak. Tak lama kemudian datang Nabi shallallahu 'alaihi wasallam berjalan di tengah-tengan shaf membelah barisan hingga sampai di shaf. Maka orang-orang memberi isyarat dengan bertepuk tangan. Sahal berkata: \"At-Tashfiih sama maksudnya dengan At-Tashfiiq. Dia berkata: \"Saat itu Abu Bakar tidak bereaksi dalam shalatnya. Ketika suara tepukan semakin nyaring terdengar, Abu Bakar baru berbalik dan ternyata ada Rasulullah shallallahu 'alaihi wasallam. Maka Nabi memberi isyarat kepadanya agar tetap meneruskan shalatnya. Lalu Abu Bakar mengangkat kedua tangannya lalu memuji Allah kemudian dia mundur ke belakang dan berdiri di barisan, lalu Rasulullah shallallahu 'alaihi wasallam maju untuk memimpin shalat berjama'ah. Setelah selesai Nabi berbalik menghadap jama'ah lalu bersabda: \"Wahai sekalian manusia, mengapa kalian ketika mendapatkan sesuatu dalam shalat, kalian melakukannya dengan bertepuk tangan? Sesungguhnya bertepuk tangan itu adalah isyarat yang dilakukan bagi kaum wanita. Maka siapa yang mendapatkan sesuatu yang keliru dalam shalat hendaklah mengucapkan Subhaanallah\". Kemudian Beliau memandang ke arah Abu Bakar radliallahu 'anhu seraya berkata: \"Wahai Abu Bakar, apa yang menghalangimu untuk melanjutkan memimpin shalat berjama'ah bersama orang banyak ketika aku sudah memberi isyarat kepadamu (agar meneruskannya)?\" Abu Bakar menjawab: \"Tidak patut bagi Ibnu Abu Quhafah memimpin shalat di hadapan Rasulullah shallallahu 'alaihi wasallam \"."},"1143":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَنُهِيَ عَنْ الْخَصْرِ فِي الصَّلَاةِوَقَالَ هِشَامٌ وَأَبُو هِلَالٍ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Muhammad] dari [Abu Hurairah radliallahu 'anhu] berkata: \"Dilarang bertolak pinggang dalam shalat\". Dan berkata, [Hisyam] dan [Abu Hilal] dari [Ibnu Sirin] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam."},"1144":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى حَدَّثَنَا هِشَامٌ حَدَّثَنَا مُحَمَّدٌ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُصَلِّيَ الرَّجُلُ مُخْتَصِرًا","id":"Telah menceritakan kepada kami ['Amru bin 'Ali] telah menceritakan kepada kami [Yahya] dari [Hisyam] telah menceritakan kepada kami [Muhammad] dari [Abu Hurairah radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam melarang seseorang shalat dengan bertolak pinggang\". "},"1145":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ حَدَّثَنَا رَوْحٌ حَدَّثَنَا عُمَرُ هُوَ ابْنُ سَعِيدٍ قَالَ أَخْبَرَنِي ابْنُ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ بْنِ الْحَارِثِ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ فَلَمَّا سَلَّمَ قَامَ سَرِيعًا دَخَلَ عَلَى بَعْضِ نِسَائِهِ ثُمَّ خَرَجَ وَرَأَى مَا فِي وُجُوهِ الْقَوْمِ مِنْ تَعَجُّبِهِمْ لِسُرْعَتِهِ فَقَالَ ذَكَرْتُ وَأَنَا فِي الصَّلَاةِ تِبْرًا عِنْدَنَا فَكَرِهْتُ أَنْ يُمْسِيَ أَوْ يَبِيتَ عِنْدَنَا فَأَمَرْتُ بِقِسْمَتِهِ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami ['Umar] -dia adalah anak dari Sa'id- berkata, telah mengabarkan kepada saya [Ibnu Abu Mulaikah] dari ['Uqbah bin Al Harits radliallahu 'anhu] berkata: \"Aku pernah shalat 'Ashar bersama Nabi shallallahu 'alaihi wasallam. Setelah memberi salam, tiba-tiba Beliau berdiri dengan tergesa-gesa dan menemui sebagian isteri-isteri Beliau. Kemudian setelah itu Beliau keluar kembali dan Beliau melihat bahwa orang-orang semua keheranan dengan ketergesaan Beliau. Maka akhirnya Beliau bersabda: \"Aku teringat ketika aku shalat tadi tentang sebatang emas yang ada pada kami. Aku tidak suka bila benda itu berada pada kami sampai sore atau bermalam, maka aku perintahkan untuk dibagi-bagikan\"."},"1146":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ جَعْفَرٍ عَنْ الْأَعْرَجِ قَالَ قَالَ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُذِّنَ بِالصَّلَاةِ أَدْبَرَ الشَّيْطَانُ لَهُ ضُرَاطٌ حَتَّى لَا يَسْمَعَ التَّأْذِينَ فَإِذَا سَكَتَ الْمُؤَذِّنُ أَقْبَلَ فَإِذَا ثُوِّبَ أَدْبَرَ فَإِذَا سَكَتَ أَقْبَلَ فَلَا يَزَالُ بِالْمَرْءِ يَقُولُ لَهُ اذْكُرْ مَا لَمْ يَكُنْ يَذْكُرُ حَتَّى لَا يَدْرِيَ كَمْ صَلَّىقَالَ أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ إِذَا فَعَلَ أَحَدُكُمْ ذَلِكَ فَلْيَسْجُدْ سَجْدَتَيْنِ وَهُوَ قَاعِدٌ وَسَمِعَهُ أَبُو سَلَمَةَ مِنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Ja'far] dari [Al A'raj] berkata; Berkata, [Abu Hurairah radliallahu 'anhu]; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika panggilan shalat (adzan) dikumandangkan maka setan lari sambil mengeluarkan kentut hingga ia tidak mendengar suara adzan tersebut. Apabila panggilan adzan telah selesai maka setan kembali. Dan bila iqamat dikumandangkan setan kembali berlari dan jika iqamat telah selesai dia kembali lagi hingga senantiasa dia mengganggu seseorang seraya berkata; ingatlah sesuatu, yang semestinya harus tidak diingat, yang pada akhirnya orang itu tidak menyadari berapa raka'at yang sudah dia laksanakan dalam shalatnya\". Berkata, Abu Salamah bin 'Abdurrahman; \"Bila seseorang melakukan hal seperti itu, maka hendaklah dia sujud dua kali dalam posisi duduk\". Dan [Abu Salamah] mendengar keterangan ini dari [Abu Hurairah radliallahu 'anhu]."},"1147":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ أَخْبَرَنِي ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ قَالَ قَالَ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُيَقُولُ النَّاسُ أَكْثَرَ أَبُو هُرَيْرَةَ فَلَقِيتُ رَجُلًا فَقُلْتُ بِمَا قَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَارِحَةَ فِي الْعَتَمَةِ فَقَالَ لَا أَدْرِي فَقُلْتُ لَمْ تَشْهَدْهَا قَالَ بَلَى قُلْتُ لَكِنْ أَنَا أَدْرِي قَرَأَ سُورَةَ كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami ['Utsman bin 'Umar] berkata, telah mengabarkan kepada saya [Ibnu Abu Dza'bi] dari [Sa'id Al Maqburiy] berkata; [Abu Hurairah radliallahu 'anhu] berkata: \"Orang-orang mengatakan bahwa Abu Hurairah banyak menyampaikan hadits (dari Rasulullah shallallahu 'alaihi wasallam). Maka aku temui seseorang lalu aku bertanya kepadanya; Surat apa yang dibaca oleh Rasulullah shallallahu 'alaihi wasallam dalam shalat 'Isya' tadi\". Orang itu menjawab: \"Aku tak tahu\". Aku tanyakan lagi: \"Bukankah anda ikut shalat? Orang itu menjawab: \"Ya benar\". Maka aku katakan: \"Aku tahu Beliau membaca surah ini dan ini\"."},"1148":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكُ بْنُ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ عَبْدِ اللَّهِ ابْنِ بُحَيْنَةَ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَصَلَّى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ مِنْ بَعْضِ الصَّلَوَاتِ ثُمَّ قَامَ فَلَمْ يَجْلِسْ فَقَامَ النَّاسُ مَعَهُ فَلَمَّا قَضَى صَلَاتَهُ وَنَظَرْنَا تَسْلِيمَهُ كَبَّرَ قَبْلَ التَّسْلِيمِ فَسَجَدَ سَجْدَتَيْنِ وَهُوَ جَالِسٌ ثُمَّ سَلَّمَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik bin Anas] dari [Ibnu Syihab] dari ['Abdurrahman Al A'raj] dari ['Abdullah Ibnu Buhainah radliallahu 'anhu] bahwa dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah shalat dua raka'at diantara shalat Beliau, lalu Beliau berdiri dan tidak duduk, Maka orang-orang ikut berdiri mengikuti Beliau. Ketika Beliau menyelesaikan shalatnya (empat raka'at) sedangkan kami sedang menunggu-nunggu Beliau memberi salam, Beliau bahkan bertakbir sebelum memberi salam kemudian sujud dua kali dalam posisi duduk lalu baru memberi salam\"."},"1149":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ عَبْدِ اللَّهِ ابْنِ بُحَيْنَةَ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ مِنْ اثْنَتَيْنِ مِنْ الظُّهْرِ لَمْ يَجْلِسْ بَيْنَهُمَا فَلَمَّا قَضَى صَلَاتَهُ سَجَدَ سَجْدَتَيْنِ ثُمَّ سَلَّمَ بَعْدَ ذَلِكَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Yahya bin Sa'id] dari ['Abdurrahman Al A'raj] dari ['Abdullah Ibnu Buhainah radliallahu 'anhu] bahwa dia berkata; \"Rasulullah shallallahu 'alaihi wasallam berdiri dari dua raka'at shalat Zhuhur dan tidak duduk diantaranya. Setelah Beliau menyelesaikan shalatnya, Beliau sujud dua kali lalu memberi salam setelah itu\"."},"1150":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ خَمْسًا فَقِيلَ لَهُ أَزِيدَ فِي الصَّلَاةِ فَقَالَ وَمَا ذَاكَ قَالَ صَلَّيْتَ خَمْسًا فَسَجَدَ سَجْدَتَيْنِ بَعْدَ مَا سَلَّمَ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu.bah] dari [Al Hakam] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat Zhuhur lima raka'at. Beliau ditegur: \"Apakah ada tambahan raka'at shalat?\" Beliau menjawab: \"Memangnya apa yang terjadi?\" Dia ('Abdullah) berkata: \"Anda kerjakan shalat lima raka'at\". Maka Beliau sujud dua kali setelah memberi salam\"."},"1151":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّى بِنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ أَوْ الْعَصْرَ فَسَلَّمَ فَقَالَ لَهُ ذُو الْيَدَيْنِ الصَّلَاةُ يَا رَسُولَ اللَّهِ أَنَقَصَتْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ أَحَقٌّ مَا يَقُولُ قَالُوا نَعَمْ فَصَلَّى رَكْعَتَيْنِ أُخْرَيَيْنِ ثُمَّ سَجَدَ سَجْدَتَيْنِ قَالَ سَعْدٌ وَرَأَيْتُ عُرْوَةَ بْنَ الزُّبَيْرِ صَلَّى مِنْ الْمَغْرِبِ رَكْعَتَيْنِ فَسَلَّمَ وَتَكَلَّمَ ثُمَّ صَلَّى مَا بَقِيَ وَسَجَدَ سَجْدَتَيْنِ وَقَالَ هَكَذَا فَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Sa'ad bin Ibrahim] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam shalat Zhuhur atau 'Ashar bersama kami, lalu Beliau memberi salam. Kemudian Dzul Yadain berkata kepada Beliau: \"Wahai Rasulullah, apakah shalat dikurangi (raka'atnya)?\" Maka Nabi shallallahu 'alaihi wasallam berkata kepada para sahabatnya: \"Benarkah yang dikatakannya?\" Orang-orang menjawab: \"Benar\". Maka Beliau menyempurnakan dua raka'at yang tertinggal lalu sujud dua kali\". Berkata, Abu Hurairah radliallahu 'anhu: \"Begitulah yang dikerjakan oleh Nabi shallallahu 'alaihi wasallam \"."},"1152":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكُ بْنُ أَنَسٍ عَنْ أَيُّوبَ بْنِ أَبِي تَمِيمَةَ السَّخْتِيَانِيِّ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصَرَفَ مِنْ اثْنَتَيْنِ فَقَالَ لَهُ ذُو الْيَدَيْنِ أَقَصُرَتْ الصَّلَاةُ أَمْ نَسِيتَ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَدَقَ ذُو الْيَدَيْنِ فَقَالَ النَّاسُ نَعَمْ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى اثْنَتَيْنِ أُخْرَيَيْنِ ثُمَّ سَلَّمَ ثُمَّ كَبَّرَ فَسَجَدَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَ ثُمَّ رَفَعَحَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ سَلَمَةَ بْنِ عَلْقَمَةَ قَالَ قُلْتُ لِمُحَمَّدٍ فِي سَجْدَتَيْ السَّهْوِ تَشَهُّدٌ قَالَ لَيْسَ فِي حَدِيثِ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik bin Anas] dari [Ayyub bin Abu Tamimah As-Sakhtiyaniy] dari [Muhammad bin Sirin] dari [Abu Hurairah radliallahu 'anhu], ketika Rasulullah menyelesaikan shalatnya yang baru dua raka'at, Dzul Yadain berkata kepada Beliau: \"Apakah shalat diqashar atau anda lupa, wahai Rasulullah?\" Maka Rasulullah shallallahu 'alaihi wasallam berkata: \"Apakah benar yang dikatakan Dzul Yadain?\" Orang-orang menjawab: \"Benar\". Maka Rasulullah shallallahu 'alaihi wasallam bediri dan mengerjakan shalat dua raka'at yang kurang tadi kemudian memberi salam. Kemudian Beliau bertakbir lalu sujud seperti sujudnya (yang biasa) atau lebih lama lagi kemudian mengangkat kepalanya\". Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad] dari [Salamah bin 'Alqamah] berkata; \"Aku bertanya kepada [Muhammad] tentang dua sujud sahwi apakah ada tasyahudnya? Dia menjawab: \"Tidak ada menurut hadits Abu Hurairah radliallahu 'anhu \"."},"1153":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا يَزِيدُ بْنُ إِبْرَاهِيمَ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِحْدَى صَلَاتَيْ الْعَشِيِّ قَالَ مُحَمَّدٌ وَأَكْثَرُ ظَنِّي الْعَصْرَ رَكْعَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ قَامَ إِلَى خَشَبَةٍ فِي مُقَدَّمِ الْمَسْجِدِ فَوَضَعَ يَدَهُ عَلَيْهَا وَفِيهِمْ أَبُو بَكْرٍ وَعُمَرُ رَضِيَ اللَّهُ عَنْهُمَا فَهَابَا أَنْ يُكَلِّمَاهُ وَخَرَجَ سَرَعَانُ النَّاسِ فَقَالُوا أَقَصُرَتْ الصَّلَاةُ وَرَجُلٌ يَدْعُوهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذُو الْيَدَيْنِ فَقَالَ أَنَسِيتَ أَمْ قَصُرَتْ فَقَالَ لَمْ أَنْسَ وَلَمْ تُقْصَرْ قَالَ بَلَى قَدْ نَسِيتَ فَصَلَّى رَكْعَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ كَبَّرَ فَسَجَدَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَ ثُمَّ رَفَعَ رَأْسَهُ فَكَبَّرَ ثُمَّ وَضَعَ رَأْسَهُ فَكَبَّرَ فَسَجَدَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَ ثُمَّ رَفَعَ رَأْسَهُ وَكَبَّرَ","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] telah menceritakan kepada kami [Yazid bin Ibrahim] dari [Muhammad] dari [Abu Hurairah radliallahu 'anhu] berkata: \"Rasulullah shalat bersama kami dalam suatu shalat malam, Berkata Muhammad; Kecenderungan dugaanku adalah shalat 'Ashar, yaitu sebanyak dua raka'at lalu memberi salam. Setelah itu Beliau mendatangi kayu yang tergeletak di masjid, Beliau berbaring dengan meletakkan kedua tangannya pada kayu tersebut. Diantara mereka yang ikut shalat ada Abu Bakar dan 'Umar radliallahu 'anhuma. Namun keduanya sungkan untuk berbicara dengan Beliau lalu keluar mendahului orang banyak. Sementara orang-orang berkata; \"Shalat diringkas (qashar) \". Tiba-tiba ada seorang yang dipanggil oleh Nabi shallallahu 'alaihi wasallam dengan panggilan Dzul Yadain, dan ia berkata: \"Apakah anda lupa atau shalat diqashar?\" Beliau berkata: \"Aku tidak lupa dan shalat juga tidak diqashar\". Beliau berkata: \"Aku tidak lupa dan juga shalat tidak diqashar!\". (Dzul Yadain) berkata: \"Benar, sebenarnya anda telah lupa\". Maka Beliau shalat dua raka'at kemudian memberi salam. Kemudian Beliau bertakbir lalu sujud seperti sujudnya (yang biasa) atau lebih lama lagi kemudian mengangkat kepalanya lalu bertakbir lagi kemudian meletakkan kepalanya lalu bertakbir kemudian sujud seperti sujudnya atau lebih lama lagi, kemudian mengangkat kepalanya dan takbir."},"1154":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ ابْنِ شِهَابٍ عَنْ الْأَعْرَجِ عَنْ عَبْدِ اللَّهِ ابْنِ بُحَيْنَةَ الْأَسْدِيِّ حَلِيفِ بَنِي عَبْدِ الْمُطَّلِبِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فِي صَلَاةِ الظُّهْرِ وَعَلَيْهِ جُلُوسٌ فَلَمَّا أَتَمَّ صَلَاتَهُ سَجَدَ سَجْدَتَيْنِ فَكَبَّرَ فِي كُلّ�� سَجْدَةٍ وَهُوَ جَالِسٌ قَبْلَ أَنْ يُسَلِّمَ وَسَجَدَهُمَا النَّاسُ مَعَهُ مَكَانَ مَا نَسِيَ مِنْ الْجُلُوسِتَابَعَهُ ابْنُ جُرَيْجٍ عَنْ ابْنِ شِهَابٍ فِي التَّكْبِيرِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Ibnu Syihab] dari [Al A'raj] dari ['Abdullah Ibnu Buhainah Al Asadiy] sekutunya suku 'Abdul Muthalib bahwa Rasulullah shallallahu 'alaihi wasallam mendirikan shalat Zhuhur namun tidak melakukan duduk (tasyahud awal). Setelah Beliau menyempurnakan shalatnya, Beliau sujud dua kali, dan Beliau bertakbir pada setiap akan sujud dalam posisi duduk sebelum memberi salam. Maka orang-orang mengikuti sujud bersama Beliau sebagai ganti yang terlupa dari duduk (tasyahud awal). Hadits ini diperkuat oleh [Ibnu Juraij] dari [Ibnu Syihab] dalam masalah \"takbir (dalam sujud sahwi) \"."},"1155":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا هِشَامُ بْنُ أَبِي عَبْدِ اللَّهِ الدَّسْتَوَائِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا نُودِيَ بِالصَّلَاةِ أَدْبَرَ الشَّيْطَانُ وَلَهُ ضُرَاطٌ حَتَّى لَا يَسْمَعَ الْأَذَانَ فَإِذَا قُضِيَ الْأَذَانُ أَقْبَلَ فَإِذَا ثُوِّبَ بِهَا أَدْبَرَ فَإِذَا قُضِيَ التَّثْوِيبُ أَقْبَلَ حَتَّى يَخْطِرَ بَيْنَ الْمَرْءِ وَنَفْسِهِ يَقُولُ اذْكُرْ كَذَا وَكَذَا مَا لَمْ يَكُنْ يَذْكُرُ حَتَّى يَظَلَّ الرَّجُلُ إِنْ يَدْرِي كَمْ صَلَّى فَإِذَا لَمْ يَدْرِ أَحَدُكُمْ كَمْ صَلَّى ثَلَاثًا أَوْ أَرْبَعًا فَلْيَسْجُدْ سَجْدَتَيْنِ وَهُوَ جَالِسٌ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadhalah] telah menceritakan kepada kami [Hisyam bin Abu 'Abdullah ad-Dastawaniy] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika panggilan shalat (adzan) dikumandangkan, setan lari sambil mengeluarkan kentut hingga ia tidak mendengar suara adzan tersebut. Apabila panggilan adzan telah selesai maka setan kembali. Dan bila iqamat dikumandangkan setan kembali berlari dan jika iqamat telah selesai dia kembali lagi hingga untuk mengganggu hatinya seseorang seraya berkata; ingatlah ini dan itu, yang semestinya tidak diingat sehingga seseorang membayanngkannya hingga akhirnya orang itu tidak tahu berapa raka'at shalat yang sudah dia laksanakan. Oleh karena itu bila seorang dari kalian tidak mengetahui berapa raka'at dari shalat yang sudah dikerjakannya, apakah tiga atau empat raka'at maka hendaklah dia melakukan sujud dua kali dalam posisi duduk\"."},"1156":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَحَدَكُمْ إِذَا قَامَ يُصَلِّي جَاءَ الشَّيْطَانُ فَلَبَسَ عَلَيْهِ حَتَّى لَا يَدْرِيَ كَمْ صَلَّى فَإِذَا وَجَدَ ذَلِكَ أَحَدُكُمْ فَلْيَسْجُدْ سَجْدَتَيْنِ وَهُوَ جَالِسٌ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya bila seseorang dari kalian berdiri mengerjakan shalat, setan akan datang menghampirinya (untuk menggodanya) sehingga tidak menyadari berapa raka'at shalat yang sudah dia laksanakan. Oleh karena itu bila seorang dari kalian mengalami peristiwa itu hendaklah dia melakukan sujud dua kali dalam posisi duduk\"."},"1157":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرٌو عَنْ بُكَيْرٍ عَنْ كُرَيْبٍأَنَّ ابْنَ عَبَّاسٍ وَالْمِسْوَرَ بْنَ مَخْرَمَةَ وَعَبْدَ الرَّحْمَنِ بْنَ أَزْهَرَ رَضِيَ اللَّهُ عَنْهُمْ أَرْسَلُوهُ إِلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَقَالُوا اقْرَأْ عَلَيْهَا السَّلَامَ مِنَّا جَمِيعًا وَسَلْهَا عَنْ الرَّكْعَتَيْنِ بَعْدَ صَلَاةِ الْعَصْرِ وَقُلْ لَهَا إِنَّا أُخْبِرْنَا عَنْكِ أَنَّكِ تُصَلِّينَهُمَا وَقَدْ بَلَغَنَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهَا وَقَالَ ابْنُ عَبَّاسٍ وَكُنْتُ أَضْرِبُ النَّاسَ مَعَ عُمَرَ بْنِ الخَطَّابِ عَنْهَا فَقَالَ كُرَيْبٌ فَدَخَلْتُ عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَبَلَّغْتُهَا مَا أَرْسَلُونِي فَقَالَتْ سَلْ أُمَّ سَلَمَةَ فَخَرَجْتُ إِلَيْهِمْ فَأَخْبَرْتُهُمْ بِقَوْلِهَا فَرَدُّونِي إِلَى أُمِّ سَلَمَةَ بِمِثْلِ مَا أَرْسَلُونِي بِهِ إِلَى عَائِشَةَ فَقَالَتْ أُمُّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَا سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْهَا ثُمَّ رَأَيْتُهُ يُصَلِّيهِمَا حِينَ صَلَّى الْعَصْرَ ثُمَّ دَخَلَ عَلَيَّ وَعِنْدِي نِسْوَةٌ مِنْ بَنِي حَرَامٍ مِنْ الْأَنْصَارِ فَأَرْسَلْتُ إِلَيْهِ الْجَارِيَةَ فَقُلْتُ قُومِي بِجَنْبِهِ فَقُولِي لَهُ تَقُولُ لَكَ أُمُّ سَلَمَةَ يَا رَسُولَ اللَّهِ سَمِعْتُكَ تَنْهَى عَنْ هَاتَيْنِ وَأَرَاكَ تُصَلِّيهِمَا فَإِنْ أَشَارَ بِيَدِهِ فَاسْتَأْخِرِي عَنْهُ فَفَعَلَتْ الْجَارِيَةُ فَأَشَارَ بِيَدِهِ فَاسْتَأْخَرَتْ عَنْهُ فَلَمَّا انْصَرَفَ قَالَ يَا بِنْتَ أَبِي أُمَيَّةَ سَأَلْتِ عَنْ الرَّكْعَتَيْنِ بَعْدَ الْعَصْرِ وَإِنَّهُ أَتَانِي نَاسٌ مِنْ عَبْدِ الْقَيْسِ فَشَغَلُونِي عَنْ الرَّكْعَتَيْنِ اللَّتَيْنِ بَعْدَ الظُّهْرِ فَهُمَا هَاتَانِ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] berkata, telah menceritakan kepada saya [Ibnu Wahb] berkata, telah mengabarkan kepada saya ['Amru] dari [Bukair] dari [Kuraib] bahwa Ibnu 'Abbas dan Al Mismar bin Makhramah dan 'Abdurrahman bin Azhar radliallahu 'anhum, ketiganya mengutusnya (Kuraib) untuk menemui 'Aisyah radliallahu 'anha dengan mengatakan; \"Sampaikan salam dari kami semua kepadanya, dan tanyakan tentang dua raka'at setelah shalat 'Ashar dan tanyakan kepadanya bahwa kami mendapat berita bahwa dia mengerjakan shalat tersebut padahal telah sampai berita kepada kami dari Nabi shallallahu 'alaihi wasallam bahwa Beliau melarang mengerjakannya, bahkan aku bersama 'Umar bin Al Khaththab pernah memukul orang yang mengerjakannya. Kuraib berkata; \"Maka aku menemui 'Aisyah radliallahu 'anha lalu kusampaikan kepadanya semua tujuan aku diutus. Maka (Aisyah radliallahu 'anha) menjawab; \"Tanyakan saja kepada [Ummu Salamah] \". Lalu aku menemui mereka yang mengutusku dan aku sampaikan ucapan 'Aisyah radliallahu 'anha. Lantas mereka memerintahkanku menemui Ummu Salamah dengan memerintahkan hal yang sama seperti ketika mereka mengutusku menemui 'Aisyah radliallahu 'anha. Maka Ummu Salamah radliallahu 'anhah berkata: \"Aku mendengar Nabi shallallahu 'alaihi wasallam pernah melarang mengerjakannya namun di kemudian hari aku melihat Beliau mengerjakannya seusai mengerjakan shalat 'Ashar. Setelah itu Beliau menemuiku yang ketika itu bersamaku ada beberapa wanita dari suku Bani Haram dari kalangan Kaum Anshar. Maka aku utus seorang sahaya wanita dan aku berkata kepadanya; \"Pergilah menemui Beliau (Rasulullah shallallahu 'alaihi wasallam) dan sampaikan kepadanya bahwa Ummu Salamah bertanya; Wahai Rasulullah shallallahu 'alaihi wasallam, Aku mendengar anda pernah melarang shalat dua raka'at setelah 'Ashar namun aku juga melihat anda mengerjakannya. Jika Beliau memberi isyarat dengan tangannya maka tunggulah\". Maka sahaya tersebut melaksanakannya dan ternyata Beliau memberi isyarat dengan tangannya. Maka sahaya ini menunggu dari Beliau. Setelah selesai Beliau berkata: \"Wahai binti Abu Umayyah, kamu bertanya tentang dua raka'at setelah 'Ashar. Sungguh aku kedatangan rambongan orang dari suku 'Abdul Qais yang menyebabkan aku terhalang dari mengerjakan dua raka'at setelah Zhuhur. Itulah yang aku kerjakan (setelah 'Ashar) \"."},"1158":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَلَغَهُ أَنَّ بَنِي عَمْرِو بْنِ عَوْفٍ كَانَ بَيْنَهُمْ شَيْءٌ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصْلِحُ بَيْنَهُمْ فِي أُنَاسٍ مَعَهُ فَحُبِسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَانَتْ الصَّلَاةُ فَجَاءَ بِلَالٌ إِلَى أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَقَالَ يَا أَبَا بَكْرٍ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ حُبِسَ وَقَدْ حَانَتْ الصَّلَاةُ فَهَلْ لَكَ أَنْ تَؤُمَّ النَّاسَ قَالَ نَعَمْ إِنْ شِئْتَ فَأَقَامَ بِلَالٌ وَتَقَدَّمَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَكَبَّرَ لِلنَّاسِ وَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْشِي فِي الصُّفُوفِ حَتَّى قَامَ فِي الصَّفِّ فَأَخَذَ النَّاسُ فِي التَّصْفِيقِ وَكَانَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ لَا يَلْتَفِتُ فِي صَلَاتِهِ فَلَمَّا أَكْثَرَ النَّاسُ الْتَفَتَ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَشَارَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُهُ أَنْ يُصَلِّيَ فَرَفَعَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ يَدَيْهِ فَحَمِدَ اللَّهَ وَرَجَعَ الْقَهْقَرَى وَرَاءَهُ حَتَّى قَامَ فِي الصَّفِّ فَتَقَدَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى لِلنَّاسِ فَلَمَّا فَرَغَ أَقْبَلَ عَلَى النَّاسِ فَقَالَ يَا أَيُّهَا النَّاسُ مَا لَكُمْ حِينَ نَابَكُمْ شَيْءٌ فِي الصَّلَاةِ أَخَذْتُمْ فِي التَّصْفِيقِ إِنَّمَا التَّصْفِيقُ لِلنِّسَاءِ مَنْ نَابَهُ شَيْءٌ فِي صَلَاتِهِ فَلْيَقُلْ سُبْحَانَ اللَّهِ فَإِنَّهُ لَا يَسْمَعُهُ أَحَدٌ حِينَ يَقُولُ سُبْحَانَ اللَّهِ إِلَّا الْتَفَتَ يَا أَبَا بَكْرٍ مَا مَنَعَكَ أَنْ تُصَلِّيَ لِلنَّاسِ حِينَ أَشَرْتُ إِلَيْكَ فَقَالَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ مَا كَانَ يَنْبَغِي لِابْنِ أَبِي قُحَافَةَ أَنْ يُصَلِّيَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub bin 'Abdurrahman] dari [Abu Hazim] dari [Sahal bin Sa'ad as-Sa'adiy radliallahu 'anhu]; Rasulullah shallallahu 'alaihi wasallam mendapat kabar bahwa telah terjadi masalah diantara suku Bani 'Amru bin 'Auf bin Al Harits. Maka Beliau disertai beberapa orang berangkat kesana untuk menyelesaikan masalah yang terjadi. Namun Rasulullah shallallahu 'alaihi wasallam tertahan lama disana hingga waktu shalat sudah masuk. Maka Bilal menemui Abu Bakar radliallahu 'anhuma seraya berkata: \"Wahai Abu Bakar, Rasulullah shallallahu 'alaihi wasallam terlambat hadir sedangkan waktu shalat sudah masuk, apakah engkau bersedia memimpin shalat berjama'ah? Dia (Abu Bakar) menjawab: \"Boleh, jika kamu menghendaki\". Maka Bilal membacakan iqamat lalu Abu Bakar maju dan memulai takbir memimpin shalat bersama orang banyak. Tak lama kemudian datang Nabi shallallahu 'alaihi wasallam menerobos tengah-tengan shaf hingga sampai di shaf (depan). Maka orang-orang memberi isyarat dengan bertepuk tangan namun Abu Bakar tidak bereaksi dalam shalatnya. Ketika orang-orang (yang memberi tepukan) semakin banyak, Abu Bakar menoleh dan ternyata ada Rasulullah shallallahu 'alaihi wasallam. Maka Rasulullah shallallahu 'alaihi wasallam memberi isyarat memerintahkan kepadanya agar tetap meneruskan shalatnya. Abu Bakar mengangkat kedua tangannya lalu memuji Allah dan mundur, lantas berdiri di barisan lalu Rasulullah shallallahu 'alaihi wasallam maju untuk memimpin shalat berjama'ah. Setelah selesai Beliau berbalik menghadap jama'ah lalu bersabda: \"Wahai sekalian manusia mengapa kalian ketika mendapatkan sesuatu dalam shalat, kalian melakukannya dengan bertepuk tangan? Sesungguhnya bertepuk tangan itu adalah isyarat yang hanya dilakukan bagi kaum wanita. Maka siapa yang mendapatkan sesuatu yang keliru dalam shalat hendaklah mengucapkan subhaanallah, karena tidaklah seseorang mendengar ketika ada yang berucap subhaanallah kecuali dia harus memperhatikannya. Dan kamu wahai Abu Bakar, apa yang menghalangimu untuk melanjutkan memimpin shalat berjama'ah bersama orang banyak ketika aku sudah memberi isyarat kepadamu (agar meneruskannya)?\" Abu Bakar menjawab: \"Tidak patut bagi Ibn Abu Quhafah memimpin shalat di hadapan Rasulullah shallallahu 'alaihi wasallam \"."},"1159":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ قَالَ ��َدَّثَنِي ابْنُ وَهْبٍ حَدَّثَنَا الثَّوْرِيُّ عَنْ هِشَامٍ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَ قَالَتْدَخَلْتُ عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا وَهِيَ تُصَلِّي قَائِمَةً وَالنَّاسُ قِيَامٌ فَقُلْتُ مَا شَأْنُ النَّاسِ فَأَشَارَتْ بِرَأْسِهَا إِلَى السَّمَاءِ فَقُلْتُ آيَةٌ فَقَالَتْ بِرَأْسِهَا أَيْ نَعَمْ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] berkata, telah menceritakan kepada saya [Ibnu Wahb] telah menceritakan kepada kami [Atz-Tsauriy] dari [Hisyam] dari [Fathimah] dari [Asma'] berkata: \"Aku menemui Aisyah radliallahu 'anha sedangkan saat itu dia sedang berdiri shalat begitu juga orang-orang sedang mengerjakan shalat. Lalu aku bertanya: \"Apa yang sedang terjadi?\" Maka dia memberi isyarat ke atas dengan kepalanya. Lalu aku berkata: \"Benarkah tanda itu (gerhana)?\" Maka dia menjawab dengan (menganggukkan) kepalanya tanda mengiyakan\"."},"1160":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبِي أُوَيْسٍ قَالَ حَدَّثَنِي مَالِكٌ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِهِ وَهُوَ شَاكٍ جَالِسًا وَصَلَّى وَرَاءَهُ قَوْمٌ قِيَامًا فَأَشَارَ إِلَيْهِمْ أَنْ اجْلِسُوا فَلَمَّا انْصَرَفَ قَالَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا رَفَعَ فَارْفَعُوا","id":"Telah menceritakan kepada kami [Isma'il bin Abu Uwais] berkata, telah menceritakan kepada saya [Malik] dari [Hisyam] dari [bapaknya] dari ['Aisyah] radliallahu 'anha, isteri Nabi shallallahu 'alaihi wasallam berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah shalat di rumahnya. Ketika itu Beliau sedang sakit hingga shalat dengan duduk, dan orang-orang mengikuti shalat di belakang Beliau dengan berdiri. Maka Beliau memberi isyarat kepada mereka agar shalat dengan duduk. Setelah selesai Beliau bersabda: \"Sesungguhnya imam diangkat untuk diikuti. Maka bila dia ruku', ruku'lah kalian dan bila dia mengangkat (kepala), agkatlah (kepala) kalian\"."},"1161":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ حَدَّثَنَا وَاصِلٌ الْأَحْدَبُ عَنْ الْمَعْرُورِ بْنِ سُوَيْدٍ عَنْ أَبِي ذَرٍّ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَانِي آتٍ مِنْ رَبِّي فَأَخْبَرَنِي أَوْ قَالَ بَشَّرَنِي أَنَّهُ مَنْ مَاتَ مِنْ أُمَّتِي لَا يُشْرِكُ بِاللَّهِ شَيْئًا دَخَلَ الْجَنَّةَ قُلْتُ وَإِنْ زَنَى وَإِنْ سَرَقَ قَالَ وَإِنْ زَنَى وَإِنْ سَرَقَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Mahdiy bin Maymun] telah menceritakan kepada kami [Washil Al Ahdab] dari [Al Ma'rur bin Suaid] dari [Abu Dzar radliallahu 'anhu] berkata; Telah bersabda Rasulullah shallallahu 'alaihi wasallam: \"Baru saja datang kepadaku utusan dari Rabbku lalu mengabarkan kepadaku\" atau Beliau bersabda: \"Telah datang mengabarkan kepadaku bahwa barangsiapa yang mati dari ummatku sedang dia tidak menyekutukan Allah dengan suatu apapun maka dia pasti masuk surga\". Aku tanyakan: \"Sekalipun dia berzina atau mencuri?\" Beliau menjawab: \"Ya, sekalipun dia berzina atau mencuri\"."},"1162":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا شَقِيقٌ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ مَاتَ يُشْرِكُ بِاللَّهِ شَيْئًا دَخَلَ النَّارَوَقُلْتُ أَنَا مَنْ مَاتَ لَا يُشْرِكُ بِاللَّهِ شَيْئًا دَخَلَ الْجَنَّةَ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Syaqiq] dari ['Abdullah radliallahu 'anhu] berkata; Telah bersabda Rasulullah shallallahu 'alaihi wasallam: \"Barangsiapa yang mati dengan menyekutukan Allah dengan sesuatu maka dia pasti masuk neraka\". Dan aku ('Abdullah) berkata, dariku sendiri: \"Dan barangsiapa yang mati tidak menyekutukan Allah dengan suatu apapun maka dia pasti masuk surga\"."},"1163":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ الْأَشْعَثِ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ سُوَيْدِ بْنِ مُقَرِّنٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَمَرَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَبْعٍ وَنَهَانَا عَنْ سَبْعٍ أَمَرَنَا بِاتِّبَاعِ الْجَنَائِزِ وَعِيَادَةِ الْمَرِيضِ وَإِجَابَةِ الدَّاعِي وَنَصْرِ الْمَظْلُومِ وَإِبْرَارِ الْقَسَمِ وَرَدِّ السَّلَامِ وَتَشْمِيتِ الْعَاطِسِ وَنَهَانَا عَنْ آنِيَةِ الْفِضَّةِ وَخَاتَمِ الذَّهَبِ وَالْحَرِيرِ وَالدِّيبَاجِ وَالْقَسِّيِّ وَالْإِسْتَبْرَقِ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Al Asy'ats] berkata, aku mendengar [Mu'awiyyah bin Suwaid bin Muqarrin] dari [Al Bara' bin 'Azib radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam memerintahkan kami tentang tujuh perkara dan melarang kami dari tujuh perkara pula. Beliau memerintahkan kami untuk; mengiringi jenazah, menjenguk orang yang sakit, memenuhi undangan, menolong orang yang dizhalimi, berbuat adil dalam pembagian, menjawab salam dan mendoakan orang yang bersin. Dan Beliau melarang kami dari menggunakan bejana terbuat dari perak, memakai cincin emas, memakai kain sutera kasar, sutera halus, baju berbordir sutera dan sutera tebal\"."},"1164":{"ar":"حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا عَمْرُو بْنُ أَبِي سَلَمَةَ عَنْ الْأَوْزَاعِيِّ قَالَ أَخْبَرَنِي ابْنُ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ حَقُّ الْمُسْلِمِ عَلَى الْمُسْلِمِ خَمْسٌ رَدُّ السَّلَامِ وَعِيَادَةُ الْمَرِيضِ وَاتِّبَاعُ الْجَنَائِزِ وَإِجَابَةُ الدَّعْوَةِ وَتَشْمِيتُ الْعَاطِسِتَابَعَهُ عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ وَرَوَاهُ سَلَامَةُ بْنُ رَوْحٍ عَنْ عُقَيْلٍ","id":"Telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami ['Amru bin Abu Salamah] dari [Al Awza'iy] berkata, telah mengabarkan kepada saya [Ibnu Syihab] berkata, telah mengabarkan kepada saya [Sa'id bin Al Musayyab] bahwa [Abu Hurairah radliallahu 'anhu] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hak muslim atas muslim lainnya ada lima, yaitu; menjawab salam, menjenguk yang sakit, mengiringi jenazah, memenuhi undangan dan mendoakan orang yang bersin\". Hadits ini diriwayatkan pula oleh ['Abdur Razaq] berkata, telah mengabarkan kepada kami [Ma'mar] dan meriwayatkan kepadanya [Salamah bin Rauh] dari ['Uqail]."},"1165":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنِي مَعْمَرٌ وَيُونُسُ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُ قَالَتْأَقْبَلَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ عَلَى فَرَسِهِ مِنْ مَسْكَنِهِ بِالسُّنْحِ حَتَّى نَزَلَ فَدَخَلَ الْمَسْجِدَ فَلَمْ يُكَلِّمْ النَّاسَ حَتَّى دَخَلَ عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَتَيَمَّمَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُسَجًّى بِبُرْدِ حِبَرَةٍ فَكَشَفَ عَنْ وَجْهِهِ ثُمَّ أَكَبَّ عَلَيْهِ فَقَبَّلَهُ ثُمَّ بَكَى فَقَالَ بِأَبِي أَنْتَ يَا نَبِيَّ اللَّهِ لَا يَجْمَعُ اللَّهُ عَلَيْكَ مَوْتَتَيْنِ أَمَّا الْمَوْتَةُ الَّتِي كُتِبَتْ عَلَيْكَ فَقَدْ مُتَّهَاقَالَ أَبُو سَلَمَةَ فَأَخْبَرَنِي ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا أَنَّ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ خَرَجَ وَعُمَرُ رَضِيَ اللَّهُ عَنْهُ يُكَلِّمُ النَّاسَ فَقَالَ اجْلِسْ فَأَبَى فَقَالَ اجْلِسْ فَأَبَى فَتَشَهَّدَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَمَالَ إِلَيْهِ النَّاسُ وَتَرَكُوا عُمَرَ فَقَالَ أَمَّا بَعْدُ فَمَنْ كَانَ مِنْكُمْ يَعْبُدُ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ مَاتَ وَمَنْ كَانَ يَعْبُدُ اللَّهَ فَإِنَّ اللَّهَ حَيٌّ لَا يَمُوتُ قَالَ اللَّهُ تَعَالَى{ وَمَا مُحَمَّدٌ إِلَّا رَسُولٌ قَدْ خَلَتْ مِنْ قَبْلِهِ الرُّسُلُ إِلَى الشَّاكِرِينَ }وَاللَّهِ لَكَأَنَّ النَّاسَ لَمْ يَكُونُوا يَعْلَمُونَ أَنَّ اللَّهَ أَنْزَلَهَا حَتَّى تَلَاهَا أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَتَلَقَّاهَا مِنْهُ النَّاسُ فَمَا يُسْمَعُ بَشَرٌ إِلَّا يَتْلُوهَا","id":"Telah menceritakan kepada kami [Bisyir bin Muhammad] telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada saya [Ma'mar] dan [Yunus] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya [Abu Salamah] bahwa ['Aisyah radliallahu 'anha] isteri Nabi shallallahu 'alaihi wasallam mengabarkan kepadanya, katanya; [Abu Bakar] radliallahu 'anhu menunggang kudanya dari suatu tempat bernama Sunih hingga sampai dan masuk ke dalam masjid dan dia tidak berbicara dengan orang-orang, lalu dia menemui 'Aisyah radliallahu 'anha dan langsung mendatangi Nabi shallallahu 'alaihi wasallam yang sudah ditutupi (jasadnya) dengan kain terbuat dari katun. Kemudian dia membuka tutup wajah Beliau lalu Abu Bakar bersimpuh didepan jasad Nabi, lalu menutupnya kembali. Kemudian Abu Bakar menangis dan berkata: \"Demi bapak dan ibuku, wahai Nabi Allah, Allah tidak akan menjadikan kematian dua kali kepadamu. Adapun kematian pertama yang telah ditetapkan buatmu itu sudah terjadi\". Berkata, [Abu Salamah]; telah mengabarkan kepada saya [Ibnu 'Abbas] radliallahu 'anhuma bahwa; Kemudian [Abu Bakar] radliallahu 'anhu keluar bertepatan 'Umar radliallahu 'anhu sedang berbicara dengan orang banyak. Maka (Abu Bakar radliallahu 'anhu) berkata, kepada (\"Umar radliallahu 'anhu): \"Duduklah!\". Namun 'Umar tidak mempedulikannya. Lalu Abu Bakar berkata, lagi: \"Duduklah!\". Namun 'Umar tetap tidak mempedulikannya. Akhirnya Abu Bakar bersaksi (tentang kewafatan Nabi shallallahu 'alaihi wasallam) sehingga orang-orang berkumpul kepadanya dan meninggalkan 'Umar, lalu Abu Bakar berkata: \"Kemudian, barangsiapa dari kalian yang menyembah Muhammad shallallahu 'alaihi wasallam, sungguh Muhammad shallallahu 'alaihi wasallam sekarang sudah wafat dan barangsiapa dari kalian yang menyembah Allah, sungguh Allah Maha Hidup yang tidak akan pernah mati. Allah Ta'ala telah berfirman: (yang artinya): \"Dan Muhammad itu tidak lain kecuali hanyalah seorang rasul sebagaimana telah berlalu (mati) rasul-rasul sebelum dia\"..seterusnya hingga akhir ayat … Allah akan memberi balasan pahala bagi orang-orang yang bersyukur\" (QS. Ali'Imran 165). Demi Allah, seakan-akan orang-orang belum pernah mengetahui bahwa Allah sudah menurunkan ayat tersebut sampai Abu Bakar radliallahu 'anhu membacakannya. Akhirnya orang-orang memahaminya dan tidak ada satupun orang yang mendengarnya (wafatnya Nabi) kecuali pasti membacakannya\"."},"1166":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي خَارِجَةُ بْنُ زَيْدِ بْنِ ثَابِتٍ أَنَّ أُمَّ الْعَلَاءِ امْرَأَةً مِنْ الْأَنْصَارِبَايَعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُ أَنَّهُ اقْتُسِمَ الْمُهَاجِرُونَ قُرْعَةً فَطَارَ لَنَا عُثْمَانُ بْنُ مَظْعُونٍ فَأَنْزَلْنَاهُ فِي أَبْيَاتِنَا فَوَجِعَ وَجَعَهُ الَّذِي تُوُفِّيَ فِيهِ فَلَمَّا تُوُفِّيَ وَغُسِّلَ وَكُفِّنَ فِي أَثْوَابِهِ دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ رَحْمَةُ اللَّهِ عَلَيْكَ أَبَا السَّائِبِ فَشَهَادَتِي عَلَيْكَ لَقَدْ أَكْرَمَكَ اللَّهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا يُدْرِيكِ أَنَّ اللَّهَ قَدْ أَكْرَمَهُ فَقُلْتُ بِأَبِي أَنْتَ يَا رَسُولَ اللَّهِ فَمَنْ يُكْرِمُهُ اللَّهُ فَقَالَ أَمَّا هُوَ فَقَدْ جَاءَهُ الْيَقِينُ وَاللَّهِ إِنِّي لَأَرْجُو لَهُ الْخَيْرَ وَاللَّهِ مَا أَدْرِي وَأَنَا رَسُولُ اللَّهِ مَا يُفْعَلُ بِي قَالَتْ فَوَاللَّهِ لَا أُزَكِّي أَحَدًا بَعْدَهُ أَبَدًاحَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ حَدَّثَنَا اللَّيْثُ مِثْلَهُ وَقَالَ نَافِعُ بْنُ يَزِيدَ عَنْ عُقَيْلٍ مَا يُفْعَلُ بِهِ وَتَابَعَهُ شُعَيْبٌ وَعَمْرُو بْنُ دِينَارٍ وَمَعْمَرٌ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] berkata, telah mengabarkan kepada saya [Kharijah bin Zaid bin Tsabit] bahwa [Ummu Al 'Ala'] seorang wanita Kaum Anshar yang pernah berbai'at kepada Nabi shallallahu 'alaihi wasallam mengabarkannya bahwa; Ketika Beliau sedang mengundi pembagian sahabat Muhajirin (untuk tinggal di rumah-rumah sahabat Anshar sesampainya mereka di Madinah), maka 'Utsman bin Mazh'un mendapatkan bagiannya untuk tinggal bersama kami. Akhirnya dia kami bawa ke rumah-rumah kami. Namun kemudian dia menderita sakit yang membawa kepada kematianya. Setelah dia wafat, maka dia dimandikan dan dikafani dengan baju yang dikenakannya. Tak lama kemudian Rasulullah shallallahu 'alaihi wasallam datang lalu aku berkata, kepada Beliau: \"Semoga rahmat Allah tercurah atasmu wahai Abu As-Sa'ib ('Utsman bin Mazh'un). Dan persaksianku atasmu bahwa Allah telah memuliakanmu\". Maka Nabi shallallahu 'alaihi wasallam berkata: \"Dari mana kamu tahu bahwa Allah telah memuliakannya?\" Aku jawab: \"Demi bapakku, wahai Rasulullah, siapakah seharusnya orang yang dimuliakan Allah itu?\" Beliau menjawab: \"Adapun dia, telah datang kepadanya Al Yaqin (kematian) dan aku berharap dia berada diatas kebaikan. Demi Allah meskipun aku ini Rasulullah, aku tidak tahu apa yang akan dilakukan-Nya terhadapku\". Dia (Ummu Al 'Ala') berkata: \"Demi Allah, tidak seorangpun yang aku anggap suci setelah peristiwa itu selamanya\". Telah menceritakan kepada kami [Sa'id bin 'Uqair] telah menceritakan kepada kami [Al Laits] seperti ini. Dan berkata, [Nafi' bin Yazid] dari ['Uqail]: \"Apa yang akan dilakukan-Nya terhadapnya\". Dan dikuatkan oleh [Syu'aib] dan ['Amru bin Dinar] dan [Ma'mar]."},"1167":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ الْمُنْكَدِرِ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا قُتِلَ أَبِي جَعَلْتُ أَكْشِفُ الثَّوْبَ عَنْ وَجْهِهِ أَبْكِي وَيَنْهَوْنِي عَنْهُ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَنْهَانِي فَجَعَلَتْ عَمَّتِي فَاطِمَةُ تَبْكِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَبْكِينَ أَوْ لَا تَبْكِينَ مَا زَالَتْ الْمَلَائِكَةُ تُظِلُّهُ بِأَجْنِحَتِهَا حَتَّى رَفَعْتُمُوهُتَابَعَهُ ابْنُ جُرَيْجٍ أَخْبَرَنِي مُحَمَّدُ بْنُ الْمُنْكَدِرِ سَمِعَ جَابِرًا رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] berkata; Aku mendengar [Muhammad bin Al Munkadir] berkata; Aku mendengar [Jabir bin 'Abdullah radliallahu 'anha] berkata: Ketika bapakku meninggal dunia aku menyingkap kain penutup wajahnya, maka aku menangis namun orang-orang melarangku menangis sedangkan Nabi shallallahu 'alaihi wasallam tidak melarangku. Hal ini membuat bibiku Fathimah ikut menangis. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Dia menangis atau tidak menangis, malaikat senantiaa akan tetap menaunginya sampai kalian mengangkatnya\". Hadits ini dperkuat pula oleh [Ibnu Juraij] telah mengabarkan kepada saya [Muhammad bin Al Munkadir] bahwa dia mendengar [Jabir radliallahu 'anha]."},"1168":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَى النَّجَاشِيَّ فِي الْيَوْمِ الَّذِي مَاتَ فِيهِ خَرَجَ إِلَى الْمُصَلَّى فَصَفَّ بِهِمْ وَكَبَّرَ أَرْبَعًا","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada saya [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam mengumumkan kematian An-Najasyi pada hari kematiannya kemudian Beliau keluar menuju tempat shalat lalu Beliau membariskan shaf kemudian takbir empat kali."},"1169":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ الرَّايَةَ زَيْدٌ فَأُصِيبَ ثُمَّ أَخَذَهَا جَعْفَرٌ فَأُصِيبَ ثُمَّ أَخَذَهَا عَبْدُ اللَّهِ بْنُ رَوَاحَةَ فَأُصِيبَ وَإِنَّ عَيْنَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَتَذْرِفَانِ ثُمَّ أَخَذَهَا خَالِدُ بْنُ الْوَلِيدِ مِنْ غَيْرِ إِمْرَةٍ فَفُتِحَ لَهُ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami [Ayyub] dari [Humaid bin Hilal] dari [Anas bin Malik radliallahu 'anhu] berkata: Telah bersabda Nabi shallallahu 'alaihi wasallam: \"Bendera perang dipegang oleh Zaid lalu dia terbunuh kemudian dipegang oleh Ja'far lalu dia terbunuh kemudian dipegang oleh 'Abdullah bin Rawahah namun diapun terbunuh, Dan nampak kedua mata Rasulullah shallallahu 'alaihi wasallam berlinang. Akhirnya bendera dipegang oleh Khalid bin Al Walid tanpa menunggu perintah, namun akhirnya kemenangan diraihnya\"."},"1170":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ أَبِي إِسْحَاقَ الشَّيْبَانِيِّ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَمَاتَ إِنْسَانٌ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُهُ فَمَاتَ بِاللَّيْلِ فَدَفَنُوهُ لَيْلًا فَلَمَّا أَصْبَحَ أَخْبَرُوهُ فَقَالَ مَا مَنَعَكُمْ أَنْ تُعْلِمُونِي قَالُوا كَانَ اللَّيْلُ فَكَرِهْنَا وَكَانَتْ ظُلْمَةٌ أَنْ نَشُقَّ عَلَيْكَ فَأَتَى قَبْرَهُ فَصَلَّى عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Abu Ishaq Asy-Syaibaniy] dari [Asy-Sya'biy] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Bila ada orang yang meninggal dunia biasanya Rasulullah shallallahu 'alaihi wasallam melayatnya. Suatu hari ada seorang yang meninggal dunia di malam hari kemudian dikuburkan malam itu juga. Keesokan paginya orang-orang memberitahu Beliau. Maka Beliau bersabda: \"Mengapa kalian tidak memberi tahu aku?\" Mereka menjawab: \"Kejadiannya malam hari, kami khawatir memberatkan anda\". Maka kemudian Beliau mendatangi kuburan orang itu lalu mengerjakan shalat untuknya\"."},"1171":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ النَّاسِ مِنْ مُسْلِمٍ يُتَوَفَّى لَهُ ثَلَاثٌ لَمْ يَبْلُغُوا الْحِنْثَ إِلَّا أَدْخَلَهُ اللَّهُ الْجَنَّةَ بِفَضْلِ رَحْمَتِهِ إِيَّاهُمْ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami ['Abdul 'Aziz] dari [Anas radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam telah bersabda: \"Tidak seorang muslim pun yang ditinggal wafat oleh tiga orang anaknya yang belum baligh kecuali akan Allah masukkan dia ke dalam surga karena limpahan rahmatNya kepada mereka\"."},"1172":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْأَصْبَهَانِيِّ عَنْ ذَكْوَانَ عَنْ أَبِي سَعِيدٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النِّسَاءَ قُلْنَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْعَلْ لَنَا يَوْمًا فَوَعَظَهُنَّ وَقَالَ أَيُّمَا امْرَأَةٍ مَاتَ لَهَا ثَلَاثَةٌ مِنْ الْوَلَدِ كَانُوا حِجَابًا مِنْ النَّارِ قَالَتْ امْرَأَةٌ وَاثْنَانِ قَالَ وَاثْنَانِوَقَالَ شَرِيكٌ عَنْ ابْنِ الْأَصْبَهَانِيِّ حَدَّثَنِي أَبُو صَالِحٍ عَنْ أَبِي سَعِيدٍ وَأَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُمَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو هُرَيْرَةَ لَمْ يَبْلُغُوا الْحِنْثَ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami ['Abdurrahman bin Al Ashbahaaniy] dari [Dzakwan] dari [Abu Sa'id] radliallahu 'anhu bahwa para wanita pernah berkata, kepada Nabi shallallahu 'alaihi wasallam; \"Sediakanlah satu hari untuk kami!\". Maka kemudian Beliau memberikan pelajaran untuk mereka dan diantaranya bersabda: \"Siapa saja dari wanita yang ditinggal mati oleh tiga orang anaknya melainkan mereka akan menjadi hijab (pembatas) dari api neraka\". Seorang wanita berkata: \"Bagaimana kalau ditinggal mati oleh dua orang anak? Beliau menjawab: \"Dan juga oleh dua orang\". Dan berkata, [Syarik] dari [Al Ashbahaaniy] telah menceritakan kepada saya [Abu Shalih] dari [Abu Sa'id] dan [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam. Berkata, Abu Hurairah radliallahu 'anhu: \"Bila mereka belum baligh.\""},"1173":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ الزُّهْرِيَّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمُوتُ لِمُسْلِمٍ ثَلَاثَةٌ مِنْ الْوَلَدِ فَيَلِجَ النَّارَ إِلَّا تَحِلَّةَ الْقَسَمِقَالَ أَبُو عَبْد اللَّهِ{ وَإِنْ مِنْكُمْ إِلَّا وَارِدُهَا }","id":"Telah menceritakan kepada kami ['Ali] telah menceritakan kepada kami [Sufyan] berkata; aku mendengar [Az Zuhriy] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Seorang muslim yang ditinggal wafat oleh tiga orang anaknya, tidak bakalan masuki neraka selain sebatas melakukan sumpah Allah\". Berkata, Abu 'Abdullah: Maksudnya melakukan sumpah Allah yang tersebut dalam Firman-Nya yang artinya; \"Tidaklah dari kalian melainkan pasti akan melewatinya (neraka) (QS. Maryam 71) \". "},"1174":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِامْرَأَةٍ عِنْدَ قَبْرٍ وَهِيَ تَبْكِي فَقَالَ اتَّقِي اللَّهَ وَاصْبِرِي","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Tsabit] dari [Anas bin Malik radliallahu 'anhu] berkata: \"Rasulullah shallallahu 'alaihi wasallam berjalan melewati seorang wanita yang sedang berada di kuburan dalam keadaan menangis. Maka Beliau berkata;: \"Bertakwalah kamu kepada Allah dan bersabarlah\"."},"1175":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَيُّوبَ السَّخْتِيَانِيِّ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ الْأَنْصَارِيَّةِ رَضِيَ اللَّهُ عَنْهَا قَالَتْدَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تُوُفِّيَتْ ابْنَتُهُ فَقَالَ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكَ إِنْ رَأَيْتُنَّ ذَلِكَ بِمَاءٍ وَسِدْرٍ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي فَلَمَّا فَرَغْنَا آذَنَّاهُ فَأَعْطَانَا حِقْوَهُ فَقَالَ أَشْعِرْنَهَا إِيَّاهُ تَعْنِي إِزَارَهُ","id":"Telah menceritakan kepada kami [Isma'il bin 'Abdullah] berkata, telah menceritakan kepada saya [Malik] dari [Ayyub As-Sakhtiyaniy] dari [Muhammad bin Sirin] dari [Ummu 'Athiyyah seorang wanita Anshar radliallahu 'anha] berkata: Rasulullah shallallahu 'alaihi wasallam menemui kami saat kematian puteri kami, lalu bersabda: \"Mandikanlah dengan mengguyurkan air yang dicampur dengan daun bidara tiga kali, lima kali atau lebih dari itu jika kalian anggap perlu dan jadikanlah yang terakhirnya dengan kafur barus (wewangian) atau yang sejenis. Dan bila kalian telah selesai beritahu aku\". Ketika kami telah selesai kami memberi tahu Beliau. Maka kemudian Beliau memberikan kain Beliau kepada kami seraya berkata: \"Pakaikanlah ini kepadanya\". Maksudnya pakaian Beliau\"."},"1176":{"ar":"حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْدَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَغْسِلُ ابْنَتَهُ فَقَالَ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكَ بِمَاءٍ وَسِدْرٍ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي فَلَمَّا فَرَغْنَا آذَنَّاهُ فَأَلْقَى إِلَيْنَا حِقْوَهُ فَقَالَ أَشْعِرْنَهَا إِيَّاهُفَقَالَ أَيُّوبُ وَحَدَّثَتْنِي حَفْصَةُ بِمِثْلِ حَدِيثِ مُحَمَّدٍ وَكَانَ فِي حَدِيثِ حَفْصَةَ اغْسِلْنَهَا وِتْرًا وَكَانَ فِيهِ ثَلَاثًا أَوْ خَمْسًا أَوْ سَبْعًا وَكَانَ فِيهِ أَنَّهُ قَالَ ابْدَءُوا بِمَيَامِنِهَا وَمَوَاضِعِ الْوُضُوءِ مِنْهَا وَكَانَ فِيهِ أَنَّ أُمَّ عَطِيَّةَ قَالَتْ وَمَشَطْنَاهَا ثَلَاثَةَ قُرُونٍ","id":"Telah menceritakan kepada kami [Muhammad] telah menceritakan kepada saya ['Abdul Wahhab Ats-Tsaqafiy] dari [Ayyub] dari [Muhammad] dari [Ummu 'Athiyyah radliallahu 'anha] berkata: Rasulullah shallallahu 'alaihi wasallam menemui kami ketika kami akan memandikan puteri. Beliau lalu bersabda: \"Mandikanlah dengan mengguyurkan air yang dicampur dengan daun bidara tiga kali, lima kali atau lebih dari itu jika kalian anggap perlu dan jadikanlah yang terakhirnya dengan kafur barus (wewangian). Dan bila kalian telah selesai beritahu aku\". Ketika kami telah selesai kami memberi tahu Beliau. Maka kemudian Beliau memberikan kain Beliau kepada kami seraya berkata: \"Pakaikanlah ini kepadanya\". Berkata, [Ayyub] telah menceritakan kepada saya [Hafshah] seperti hadits Muhammad ini dimana pada hadits Hadshah berbunyi: \"Mandikanlah dengan siraman air berjumlah ganjil\". Pada hadits itu juga ada disebutkan: \"Tiga, lima atau tujuh kali siraman\". Dan juga didalamnya ada berbunyi: \"Mulailah dengan anggota badan yang kanan dan badan anggota wudhu'\". Pada hadits itu juga ada disebutkan bahwa Ummu 'Athiyyah berkata: \"Kami menyisir rambut puteri Beliau dengan tiga kepang\"."},"1177":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا خَالِدٌ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَسْلِ ابْنَتِهِ ابْدَأْنَ بِمَيَامِنِهَا وَمَوَاضِعِ الْوُضُوءِ مِنْهَا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Khalid] dari [Hafshah binti Sirin] dari [Ummu 'Athiyyah] radliallahu 'anhu berkata; Telah bersabda Rasulullah shallallahu 'alaihi wasallam ketika pemandian puteri Beliau yang meninggal dunia: \"Mulailah dengan anggota badan yang kanan dan anggota wudhu' dari badan\"."},"1178":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمَّا غَسَّلْنَا بِنْتَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَنَا وَنَحْنُ نَغْسِلُهَا ابْدَءُوا بِمَيَامِنِهَا وَمَوَاضِعِ الْوُضُوءِ مِنْهَا","id":"Telah menceritakan kepada kami [Yahya bin Musa] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Khalid Al Hadza`i] dari [Hafshah binti Sirin] dari [Ummu 'Athiyyah radliallahu 'anhu] berkata; Telah bersabda Rasulullah shallallahu 'alaihi wasallam berkenaan pemandian puteri Beliau yang meninggal dunia: \"Mulailah dengan anggota badan yang kanan dan anggota wudhu' dari badan\"."},"1179":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ حَمَّادٍ أَخْبَرَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ قَالَتْتُوُفِّيَتْ بِنْتُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَنَا اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكَ إِنْ رَأَيْتُنَّ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي فَلَمَّا فَرَغْنَا آذَنَّاهُ فَنَزَعَ مِنْ حِقْوِهِ إِزَارَهُ وَقَالَ أَشْعِرْنَهَا إِيَّاهُ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Hammad] telah mengabarkan kepada kami [Ibnu 'Aun] dari [Muhammad] dari [Ummu 'Athiyyah radliallahu 'anhu] berkata: Ketika puteri Nabi shallallahu 'alaihi wasallam wafat Beliau berkata, kepada kami: \"Mandikanlah ia (dengan mengguyurkan air) tiga kali, lima kali atau lebih dari itu jika kalian anggap perlu dan bila kalian telah selesai beritahu aku\". Ketika kami telah selesai kami memberi tahu Beliau. Maka kemudian Beliau memberikan kain Beliau kepada kami seraya berkata: \"Pakaikanlah ini kepadanya\"."},"1180":{"ar":"حَدَّثَنَا حَامِدُ بْنُ عُمَرَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ قَالَتْتُوُفِّيَتْ إِحْدَى بَنَاتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكَ إِنْ رَأَيْتُنَّ بِمَاءٍ وَسِدْرٍ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي قَالَتْ فَلَمَّا فَرَغْنَا آذَنَّاهُ فَأَلْقَى إِلَيْنَا حِقْوَهُ فَقَالَ أَشْعِرْنَهَا إِيَّاهُوَعَنْ أَيُّوبَ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ رَضِيَ اللَّهُ عَنْهُمَا بِنَحْوِهِ وَقَالَتْ إِنَّهُ قَالَ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ سَبْعًا أَوْ أَكْثَرَ مِنْ ذَلِكَ إِنْ رَأَيْتُنَّ قَالَتْ حَفْصَةُ قَالَتْ أُمُّ عَطِيَّةَ رَضِيَ اللَّهُ عَنْهَا وَجَعَلْنَا رَأْسَهَا ثَلَاثَةَ قُرُونٍ","id":"Telah menceritakan kepada kami [Hamid bin 'Umar] telah menceritakan kepada saya [Hammad bin Zaid] dari [Ayyub] dari [Muhammad] dari [Ummu 'Athiyyah radliallahu 'anha] berkata: Ketika salah satu puteri Nabi shallallahu 'alaihi wasallam wafat, Nabi shallallahu 'alaihi wasallam keluar seraya berkata: \"Mandikanlah dengan mengguyurkan air yang dicampur dengan daun bidara tiga kali, lima kali atau lebih dari itu jika kalian anggap perlu dan jadikanlah yang terakhirnya dengan kafur barus (wewangian) atau yang sejenis dari kapur barus (kamper). Dan bila kalian telah selesai beritahu aku\". Berkata, Ummu 'Athiyyah radliallahu 'anha: \"Ketika kami telah selesai, kami memberi tahu Beliau, kemudian Beliau memberikan kain, Beliau kepada kami seraya berkata: \"Pakaikanlah ini kepadanya\". Dan dari [Ayyub] dari [Hafshah] dari [Ummu 'Athiyyah radliallahu 'anha] dan dia berkata, bahwa Beliau bersabda: \"Mandikanlah ia tiga kali, lima kali, tujuh kali atau lebih dari itu jika kalian anggap perlu \". Berkata, Hafshah telah berkata, Ummu 'Athiyyah radliallahu 'anha: \"Kami kepang rambut kepala puteri Beliau dengan tiga kepang\"."},"1181":{"ar":"حَدَّثَنَا أَحْمَدُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَيُّوبُ وَسَمِعْتُ حَفْصَةَ بِنْتَ سِيرِينَ قَالَتْ حَدَّثَتْنَا أُمُّ عَطِيَّةَ رَضِيَ اللَّهُ عَنْهَاأَنَّهُنَّ جَعَلْنَ رَأْسَ بِنْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةَ قُرُونٍ نَقَضْنَهُ ثُمَّ غَسَلْنَهُ ثُمَّ جَعَلْنَهُ ثَلَاثَةَ قُرُونٍ","id":"Telah menceritakan kepada kami [Ahmad] telah menceritakan kepada kami ['Abdullah bin Wahb] telah mengabarkan kepada kami [Ibnu Juraij] berkata, [Ayyub]; Aku mendengar [Hafshah binti Sirin] berkata, telah menceritakan kepada kami [Ummu 'Athiyyah radliallahu 'anha]; Bahwa mereka menjadikan (rambut) puteri Rasulullah shallallahu 'alaihi wasallam tiga ikatan kemudian mereka melepaskannya lalu aku membasuhnya kemudian mereka jadikan kembali menjadi tiga ikatan (kepang) \"."},"1182":{"ar":"حَدَّثَنَا أَحْمَدُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَنَّ أَيُّوبَ أَخْبَرَهُ قَالَ سَمِعْتُ ابْنَ سِيرِينَ يَقُولُ جَاءَتْ أُمُّ عَطِيَّةَ رَضِيَ اللَّهُ عَنْهَاامْرَأَةٌ مِنْ الْأَنْصَارِ مِنْ اللَّاتِي بَايَعْنَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدِمَتْ الْبَصْرَةَ تُبَادِرُ ابْنًا لَهَا فَلَمْ تُدْرِكْهُ فَحَدَّثَتْنَا قَالَتْ دَخَلَ عَلَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَغْسِلُ ابْنَتَهُ فَقَالَ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكَ إِنْ رَأَيْتُنَّ ذَلِكَ بِمَاءٍ وَسِدْرٍ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي قَالَتْ فَلَمَّا فَرَغْنَا أَلْقَى إِلَيْنَا حِقْوَهُ فَقَالَ أَشْعِرْنَهَا إِيَّاهُ وَلَمْ يَزِدْ عَلَى ذَلِكَوَلَا أَدْرِي أَيُّ بَنَاتِهِ وَزَعَمَ أَنَّ الْإِشْعَارَ الْفُفْنَهَا فِيهِ وَكَذَلِكَ كَانَ ابْنُ سِيرِينَ يَأْمُرُ بِالْمَرْأَةِ أَنْ تُشْعَرَ وَلَا تُؤْزَرَ","id":"Telah menceritakan kepada kami [Ahmad] telah menceritakan kepada kami ['Abdullah bin Wahb] telah mengabarkan kepada kami [Ibnu Juraij] bahwa [Ayyub] yang mengabarkan kepadanya berkata; Aku mendengar [Ibnu Sirin] berkata: Telah datang [Ummu 'Athiyyah radliallahu 'anha] seorang diantara wanita Anshar yang pernah berbai'at kepada Nabi shallallahu 'alaihi wasallam sekembalinya dari Bashrah untuk menemui anaknya disana, namun dia tidak menemukannya lalu dia menceritakan kepada kami, katanya: \"Nabi shallallahu 'alaihi wasallam menemui kami saat kami sedang memandikan putri Beliau yang wafat lalu berkata: \"Mandikanlah ia dengan mengguyurkan air yang dicampur dengan daun bidara tiga kali, lima kali atau lebih dari itu jika kalian anggap perlu dan jadikanlah yang terakhirnya dengan kafur barus dan bila kalian telah selesai beritahu aku\". Berkata, Ummu 'Athiyyah radliallahu 'anha: \"Ketika kami telah selesai, Beliau kemudian memberikan kain Beliau kepada kami seraya berkata: \"Pakaikanlah ini kepadanya\". Dan Beliau tidak memerintahkan lebih dari itu dan aku sendiri sudah tidak ingat puteri Beliau mana yang meninggal saat itu\". Ayyub berpendapat memakaikan kain maksudnya adalah menutupi seluruh badan mayat perempuan. Dan begitu juga bahwa Ibnu Sirin memerintahkan agar untuk jenazah perempuan ditutupi selluruh bagian badannya bukan hanya bagian bawahnya."},"1183":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ أُمِّ الْهُذَيْلِ عَنْ أُمِّ عَطِيَّةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْضَفَرْنَا شَعَرَ بِنْتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعْنِي ثَلَاثَةَ قُرُونٍوَقَالَ وَكِيعٌ قَالَ سُفْيَانُ نَاصِيَتَهَا وَقَرْنَيْهَا","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Hisyam] dari [Ummu Al Hudzail] dari [Ummu 'Athiyyah radliallahu 'anha] berkata: \"Kami menjalin (rambut) keala putri Nabi shallallahu 'alaihi wasallam menjadi tiga ikatan (kepang) \". Berkata, [Waki'] berkata, [Sufyan]: \"Diikat kepang dan diketakkan di belakangnya\"."},"1184":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامِ بْنِ حَسَّانٍ قَالَ حَدَّثَتْنَا حَفْصَةُ عَنْ أُمِّ عَطِيَّةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْتُوُفِّيَتْ إِحْدَى بَنَاتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَانَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اغْسِلْنَهَا بِالسِّدْرِ وِتْرًا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكَ إِنْ رَأَيْتُنَّ ذَلِكَ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي فَلَمَّا فَرَغْنَا آذَنَّاهُ فَأَلْقَى إِلَيْنَا حِقْوَهُ فَضَفَرْنَا شَعَرَهَا ثَلَاثَةَ قُرُونٍ وَأَلْقَيْنَاهَا خَلْفَهَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada saya [Yahya bin Sa'id] dari [Hisyam bin Hassan] berkata, telah menceritakan kepada kami [Hafshah] dari [Ummu 'Athiyyah radliallahu 'anha] berkata: Ketika salah satu puteri Nabi shallallahu 'alaihi wasallam wafat, Nabi shallallahu 'alaihi wasallam mendatangi kami seraya berkata: \"Mandikanlah menggunakan daun bidara dengan ganjil, tiga kali, lima kali atau lebih dari itu jika kalian anggap perlu dan jadikanlah yang terakhirnya dengan kafur barus (wewangian) atau yang sejenis dari kapur barus (kamper). Dan bila kalian telah selesai beritahu aku\". Ketika kami telah selesai, kami memberi tahu Beliau, kemudian Beliau memberikan kain Beliau kepada kami. Maka kami menyisir (dan menguraikan lalu mengepangnya) rambut kepalanya menjadi tiga kepang dan kami letakkan di belakangnya\"."},"1185":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُفِّنَ فِي ثَلَاثَةِ أَثْوَابٍ يَمَانِيَةٍ بِيضٍ سَحُولِيَّةٍ مِنْ كُرْسُفٍ لَيْسَ فِيهِنَّ قَمِيصٌ وَلَا عِمَامَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami ['Abdullah bin Al Mubarak] telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha] bahwa Rasulullah shallallahu 'alaihi wasallam (ketika wafat) dikafani jasadnya dengan tiga helai kain yang sangat putih terbuat dari katun dari negeri Yaman dan tidak dikenakan padanya baju dan serban (tutup kepala)."},"1186":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمْ قَالَبَيْنَمَا رَجُلٌ وَاقِفٌ بِعَرَفَةَ إِذْ وَقَعَ عَنْ رَاحِلَتِهِ فَوَقَصَتْهُ أَوْ قَالَ فَأَوْقَصَتْهُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْسِلُوهُ بِمَاءٍ وَسِدْرٍ وَكَفِّنُوهُ فِي ثَوْبَيْنِ وَلَا تُحَنِّطُوهُ وَلَا تُخَمِّرُوا رَأْسَهُ فَإِنَّهُ يُبْعَثُ يَوْمَ الْقِيَامَةِ مُلَبِّيًا","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhum] berkata; \"Ada seorang laki-laki ketika sedang wukuf di 'Arafah terjatuh dari hewan tunggangannya sehingga ia terinjak\" atau dia Ibnu 'Abbas radliallahu 'anhuma berkata: \"Hingga orang itu mati seketika\". Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Mandikanlah dia dengan air yang dicampur daun bidara dan kafanilah dengan dua helai kain dan janganlah diberi wewangian dan jangan pula diberi tutup kepala (serban) karena dia nanti akan dibangkitkan pada hari qiyamat dalam keadaan bertalbiyyah\"."},"1187":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَبَيْنَمَا رَجُلٌ وَاقِفٌ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَةَ إِذْ وَقَعَ مِنْ رَاحِلَتِهِ فَأَقْصَعَتْهُ أَوْ قَالَ فَأَقْعَصَتْهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْسِلُوهُ بِمَاءٍ وَسِدْرٍ وَكَفِّنُوهُ فِي ثَوْبَيْنِ وَلَا تُحَنِّطُوهُ وَلَا تُخَمِّرُوا رَأْسَهُ فَإِنَّ اللَّهَ يَبْعَثُهُ يَوْمَ الْقِيَامَةِ مُلَبِّيًا","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; \"Ada seorang laki-laki yang sedang wukuf di 'Arafah bersama Rasulullah shallallahu 'alaihi wasallam lalu dia terjatuh dari hewan tunggangannya sehingga ia terinjak\" atau dia Ibnu 'Abbas radliallahu 'anhuma berkata: \"Hingga orang itu mati seketika\". Maka Rasulullah shallallahu 'alaihi wasallam berkata: \"Mandikanlah dia dengan air yang dicampur daun bidara dan kafanilah dengan dua helai kain dan janganlah diberi wewangian dan jangan pula diberi tutup kepalanya (serban) karena dia nanti akan dibangkitkan pada hari qiyamat dalam keadaan bertalbiyyah\"."},"1188":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمْأَنَّ رَجُلًا وَقَصَهُ بَعِيرُهُ وَنَحْنُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُحْرِمٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْسِلُوهُ بِمَاءٍ وَسِدْرٍ وَكَفِّنُوهُ فِي ثَوْبَيْنِ وَلَا تُمِسُّوهُ طِيبًا وَلَا تُخَمِّرُوا رَأْسَهُ فَإِنَّ اللَّهَ يَبْعَثُهُ يَوْمَ الْقِيَامَةِ مُلَبِّيًا","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah mengabarkan kepada kami [Abu 'Awanah] dari [Abu Bisyir] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas Ram]; Bahwa ada seorang laki-laki yang sedang berihram dijatuhkan oleh untanya yang saat itu kami sedang bersama Nabi shallallahu 'alaihi wasallam. Maka Nabi shallallahu 'alaihi wasallam berkata: \"Mandikanlah dia dengan air yang dicampur daun bidara dan kafanilah dengan dua helai kain dan janganlah diberi wewangian dan jangan pula diberi tutup kepala (serban) karena dia nanti akan dibangkitkan pada hari qiyamat dalam keadaan bertalbiyyah\"."},"1189":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرٍو وَأَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمْ قَالَكَانَ رَجُلٌ وَاقِفٌ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَةَ فَوَقَعَ عَنْ رَاحِلَتِهِ قَالَ أَيُّوبُ فَوَقَصَتْهُ وَقَالَ عَمْرٌو فَأَقْصَعَتْهُ فَمَاتَ فَقَالَ اغْسِلُوهُ بِمَاءٍ وَسِدْرٍ وَكَفِّنُوهُ فِي ثَوْبَيْنِ وَلَا تُحَنِّطُوهُ وَلَا تُخَمِّرُوا رَأْسَهُ فَإِنَّهُ يُبْعَثُ يَوْمَ الْقِيَامَةِ قَالَ أَيُّوبُ يُلَبِّي وَقَالَ عَمْرٌو مُلَبِّيًا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Amru] dan [Ayyub] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhu] berkata; \"Ada seorang laki-laki ketika sedang wukuf bersama Nabi shallallahu 'alaihi wasallam di 'Arafah terjatuh dari hewan tunggangannya\". Berkata, Ayyub: \"Maka hewannya itu mematahkan lehernya\". Dan berkata, 'Amru: \"Maka hewannya itu menginjaknya\". Lalu orang itu meninggal. Sehingga ia terinjak\" atau dia Ibnu 'Abbas radliallahu 'anhuma berkata: \"Hingga orang itu mati seketika\". Maka Beliau shallallahu 'alaihi wasallam berkata: \"Mandikanlah dia dengan air yang dicampur daun bidara dan kafanilah dengan dua helai kain dan janganlah diberi wewangian dan jangan pula diberi tutup kepala (serban) karena dia nanti akan dibangkitkan pada hari qiyamat…Menurut Ayyub berkata: \"sedang membaca talbiyyah\". Dan menurut 'Amru: \"sebagai orang yang bertalbiyyah\"."},"1190":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ عَبْدَ اللَّهِ بْنَ أُبَيٍّ لَمَّا تُوُفِّيَ جَاءَ ابْنُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَعْطِنِي قَمِيصَكَ أُكَفِّنْهُ فِيهِ وَصَلِّ عَلَيْهِ وَاسْتَغْفِرْ لَهُ فَأَعْطَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَمِيصَهُ فَقَالَ آذِنِّي أُصَلِّي عَلَيْهِ فَآذَنَهُ فَلَمَّا أَرَادَ أَنْ يُصَلِّيَ عَلَيْهِ جَذَبَهُ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فَقَالَ أَلَيْسَ اللَّهُ نَهَاكَ أَنْ تُصَلِّيَ عَلَى الْمُنَافِقِينَ فَقَالَ أَنَا بَيْنَ خِيَرَتَيْنِ قَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَنْ يَغْفِرَ اللَّهُ لَهُمْ }فَصَلَّى عَلَيْهِ فَنَزَلَتْ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] berkata, telah menceritakan kepada saya [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] bahwa ketika 'Abdullah bin Ubay wafat, anaknya datang menemui Nabi shallallahu 'alaihi wasallam lalu berkata: \"Wahai Rasulullah shallallahu 'alaihi wasallam: \"Berikanlah kepadaku baju anda untuk aku gunakan mengafani (ayahku) dan shalatlah untuknya serta mohonkanlah ampunan baginya\". Maka Nabi shallallahu 'alaihi wasallam memberikan bajunya kepadanya lalu berkata: \"izinkanlah aku untuk menshalatkannya\". Ketika Beliau hendak menshalatkannya tiba-tiba 'Umar bin Al Khaththab radliallahu 'anhu datang menarik Beliau seraya berkata: \"Bukankah Allah telah melarang anda untuk menshalatkan orang munafiq?\" Maka Beliau bersabda: \"Aku berada pada dua pilihan dari firman Allah Ta'ala (QS. At-Taubah ayat 80, yang artinya): \"Kamu mohonkan ampun buat mereka atau kamu tidak mohonkan ampun buat mereka (sama saja bagi mereka). Sekalipun kamu memohonkan ampun buat mereka sebanyak tujuh puluh kali, Allah sekali-kali tidak akan mengampuni mereka\". Maka Beliau shallallahu 'alaihi wasallam menshalatkannya. Lalu turunlah ayat: (QS. At-Taubah ayat 84 yang artinya): \"Janganlah kamu shalatkan seorangpun yang mati dari mereka selamanya dan janganlah kamu berdiri di atas kuburannya\"."},"1191":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ عَمْرٍو سَمِعَ جَابِرًا رَضِيَ اللَّهُ عَنْهُ قَالَأَتَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدَ اللَّهِ بْنَ أُبَيٍّ بَعْدَ مَا دُفِنَ فَأَخْرَجَهُ فَنَفَثَ فِيهِ مِنْ رِيقِهِ وَأَلْبَسَهُ قَمِيصَهُ","id":"Telah menceritakan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Ibnu 'Uyainah] dari ['Amru] bahwa dia mendengar [Jabir radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam mendatangi (jenazah) 'Abdullah bin Ubay setelah dimasukkan dalam kubur lalu Beliau mengeluarkannya, memberkahi dengan ludahnya dan memakaikan dengan baju Beliau kepadanya\"."},"1192":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكُفِّنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَلَاثَةِ أَثْوَابِ سُحُولٍ كُرْسُفٍ لَيْسَ فِيهَا قَمِيصٌ وَلَا عِمَامَةٌ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Hisyam] dari ['Urwah] dari ['Aisyah radliallahu 'anha] berkata: Nabi shallallahu 'alaihi wasallam (ketika wafat) dikafani jasadnya dengan tiga helai kain yang sangat putih terbuat dari katun dari dan tidak dikenakan padanya baju dan serban (tutup kepala)."},"1193":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ حَدَّثَنِي أَبِي عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُفِّنَ فِي ثَلَاثَةِ أَثْوَابٍ لَيْسَ فِيهَا قَمِيصٌ وَلَا عِمَامَةٌ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Hisyam] telah menceritakan kepadaku [bapaknya] dari ['Aisyah radliallahu 'anha] bahwa Rasulullah shallallahu 'alaihi wasallam (ketika wafat) dikafani jasadnya dengan tiga helai kain dan tidak dikenakan padanya baju dan serban (tutup kepala)."},"1194":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُفِّنَ فِي ثَلَاثَةِ أَثْوَابٍ بِيضٍ سَحُولِيَّةٍ لَيْسَ فِيهَا قَمِيصٌ وَلَا عِمَامَةٌ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada saya [Malik] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah radliallahu 'anha] bahwa Rasulullah shallallahu 'alaihi wasallam (ketika wafat) dikafani jasadnya dengan tiga helai kain yang sangat putih terbuat dari katun dan tidak dikenakan padanya baju dan serban (tutup kepala)."},"1195":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَكِّيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ سَعْدٍ عَنْ أَبِيهِ قَالَ أُتِيَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ رَضِيَ اللَّهُ عَنْهُيَوْمًا بِطَعَامِهِ فَقَالَ قُتِلَ مُصْعَبُ بْنُ عُمَيْرٍ وَكَانَ خَيْرًا مِنِّي فَلَمْ يُوجَدْ لَهُ مَا يُكَفَّنُ فِيهِ إِلَّا بُرْدَةٌ وَقُتِلَ حَمْزَةُ أَوْ رَجُلٌ آخَرُ خَيْرٌ مِنِّي فَلَمْ يُوجَدْ لَهُ مَا يُكَفَّنُ فِيهِ إِلَّا بُرْدَةٌ لَقَدْ خَشِيتُ أَنْ يَكُونَ قَدْ عُجِّلَتْ لَنَا طَيِّبَاتُنَا فِي حَيَاتِنَا الدُّنْيَا ثُمَّ جَعَلَ يَبْكِي","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Makkiy] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Saad] dari [bapaknya] ia berkata; Pada suatu hari ['Abdurrahman bin 'Auf] dihidangkan makanan kepadanya, lalu ia berkata, Mus'ab bin Umair telah terbunuh. Ia adalah orang yang lebih baik dariku, namun saat (hendak dikafani) tidak ada kain kafan yang bisa membungkusnya kecuali hanyalah burdah (kain bergaris). Dan Hamzah terbunuh atau orang lain yang lebih baik dariku lalu tidak ada kain yang bisa dijadikan kafan untuknya kecuali burdah. Aku khawatir jika kebaikan-kebakan kita disegerakan didunia ini. Lalu ia mulai menangis."},"1196":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِيهِ إِبْرَاهِيمَ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ رَضِيَ اللَّهُ عَنْهُأُتِيَ بِطَعَامٍ وَكَانَ صَائِمًا فَقَالَ قُتِلَ مُصْعَبُ بْنُ عُمَيْرٍ وَهُوَ خَيْرٌ مِنِّي كُفِّنَ فِي بُرْدَةٍ إِنْ غُطِّيَ رَأْسُهُ بَدَتْ رِجْلَاهُ وَإِنْ غُطِّيَ رِجْلَاهُ بَدَا رَأْسُهُ وَأُرَاهُ قَالَ وَقُتِلَ حَمْزَةُ وَهُوَ خَيْرٌ مِنِّي ثُمَّ بُسِطَ لَنَا مِنْ الدُّنْيَا مَا بُسِطَ أَوْ قَالَ أُعْطِينَا مِنْ الدُّنْيَا مَا أُعْطِينَا وَقَدْ خَشِينَا أَنْ تَكُونَ حَسَنَاتُنَا عُجِّلَتْ لَنَا ثُمَّ جَعَلَ يَبْكِي حَتَّى تَرَكَ الطَّعَامَ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Syu'nah] dari [Sa'ad bin Ibrahim] dari bapaknya [Ibrahim] bahwa; \"Pada suatu hari ['Abdurrahman bin 'Auf] dihidangkan makanan kepadanya saat itu ia sedang berpuasa. Lalu ia berkata, Mus'ab bin Umair telah terbunuh. Ia adalah orang yang lebih baik dariku, namun saat (hendak dikafani) tidak ada kain kafan yang bisa membungkusnya kecuali hanyalah burdah (kain bergaris) yang apabila kepalanya akan ditutup, kakinya terbuka (karena kain yang pendek) dan bila kakinya yang hendak ditutup kepalanyalah yang terbuka. Dan aku melihat dia berkata, pula; \"Hamzah pun atau orang lain yang lebih baik dariku telah terbunuh. Kemudian setelah itu dunia telah dibukakan buat kami atau katanya kami telah diberi kenikmatan dunia dan sungguh kami khawatir bila kebaikan-kebaikan kami disegerakan balasannya buat kami (berupa kenikmatan dunia). Lalu ia pun mulai menangis."},"1197":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا شَقِيقٌ حَدَّثَنَا خَبَّابٌ رَضِيَ اللَّهُ عَنْهُ قَالَهَاجَرْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَلْتَمِسُ وَجْهَ اللَّهِ فَوَقَعَ أَجْرُنَا عَلَى اللَّهِ فَمِنَّا مَنْ مَاتَ لَمْ يَأْكُلْ مِنْ أَجْرِهِ شَيْئًا مِنْهُمْ مُصْعَبُ بْنُ عُمَيْرٍ وَمِنَّا مَنْ أَيْنَعَتْ لَهُ ثَمَرَتُهُ فَهُوَ يَهْدِبُهَا قُتِلَ يَوْمَ أُحُدٍ فَلَمْ نَجِدْ مَا نُكَفِّنُهُ إِلَّا بُرْدَةً إِذَا غَطَّيْنَا بِهَا رَأْسَهُ خَرَجَتْ رِجْلَاهُ وَإِذَا غَطَّيْنَا رِجْلَيْهِ خَرَجَ رَأْسُهُ فَأَمَرَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُغَطِّيَ رَأْسَهُ وَأَنْ نَجْعَلَ عَلَى رِجْلَيْهِ مِنْ الْإِذْخِرِ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh bin Ghiyats] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Syaqiq] telah menceritakan kepada kami [Khabab radliallahu 'anhu] berkata; Kami berhijrah bersama Nabi shallallahu 'alaihi wasallam dengan hanya mengharapkan ridha Allah dan kami telah mendapatkan pahala di sisi Allah. Lalu diantara kami ada yang meninggal lebih dahulu sebelum menikmati pahalanya sedikitpun (di dunia ini), diantaranya adalah Mus'ab bin Umair. Dan diantara kami ada yang buah (perjuangannya) sudah masak lalu dia memetiknya dengan terbunuh sebagai syahid di medan Perang Uhud namun kami tidak mendapatkan kain untuk mengafaninya kecuali burdah (kain bergaris) yang kain tersebut bila kami gunakan untuk menutup kepalanya, kakinya terbuka dan bila kakinya yang hendak kami tutup kepalanyalah yang terbuka. Maka kemudian Nabi shallallahu 'alaihi wasallam memerintahkan kami untuk menutup kepalanya dengan kain tersebut sedangkan kakinya kami tutup dengan dedaunan\"."},"1198":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا ابْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلٍ رَضِيَ اللَّهُ عَنْهُأَنَّ امْرَأَةً جَاءَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبُرْدَةٍ مَنْسُوجَةٍ فِيهَا حَاشِيَتُهَا أَتَدْرُونَ مَا الْبُرْدَةُ قَالُوا الشَّمْلَةُ قَالَ نَعَمْ قَالَتْ نَسَجْتُهَا بِيَدِي فَجِئْتُ لِأَكْسُوَكَهَا فَأَخَذَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُحْتَاجًا إِلَيْهَا فَخَرَجَ إِلَيْنَا وَإِنَّهَا إِزَارُهُ فَحَسَّنَهَا فُلَانٌ فَقَالَ اكْسُنِيهَا مَا أَحْسَنَهَا قَالَ الْقَوْمُ مَا أَحْسَنْتَ لَبِسَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُحْتَاجًا إِلَيْهَا ثُمَّ سَأَلْتَهُ وَعَلِمْتَ أَنَّهُ لَا يَرُدُّ قَالَ إِنِّي وَاللَّهِ مَا سَأَلْتُهُ لِأَلْبَسَهُ إِنَّمَا سَأَلْتُهُ لِتَكُونَ كَفَنِي قَالَ سَهْلٌ فَكَانَتْ كَفَنَهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] telah menceritakan kepada kami [Ibnu Abu Hazim] dari [bapaknya] dari [Sahal radliallahu 'anhu] bahwa ada seorang wanita mendatangi Nabi shallallahu 'alaihi wasallam dengan membawa burdah yang pinggirnya berjahit. (Sahal) berkata; \"Tahukah kamu apa yang dimaksud dengan burdah?\" Mereka menjawab: \"Bukankah itu kain selimut?\" Dia berkata: \"Ya benar\". Wanita itu berkata: \"Aku menjahitnya dengan tanganku sendiri, dan aku datang untuk memakaikannya kepada anda\". Maka Nabi shallallahu 'alaihi wasallam mengambilnya karena Beliau memerlukannya. Kemudian Beliau menemui kami dengan mengenakan kain tersebut. Diantara kami ada seseorang yang tertarik dengan kain tersebut lalu berkata: \"Alangkah bagusnya kain ini\". Orang-orang berkata, kepada orang itu: \"Mengapa kamu memuji apa yang dipakai oleh Nabi shallallahu 'alaihi wasallam lalu kamu memintanya padahal kamu tahu bahwa Beliau tidak akan menolak (permintaan orang). Orang itu menjawab: \"Demi Allah, sungguh aku tidak memintanya untuk aku pakai. Sesungguhnya aku memintanya untuk aku jadikan sebagai kain kafanku\". Sahal berkata: \"Akhirnya memang kain itu yang jadi kain kafannya\"."},"1199":{"ar":"حَدَّثَنَا قَبِيصَةُ بْنُ عُقْبَةَ حَدَّثَنَا سُفْيَانُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أُمِّ الْهُذَيْلِ عَنْ أُمِّ عَطِيَّةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْنُهِينَا عَنْ اتِّبَاعِ الْجَنَائِزِ وَلَمْ يُعْزَمْ عَلَيْنَا","id":"Telah menceritakan kepada kami [Qabishah bin 'Uqbah] telah menceritakan kepada kami [Sufyan] dari [Khalid Al Hadza'] dari [Ummu AL Hudzail] dari [Ummu 'Athiyyah radliallahu 'anha] berkata: \"Kami dilarang mengantar jenazah namun Beliau tidak menekankan hal tersebut kepada kami\"."},"1200":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا سَلَمَةُ بْنُ عَلْقَمَةَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَ تُوُفِّيَ ابْنٌ لِأُمِّ عَطِيَّةَ رَضِيَ اللَّهُ عَنْهَافَلَمَّا كَانَ الْيَوْمُ الثَّالِثُ دَعَتْ بِصُفْرَةٍ فَتَمَسَّحَتْ بِهِ وَقَالَتْ نُهِينَا أَنْ نُحِدَّ أَكْثَرَ مِنْ ثَلَاثٍ إِلَّا بِزَوْجٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyir bin Al Mufadhdhal] telah menceritakan kepada kami [Salamah bin 'Alqamah] dari [Muhammad bin Sirin] berkata: Telah wafat anak [Ummu 'Athiyyah] radliallahu 'anha. Pada hari ketiga (dari kematian anaknya) dia meminta wewangian, lalu memakainya kemudian berkata: \"Kami dilarang berkabung melebihi tiga hari kecuali bila ditinggal mati suaminya\"."},"1201":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَيُّوبُ بْنُ مُوسَى قَالَ أَخْبَرَنِي حُمَيْدُ بْنُ نَافِعٍ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ قَالَتْلَمَّا جَاءَ نَعْيُ أَبِي سُفْيَانَ مِنْ الشَّأْمِ دَعَتْ أُمُّ حَبِيبَةَ رَضِيَ اللَّهُ عَنْهَا بِصُفْرَةٍ فِي الْيَوْمِ الثَّالِثِ فَمَسَحَتْ عَارِضَيْهَا وَذِرَاعَيْهَا وَقَالَتْ إِنِّي كُنْتُ عَنْ هَذَا لَغَنِيَّةً لَوْلَا أَنِّي سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ تُحِدَّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثٍ إِلَّا عَلَى زَوْجٍ فَإِنَّهَا تُحِدُّ عَلَيْهِ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah menceritakan kepada kami [Al Humaidiy] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Ayyub bin Musa] berkata, telah mengabarkan kepada saya [Humaid bin Nafi'] dari [Zainab binti Abu Salamah] berkata; Ketika kabar kematian Abu Sufyan sampai dari negeri Syam, [Ummu Habibah] radliallahu 'anha meminta wewangian pada hari ketiga lalu memakainya untuk bagian sisi badannya dan lengannya dan berkata; Sungguh bagiku ini sudah cukup seandainya aku tidak mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Tidak halal bagi wanita yang beriman kepada Allah dan Hari Akhir untuk berkabung melebihi tiga hari kecuali bila ditinggal mati suaminya yang saat itu dia boleh berkabung sampai empat bulan sepuluh hari\"."},"1202":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ حُمَيْدِ بْنِ نَافِعٍ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ أَخْبَرَتْهُ قَالَتْ دَخَلْتُ عَلَى أُمِّ حَبِيبَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ تُحِدُّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثٍ إِلَّا عَلَى زَوْجٍ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا ثُمَّ دَخَلْتُ عَلَى زَيْنَبَ بِنْتِ جَحْشٍ حِينَ تُوُفِّيَ أَخُوهَا فَدَعَتْ بِطِيبٍ فَمَسَّتْ بِهِ ثُمَّ قَالَتْ مَا لِي بِالطِّيبِ مِنْ حَاجَةٍ غَيْرَ أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ يَقُولُ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ تُحِدُّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثٍ إِلَّا عَلَى زَوْجٍ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada saya [Malik] dari ['Abdullah bin Abu Bakar bin Muhammad bin 'Amru bin Hazm] dari [Humaid bin Nafi'] dari [Zainab binti Abu Salamah] bahwa dia mengabarkannya, katanya; Aku pernah menemui [Ummu Habibah] radliallahu 'anha, isteri Nabi Shallallahu'alaihiwasallam. Lalu dia berkata; Aku mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak halal bagi wanita yang beriman kepada Allah dan Hari Akhir untuk berkabung melebihi tiga hari kecuali bila ditinggal mati suaminya yang saat itu dia boleh berkabung sampai empat bulan sepuluh hari\". Lalu aku menemui [Zainab binti Jahsy] ketika saudara laki-lakinya meninggal dunia. Saat itu dia meminta minyak wangi lalu memakainya kemudian berkata, \"Aku sebenarnya tidak memerlukan minyak wangi seandainya aku tidak mendengar Rasulullah Shallallahu'alaihiwasallam bersabda dari atas mimbar: tidak halal bagi seorang wanita yang beriman kepada Allah dan hari akhir berkabung atas mayit melebihi tiga hari selain karena kematian suaminya, boleh hingga empat bulan sepuluh hari. "},"1203":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِامْرَأَةٍ تَبْكِي عِنْدَ قَبْرٍ فَقَالَ اتَّقِي اللَّهَ وَاصْبِرِي قَالَتْ إِلَيْكَ عَنِّي فَإِنَّكَ لَمْ تُصَبْ بِمُصِيبَتِي وَلَمْ تَعْرِفْهُ فَقِيلَ لَهَا إِنَّهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَتْ بَابَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ تَجِدْ عِنْدَهُ بَوَّابِينَ فَقَالَتْ لَمْ أَعْرِفْكَ فَقَالَ إِنَّمَا الصَّبْرُ عِنْدَ الصَّدْمَةِ الْأُولَى","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Tsabit] dari [Anas bin Malik radliallahu 'anhu] berkata,: Nabi Shallallahu'alaihiwasallam pernah berjalan melewati seorang wanita yang sedang menangis di sisi kubur. Maka Beliau berkata,: \"Bertakwalah kepada Allah dan bersabarlah\". Wanita itu berkata,: \"Kamu tidak mengerti keadaan saya, karena kamu tidak mengalami mushibah seperti yang aku alami\". Wanita itu tidak mengetahui jika yang menasehati itu Nabi Shallallahu'alaihiwasallam. Lalu diberi tahu: \"Sesungguhnya orang tadi adalah Nabi Shallallahu'alaihiwasallam. Spontan wanita tersebut mendatangi rumah Nabi Shallallahu'alaihiwasallam namun dia tidak menemukannya. Setelah bertemu dia berkata; \"Maaf, tadi aku tidak mengetahui anda\". Maka Beliau bersabda: \"Sesungguhnya sabar itu pada kesempatan pertama (saat datang mushibah) \"."},"1204":{"ar":"حَدَّثَنَا عَبْدَانُ وَمُحَمَّدٌ قَالَا أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عَاصِمُ بْنُ سُلَيْمَانَ عَنْ أَبِي عُثْمَانَ قَالَ حَدَّثَنِي أُسَامَةُ بْنُ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَرْسَلَتْ ابْنَةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهِ إِنَّ ابْنًا لِي قُبِضَ فَأْتِنَا فَأَرْسَلَ يُقْرِئُ السَّلَامَ وَيَقُولُ إِنَّ لِلَّهِ مَا أَخَذَ وَلَهُ مَا أَعْطَى وَكُلٌّ عِنْدَهُ بِأَجَلٍ مُسَمًّى فَلْتَصْبِرْ وَلْتَحْتَسِبْ فَأَرْسَلَتْ إِلَيْهِ تُقْسِمُ عَلَيْهِ لَيَأْتِيَنَّهَا فَقَامَ وَمَعَهُ سَعْدُ بْنُ عُبَادَةَ وَمَعَاذُ بْنُ جَبَلٍ وَأُبَيُّ بْنُ كَعْبٍ وَزَيْدُ بْنُ ثَابِتٍ وَرِجَالٌ فَرُفِعَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّبِيُّ وَنَفْسُهُ تَتَقَعْقَعُ قَالَ حَسِبْتُهُ أَنَّهُ قَالَ كَأَنَّهَا شَنٌّ فَفَاضَتْ عَيْنَاهُ فَقَالَ سَعْدٌ يَا رَسُولَ اللَّهِ مَا هَذَا فَقَالَ هَذِهِ رَحْمَةٌ جَعَلَهَا اللَّهُ فِي قُلُوبِ عِبَادِهِ وَإِنَّمَا يَرْحَمُ اللَّهُ مِنْ عِبَادِهِ الرُّحَمَاءَ","id":"Telah menceritakan kepada kami ['Abdan] dan [Muhammad] keduanya berkata, telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami ['Ashim bin Sulaiman] dari [Abu 'Utsman] berkata, telah menceritakan kepada saya [Usamah bin Zaid radliallahu 'anhuma] berkata; Putri Nabi Shallallahu'alaihiwasallam datang untuk menemui Beliau dan mengabarkan bahwa; \"Anakku telah meninggal, maka datanglah kepada kami\". Maka Nabi Shallallahu'alaihiwasallam memerintahkannya untuk menyampaikan salam lalu bersabda: \"Sesungguhnya milik Allah apa yang diambilNya dan apa yang diberiNya. Dan segala sesuatu disisiNya sesudah ditentukan ajalnya, maka bersabarlah engkau karenanya dan mohonkanlah pahala darinya.\" Kemudian dia datang lagi kepada Beliau dan meminta dengan sangat agar Beliau bisa datang. Maka Beliau berangkat, bersamanya ada Sa'ad bin 'Ubadah, Mu'adz bin Jabal, Ubay bin Ka'ab, Zaid bin Tsabit dan beberapa orang lain. Kemudian bayi tersebut diserahkan kepada Nabi Shallallahu'alaihiwasallam dan hati Beliau nampak berguncang (karena bersedih). Aku menduga dia berkata,: Seakan dia seperti geriba yang kosong. Maka mengalirlah air mata Beliau. Sa'ad berkata,: \"Wahai Rasulullah, mengapakah engkau menangis? Beliau berkata,: \"Inilah rahmat yang Allah berikan kepada hati hamba-hambaNya dan sesungguhnya Allah akan merahmati diantara hamba-hambaNya mereka yang saling berkasih sayang\"."},"1205":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ هِلَالِ بْنِ عَلِيٍّ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَشَهِدْنَا بِنْتًا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ عَلَى الْقَبْرِ قَالَ فَرَأَيْتُ عَيْنَيْهِ تَدْمَعَانِ قَالَ فَقَالَ هَلْ مِنْكُمْ رَجُلٌ لَمْ يُقَارِفْ اللَّيْلَةَ فَقَالَ أَبُو طَلْحَةَ أَنَا قَالَ فَانْزِلْ قَالَ فَنَزَلَ فِي قَبْرِهَا","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Abu 'Amir] telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Hilal bin 'Ali] dari [Anas bin Malik radliallahu 'anhu] berkata,: \"Kami menyaksikan pemakaman puteri Nabi Shallallahu'alaihiwasallam.\" Dia (Anas bin Malik radliallahu 'anhu) berkata,: \"Dan saat itu Rasulullah Shallallahu'alaihiwasallam duduk disisi liang lahad. Dia (Anas bin Malik radliallahu 'anhu) berkata,: Lalu aku melihat kedua mata Beliau mengucurkan air mata\". Dia (Anas bin Malik radliallahu 'anhu) berkata,: Maka Beliau bertanya: \"Siapakah diantara kalian yang malam tadi tidak berhubungan (dengan isterinya)?\". Berkata Abu Tholhah: \"Aku\". Beliau berkata,: \"Turunlah engkau ke lahad!\". Dia (Anas bin Malik radliallahu 'anhu) berkata,: \"Maka Beliaupun ikut turun kedalam kuburnya\". "},"1206":{"ar":"حَدَّثَنَا عَبْدَانُ حَدَّثَنَا عَبْدُ اللَّهِ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عُبَيْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ قَالَتُوُفِّيَتْ ابْنَةٌ لِعُثْمَانَ رَضِيَ اللَّهُ عَنْهُ بِمَكَّةَ وَجِئْنَا لِنَشْهَدَهَا وَحَضَرَهَا ابْنُ عُمَرَ وَابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمْ وَإِنِّي لَجَالِسٌ بَيْنَهُمَا أَوْ قَالَ جَلَسْتُ إِلَى أَحَدِهِمَا ثُمَّ جَاءَ الْآخَرُ فَجَلَسَ إِلَى جَنْبِي فَقَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا لِعَمْرِو بْنِ عُثْمَانَ أَلَا تَنْهَى عَنْ الْبُكَاءِ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَيِّتَ لَيُعَذَّبُ بِبُكَاءِ أَهْلِهِ عَلَيْهِفَقَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَدْ كَانَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ يَقُولُ بَعْضَ ذَلِكَ ثُمَّ حَدَّثَ قَالَ صَدَرْتُ مَعَ عُمَرَ رَضِيَ اللَّهُ عَنْهُ مِنْ مَكَّةَ حَتَّى إِذَا كُنَّا بِالْبَيْدَاءِ إِذَا هُوَ بِرَكْبٍ تَحْتَ ظِلِّ سَمُرَةٍ فَقَالَ اذْهَبْ فَانْظُرْ مَنْ هَؤُلَاءِ الرَّكْبُ قَالَ فَنَظَرْتُ فَإِذَا صُهَيْبٌ فَأَخْبَرْتُهُ فَقَالَ ادْعُهُ لِي فَرَجَعْتُ إِلَى صُهَيْبٍ فَقُلْتُ ارْتَحِلْ فَالْحَقْ أَمِيرَ الْمُؤْمِنِينَ فَلَمَّا أُصِيبَ عُمَرُ دَخَلَ صُهَيْبٌ يَبْكِي يَقُولُ وَا أَخَاهُ وَا صَاحِبَاهُ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ يَا صُهَيْبُ أَتَبْكِي عَلَيَّ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمَيِّتَ يُعَذَّبُ بِبَعْضِ بُكَاءِ أَهْلِهِ عَلَيْهِ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا فَلَمَّا مَاتَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ ذَكَرْتُ ذَلِكَ لِعَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَقَالَتْ رَحِمَ اللَّهُ عُمَرَ وَاللَّهِ مَا حَدَّثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ لَيُعَذِّبُ الْمُؤْمِنَ بِبُكَاءِ أَهْلِهِ عَلَيْهِ وَلَكِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ لَيَزِيدُ الْكَافِرَ عَذَابًا بِبُكَاءِ أَهْلِهِ عَلَيْهِ وَقَالَتْ حَسْبُكُمْ الْقُرْآنُ{ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا عِنْدَ ذَلِكَ وَاللَّهُ{ هُوَ أَضْحَكَ وَأَبْكَى }قَالَ ابْنُ أَبِي مُلَيْكَةَ وَاللَّهِ مَا قَالَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا شَيْئًا","id":"Telah menceritakan kepada kami ['Abdan] telah menceritakan kepada kami ['Abdullah] telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepada saya ['Abdullah bin 'ubaidullah bin Abu Mulaikah] berkata; \"Telah wafat isteri 'Utsman radliallahu 'anha di Makkah lalu kami datang menyaksikan (pemakamannya). Hadir pula Ibnu 'Umar dan Ibnu 'Abbas radliallahu 'anhum dan saat itu aku duduk diantara keduanya\". Atau katanya: \"Aku duduk dekat salah satu dari keduanya\". Kemudian datang orang lain lalu duduk di sampingku. Berkata, [Ibnu 'Umar radliallahu 'anhuma] kepada 'Amru bin 'Utsman: \"Bukankan dilarang menangis dan sungguh Rasulullah Shallallahu'alaihiwasallam telah bersabda: \"Sesungguhnya mayat pasti akan disiksa disebabkan tangisan keluarganya kepadanya?\". Maka [Ibnu 'Abbas radliallahu 'anhuma] berkata,: \"Sungguh 'Umar radliallahu 'anhu pernah mengatakan sebagiannya dari hal tadi\". Kemudian dia menceritakan, katanya: \"Aku pernah bersama 'Umar radliallahu 'anhu dari kota Makkah hingga kami sampai di Al Baida, di tempat itu dia melihat ada orang yang menunggang hewan tunggangannya di bawah pohon. Lalu dia berkata,: \"Pergi dan lihatlah siapa mereka yang menunggang hewan tunggangannya itu!\". Maka aku datang melihatnya yang ternyata dia adalah Shuhaib. Lalu aku kabarkan kepadanya. Dia (\"Umar) berkata,: \"Panggillah dia kemari!\". Aku kembali menemui Shuhaib lalu aku berkata: \"Pergi dan temuilah Amirul Mu'minin\". Kemudian hari 'Umar mendapat musibah dibunuh orang, Shuhaib mendatanginya sambil menangis sambil terisak berkata,: Wahai saudaraku, wahai sahabat\". Maka ['Umar] berkata,: \"Wahai Shuhaib, mengapa kamu menangis untukku padahal Nabi Shallallahu'alaihiwasallam telah bersabda: \"Sesungguhnya mayat pasti akan disiksa disebabkan sebagian tangisan keluarganya \". Berkata, [Ibnu 'Abbas radliallahu 'anhuma]: \"Ketika 'Umar sudah wafat aku tanyakan masalah ini kepada ['Aisyah] radliallahu 'anha, maka dia berkata,: \"Semoga Allah merahmati 'Umar. Demi Allah, tidaklah Rasulullah Shallallahu'alaihiwasallam pernah berkata seperti itu, bahwa Allah pasti akan menyiksa orang beriman disebabkan tangisan keluarganya kepadanya, akan tetapi yang benar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Sesungguhnya Allah pasti akan menambah siksaan buat orang kafir disebabkan tangisan keluarganya kepadanya\". Dan cukuplah buat kalian firman Allah) dalam AL Qur'an (QS. An-Najm: 38) yang artinya: \"Dan tidaklah seseorang memikul dosa orang lain\". Ibnu 'Abbas radliallahu 'anhu berkata seketika itu pula: Dan Allahlah yang menjadikan seseorang tertawa dan menangis\" (QS. Annajm 43). Berkata Ibnu Abu Mulaikah: \"Demi Allah, setelah itu Ibnu 'Umar radliallahu 'anhu tidak mengucapkan sepatah kata pun\"."},"1207":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ أَنَّهَا أَخْبَرَتْهُ أَنَّهَا سَمِعَتْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْإِنَّمَا مَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى يَهُودِيَّةٍ يَبْكِي عَلَيْهَا أَهْلُهَا فَقَالَ إِنَّهُمْ لَيَبْكُونَ عَلَيْهَا وَإِنَّهَا لَتُعَذَّبُ فِي قَبْرِهَا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari ['Abdullah bin Abu Bakar] dari [bapaknya] dari ['Amrah binti 'Abdurrahman] ia mengabarkannya bahwasanya ia mendengar ['Aisyah radliallahu 'anha] isteri Nabi Shallallahu'alaihiwasallam berkata, Rasulullah Shallallahu'alaihiwasallam pernah melewati (kubur) seorang wanita yahudi yang suaminya menangisinya, lalu Beliau bersabda: \"Mereka sungguh menangisinya padahal ia sedang diadzab dikuburnya\"."},"1208":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ خَلِيلٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ حَدَّثَنَا أَبُو إِسْحَاقَ وَهْوَ الشَّيْبَانِيُّ عَنْ أَبِي بُرْدَةَ عَنْ أَبِيهِ قَالَلَمَّا أُصِيبَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ جَعَلَ صُهَيْبٌ يَقُولُ وَا أَخَاهُ فَقَالَ عُمَرُ أَمَا عَلِمْتَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَيِّتَ لَيُعَذَّبُ بِبُكَاءِ الْحَيِّ","id":"Telah menceritakan kepada kami [Isma'il bin Khalil] telah menceritakan kepada kami ['Ali bin Mushir] telah menceritakan kepada kami [Abu Ishaq] dia adalah dari suku Asy-Syaibaniy dari [Abu Burdah] dari [bapaknya] berkata; Ketika 'Umar radliallahu 'anhu terbunuh Shuhaib berkata, sambil menangis: \"Wahai saudaraku\". Maka ['Umar radliallahu 'anhu] berkata,: Bukankah kamu mengetahui bahwa Nabi Shallallahu'alaihiwasallam telah bersabda \"Sesungguhnya mayat pasti akan disiksa disebabkan tangisan orang yang masih hidup\"."},"1209":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سَعِيدُ بْنُ عُبَيْدٍ عَنْ عَلِيِّ بْنِ رَبِيعَةَ عَنْ الْمُغِيرَةِ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ كَذِبًا عَلَيَّ لَيْسَ كَكَذِبٍ عَلَى أَحَدٍ مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ نِيحَ عَلَيْهِ يُعَذَّبُ بِمَا نِيحَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sa'id bin 'Ubaid] dari ['Ali bin Rabi'ah] dari [Al Mughirah radliallahu 'anhu] berkata; Aku mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Sesungguhnya berdusta kepadaku tidak sama dengan orang yang berdusta kepada orang lain. Barangsiapa yang berdusta atas namaku dengan sengaja maka hendaklah dia bersiap-siap (mendapat) tempat duduknya di neraka. Aku juga mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang meratapi mayat maka mayat itu akan disiksa disebabkan ratapan kepadanya\"."},"1210":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنِي أَبِي عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ ابْنِ عُمَرَ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَيِّتُ يُعَذَّبُ فِي قَبْرِهِ بِمَا نِيحَ عَلَيْهِتَابَعَهُ عَبْدُ الْأَعْلَى حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ حَدَّثَنَا قَتَادَةُ وَقَالَ آدَمُ عَنْ شُعْبَةَ الْمَيِّتُ يُعَذَّبُ بِبُكَاءِ الْحَيِّ عَلَيْهِ","id":"Telah menceritakan kepada kami ['Abdan] berkata, telah mengabarkan [bapakku] kepadaku dari [Syu'bah] dari [Qatadah] dari [Sa'id AL Musayyab] dari [Ibnu 'Umar] dari [bapaknya radliallahu 'anhuma] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Mayat akan disiksa didalam kuburnya disebabkan ratapan kepadanya\". Hadits ini dikuatkan oleh ['Abdu Al A'laa] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] telah menceritakan kepada kami [Qatadah] dan berkata, [Adam] dari [Syu'bah]: \"Sesungguhnya mayat pasti akan disiksa disebabkan tangisan orang yang masih hidup kepadanya\"."},"1211":{"ar":"بَاب حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا ابْنُ الْمُنْكَدِرِ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَجِيءَ بِأَبِي يَوْمَ أُحُدٍ قَدْ مُثِّلَ بِهِ حَتَّى وُضِعَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ سُجِّيَ ثَوْبًا فَذَهَبْتُ أُرِيدُ أَنْ أَكْشِفَ عَنْهُ فَنَهَانِي قَوْمِي ثُمَّ ذَهَبْتُ أَكْشِفُ عَنْهُ فَنَهَانِي قَوْمِي فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُفِعَ فَسَمِعَ صَوْتَ صَائِحَةٍ فَقَالَ مَنْ هَذِهِ فَقَالُوا ابْنَةُ عَمْرٍو أَوْ أُخْتُ عَمْرٍو قَالَ فَلِمَ تَبْكِي أَوْ لَا تَبْكِي فَمَا زَالَتْ الْمَلَائِكَةُ تُظِلُّهُ بِأَجْنِحَتِهَا حَتَّى رُفِعَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Ibnu Al Munkadir] berkata; Aku mendengar [Jabir bin 'Abdullah radliallahu 'anhu] berkata,: \"Pada hari Perang Uhud, bapakku didatangkan dalam kondisi sudah terbunuh dengan bagian anggota badannya ada yang terpotong hingga diletakkan di hadapan Rasulullah Shallallahu'alaihiwasallam, sedangkan jasadnya sudah ditutup dengan kain. Maka aku menghampiri untuk membukanya namun kaumku mencegahku. Aku coba sekali lagi untuk membukanya namun kaumku tetap mencegahku hingga akhirnya Rasulullah Shallallahu'alaihiwasallam memerintahkan untuk diangkat (dibawa). Saat itu Beliau mendengar ada suara teriakan. Maka Beliau bertanya: \"(Suara) siapakah itu?\". Orang-orang menjawab: \"Putri dari 'Amru\" atau \"saudara perempuan 'Amru. Kemudian Beliau berkata,: \"Mengapa kamu menangis?\" atau \"Janganlah kamu menangis, karena malaikat senantiasa akan menaunginya dengan sayap-sayapnya hingga (jenazah) ini diangkat\"."},"1212":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا زُبَيْدٌ الْيَامِيُّ عَنْ إِبْرَاهِيمَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنَّا مَنْ لَطَمَ الْخُدُودَ وَشَقَّ الْجُيُوبَ وَدَعَا بِدَعْوَى الْجَاهِلِيَّةِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Zubaid Al Yamiy] dari [Ibrahim] dari [Masruq] dari ['Abdullah radliallahu 'anhu] berkata; Nabi Shallallahu'alaihiwasallam telah bersabda: \"Bukan dari golongan kami siapa yang menampar-nampar pipi, merobek-robek baju dan menyeru dengan seruan jahiliyyah (meratap) \"."},"1213":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي عَامَ حَجَّةِ الْوَدَاعِ مِنْ وَجَعٍ اشْتَدَّ بِي فَقُلْتُ إِنِّي قَدْ بَلَغَ بِي مِنْ الْوَجَعِ وَأَنَا ذُو مَالٍ وَلَا يَرِثُنِي إِلَّا ابْنَةٌ أَفَأَتَصَدَّقُ بِثُلُثَيْ مَالِي قَالَ لَا فَقُلْتُ بِالشَّطْرِ فَقَالَ لَا ثُمَّ قَالَ الثُّلُثُ وَالثُّلُثُ كَبِيرٌ أَوْ كَثِيرٌ إِنَّكَ أَنْ تَذَرَ وَرَثَتَكَ أَغْنِيَاءَ خَيْرٌ مِنْ أَنْ تَذَرَهُمْ عَالَةً يَتَكَفَّفُونَ النَّاسَ وَإِنَّكَ لَنْ تُنْفِقَ نَفَقَةً تَبْتَغِي بِهَا وَجْهَ اللَّهِ إِلَّا أُجِرْتَ بِهَا حَتَّى مَا تَجْعَلُ فِي فِي امْرَأَتِكَ فَقُلْتُ يَا رَسُولَ اللَّهِ أُخَلَّفُ بَعْدَ أَصْحَابِي قَالَ إِنَّكَ لَنْ تُخَلَّفَ فَتَعْمَلَ عَمَلًا صَالِحًا إِلَّا ازْدَدْتَ بِهِ دَرَجَةً وَرِفْعَةً ثُمَّ لَعَلَّكَ أَنْ تُخَلَّفَ حَتَّى يَنْتَفِعَ بِكَ أَقْوَامٌ وَيُضَرَّ بِكَ آخَرُونَ اللَّهُمَّ أَمْضِ لِأَصْحَابِي هِجْرَتَهُمْ وَلَا تَرُدَّهُمْ عَلَى أَعْقَابِهِمْ لَكِنْ الْبَائِسُ سَعْدُ بْنُ خَوْلَةَ يَرْثِي لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ مَاتَ بِمَكَّةَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari ['Amir bin Sa'ad bin Abu Waqash] dari [bapaknya] radliallahu 'anhu berkata; Rasulullah Shallallahu'alaihiwasallam pernah mengunjungiku pada hari Haji Wada' (perpisahan) saat sakitku sudah sangat parah, lalu aku berkata: \" Sakitku sudah sangat parah (menjelang kematianku) dan aku banyak memiliki harta sedangkan tidak ada yang akan mewarisinya kecuali anak perempuanku. Bolehkah aku menyedekahkan sepertiga dari hartaku ini?. Beliau menjawab: \"Tidak boleh\". Aku katakan lagi: \"Bagaimana kalau setengahnya?\". Beliau menjawab: \"Tidak boleh\". Kemudian Beliau melanjutkan: \"Sepertiga dan sepertiga itu sudah besar atau banyak. Sesungguhnya kamu bila meninggalkan ahli warismu dalam keadaan berkecukupan (kaya) itu lebih baik dari pada kamu meninggalkan mereka serba kekurangan sehingga nantinya mereka meminta-minta kepada manusia. Dan kamu tidaklah menginfaqkan suatu nafaqah yang hanya kamu hanya niatkan mencari ridha Allah kecuali kamu pasti diberi balasan pahala atasnya bahkan sekalipun nafkah yang kamu berikan untuk mulut isterimu\". Lalu aku bertanya: \"Wahai Rasulullah, apakah aku diberi umur panjang setelah sahabat-sahabatku?. Beliau berkata,: \"Tidaklah sekali-kali engkau diberi umur panjang lalu kamu beramal shalih melainkan akan bertambah derajat dan kemuliaanmu. Dan semoga kamu diberi umur panjang sehingga orang-orang dapat mengambil manfaat dari dirimu dan juga mungkin dapat mendatangkan madharat bagi kaum yang lain. Ya Allah sempurnakanlah pahala hijrah sahabat-sahabatku dan janganlah Engkau kembalikan mereka ke belakang\". Namun Sa'ad bin Khaulah membuat Rasulullah Shallallahu'alaihiwasallam bersedih karena dia akhirnya meningal dunia di Makkah. "},"1214":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ مِنَّا مَنْ ضَرَبَ الْخُدُودَ وَشَقَّ الْجُيُوبَ وَدَعَا بِدَعْوَى الْجَاهِلِيَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami ['Abdurrahman] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari ['Abdullah bin Murrah] dari [Masruq] dari ['Abdullah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Bukan dari golongan kami siapa yang memukul-mukul pipi, merobek-robek baju dan menyeru dengan seruan jahiliyyah (meratap) \"."},"1215":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنَّا مَنْ ضَرَبَ الْخُدُودَ وَشَقَّ الْجُيُوبَ وَدَعَا بِدَعْوَى الْجَاهِلِيَّةِ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] dari ['Abdullah bin Murrah] dari [Masruq] dari ['Abdullah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Bukan dari golongan kami siapa yang memukul-mukul pipi, merobek-robek baju dan menyeru dengan seruan jahiliyyah (meratap) \"."},"1216":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ سَمِعْتُ يَحْيَى قَالَ أَخْبَرَتْنِي عَمْرَةُ قَالَتْ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمَّا جَاءَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَتْلُ ابْنِ حَارِثَةَ وَجَعْفَرٍ وَابْنِ رَوَاحَةَ جَلَسَ يُعْرَفُ فِيهِ الْحُزْنُ وَأَنَا أَنْظُرُ مِنْ صَائِرِ الْبَابِ شَقِّ الْبَابِ فَأَتَاهُ رَجُلٌ فَقَالَ إِنَّ نِسَاءَ جَعْفَرٍ وَذَكَرَ بُكَاءَهُنَّ فَأَمَرَهُ أَنْ يَنْهَاهُنَّ فَذَهَبَ ثُمَّ أَتَاهُ الثَّانِيَةَ لَمْ يُطِعْنَهُ فَقَالَ انْهَهُنَّ فَأَتَاهُ الثَّالِثَةَ قَالَ وَاللَّهِ لَقَدْ غَلَبْنَنَا يَا رَسُولَ اللَّهِ فَزَعَمَتْ أَنَّهُ قَالَ فَاحْثُ فِي أَفْوَاهِهِنَّ التُّرَابَ فَقُلْتُ أَرْغَمَ اللَّهُ أَنْفَكَ لَمْ تَفْعَلْ مَا أَمَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ تَتْرُكْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْعَنَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami ['Abdul Wahhab] berkata, aku mendengar [Yahya] berkata, telah mengabarkan kepada saya ['Amrah] berkata; Aku mendengar ['Aisyah radliallahu 'anha] berkata,: \"Ketika telah tiba di hadapan Nabi Shallallahu'alaihiwasallam jenazah Ibnu Haritsah, Ja'far dan Ibnu Rawahah, Beliau duduk dengan nampak kesedihannya sedangkan aku melihat dari lobang pintu. Lalu datang seorang laki-laki seraya berkata,: \"Sesungguhnya isteri-isterinya Ja'far\", lalu orang itu menceritakan tentang tangisan mereka. Maka Beliau memerintahkan laki-laki itu agar melarang mereka. Orang itu pergi namun kemudian datang untuk kedua kalinya dan belum berhasil melaksanakan perintah Beliau. Lalu Beliau berkata,: \"Laranglah mereka?\". Orang itu datang untuk ketiga kalinya seraya berkata,: \"Demi Allah, mereka mengalahkan kami wahai Rasulullah!\". 'Aisyah radliallahu 'anha menduga Beliau kemudian berkata,: \"Sumpallah mulut-mulut nereka dengan tanah\". Aku berkata kepada laki-laki itu: \"Semoga Allah menyumpal hidungmu karena belum melaksanakan apa yang Rasulullah Shallallahu'alaihiwasallam perintahkan, serta kamu (membiarkan) tidak meninggalkan Rasulullah Shallallahu'alaihiwasallam dari kondisinya yang lelah dan kesusahan\"."},"1217":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَنَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهْرًا حِينَ قُتِلَ الْقُرَّاءُ فَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَزِنَ حُزْنًا قَطُّ أَشَدَّ مِنْهُ","id":"Telah menceritakan kepada kami ['Amru bin \"Ali] telah menceritakan kepada kami [Muhammad bin Fudhail] telah menceritakan kepada kami ['Ashim Al Ahwal] dari [Anas radliallahu 'anhu] berkata,: \"Rasulullah Shallallahu'alaihiwasallam melaksanakan do'a qunut selama sebulan pada waktu terbunuhnya para Qurra' (penghafal AL Qur'an). Dan belum pernah aku melihat Rasulullah Shallallahu'alaihiwasallam sedemikian sedih yang melebihi kesedihannya pada waktu itu\"."},"1218":{"ar":"حَدَّثَنَا بِشْرُ بْنُ الْحَكَمِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ أَخْبَرَنَا إِسْحَاقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُاشْتَكَى ابْنٌ لِأَبِي طَلْحَةَ قَالَ فَمَاتَ وَأَبُو طَلْحَةَ خَارِجٌ فَلَمَّا رَأَتْ امْرَأَتُهُ أَنَّهُ قَدْ مَاتَ هَيَّأَتْ شَيْئًا وَنَحَّتْهُ فِي جَانِبِ الْبَيْتِ فَلَمَّا جَاءَ أَبُو طَلْحَةَ قَالَ كَيْفَ الْغُلَامُ قَالَتْ قَدْ هَدَأَتْ نَفْسُهُ وَأَرْجُو أَنْ يَكُونَ قَدْ اسْتَرَاحَ وَظَنَّ أَبُو طَلْحَةَ أَنَّهَا صَادِقَةٌ قَالَ فَبَاتَ فَلَمَّا أَصْبَحَ اغْتَسَلَ فَلَمَّا أَرَادَ أَنْ يَخْرُجَ أَعْلَمَتْهُ أَنَّهُ قَدْ مَاتَ فَصَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَخْبَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا كَانَ مِنْهُمَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّ اللَّهَ أَنْ يُبَارِكَ لَكُمَا فِي لَيْلَتِكُمَاقَالَ سُفْيَانُ فَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ فَرَأَيْتُ لَهُمَا تِسْعَةَ أَوْلَادٍ كُلُّهُمْ قَدْ قَرَأَ الْقُرْآنَ","id":"Telah menceritakan kepada kami [Bisyir bin Al Hakam] telah menceritakan kepada kami [Sufyan bin 'Uyainah] telah mengabarkan kepada kami [Ishaq bin 'Abdullah bin Abu Tholhah] bahwasanya dia mendengar [Anas bin Malik radliallahu 'anhu] berkata; Anak dari Abu Tholhah dalam kondisi sakit yang parah. Katanya: \"Dan akhirnya dia meninggal dunia\". Saat itu Abu Tholhah sedang bepergian. Ketika isterinya melihat bahwa dia (anaknya) sudah meninggal, maka dia mengerjakan sesuatu dan meletakkannya di samping rumah. Ketika Abu Tholhah sudah datang, dia bertanya: \"Bagaimana keadaan anak (kita)?. Isterinya menjawab: \"Dia sudah tenang dan aku berharap dia sudah beristirahat\".. Abu Tholhah menganggap bahwa isterinya berkata, benar adanya. Anas bin Malik radliallahu 'anhu; Maka dia tidur pada malam itu. Pada keesokan harinya, dia mandi. Ketika dia hendak pergi keluar, isterinya memberitahu bahwa anaknya sudah meninggal dunia. Kemudian dia shalat bersama Nabi Shallallahu'alaihiwasallam lalu dia menceritakan apa yang sudah terjadi antara dia berdua (dengan isterinya). Maka Rasulullah Shallallahu'alaihiwasallam berkata,: \"Semoga Allah memberkahi kalian berdua pada malam kalian itu\". Sufyan berkata; Ada seorang dari kalangan Anshar berkata,: \"Kemudian setelah itu aku melihat keduanya memiliki sembilan anak yang semuanya telah hafal Al Qur'an\"."},"1219":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ ثَابِتٍ قَالَ سَمِعْتُ أَنَسًا رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الصَّبْرُ عِنْدَ الصَّدْمَةِ الْأُولَى","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Tsabit] berkata; Aku mendengar [Anas radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Sesungguhnya shabar itu pada kesempatan pertama (saat datang mushibah) \"."},"1220":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَبْدِ الْعَزِيزِ حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا قُرَيْشٌ هُوَ ابْنُ حَيَّانَ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَدَخَلْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَبِي سَيْفٍ الْقَيْنِ وَكَانَ ظِئْرًا لِإِبْرَاهِيمَ عَلَيْهِ السَّلَام فَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِبْرَاهِيمَ فَقَبَّلَهُ وَشَمَّهُ ثُمَّ دَخَلْنَا عَلَيْهِ بَعْدَ ذَلِكَ وَإِبْرَاهِيمُ يَجُودُ بِنَفْسِهِ فَجَعَلَتْ عَيْنَا رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَذْرِفَانِ فَقَالَ لَهُ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ رَضِيَ اللَّهُ عَنْهُ وَأَنْتَ يَا رَسُولَ اللَّهِ فَقَالَ يَا ابْنَ عَوْفٍ إِنَّهَا رَحْمَةٌ ثُمَّ أَتْبَعَهَا بِأُخْرَى فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْعَيْنَ تَدْمَعُ وَالْقَلْبَ يَحْزَنُ وَلَا نَقُولُ إِلَّا مَا يَرْضَى رَبُّنَا وَإِنَّا بِفِرَاقِكَ يَا إِبْرَاهِيمُ لَمَحْزُونُونَرَوَاهُ مُوسَى عَنْ سُلَيْمَانَ بْنِ المُغِيرَةِ عَنْ ثَابِتٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Abdul 'Aziz] telah menceritakan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Quraisy] dia adalah Ibnu Hayyan dari [Tsabit] dari [Anas bin Malik radliallahu 'anhu] berkata; Kami bersama Rasulullah Shallallahu'alaihiwasallam mendatangi Abu Saif Al Qaiyn yang (isterinya) telah mengasuh dan menyusui Ibrahim 'alaihissalam (putra Nabi Shallallahu'alaihiwasallam. Lalu Rasulullah Shallallahu'alaihiwasallam mengambil Ibrahim dan menciumnya. Kemudian setelah itu pada kesempatan yang lain kami mengunjunginya sedangkan Ibrahim telah meninggal. Hal ini menyebabkan kedua mata Rasulullah Shallallahu'alaihiwasallam berlinang air mata. Lalu berkatalah 'Abdurrahman bin 'Auf radliallahu 'anhu kepada Beliau: \"Mengapa anda menangis, wahai Rasulullah?\". Beliau menjawab: \"Wahai Ibnu 'Auf, sesungguhnya ini adalah rahmat (tangisan kasih sayang) \". Beliau lalu melanjutkan dengan kalimat yang lain dan bersabda: \"Kedua mata boleh mencucurkan air mata, hati boleh bersedih, hanya kita tidaklah mengatakan kecuali apa yang diridhai oleh Rabb kita. Dan kami dengan perpisahan ini wahai Ibrahim pastilah bersedih\". Dan diriwayatkan oleh [Musa] dari [Sulaiman bin Al Mughirah] dari [Tsabit] dari [Anas bin Malik radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam. "},"1221":{"ar":"حَدَّثَنَا أَصْبَغُ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرٌو عَنْ سَعِيدِ بْنِ الْحَارِثِ الْأَنْصَارِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَاشْتَكَى سَعْدُ بْنُ عُبَادَةَ شَكْوَى لَهُ فَأَتَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُهُ مَعَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَسَعْدِ بْنِ أَبِي وَقَّاصٍ وَعَبْدِ اللَّهِ بْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُمْ فَلَمَّا دَخَلَ عَلَيْهِ فَوَجَدَهُ فِي غَاشِيَةِ أَهْلِهِ فَقَالَ قَدْ قَضَى قَالُوا لَا يَا رَسُولَ اللَّهِ فَبَكَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَأَى الْقَوْمُ بُكَاءَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَكَوْا فَقَالَ أَلَا تَسْمَعُونَ إِنَّ اللَّهَ لَا يُعَذِّبُ بِدَمْعِ الْعَيْنِ وَلَا بِحُزْنِ الْقَلْبِ وَلَكِنْ يُعَذِّبُ بِهَذَا وَأَشَارَ إِلَى لِسَانِهِ أَوْ يَرْحَمُ وَإِنَّ الْمَيِّتَ يُعَذَّبُ بِبُكَاءِ أَهْلِهِ عَلَيْهِوَكَانَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ يَضْرِبُ فِيهِ بِالْعَصَا وَيَرْمِي بِالْحِجَارَةِ وَيَحْثِي بِالتُّرَابِ","id":"Telah menceritakan kepada kami [Ashbagh] dari [Ibnu Wahb] berkata, telah mengabarkan kepada saya ['Amru] dari [Sa'id bin Al Harits Al Anshariy] dari ['Abdullah bin Umar radliallahu 'anhuma] berkata; Ketika Saad bin Ubadah sedang sakit, Nabi Shallallahu'alaihiwasallam menjenguknya bersama 'Abdurrahman bin 'Auf, Saad bin Abu Waqqash dan 'Abdullah bin Mas'ud radliallahu 'anhum. Ketika Beliau menemuinya, Beliau mendapatinya sedang dikerumuni keluarganya, Beliau bertanya: \"Apakah ia sudah meninggal?\". Mereka menjawab: \"Belum, wahai Rasulullah\". Lalu Nabi Shallallahu'alaihiwasallam menangis. Ketika orang-orang melihat Nabi Shallallahu'alaihiwasallam menangis, mereka pun turut menangis, maka Beliau bersabda: \"Tidakkah kalian mendengar bahwa Allah tidak mengadzab dengan tangisan air mata, tidak dengan hati yang bersedih, namun Dia mengadzab dengan ini, \" lalu Beliau menunjuk lidahnya, atau dirahmati (karena lisan itu) dan sesungguhnya mayat itu diadzab disebabkan tangisan keluarganya kepadanya\" Sambil 'Umar radliallahu 'anhu memukul tanah dengan tongkat, melempar batu dan menumpahkan tanah."},"1222":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ حَوْشَبٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ أَخْبَرَتْنِي عَمْرَةُ قَالَتْ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا تَقُولُلَمَّا جَاءَ قَتْلُ زَيْدِ بْنِ حَارِثَةَ وَجَعْفَرٍ وَعَبْدِ اللَّهِ بْنِ رَوَاحَةَ جَلَسَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْرَفُ فِيهِ الْحُزْنُ وَأَنَا أَطَّلِعُ مِنْ شَقِّ الْبَابِ فَأَتَاهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ نِسَاءَ جَعْفَرٍ وَذَكَرَ بُكَاءَهُنَّ فَأَمَرَهُ بِأَنْ يَنْهَاهُنَّ فَذَهَبَ الرَّجُلُ ثُمَّ أَتَى فَقَالَ قَدْ نَهَيْتُهُنَّ وَذَكَرَ أَنَّهُنَّ لَمْ يُطِعْنَهُ فَأَمَرَهُ الثَّانِيَةَ أَنْ يَنْهَاهُنَّ فَذَهَبَ ثُمَّ أَتَى فَقَالَ وَاللَّهِ لَقَدْ غَلَبْنَنِي أَوْ غَلَبْنَنَا الشَّكُّ مِنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ حَوْشَبٍ فَزَعَمَتْ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَاحْثُ فِي أَفْوَاهِهِنَّ التُّرَابَ فَقُلْتُ أَرْغَمَ اللَّهُ أَنْفَكَ فَوَاللَّهِ مَا أَنْتَ بِفَاعِلٍ وَمَا تَرَكْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْعَنَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Hawsyab] telah menceritakan kepada kami ['Abdul Wahhab] telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah mengabarkan kepada saya ['Amrah] berkata; Aku mendengar ['Aisyah radliallahu 'anha] berkata,: \"Ketika tiba di hadapan Nabi Shallallahu'alaihiwasallam jenazah Zaid bin Haritsah, Ja'far dan 'Abdullah bin Rawahah, Beliau duduk yang nampak kesedihannya sedangkan aku memandang dari lobang pintu. Lalu datang seorang laki-laki seraya berkata,: \"Sesungguhnya isteri-isterinya Ja'far\", lalu orang itu menceritakan tentang tangisan mereka. Maka Beliau memerintahkan laki-laki itu agar melarang mereka. Maka orang itu pergi kemudian datang dan berkata,: \"Aku telah melarang mereka\". Dan laki-laki itu menyebutkan bahwa mereka tidak menaatinya. Maka Beliau memerintahkan laki-laki itu untuk kedua kalinya agar melarang mereka. Maka laki-laki itu pun pergi kemudian datang dan berkata,: \"Demi Allah, mereka mengalahkan aku\" atau \"mereka mengalahkan kami!\". Keraguan perkataan ini datang dari Muhammad bin 'Abdullah bin Hawsyab. 'Aisyah radliallahu 'anha menduga Beliau kemudian berkata,: \"Bungkamlah mulut-mulut nereka dengan tanah\". Aku berkata kepada laki-laki itu: \"Semoga Allah menghinakanmu karena kamu tidak melaksanakan yang Rasulullah Shallallahu'alaihiwasallam perintahkan, serta kamu tidak meninggalkan Rasulullah Shallallahu'alaihiwasallam dari kondisinya yang lelah dan kesedihannya (membiarkan Beliau dalam kesedihan) \"."},"1223":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْأَخَذَ عَلَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ الْبَيْعَةِ أَنْ لَا نَنُوحَ فَمَا وَفَتْ مِنَّا امْرَأَةٌ غَيْرَ خَمْسِ نِسْوَةٍ أُمِّ سُلَيْمٍ وَأُمِّ الْعَلَاءِ وَابْنَةِ أَبِي سَبْرَةَ امْرَأَةِ مُعَاذٍ وَامْرَأَتَيْنِ أَوْ ابْنَةِ أَبِي سَبْرَةَ وَامْرَأَةِ مُعَاذٍ وَامْرَأَةٍ أُخْرَى","id":"Telah menceritakan kepada kami ['Abdullah bin 'Abdul Wahhab] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ayyub] dari [Muhammad] dari [Ummu 'Athiyyah radliallahu 'anha] berkata,: \"Nabi Shallallahu'alaihiwasallam mengambil sumpah setia dari kami ketika kami berbai'at yaitu kami dilarang meratap."},"1224":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ عَنْ سَالِمٍ عَنْ أَبِيهِ عَنْ عَامِرِ بْنِ رَبِيعَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَأَيْتُمْ الْجَنَازَةَ فَقُومُوا حَتَّى تُخَلِّفَكُمْقَالَ سُفْيَانُ قَالَ الزُّهْرِيُّ أَخْبَرَنِي سَالِمٌ عَنْ أَبِيهِ قَالَ أَخْبَرَنَا عَامِرُ بْنُ رَبِيعَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَادَ الْحُمَيْدِيُّ حَتَّى تُخَلِّفَكُمْ أَوْ تُوضَعَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Az Zuhriy] dari [Salim] dari [bapaknya] dari ['Amir bin Rabi'ah] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Jika kalian melihat jenazah maka berdirilah hingga dia meninggalkan (berlalu dari) kalian. Berkata, [Sufyan] berkata, [Az Zuhriy] telah mengabarkan kepada saya [Salim] dari [bapaknya] berkata, telah mengabarkan kepada kami ['Amir bin Rabi'ah] dari Nabi Shallallahu'alaihiwasallam. [Al Humaidiy] menambahkan: \"Hingga meninggalkan kalian atau diletakkan\"."},"1225":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا عَنْ عَامِرِ بْنِ رَبِيعَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَأَى أَحَدُكُمْ جِنَازَةً فَإِنْ لَمْ يَكُنْ مَاشِيًا مَعَهَا فَلْيَقُمْ حَتَّى يُخَلِّفَهَا أَوْ تُخَلِّفَهُ أَوْ تُوضَعَ مِنْ قَبْلِ أَنْ تُخَلِّفَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] dari ['Amir bin Rabi'ah radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam bersabda: \"\"Jika seorang dari kalian melihat jenazah dan dia tidak sedang berjalan bersamanya maka hendaklah dia berdiri hingga dia meninggalkan jenazah tersebut, atau jenazah sudah berlalu atau diletakkan sebelum dibawa pergi\". "},"1226":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ قَالَكُنَّا فِي جَنَازَةٍ فَأَخَذَ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ بِيَدِ مَرْوَانَ فَجَلَسَا قَبْلَ أَنْ تُوضَعَ فَجَاءَ أَبُو سَعِيدٍ رَضِيَ اللَّهُ عَنْهُ فَأَخَذَ بِيَدِ مَرْوَانَ فَقَالَ قُمْ فَوَاللَّهِ لَقَدْ عَلِمَ هَذَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا عَنْ ذَلِكَفَقَالَ أَبُو هُرَيْرَةَ صَدَقَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Ibnu Abu Dza'bi] dari [Sa'id Al Maqbariy] dari [bapaknya] berkata,: Kami pernah berada dekat jenazah, ketika itu Abu Hurairah radliallahu 'anhu memegang tangan Marwan lalu keduanya duduk sebelum diletakkan. Kemudian datang [Abu Sa'id radliallahu 'anhu] lalu memegang tangan Marwan seraya berkata,: \"Berdirilah!. Demi Allah, sungguh kamu telah tahu bahwa Nabi Shallallahu'alaihiwasallam melarang kita tentang hal ini\". Maka [Abu Hurairah radliallahu 'anhu] berkata,: \"Dia benar\"."},"1227":{"ar":"حَدَّثَنَا مُسْلِمٌ يَعْنِي ابْنَ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَأَيْتُمْ الْجَنَازَةَ فَقُومُوا فَمَنْ تَبِعَهَا فَلَا يَقْعُدْ حَتَّى تُوضَعَ","id":"Telah menceritakan kepada kami [Muslim] yakni putra Ibrahim telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Yahya] dari [Abu Salamah] dari [Abu Sa'id Al Khudriy radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam bersabda: \"\"Jika kalian melihat jenazah maka berdirilah dan barangsiapa mengiringinya janganlah dia duduk hingga jenazah itu diletakkan \". "},"1228":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ عُبَيْدِ اللَّهِ بْنِ مِقْسَمٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَمَرَّ بِنَا جَنَازَةٌ فَقَامَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقُمْنَا بِهِ فَقُلْنَا يَا رَسُولَ اللَّهِ إِنَّهَا جِنَازَةُ يَهُودِيٍّ قَالَ إِذَا رَأَيْتُمْ الْجِنَازَةَ فَقُومُوا","id":"Telah menceritakan kepada kami [Mu'adz bin Fadhalah] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari ['Ubaidullah bin Muqsim] dari [Jabir bin 'Abdullah radliallahu 'anhua] berkata,: \"Suatu hari jenazah pernah lewat di hadapan kami maka Nabi Shallallahu'alaihiwasallam berdiri menghormatinya dan kami pun ikut berdiri. Lalu kami tanyakan: \"Wahai Rasulullah, jenazah itu adalah seorang Yahudi\". Maka Beliau berkata,: \"\"Jika kalian melihat jenazah maka berdirilah\". "},"1229":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَمْرُو بْنُ مُرَّةَ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ أَبِي لَيْلَى قَالَ كَانَ سَهْلُ بْنُ حُنَيْفٍ وَقَيْسُ بْنُ سَعْدٍقَاعِدَيْنِ بِالْقَادِسِيَّةِ فَمَرُّوا عَلَيْهِمَا بِجَنَازَةٍ فَقَامَا فَقِيلَ لَهُمَا إِنَّهَا مِنْ أَهْلِ الْأَرْضِ أَيْ مِنْ أَهْلِ الذِّمَّةِ فَقَالَا إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّتْ بِهِ جِنَازَةٌ فَقَامَ فَقِيلَ لَهُ إِنَّهَا جِنَازَةُ يَهُودِيٍّ فَقَالَ أَلَيْسَتْ نَفْسًاوَقَالَ أَبُو حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ عَمْرٍو عَنْ ابْنِ أَبِي لَيْلَى قَالَ كُنْتُ مَعَ قَيْسٍ وَسَهْلٍ رَضِيَ اللَّهُ عَنْهُمَا فَقَالَا كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ زَكَرِيَّاءُ عَنْ الشَّعْبِيِّ عَنْ ابْنِ أَبِي لَيْلَى كَانَ أَبُو مَسْعُودٍ وَقَيْسٌيَقُومَانِ لِلْجَنَازَةِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami ['Amru bin Murrah] berkata; Aku mendengar ['Abdurrahman bin Abu Laila] berkata,: \"Suatu hari [Sahal bin Hunaif] dan [Qais bin Sa'ad] sedang duduk di Qadisiyah, lalu lewatlah jenazah di hadapan keduanya, maka keduanya berdiri. Kemudian dikatakan kepada keduanya bahwa jenazah itu adalah dari penduduk asli, atau dari Ahlu dzimmah. Maka keduanya berkata,: \"Nabi Shallallahu'alaihiwasallam pernah jenazah lewat di hadapan Beliau lalu Beliau berdiri. Kemudian dikatakan kepada Beliau bahwa itu adalah jenazah orang Yahudi. Maka Beliau bersabda: \"Bukankah ia juga memiliki nyawa?\" Dan berkata [Abu Hamzah] dari [Al A'masy] dari ['Amru] dari [Ibnu Abu Laila] berkata,: \"Aku pernah bersama [Qais] dan [Sahl] Radliallahu 'anhu, lalu keduanya berkata; Kami pernah bersama Nabi Shallallahu'alaihiwasallam. Dan berkata, [Zakariya] dari [Sya'biy] dari [Ibnu Abi Laila], dulu [Abu Mas'ud] dan [Qais] berdiri untuk jenazah."},"1230":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وُضِعَتْ الْجِنَازَةُ وَاحْتَمَلَهَا الرِّجَالُ عَلَى أَعْنَاقِهِمْ فَإِنْ كَانَتْ صَالِحَةً قَالَتْ قَدِّمُونِي وَإِنْ كَانَتْ غَيْرَ صَالِحَةٍ قَالَتْ يَا وَيْلَهَا أَيْنَ يَذْهَبُونَ بِهَا يَسْمَعُ صَوْتَهَا كُلُّ شَيْءٍ إِلَّا الْإِنْسَانَ وَلَوْ سَمِعَهُ صَعِقَ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] telah menceritakan kepada kami [Al Laits] dari [Sa'id AL Maqbariy] dari [bapaknya] bahwa dia mendengar dari [Abu Sa'id AL Khudriy radliallahu 'anhu] bahwa Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika jenazah diletakkan lalu dibawa oleh para laki-laki di atas pundak mereka, maka jika jenazah tersebut termasuk orang shalih (semasa hidupnya) maka dia (jenazah tersebut) berkata; \"Bersegeralah kalian (membawa aku). Dan jika ia bukan dari orang shalih, maka dia akan berkata; \"Celaka, kemana mereka akan membawanya?. Suara jenazah itu akan didengar oleh setiap makhluq kecuali manusia dan seandainya manusia mendengarnya, tentu dia jatuh pingsan\"."},"1231":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ حَفِظْنَاهُ مِنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَسْرِعُوا بِالْجِنَازَةِ فَإِنْ تَكُ صَالِحَةً فَخَيْرٌ تُقَدِّمُونَهَا وَإِنْ يَكُ سِوَى ذَلِكَ فَشَرٌّ تَضَعُونَهُ عَنْ رِقَابِكُمْ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] berkata, kami menghafalnya dari [Az Zuhriy] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Bercepat-cepatlah membawa jenazah, karena bila jenazah itu dari orang shalih berarti kalian telah mempercepat kebaikan untuknya dan jika tidak, berarti kalian telah menyingkirkan kejelekan dari pundak kalian\". "},"1232":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ حَدَّثَنَا سَعِيدٌ عَنْ أَبِيهِ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا وُضِعَتْ الْجِنَازَةُ فَاحْتَمَلَهَا الرِّجَالُ عَلَى أَعْنَاقِهِمْ فَإِنْ كَانَتْ صَالِحَةً قَالَتْ قَدِّمُونِي وَإِنْ كَانَتْ غَيْرَ صَالِحَةٍ قَالَتْ لِأَهْلِهَا يَا وَيْلَهَا أَيْنَ يَذْهَبُونَ بِهَا يَسْمَعُ صَوْتَهَا كُلُّ شَيْءٍ إِلَّا الْإِنْسَانَ وَلَوْ سَمِعَ الْإِنْسَانُ لَصَعِقَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] dari [Sa'id] dari [Bapaknya] bahwa dia mendengar dari [Abu Sa'id AL Khudriy radliallahu 'anhu] berkata, bahwa Rasulullah Shallallahu'alaihiwasallam telah bersabda: \"Jika jenazah diletakkan lalu dibawa oleh para orang-orang di atas pundak mereka, jika jenazah tersebut termasuk orang shalih (semasa hidupnya) maka (jenazah tersebut) akan berkata; \"Bersegeralah kalian (membawa aku). Dan jika ia bukan dari orang shalih, maka dia akan berkata kepada keluarganya; \"Celaka, kemana mereka akan membawanya?. Suara jenazah itu akan didengar oleh setiap makhluq kecuali manusia dan seandainya ada manusia yang mendengarnya tentu dia akan jatuh pingsan\"."},"1233":{"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ أَبِي عَوَانَةَ عَنْ قَتَادَةَ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى النَّجَاشِيِّ فَكُنْتُ فِي الصَّفِّ الثَّانِي أَوْ الثَّالِثِ","id":"Telah menceritakan kepada kami [Musaddad] dari [Abu 'Awanah] dari [Qatadah] dari ['Atha'] dari [Jabir bin 'Abdullah radliallahu 'anhua] bahwa Rasulullah Shallallahu'alaihiwasallam melaksanakan shalat jenazah sedang aku ikut shalat berdiri pada shaf kedua atau ketiga."},"1234":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَنَعَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَصْحَابِهِ النَّجَاشِيَّ ثُمَّ تَقَدَّمَ فَصَفُّوا خَلْفَهُ فَكَبَّرَ أَرْبَعًا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhriy] dari [Sa'id] dari [Abu Hurairah radliallahu 'anhu] berkata,: Nabi Shallallahu'alaihiwasallam mengumumkan kematian An-Najasyi, kemudian Beliau maju dan membuat barisan shaf di belakang, Beliau lalu takbir empat kali."},"1235":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا الشَّيْبَانِيُّ عَنْ الشَّعْبِيِّ قَالَ أَخْبَرَنِيمَنْ شَهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى عَلَى قَبْرٍ مَنْبُوذٍ فَصَفَّهُمْ وَكَبَّرَ أَرْبَعًاقُلْتُ مَنْ حَدَّثَكَ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Asy-Syaibaniy] dari [Asy-Sya'biy] berkata, telah mengabarkan kepada saya seorang yang menyaksikan bahwa Nabi Shallallahu'alaihiwasallam pernah mendatangi kuburan yang terpisah (dari kuburan lain). Maka Beliau membariskan mereka lalu bertakbir empat kali. Aku bertanya kepadanya: \"Siapakah yang menceritakan ini kepadamu?\". Dia menjawab: \" [Ibnu 'Abbas] radliallahu 'anhu\"."},"1236":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي عَطَاءٌ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ تُوُفِّيَ الْيَوْمَ رَجُلٌ صَالِحٌ مِنْ الْحَبَشِ فَهَلُمَّ فَصَلُّوا عَلَيْهِ قَالَ فَصَفَفْنَا فَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِ وَنَحْنُ مَعَهُ صُفُوفٌقَالَ أَبُو الزُّبَيْرِ عَنْ جَابِرٍ كُنْتُ فِي الصَّفِّ الثَّانِي","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] telah mengabarkan mereka, katanya telah mengabarkan kepada saya ['Atha'] bahwa dia mendengar [Jabir bin 'Abdullah radliallahu 'anha] berkata,: \"Hari ini telah wafat seorang laki-laki shalih, untuk itu marilah laksanakan shalat untuknya\". Dia (Jabir) berkata,: Maka kami dibariskan lalu Nabi Shallallahu'alaihiwasallam melaksanakan shalat dan kami bersama Beliau shalat dalam barisan (shaf-shaf di belakang). Berkata, [Abu Az Zubair] dari [Jabir]: \"Dan aku berada pada shaf kedua\"."},"1237":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الشَّيْبَانِيُّ عَنْ عَامِرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِقَبْرٍ قَدْ دُفِنَ لَيْلًا فَقَالَ مَتَى دُفِنَ هَذَا قَالُوا الْبَارِحَةَ قَالَ أَفَلَا آذَنْتُمُونِي قَالُوا دَفَنَّاهُ فِي ظُلْمَةِ اللَّيْلِ فَكَرِهْنَا أَنْ نُوقِظَكَ فَقَامَ فَصَفَفْنَا خَلْفَهُ قَالَ ابْنُ عَبَّاسٍ وَأَنَا فِيهِمْ فَصَلَّى عَلَيْهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami [Asy-Syaibaniy] dari ['Amir] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata,: \"Bahwa Rasulullah Shallallahu'alaihiwasallam melewati kubur yang telah dimakamkan malam hari. Maka Beliau bertanya: \"Kapan dimakamkan jenazah ini?. Mereka menjawab: \"Tadi malam\". Beliau bertanya kembali: \"Mengapa kalian tidak memberi tahu aku?\". Mereka menjawab: \"Kami memakamkannya pada malam yang gelap gulita dan kami sungkan untuk membangunkan anda\". Maka Beliau berdiri dan membariskan kami di belakang Beliau. Ibnu 'Abbas radliallahu 'anhu berkata,: \"Dan aku hadir bersama mereka, maka kemudian Beliau melaksanakan shalat untuknya (jenazah) \"."},"1238":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ الشَّيْبَانِيِّ عَنْ الشَّعْبِيِّ قَالَ أَخْبَرَنِيمَنْ مَرَّ مَعَ نَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى قَبْرٍ مَنْبُوذٍ فَأَمَّنَا فَصَفَفْنَا خَلْفَهُ فَقُلْنَا يَا أَبَا عَمْرٍو مَنْ حَدَّثَكَقَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Asy-Syaibaniy] dari [Asy-Sya'biy] berkata, telah mengabarkan kepada saya seorang yang bersama Nabi kalian Shallallahu'alaihiwasallam, ia berjalan melewati kuburan yang terpisah (dari kuburan lain). Lalu Beliau membariskan kami di belakang Beliau. Kami bertanya: \"Wahai Abu \"Amru, siapakah yang menceritakan ini kepadamu?\". Dia menjawab: \" [Ibnu 'Abbas radliallahu 'anhu] \"."},"1239":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ قَالَ سَمِعْتُ نَافِعًا يَقُولُ حُدِّثَ ابْنُ عُمَرَ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُمْ يَقُولُمَنْ تَبِعَ جَنَازَةً فَلَهُ قِيرَاطٌفَقَالَ أَكْثَرَ أَبُو هُرَيْرَةَ عَلَيْنَا فَصَدَّقَتْ يَعْنِي عَائِشَةَ أَبَا هُرَيْرَةَ وَقَالَتْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُهُ فَقَالَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا لَقَدْ فَرَّطْنَا فِي قَرَارِيطَ كَثِيرَةٍ{ فَرَّطْتُ }ضَيَّعْتُ مِنْ أَمْرِ اللَّهِ","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Jarir bin Hazim] berkata; Aku mendengar [Nafi'] berkata; disampaikan kepada [Ibnu 'Umar] bahwa [Abu Hurairah radliallahu 'anhu] berkata,: \"Barangsiapa yang mengantar jenazah baginya pahala satu qirath. Maka dia (Ibnu 'Umar radliallahu 'anhu ma) berkata,: Abu Hurairah berlebihan terhadap kita\". Namun kemudian pernyataan Abu Hurairah radliallahu 'anhu dibenarkan, yakni oleh ['Aisyah radliallahu 'anha] dan [Abu Hurairah] berkata; aku mendengar Rasulullah Shallallahu'alaihiwasallam mengatakannya. Maka [Ibnu 'Umar radliallahu 'anhu] berkata: \"Kami telah banyak meremehkan masalah dan aku telah meremehkan dan melalaikan urusan (agama) Allah\""},"1240":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ قَالَ قَرَأْتُ عَلَى ابْنِ أَبِي ذِئْبٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ أَنَّهُ سَأَلَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ فَقَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح حَدَّثَنَا أَحْمَدُ بْنُ شَبِيبِ بْنِ سَعِيدٍ قَالَ حَدَّثَنِي أَبِي حَدَّثَنَا يُونُسُ قَالَ ابْنُ شِهَابٍ وَحَدَّثَنِي عَبْدُ الرَّحْمَنِ الْأَعْرَجُ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَهِدَ الْجَنَازَةَ حَتَّى يُصَلِّيَ فَلَهُ قِيرَاطٌ وَمَنْ شَهِدَ حَتَّى تُدْفَنَ كَانَ لَهُ قِيرَاطَانِ قِيلَ وَمَا الْقِيرَاطَانِ قَالَ مِثْلُ الْجَبَلَيْنِ الْعَظِيمَيْنِ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] berkata, aku membacakan kepada [Ibnu Abu Dza'bi] dari [Sa'id bin Abu Sa'id Al Maqbariy] dari [bapaknya] bahwasanya dia pernah bertanya kepada [Abu Hurairah radliallahu 'anhu], maka Abu Hurairah radliallahu 'anhu menjawab; Aku mendengar Nabi Shallallahu'alaihiwasallam. Dan dalam riwayat lain telah menceritakan kepada kami [Ahmad bin Syabib bin Sa'id] berkata, telah menceritakan [bapakku] kepadaku, telah menceritakan kepada kami [Yunus] berkata, [Ibnu Syihab] dan telah menceritakan kepada saya ['Abdurrahman Al A'raj] bahwa [Abu Hurairah radliallahu 'anhu] berkata; Telah bersabda Rasulullah Shallallahu'alaihiwasallam: \"Barangsiapa yang menyaksikan jenazah hingga ikut menyolatkannya maka baginya pahala satu qirath, dan barangsiapa yang menyaksikan jenazah hingga ikut menguburkannya maka baginya pahala dua qirath\". Ditanyakan kepada Beliau; \"Apa yang dimaksud dengan dua qirath?\" Beliau menjawab: \"Seperti dua gunung yang besar\"."},"1241":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا زَائِدَةُ حَدَّثَنَا أَبُو إِسْحَاقَ الشَّيْبَانِيُّ عَنْ عَامِرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْرًا فَقَالُوا هَذَا دُفِنَ أَوْ دُفِنَتْ الْبَارِحَةَ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا فَصَفَّنَا خَلْفَهُ ثُمَّ صَلَّى عَلَيْهَا","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Yahya bin Abu Bukair] telah menceritakan kepada kami [Za'idah] telah menceritakan kepada kami [Abu Ishaq Asy-Syaibaniy] dari ['Amir] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; Nabi Shallallahu'alaihiwasallam mendatangi kuburan. Mereka berkata; \"Ini dikebumikan kemarin\". Berkata, Ibnu 'Abbas radliallahu 'anhuma: Maka Beliau membariskan kami di belakang Beliau kemudian mengerjakan shalat untuknya\". "},"1242":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ أَنَّهُمَا حَدَّثَاهُ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَنَعَى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّجَاشِيَّ صَاحِبَ الْحَبَشَةِ يَوْمَ الَّذِي مَاتَ فِيهِ فَقَالَ اسْتَغْفِرُوا لِأَخِيكُمْوَعَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَفَّ بِهِمْ بِالْمُصَلَّى فَكَبَّرَ عَلَيْهِ أَرْبَعًا","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] telah menceritakan kepada kami [Sa'id bin Al Musayyab] dan [Abu Salamah] bahwa keduanya menceritakan kepadanya dari [Abu Hurairah radliallahu 'anhu] berkata,: Nabi Shallallahu'alaihiwasallam mengumumkan kepada kami kematian An-Najasyi, Penguasa Negeri Habasyah pada hari kematiannya lalu berkata,: \"Mohonkanlah ampun buat saudara kalian\". Dan dari [Ibnu Syihab] berkata, telah menceritakan kepada saya [Sa'id bin Al Musayyab] bahwa [Abu Hurairah radliallahu 'anhu] berkata,: Bahwa Nabi Shallallahu'alaihiwasallam membariskan mereka di tanah lapang kemudian Beliau bertakbir empat kali\"."},"1243":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَبُو ضَمْرَةَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ الْيَهُودَ جَاءُوا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجُلٍ مِنْهُمْ وَامْرَأَةٍ زَنَيَا فَأَمَرَ بِهِمَا فَرُجِمَا قَرِيبًا مِنْ مَوْضِعِ الْجَنَائِزِ عِنْدَ الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Ibrahim bin AL Mundzir] telah menceritakan kepada kami [Abu Dhamrah] telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhuma]; Orang-orang Yahudi datang kepada Nabi Shallallahu'alaihiwasallam dengan membawa seorang laki-laki dan seorang perempuan yang keduanya berzina. Maka Beliau memerintahkan untuk merajam keduanya di tempat biasa untuk menyolatkan jenazah, disamping Masjid Nabawi\". "},"1244":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ شَيْبَانَ عَنْ هِلَالٍ هُوَ الْوَزَّانُ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي مَرَضِهِ الَّذِي مَاتَ فِيهِ لَعَنَ اللَّهُ الْيَهُودَ وَالنَّصَارَى اتَّخَذُوا قُبُورَ أَنْبِيَائِهِمْ مَسْجِدًا قَالَتْ وَلَوْلَا ذَلِكَ لَأَبْرَزُوا قَبْرَهُ غَيْرَ أَنِّي أَخْشَى أَنْ يُتَّخَذَ مَسْجِدًا","id":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Syaiban] dari [Hilal] dia adalah Al Wazzan dari ['Urwah] dari ['Aisyah radliallahu 'anha] dari Nabi shallallahu 'alaihi wasallam bersabda ketika Beliau sakit yang membawa kepada kematiannya: \"Allah melaknat orang-orang Yahudi dan Nashrani disebabkan mereka menjadikan kuburan para nabi mereka sebagai masjid\". 'Aisyah radliallahu 'anha berkata; \"Kalau bukan karena sabda Beliau tersebut tentu sudah mereka pindahkan kubur beliau (dari dalam rumahnya), namun aku tetap khawatir nantinya akan dijadikan masjid\"."},"1245":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا حُسَيْنٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّيْتُ وَرَاءَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى امْرَأَةٍ مَاتَتْ فِي نِفَاسِهَا فَقَامَ عَلَيْهَا وَسَطَهَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Husain] telah menceritakan kepada kami ['Abdullah bin Buraidah] dari [Samurah bin Jundub radliallahu 'anhu] berkata; \"Aku pernah di belakang Nabi Shallallahu'alaihiwasallam ikut menshalati jenazah wanita yang meninggal pada masa nifasnya. Beliau berdiri di tengah jenazah tersebut\"."},"1246":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مَيْسَرَةَ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا حُسَيْنٌ عَنْ ابْنِ بُرَيْدَةَ حَدَّثَنَا سَمُرَةُ بْنُ جُنْدَبٍ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّيْتُ وَرَاءَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى امْرَأَةٍ مَاتَتْ فِي نِفَاسِهَا فَقَامَ عَلَيْهَا وَسَطَهَا","id":"Telah menceritakan kepada kami ['Imran bin Maisarah] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami [Husain] dari [Ibnu Buraidah] telah menceritakan kepada kami [Samurah bin Jundab radliallahu 'anhu] berkata; \"Aku pernah di belakang Nabi Shallallahu'alaihiwasallam ikut menshalati jenazah wanita yang meninggal pada masa nifasnya. Beliau berdiri di tengah jenazah tersebut\"."},"1247":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَى النَّجَاشِيَّ فِي الْيَوْمِ الَّذِي مَاتَ فِيهِ وَخَرَجَ بِهِمْ إِلَى الْمُصَلَّى فَصَفَّ بِهِمْ وَكَبَّرَ عَلَيْهِ أَرْبَعَ تَكْبِيرَاتٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah Shallallahu'alaihiwasallam mengumumkan kematian An-Najasyi, pada hari kematiannya lalu Beliau keluar bersama mereka menuju tanah lapang kemudian Beliau membariskan mereka dalam shaf lalu Beliau bertakbir empat kali\"."},"1248":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ حَدَّثَنَا سَلِيمُ بْنُ حَيَّانَ حَدَّثَنَا سَعِيدُ بْنُ مِينَاءَ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى أَصْحَمَةَ النَّجَاشِيِّ فَكَبَّرَ أَرْبَعًاوَقَالَ يَزِيدُ بْنُ هَارُونَ عَنْ سَلِيمٍ أَصْحَمَةَ وَتَابَعَهُ عَبْدُ الصَّمَدِ","id":"Telah menceritakan kepada kami [Mihammad bin Sinan] telah menceritakan kepada kami [Salim bin Hayyan] telah menceritakan kepada kami [Sa'id bin Mina'] dari [Jabir radliallahu 'anhu] bahwa Nabi Shallallahu'alaihiwasallam shalat untuk An-Najasyi, maka Beliau takbir empat kali. Dan berkata, [Yazid bin harun] dari [Salim]; Ashhamah\". Dan dikautkan pula oleh ['Abdush Shamad]. "},"1249":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدٍ عَنْ طَلْحَةَ قَالَ صَلَّيْتُ خَلْفَ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا ح حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ طَلْحَةَ بْنِ عَبْدِ اللَّهِ بْنِ عَوْفٍ قَالَ صَلَّيْتُ خَلْفَ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَلَى جَنَازَةٍ فَقَرَأَ بِفَاتِحَةِ الْكِتَابِ قَالَ لِيَعْلَمُوا أَنَّهَا سُنَّةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Sa'ad] dari [Tholhah] berkata,: Aku shalat dibelakang [Ibnu 'Abbas] radliallahu 'anhuma. Dan diriwayatkan pula oleh [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Saad bin Ibrahim] dari [Tholhah bin 'Abdullah bin 'Auf] berkata; Aku shalat dibelakang [Ibnu 'Abbas] radliallahu 'anhuma pada suatu jenazah, lalu ia membaca surat Al Fatihah, ia berkata, agar orang-orang tahu bahwa itu merupakan sunah\"."},"1250":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي سُلَيْمَانُ الشَّيْبَانِيُّ قَالَ سَمِعْتُ الشَّعْبِيَّ قَالَأَخْبَرَنِي مَنْ مَرَّ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى قَبْرٍ مَنْبُوذٍ فَأَمَّهُمْ وَصَلَّوْا خَلْفَهُ قُلْتُ مَنْ حَدَّثَكَ هَذَا يَا أَبَا عَمْرٍوقَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada saya [Sulaiman Asy-Syaibaniy] berkata; Aku mendengar [Asy-Sya'biy] berkata, telah mengabarkan kepada saya seorang yang bersama Nabi Shallallahu'alaihiwasallam pernah melewati kuburan yang terpisah (dari kuburan lain). Maka Beliau memimpin mereka shalat dan mereka shalat di belakang Beliau. Aku bertanya: \"Wahai 'Amru, siapakah yang menceritakan ini kepadamu?\". Dia menjawab: \" [Ibnu 'Abbas] radliallahu 'anhu\"."},"1251":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْفَضْلِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ أَسْوَدَ رَجُلًا أَوْ امْرَأَةً كَانَ يَكُونُ فِي الْمَسْجِدِ يَقُمُّ الْمَسْجِدَ فَمَاتَ وَلَمْ يَعْلَمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَوْتِهِ فَذَكَرَهُ ذَاتَ يَوْمٍ فَقَالَ مَا فَعَلَ ذَلِكَ الْإِنْسَانُ قَالُ��ا مَاتَ يَا رَسُولَ اللَّهِ قَالَ أَفَلَا آذَنْتُمُونِي فَقَالُوا إِنَّهُ كَانَ كَذَا وَكَذَا قِصَّتُهُ قَالَ فَحَقَرُوا شَأْنَهُ قَالَ فَدُلُّونِي عَلَى قَبْرِهِ فَأَتَى قَبْرَهُ فَصَلَّى عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Fadhal] telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Abu Rafi'] dari [Abu Hurairah radliallahu 'anhu]: \"Ada seorang laki-laki kulit hitam atau wanita kulit hitam yang menjadi tukang sapu masjid meninggal dunia yang tidak diketahui Nabi Shallallahu'alaihiwasallam tentang kamatiannya. Suatu hari Beliau diceritakan, maka Beliau berkata,: \"Apa yang telah terjadi dengan orang itu?. Mereka menjawab: \"Dia telah meninggal, wahai Rasulullah\" Lalu Nabi Shallallahu'alaihiwasallam berkata,: \"Kenapa kalian tidak memberitahu aku?. Mereka berkata,: Kejadiannya begini begini, lalu mereka menjelaskan\". Kemudian Beliau berkata,: \"Tunjukkan kepadaku kuburannya! '. Maka Beliau Shallallahu'alaihiwasallam mendatangi kuburan orang itu kemudian shalat untuknya."},"1252":{"ar":"حَدَّثَنَا عَيَّاشٌ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ قَالَ وَقَالَ لِي خَلِيفَةُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعَبْدُ إِذَا وُضِعَ فِي قَبْرِهِ وَتُوُلِّيَ وَذَهَبَ أَصْحَابُهُ حَتَّى إِنَّهُ لَيَسْمَعُ قَرْعَ نِعَالِهِمْ أَتَاهُ مَلَكَانِ فَأَقْعَدَاهُ فَيَقُولَانِ لَهُ مَا كُنْتَ تَقُولُ فِي هَذَا الرَّجُلِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَقُولُ أَشْهَدُ أَنَّهُ عَبْدُ اللَّهِ وَرَسُولُهُ فَيُقَالُ انْظُرْ إِلَى مَقْعَدِكَ مِنْ النَّارِ أَبْدَلَكَ اللَّهُ بِهِ مَقْعَدًا مِنْ الْجَنَّةِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَرَاهُمَا جَمِيعًا وَأَمَّا الْكَافِرُ أَوْ الْمُنَافِقُ فَيَقُولُ لَا أَدْرِي كُنْتُ أَقُولُ مَا يَقُولُ النَّاسُ فَيُقَالُ لَا دَرَيْتَ وَلَا تَلَيْتَ ثُمَّ يُضْرَبُ بِمِطْرَقَةٍ مِنْ حَدِيدٍ ضَرْبَةً بَيْنَ أُذُنَيْهِ فَيَصِيحُ صَيْحَةً يَسْمَعُهَا مَنْ يَلِيهِ إِلَّا الثَّقَلَيْنِ","id":"Telah menceritakan kepada kami ['Ayyasy] telah menceritakan kepada kami ['Abdul A'laa] telah menceritakan kepada kami [Sa'id] berkata; dan telah berkata, kepadaku [Khalifah] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Jika suatu jenazah sudah diletakkan didalam kuburnya dan teman-temannya sudah berpaling dan pergi meninggalkannya, dia mendengar gerak langkah sandal sandal mereka, maka akan datang kepadanya dua malaikat yang keduanya akan mendudukkannya seraya keduanya berkata, kepadanya: \"Apa yang kamu komentari tentang laki-laki ini, Muhammad Shallallahu'alaihiwasallam?\". Maka jenazah itu menjawab: \"Aku bersaksi bahwa dia adalah hamba Allah dan utusanNya\". Maka dikatakan kepadanya: \"Lihatlah tempat dudukmu di neraka yang Allah telah menggantinya dengan tempat duduk di surga\". Nabi Shallallahu'alaihiwasallam selanjutnya berkata,: \"Maka dia dapat melihat keduanya\". Adapun (jenazah) orang kafir atau munafiq akan menjawab: \"Aku tidak tahu, aku hanya berkata, mengikuti apa yang dikatakan kebanyakan orang\". Maka dikatakan kepadanya: \"Kamu tidak mengetahuinya dan tidak mengikuti orang yang mengerti\". Maka kemudian dia dipukul dengan palu godam besar terbuat dari besi diantara kedua telinganya sehingga mengeluarkan suara teriakan yang dapat didengar oleh yang ada di sekitarnya kecuali oleh dua makhluq (jin dan manusia) \". "},"1253":{"ar":"حَدَّثَنَا مَحْمُودٌ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَأُرْسِلَ مَلَكُ الْمَوْتِ إِلَى مُوسَى عَلَيْهِمَا السَّلَام فَلَمَّا جَاءَهُ صَكَّهُ فَرَجَعَ إِلَى رَبِّهِ فَقَالَ أَرْسَلْتَنِي إِلَى عَبْدٍ لَا يُرِيدُ الْمَوْتَ فَرَدَّ اللَّهُ عَلَيْهِ عَيْنَهُ وَقَالَ ارْجِعْ فَقُلْ لَهُ يَضَعُ يَدَهُ عَلَى مَتْنِ ثَوْرٍ فَلَهُ بِكُلِّ مَا غَطَّتْ بِهِ يَدُهُ بِكُلِّ شَعْرَةٍ سَنَةٌ قَالَ أَيْ رَبِّ ثُمَّ مَاذَا قَالَ ثُمَّ الْمَوْتُ قَالَ فَالْآنَ فَسَأَلَ اللَّهَ أَنْ يُدْنِيَهُ مِنْ الْأَرْضِ الْمُقَدَّسَةِ رَمْيَةً بِحَجَرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَوْ كُنْتُ ثَمَّ لَأَرَيْتُكُمْ قَبْرَهُ إِلَى جَانِبِ الطَّرِيقِ عِنْدَ الْكَثِيبِ الْأَحْمَرِ","id":"Telah menceritakan kepada kami [Mahmud] telah menceritakan kepada kami ['Abdur Razzaq] telah mengabarkan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [bapaknya] dari [Abu Hurairah radliallahu 'anhu] berkata,: \"Suatu hari malaikat maut diutus kepada Musa 'alaihissalam. Ketika menemuinya, (Nabi Musa 'alaihissalam) memukul matanya. Maka malaikat maut kembali kepada Rabbnya dan berkata,: \"Engkau mengutusku kepada hamba yang tidak menginginkan mati\". Maka Allah membalikkan matanya kepadanya seraya berfirman: \"Kembalilah dan katakan kepadanya agar dia meletakkan tangannya di atas punggung seekor lembu jantan, yang pengertiannya setiap bulu lembu yang ditutupi oleh tangannya berarti umurnya satu tahun\". Nabi Musa 'alaihissalam bertanya: \"Wahai Rabb, setelah itu apa?. Allah berfirman:: \"Kematian\". Maka Nabi Musa 'alaihissalam berkata,: \"Sekaranglah waktunya\". Kemudian Nabi Musa 'alaihissalam memohon kepada Allah agar mendekatkannya dengan tanah yang suci (Al Muqaddas) dalam jarak sejauh lemparan batu\". Abu Hurairah radliallahu 'anhu berkata; Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya aku kesana, pasti akan aku tunjukkan kepada kalian keberadaan kuburnya yang ada di pinggir jalan dibawah tumpukan pasir merah\"."},"1254":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الشَّيْبَانِيِّ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَجُلٍ بَعْدَ مَا دُفِنَ بِلَيْلَةٍ قَامَ هُوَ وَأَصْحَابُهُ وَكَانَ سَأَلَ عَنْهُ فَقَالَ مَنْ هَذَا فَقَالُوا فُلَانٌ دُفِنَ الْبَارِحَةَ فَصَلَّوْا عَلَيْهِ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Asy-Syaibaniy] dari [Asy-Sya'biy] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; Nabi Shallallahu'alaihiwasallam pernah mengerjakan shalat jenazah untuk seorang laki-laki yang telah dikebumikan pada malam hari. Beliau mengerjakannya bersama dengan para sahabatnya. Saat itu Beliau bertanya tentang jenazah tersebut: \"Siapakah orang ini?\". Mereka menjawab: \"Si anu, yang telah dikebumikan kemarin\". Maka mereka menyolatkannya\". "},"1255":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمَّا اشْتَكَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَتْ بَعْضُ نِسَائِهِ كَنِيسَةً رَأَيْنَهَا بِأَرْضِ الْحَبَشَةِ يُقَالُ لَهَا مَارِيَةُ وَكَانَتْ أُمُّ سَلَمَةَ وَأُمُّ حَبِيبَةَ رَضِيَ اللَّهُ عَنْهُمَا أَتَتَا أَرْضَ الْحَبَشَةِ فَذَكَرَتَا مِنْ حُسْنِهَا وَتَصَاوِيرَ فِيهَا فَرَفَعَ رَأْسَهُ فَقَالَ أُولَئِكِ إِذَا مَاتَ مِنْهُمْ الرَّجُلُ الصَّالِحُ بَنَوْا عَلَى قَبْرِهِ مَسْجِدًا ثُمَّ صَوَّرُوا فِيهِ تِلْكَ الصُّورَةَ أُولَئِكِ شِرَارُ الْخَلْقِ عِنْدَ اللَّهِ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah mengabarkan kepada saya [Malik] dari [Hisyam] dari [bapaknya] dari ['Aisyah radliallahu 'anhu] berkata; Ketika Nabi Shallallahu'alaihiwasallam sedang berbaring sakit sebagian isteri-isteri Beliau menceritakan tentang suatu gereja yang mereka lihat di negeri Habasyah (Etithapia) yang disebut dengan Mariyah. Sebelumnya Ummu Salamah dan Ummu Habibah radliallahu 'anhuma pernah berhijrah ke negeri Habasyah, sehingga keduanya dapat menceritakan tentang keindahan gereja tersebut dan adanya gambar (patung-patung) didalamnya. Maka Beliau Shallallahu'alaihiwasallam mengangkat kepalanya lalu bersabda: \"Mereka itulah, yang apabila ada hamba shalih atau laki-laki shalih diantara mereka yang meninggal dunia, mereka bangun masjid di atas kuburannya itu dan membuatkan patung dari orang yang meninggal itu di dalamnya. Mereka itulah seburuk-buruk makhluq disisi Allah \"."},"1256":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ حَدَّثَنَا هِلَالُ بْنُ عَلِيٍّ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَشَهِدْنَا بِنْتَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ عَلَى الْقَبْرِ فَرَأَيْتُ عَيْنَيْهِ تَدْمَعَانِ فَقَالَ هَلْ فِيكُمْ مِنْ أَحَدٍ لَمْ يُقَارِفْ اللَّيْلَةَ فَقَالَ أَبُو طَلْحَةَ أَنَا قَالَ فَانْزِلْ فِي قَبْرِهَا فَنَزَلَ فِي قَبْرِهَا فَقَبَرَهَاقَالَ ابْنُ مُبَارَكٍ قَالَ فُلَيْحٌ أُرَاهُ يَعْنِي الذَّنْبَ قَالَ أَبُو عَبْد اللَّهِ{ لِيَقْتَرِفُوا }أَيْ لِيَكْتَسِبُوا","id":"Telah menceritakan kepada kami [Muhammad bin Sinan] telah menceritakan kepada kami [Fulaih bin Sulaiman] telah menceritakan kepada kami [Hilal bin 'Ali] dari [Anas radliallahu 'anhu] berkata,: \"Kami menyaksikan pemakaman puteri Rasulullah Shallallahu'alaihiwasallam dan saat itu Rasulullah Shallallahu'alaihiwasallam duduk diatas kuburnya. Lalu aku melihat kedua mata Beliau mengucurkan air mata\". Kemudian Beliau bertanya: \"Siapakah diantara kalian yang malam tadi tidak berhubungan (dengan isterinya) \". Berkata, Abu Tholhah: \"Aku\". Beliau berkata,: \"Turunlah ke dalam kuburnya!\".\"Maka Beliau turun kedalam kuburnya lalu menguburkannya\". Berkata, Ibnu Mubarak berkata, Fulaih: \"Aku memahami makna Yuqarif maksudnya adalah \"berbuat dosa\". Berkata, Abu 'Abdullah Al Bukhariy tentang Firman Allah Ta'ala 'Liyaqtarifuu (QS Al An'am: 113, maksudnya adalah: agar mereka mengerjakan (seperti syetan mengerjakannya)."},"1257":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْمَعُ بَيْنَ الرَّجُلَيْنِ مِنْ قَتْلَى أُحُدٍ فِي ثَوْبٍ وَاحِدٍ ثُمَّ يَقُولُ أَيُّهُمْ أَكْثَرُ أَخْذًا لِلْقُرْآنِ فَإِذَا أُشِيرَ لَهُ إِلَى أَحَدِهِمَا قَدَّمَهُ فِي اللَّحْدِ وَقَالَ أَنَا شَهِيدٌ عَلَى هَؤُلَاءِ يَوْمَ الْقِيَامَةِ وَأَمَرَ بِدَفْنِهِمْ فِي دِمَائِهِمْ وَلَمْ يُغَسَّلُوا وَلَمْ يُصَلَّ عَلَيْهِمْ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] berkata, telah menceritakan kepada saya [Ibnu Syihab] dari ['Abdurrahman bin Ka'ab bin Malik] dari [Jabir bin 'Abdullah radliallahu 'anhua] berkata,: \"Nabi Shallallahu'alaihiwasallam pernah menggabungkan dalam satu kubur dua orang laki-laki yang gugur dalam perang Uhud dan dalam satu kain, lalu bersabda: \"Siapakah diantara mereka yang lebih banyak mempunyai hafalan Al Qur'an\". Bila Beliau telah diberi tahu kepada salah satu diantara keduanya, maka Beliau mendahulukannya didalam lahad lalu bersabda: \"Aku akan menjadi saksi atas mereka pada hari qiyamat\". Maka Beliau memerintahkan agar menguburkan mereka dengan darah-darah mereka, tidak dimandikan dan juga tidak dishalatkan\". "},"1258":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ يَوْمًا فَصَلَّى عَلَى أَهْلِ أُحُدٍ صَلَاتَهُ عَلَى الْمَيِّتِ ثُمَّ انْصَرَفَ إِلَى الْمِنْبَرِ فَقَالَ إِنِّي فَرَطٌ لَكُمْ وَأَنَا شَهِيدٌ عَلَيْكُمْ وَإِنِّي وَاللَّهِ لَأَنْظُرُ إِلَى حَوْضِي الْآنَ وَإِنِّي أُعْطِيتُ مَفَاتِيحَ خَزَائِنِ الْأَرْضِ أَوْ مَفَاتِيحَ الْأَرْضِ وَإِنِّي وَاللَّهِ مَا أَخَافُ عَلَيْكُمْ أَنْ تُشْرِكُوا بَعْدِي وَلَكِنْ أَخَافُ عَلَيْكُمْ أَنْ تَنَافَسُوا فِيهَا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] telah menceritakan kepada saya [Yazid bin Abu Habib] dari [Abu Al Khair] dari ['Uqbah bin 'Amir] bahwa Nabi Shallallahu'alaihiwasallam pada suatu hari keluar untuk menyolatkan syuhada' perang Uhud sebagaimana shalat untuk mayit. Kemudian Beliau pergi menuju mimbar lalu bersabda: \"Sungguh aku ini yang terdepan dari kalian dan aku menjadi saksi atas kalian. Dan aku, demi Allah, sekarang sedang melihat telagaku (yang di surga) dan aku telah diberikan kunci-kunci kekayaan bumi atau kunci-kinci bumi (dunia). Demi Allah, sungguh aku tidak khawatir kepada kalian bahwa kalian akan menyekutukan (Allah) kembali sepeninggal aku. Namun yang aku khawatirkan terhadap kalian adalah kalian akan memperebutkan (kekayaan) duniawi ini\"."},"1259":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ حَدَّثَنَا اللَّيْثُ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبٍ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَجْمَعُ بَيْنَ الرَّجُلَيْنِ مِنْ قَتْلَى أُحُدٍ","id":"Telah menceritakan kepada kami [Sa'id bin Sulaiman] telah menceritakan kepada kami [Al Laits] telah menceritakan kepada kami [Ibnu Syihab] dari ['Abdurrahman bin Ka'ab] bahwa [Jabir bin 'Abdullah radliallahu 'anhu] mengabarkan kepadanya bahwa Nabi Shallallahu'alaihiwasallam pernah menggabungkan (dalam satu kubur) dua orang laki-laki yang gugur dalam perang Uhud."},"1260":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا لَيْثٌ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ جَابِرٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادْفِنُوهُمْ فِي دِمَائِهِمْ يَعْنِي يَوْمَ أُحُدٍ وَلَمْ يُغَسِّلْهُمْ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Laits] dari [Ibnu Syihab] dari ['Abdurrahman bin Ka'ab bin Malik] dari [Jabir] berkata; Nabi Shallallahu'alaihiwasallam bersabda: \"Kuburkanlah mereka bersama dengan darah-darah mereka\". Yaitu mereka yang gugur pada perang Uhud: \"Dan janganlah mereka dimandikan\"."},"1261":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا لَيْثُ بْنُ سَعْدٍ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَجْمَعُ بَيْنَ الرَّجُلَيْنِ مِنْ قَتْلَى أُحُدٍ فِي ثَوْبٍ وَاحِدٍ ثُمَّ يَقُولُ أَيُّهُمْ أَكْثَرُ أَخْذًا لِلْقُرْآنِ فَإِذَا أُشِيرَ لَهُ إِلَى أَحَدِهِمَا قَدَّمَهُ فِي اللَّحْدِ وَقَالَ أَنَا شَهِيدٌ عَلَى هَؤُلَاءِ وَأَمَرَ بِدَفْنِهِمْ بِدِمَائِهِمْ وَلَمْ يُصَلِّ عَلَيْهِمْ وَلَمْ يُغَسِّلْهُمْوَأَخْبَرَنَا ابْنُ الْمُبَارَكِ أَخْبَرَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لِقَتْلَى أُحُدٍ أَيُّ هَؤُلَاءِ أَكْثَرُ أَخْذًا لِلْقُرْآنِ فَإِذَا أُشِيرَ لَهُ إِلَى رَجُلٍ قَدَّمَهُ فِي اللَّحْدِ قَبْلَ صَاحِبِهِ وَقَالَ جَابِرٌ فَكُفِّنَ أَبِي وَعَمِّي فِي نَمِرَةٍ وَاحِدَةٍ وَقَالَ سُلَيْمَانُ بْنُ كَثِيرٍ حَدَّثَنِي الزُّهْرِيُّ حَدَّثَنِي مَنْ سَمِعَ جَابِرًا رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Laits bin Sa'ad] telah menceritakan kepada saya [Ibnu Syihab] dari ['Abdurrahman bin Ka'ab bin Malik] dari [Jabir bin 'Abdullah radliallahu 'anhu] bahwa Nabi Shallallahu'alaihiwasallam pernah menghimpun dua orang laki-laki yang gugur dalam perang Uhud dalam satu kubur dan dalam satu kain, lalu bersabda: \"Siapakah dianrara mereka yang lebih banyak mengambil hafalan Al Qur'an\". Bila Beliau telah diberi tahu kepada salah satu diantara keduanya, maka Beliau mendahulukannya didalam lahad lalu bersabda: \"Aku akan menjadi saksi atas mereka\". Maka kemudian Beliau memerintahkan agar menguburkan mereka dengan darah-darah mereka dan tidak dishalatkan dan juga tidak dimandikan\".Dan telah mengabarkan kepada kami [Ibnu AL Mubarak] telah mengabarkan kepada kami [Al Awza'iy] dari [Az Zuhriy] dari [Jabir bin 'Abdullah radliallahu 'anhua] bahwa Nabi Shallallahu'alaihiwasallam berkata tentang mereka yang gugur dalam perang Uhud: \"Siapakah dianrara mereka yang lebih banyak mengambil hafalan Al Qur'an\". Bila Beliau telah diberi tahu kepada salah satunya, maka Beliau mendahulukannya sebelum temannya yang lain\". Berkata, Jabir: \"Maka bapakku dan pamanku dikafankan dalam satu kain namirah (selimut bergaris terbuat dari wol). Dan berkata, [Sulaiman bin Katsir] telah menceritakan kepada saya [Az Zuhriy] telah menceritakan kepada saya [orang] yang telah mendengar dari [Jabir radliallahu 'anhu]."},"1262":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ حَوْشَبٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حَرَّمَ اللَّهُ مَكَّةَ فَلَمْ تَحِلَّ لِأَحَدٍ قَبْلِي وَلَا لِأَحَدٍ بَعْدِي أُحِلَّتْ لِي سَاعَةً مِنْ نَهَارٍ لَا يُخْتَلَى خَلَاهَا وَلَا يُعْضَدُ شَجَرُهَا وَلَا يُنَفَّرُ صَيْدُهَا وَلَا تُلْتَقَطُ لُقَطَتُهَا إِلَّا لِمُعَرِّفٍ فَقَالَ الْعَبَّاس�� رَضِيَ اللَّهُ عَنْهُ إِلَّا الْإِذْخِرَ لِصَاغَتِنَا وَقُبُورِنَا فَقَالَ إِلَّا الْإِذْخِرَوَقَالَ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِقُبُورِنَا وَبُيُوتِنَا وَقَالَ أَبَانُ بْنُ صَالِحٍ عَنْ الْحَسَنِ بْنِ مُسْلِمٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ وَقَالَ مُجَاهِدٌ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا لِقَيْنِهِمْ وَبُيُوتِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Hawsyab] telah menceritakan kepada kami ['Abdul Wahhab] telah menceritakan kepada kami [Khalid] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Allah telah mengharamkan kota Makkah, maka tidak dihalalkan buat seorangpun sebelum dan sesudahku melakukan pelanggaran disana, yang sebelumnya pernah dihalalkan buatku beberapa saat dalam suatu hari. Di Makkah tidak boleh diambil rumputnya dan tidak boleh ditebang pohonnya dan tidak boleh diburu hewan buruannya dan tidak ditemukan satupun barang temuan kecuali untuk diserahkan kepada juru pengumuman (agar dikembalikan kepada pemiliknya) \". Berkata, (Al 'Abbas radliallahu 'anhu) kecuali pohon idzkhir (pohon yang harum baunya) yang berguna untuk pengerjaan celup (pewarnaan pakaian) dan kubur-kubur kami. Maka Beliau bersabda: \"Ya kecuali pohon idzkhir\". Dan berkata, Abu Hurairah radliallahu 'anhu dari Nabi Shallallahu'alaihiwasallam: \"Untuk kubur-kubur mereka dan rumah-rumah mereka\". Dan berkata, [Aban bin Shalih] dari [Al Hasan bin Muslim] dari [Shafiyah binti Syaibah] bahwa dia mendengar Nabi Shallallahu'alaihiwasallam bersabda seperti ini. Dan berkata, [Mujahid] dari [Thawus] dari [Ibnu 'Abbas radliallahu 'anhu]: \"Dan untuk alat berhias mereka (parfum) dan rumah-rumah mereka\"."},"1263":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ عَمْرٌو سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدَ اللَّهِ بْنَ أُبَيٍّ بَعْدَ مَا أُدْخِلَ حُفْرَتَهُ فَأَمَرَ بِهِ فَأُخْرِجَ فَوَضَعَهُ عَلَى رُكْبَتَيْهِ وَنَفَثَ عَلَيْهِ مِنْ رِيقِهِ وَأَلْبَسَهُ قَمِيصَهُ فَاللَّهُ أَعْلَمُ وَكَانَ كَسَا عَبَّاسًا قَمِيصًاقَالَ سُفْيَانُ وَقَالَ أَبُو هَارُونَ يَحْيَى وَكَانَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَمِيصَانِ فَقَالَ لَهُ ابْنُ عَبْدِ اللَّهِ يَا رَسُولَ اللَّهِ أَلْبِسْ أَبِي قَمِيصَكَ الَّذِي يَلِي جِلْدَكَ قَالَ سُفْيَانُ فَيُرَوْنَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلْبَسَ عَبْدَ اللَّهِ قَمِيصَهُ مُكَافَأَةً لِمَا صَنَعَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] berkata, ['Amru]; Aku mendengar [Jabir bin 'Abdullah radliallahu 'anhua] berkata, Rasulullah Shallallahu'alaihiwasallam mendatangi 'Abdullah bin Ubay setelah dimasukkan kedalam kuburnya, lalu Beliau memerintahkan untuk mengeluarkannya. Maka jenazahnya dikeluarkan dan diletakkan di kedua paha Beliau kemudian Beliau menyempratkan dengan air ludah Beliau dan memakaikan baju qamis (gamis) Beliau. Dan Allah yang lebih mengetahui. Sebelumnya Beliau pernah memakaikan (memberi) baju kepada 'Abbas. Berkata, [Sufyan] dan berkata, [Abu Harun Yahya]: \"Bahwa Rasulullah Shallallahu'alaihiwasallam memiliki dua gamis\". Maka putra 'Abdullah bertanya kepada Beliau: \"Wahai Rasulullah, pakaikanlah bapakku dengan gamis anda yang telah mengenai kulit anda\". Sufyan berkata,: \"Mereka memandang Nabi Shallallahu'alaihiwasallam memakaikan baju Beliau kepada 'Abdullah sebagai hadiah yang sama seperti yang Beliau lakukan (terhadap 'Abbas) \"."},"1264":{"ar":"حَدَّثَنَا مُسَدَّدٌ أَخْبَرَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَطَاءٍ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا حَضَرَ أُحُدٌ دَعَانِي أَبِي مِنْ اللَّيْلِ فَقَالَ مَا أُرَانِي إِلَّا مَقْتُولًا فِي أَوَّلِ مَنْ يُقْتَلُ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنِّي لَا أَتْرُكُ بَعْدِي أَعَزَّ عَلَيَّ مِنْكَ غَيْرَ نَفْسِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ عَلَيَّ دَيْنًا فَاقْضِ وَاسْتَوْصِ بِأَخَوَاتِكَ خَيْرًا فَأَصْبَحْنَا فَكَانَ أَوَّلَ قَتِيلٍ وَدُفِنَ مَعَهُ آخَرُ فِي قَبْرٍ ثُمَّ لَمْ تَطِبْ نَفْسِي أَنْ أَتْرُكَهُ مَعَ الْآخَرِ فَاسْتَخْرَجْتُهُ بَعْدَ سِتَّةِ أَشْهُرٍ فَإِذَا هُوَ كَيَوْمِ وَضَعْتُهُ هُنَيَّةً غَيْرَ أُذُنِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah mengabarkan kepada kami [Bisyir bin Al Mufadhdhal] telah menceritakan kepada kami [Husain AL Mu'alim] dari ['Atha'] dari [Jabir radliallahu 'anhu] berkata; Ketika terjadi perang Uhud, pada suatu malamnya bapakku memanggilku seraya berkata,: \"Tidaklah aku melihat diriku (menduga) melainkan aku akan menjadi orang yang pertama-tama gugur diantara para sahabat Nabi Shallallahu'alaihiwasallam (dalam peperangan ini) dan aku tidak meninggalkan sesuatu yang berharga bagimu sepeninggalku melainkan diri Rasulullah Shallallahu'alaihiwasallam. Dan aku mempunyai hutang, maka lunasilah dan berilah nasehat yang baik kepada saudara-saudaramu yang perempuan\". Pada pagi harinya kami dapati bapakku adalah orang yang pertama gugur dan dikuburkan bersama dengan yang lain dalam satu kubur. Setelah itu perasaanku tidak enak dengan membiarkan dia bersama yang lain, maka kemudian aku keluarkan setelah enam bulan lamanya dari hari pemakamannya dan aku dapati jenazah bapakku masih utuh sebagaimana hari dia dikebumikan dan tidak ada yang berubah padanya kecuali sedikit pada ujung bawah telinganya\"."},"1265":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَطَاءٍ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَدُفِنَ مَعَ أَبِي رَجُلٌ فَلَمْ تَطِبْ نَفْسِي حَتَّى أَخْرَجْتُهُ فَجَعَلْتُهُ فِي قَبْرٍ عَلَى حِدَةٍ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari [Ibnu Abu Najih] dari ['Atha'] dari [Jabir radliallahu 'anhu] berkata; \"Seorang laki-laki dikuburkan bersama dengan bapakku namun kemudian perasaanku tidak enak hingga akhirnya aku keluarkan dan aku kuburkan dalam satu liang kubur kembali\"."},"1266":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا اللَّيْثُ بْنُ سَعْدٍ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْمَعُ بَيْنَ رَجُلَيْنِ مِنْ قَتْلَى أُحُدٍ ثُمَّ يَقُولُ أَيُّهُمْ أَكْثَرُ أَخْذًا لِلْقُرْآنِ فَإِذَا أُشِيرَ لَهُ إِلَى أَحَدِهِمَا قَدَّمَهُ فِي اللَّحْدِ فَقَالَ أَنَا شَهِيدٌ عَلَى هَؤُلَاءِ يَوْمَ الْقِيَامَةِ فَأَمَرَ بِدَفْنِهِمْ بِدِمَائِهِمْ وَلَمْ يُغَسِّلْهُمْ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Al Laits bin Sa'ad] berkata, telah menceritakan kepada kami [Ibnu Syihab] dari ['Abdurrahman bin Ka'ab bin Malik] dari [Jabir bin 'Abdullah radliallahu 'anhua] berkata,: \"Nabi Shallallahu'alaihiwasallam pernah menggabungkan dalam satu kubur dua orang laki-laki yang gugur dalam perang Uhud dan dalam satu kain, lalu bersabda: \"Siapakah diantara mereka yang lebih banyak mempunyai hafalan Al Qur'an\". Bila Beliau telah diberi tahu kepada salah satu diantara keduanya, maka Beliau mendahulukannya didalam lahad lalu bersabda: \"Aku akan menjadi saksi atas mereka pada hari qiyamat\". Maka kemudian Beliau memerintahkan agar menguburkan mereka dengan darah-darah mereka dan tidak pula dimandikan\". "},"1267":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُ��َنَّ عُمَرَ انْطَلَقَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَهْطٍ قِبَلَ ابْنِ صَيَّادٍ حَتَّى وَجَدُوهُ يَلْعَبُ مَعَ الصِّبْيَانِ عِنْدَ أُطُمِ بَنِي مَغَالَةَ وَقَدْ قَارَبَ ابْنُ صَيَّادٍ الْحُلُمَ فَلَمْ يَشْعُرْ حَتَّى ضَرَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ ثُمَّ قَالَ لِابْنِ صَيَّادٍ تَشْهَدُ أَنِّي رَسُولُ اللَّهِ فَنَظَرَ إِلَيْهِ ابْنُ صَيَّادٍ فَقَالَ أَشْهَدُ أَنَّكَ رَسُولُ الْأُمِّيِّينَ فَقَالَ ابْنُ صَيَّادٍ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَشْهَدُ أَنِّي رَسُولُ اللَّهِ فَرَفَضَهُ وَقَالَ آمَنْتُ بِاللَّهِ وَبِرُسُلِهِ فَقَالَ لَهُ مَاذَا تَرَى قَالَ ابْنُ صَيَّادٍ يَأْتِينِي صَادِقٌ وَكَاذِبٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُلِّطَ عَلَيْكَ الْأَمْرُ ثُمَّ قَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي قَدْ خَبَأْتُ لَكَ خَبِيئًا فَقَالَ ابْنُ صَيَّادٍ هُوَ الدُّخُّ فَقَالَ اخْسَأْ فَلَنْ تَعْدُوَ قَدْرَكَ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ دَعْنِي يَا رَسُولَ اللَّهِ أَضْرِبْ عُنُقَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ يَكُنْهُ فَلَنْ تُسَلَّطَ عَلَيْهِ وَإِنْ لَمْ يَكُنْهُ فَلَا خَيْرَ لَكَ فِي قَتْلِهِ وَقَالَ سَالِمٌ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُ انْطَلَقَ بَعْدَ ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُبَيُّ بْنُ كَعْبٍ إِلَى النَّخْلِ الَّتِي فِيهَا ابْنُ صَيَّادٍ وَهُوَ يَخْتِلُ أَنْ يَسْمَعَ مِنْ ابْنِ صَيَّادٍ شَيْئًا قَبْلَ أَنْ يَرَاهُ ابْنُ صَيَّادٍ فَرَآهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُضْطَجِعٌ يَعْنِي فِي قَطِيفَةٍ لَهُ فِيهَا رَمْزَةٌ أَوْ زَمْرَةٌ فَرَأَتْ أمُّ ابْنِ صَيّادٍ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَتَّقِي بِجُذُوعِ النَّخْلِ فَقَالَتْ لِابْنِ صَيَّادٍ يَا صَافِ وَهُوَ اسْمُ ابْنِ صَيَّادٍ هَذَا مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَثَارَ ابْنُ صَيَّادٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ تَرَكَتْهُ بَيَّنَ وَقَالَ شُعَيْبٌ فِي حَدِيثِهِ فَرَفَصَهُ رَمْرَمَةٌ أَوْ زَمْزَمَةٌ وَقَالَ إِسْحَاقُ الْكَلْبِيُّ وَعُقَيْلٌ رَمْرَمَةٌ وَقَالَ مَعْمَرٌ رَمْزَةٌ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami ['Abdullah] dari [Yunus] dari [Az Zuhri] berkata, telah mengabarkan kepada saya [Salim bin 'Abdullah] bahwa [Ibnu'Umar radhiyallahu'anhuma] mengabarkannya bahwa 'Umar dan Nabi shallallahu 'alaihi wasallam berangkat bersama rambongan untuk mememui Ibnu Shayyad hingga akhirnya mereka mendapatinya sedang bermain bersama anak-anak yang lain di bangunan yang tinggi milik Bani Magholah. Ibnu Shayyad sudah mendekati baligh dan dia tidak menyadari (kedatangan Nabi shallallahu 'alaihi wasallam) hingga akhirnya Nabi shallallahu 'alaihi wasallam menepuknya dengan tangan Beliau kemudian berkata kepada Ibnu Shayyad: \"Apakah kamu bersaksi bahwa aku ini utusan Allah?\". Maka Ibnu Shayyad memandang Beliau lalu berkata: \"Aku bersaksi bahwa kamu utusan kaum ummiyyin (kaum yang tidak kenal baca tulis) \". Kemudian Ibnu Shayyad berkata, kepada Nabi shallallahu 'alaihi wasallam: \"Apakah kamu juga bersaksi bahwa aku ini utusan Allah?\". Maka Beliau menolaknya dan berkata, \"Aku beriman kepada Allah dan kepada Rasul-rasulNya\". Kemudian Beliau berkata: \"Apa yang kamu pandang sebagai alasan (sehingga mengaku sebagai Rasul). Berkata, Ibnu Shayyad: \"Karena telah datang kepadaku orang yang jujur dan pendusta\". Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Urusanmu jadi kacau\". Kemudian Nabi shallallahu 'alaihi wasallam berkata, kepadanya: \"Sesungguhnya aku menyembunyikan (sesuatu dalam hatiku) coba kamu tebak?\". Ibnu Shayyad berkata: \"Itu adalah asap\". Beliau berkata: \"Hinalah kamu, dan kamu tidak bakalan melebihi kemampuanmu sebagai seorang dukun. Lalu 'Umar bin Al Khaththob Radhiyallahu'anhu berkata: \"Wahai Rasulullah, biarkanlah aku memenggal leher orang ini!\". Maka Beliau berkata: \"Jika dia benar, kamu tidak akan berkuasa atasnya dan bila dia benar maka tidak ada kebaikan buatmu dengan membunuhnya\". Berkata, [Salim]; Aku mendengar [Ibnu 'Umar Radhiyallahu'anhuma]: \"Setelah itu Nabi shallallahu 'alaihi wasallam dan Ubay bin Ka'ab pergi menuju satu pohon kurma tempat Ibnu Shayyad sebelumnya berada di situ dengan harapan Beliau dapat mendengar sesuatu dari Ibnu Shayyad sebelum dia melihat Beliau. Maka Nabi shallallahu 'alaihi wasallam melihat Ibnu Shayyad sedang tertidur dibalik baju tebalnya dengan mendengkur ringan. Dalam keadaan itu ibu dari Ibnu Shayyad melihat Rasulullah shallallahu 'alaihi wasallam sedang duduk di bawah pohon kurma, maka ibunya berkata, kepada Ibnu Shayyad: \"Wahai Shaf, (ini nama dari Ibnu Shayyad), Muhammad shallallahu'alaihi wasallam\". Maka Ibnu Shayyad kembali pada keadaannya semula (berbaring). Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Seandainya ibunya biarkan, pasti jelaslah persoalannya (dajjal atau bukan)\". Dan [Syu'aib] berkata; 'menekannya dengan ramramah (suara halus) atau zamzamah. Sedangkan [Ishaq Al Kalbi] dan ['Uqail] berkata; \"ramramah\". [Ma'mar] berkata; ramzah."},"1268":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ وَهْوَ ابْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ غُلَامٌ يَهُودِيٌّ يَخْدُمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَرِضَ فَأَتَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُهُ فَقَعَدَ عِنْدَ رَأْسِهِ فَقَالَ لَهُ أَسْلِمْ فَنَظَرَ إِلَى أَبِيهِ وَهُوَ عِنْدَهُ فَقَالَ لَهُ أَطِعْ أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْلَمَ فَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ الْحَمْدُ لِلَّهِ الَّذِي أَنْقَذَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad] dia adalah Ibnu Zaid dari [Tsabit] dari [Anas radliallahu 'anhu] berkata,: \"Ada seorang anak kecil Yahudi yang bekerja membantu Nabi Shallallahu'alaihiwasallam menderita sakit. Maka Nabi Shallallahu'alaihiwasallam menjenguknya dan Beliau duduk di sisi kepalanya lalu bersabda: \"Masuklah Islam\". Anak kecil itu memandang kepada bapaknya yang berada di dekatnya, lalu bapaknya berkata,: \"Ta'atilah Abu Al Qasim Shallallahu'alaihiwasallam\". Maka anak kecil itu masuk Islam. Kemudian Nabi Shallallahu'alaihiwasallam keluar sambil bersabda: \"Segala puji bagi Allah yang telah menyelamatkan anak itu dari neraka\"."},"1269":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ قَالَ عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُكُنْتُ أَنَا وَأُمِّي مِنْ الْمُسْتَضْعَفِينَ أَنَا مِنْ الْوِلْدَانِ وَأُمِّي مِنْ النِّسَاءِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] berkata; ['Ubaidullah bin Abu Yazid] berkata; Aku mendengar [Ibnu 'Abbas radliallahu 'anhuma] berkata,: \"Aku dan ibuku adalah termasuk orang-orang lemah, aku dari golongan anak-anak dan ibuku dari golongan wanita\"."},"1270":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ قَالَ ابْنُ شِهَابٍ يُصَلَّى عَلَى كُلِّ مَوْلُودٍ مُتَوَفًّى وَإِنْ كَانَ لِغَيَّةٍ مِنْ أَجْلِ أَنَّهُ وُلِدَ عَلَى فِطْرَةِ الْإِسْلَامِ يَدَّعِي أَبَوَاهُ الْإِسْلَامَ أَوْ أَبُوهُ خَاصَّةً وَإِنْ كَانَتْ أُمُّهُ عَلَى غَيْرِ الْإِسْلَامِ إِذَا اسْتَهَلَّ صَارِخًا صُلِّيَ عَلَيْهِ وَلَا يُصَلَّى عَلَى مَنْ لَا يَسْتَهِلُّ مِنْ أَجْلِ أَنَّهُ سِقْطٌ فَإِنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُكَانَ يُحَدِّثُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مَوْلُودٍ إِلَّا يُولَدُ عَلَى الْفِطْرَةِ فَأَبَوَاهُ يُهَوِّدَانِهِ أَوْ يُنَصِّرَانِهِ أَوْ يُمَجِّسَانِهِ كَمَا تُنْتَجُ الْبَهِيمَةُ بَهِيمَةً جَمْعَاءَ هَلْ تُحِسُّونَ فِيهَا مِنْ جَدْعَاءَ ثُمَّ يَقُولُ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ{ فِطْرَةَ اللَّهِ الَّتِي فَطَرَ النَّاسَ عَلَيْهَا }الْآيَةَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] berkata, [Ibnu Syihab]: \"Setiap anak yang wafat wajib dishalatkan sekalipun anak hasil zina karena dia dilahirkan dalam keadaan fithrah Islam, jika kedua orangnya mengaku beragama Islam atau hanya bapaknya yang mengaku beragama Islam meskipun ibunya tidak beragama Islam selama anak itu ketika dilahirkan mengeluarkan suara (menangis) dan tidak dishalatkan bila ketika dilahirkan anak itu tidak sempat mengeluarkan suara (menangis) karena dianggap keguguran sebelum sempurna, berdasarkan perkataan [Abu Hurairah radliallahu 'anhu] yang menceritakan bahwa Nabi Shallallahu'alaihiwasallam bersabda: \"Tidak ada seorang anakpun yang terlahir kecuali dia dilahirkan dalam keadaan fithrah. Maka kemudian kedua orang tuanyalah yang akan menjadikan anak itu menjadi Yahudi, Nashrani atau Majusi sebagaimana binatang ternak yang melahirkan binatang ternak dengan sempurna. Apakah kalian melihat ada cacat padanya?\". Kemudian Abu Hurairah radliallahu 'anhu berkata, (mengutip firman Allah QS Ar-Ruum: 30 yang artinya: ('Sebagai fitrah Allah yang telah menciptakan manusia menurut fitrah itu\")."},"1271":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مَوْلُودٍ إِلَّا يُولَدُ عَلَى الْفِطْرَةِ فَأَبَوَاهُ يُهَوِّدَانِهِ وَيُنَصِّرَانِهِ أَوْ يُمَجِّسَانِهِ كَمَا تُنْتَجُ الْبَهِيمَةُ بَهِيمَةً جَمْعَاءَ هَلْ تُحِسُّونَ فِيهَا مِنْ جَدْعَاءَ ثُمَّ يَقُولُ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ{ فِطْرَةَ اللَّهِ الَّتِي فَطَرَ النَّاسَ عَلَيْهَا لَا تَبْدِيلَ لِخَلْقِ اللَّهِ ذَلِكَ الدِّينُ الْقَيِّمُ }","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhriy] telah mengabarkan kepada saya [Abu Salamah bin 'Abdurrahman] bahwa [Abu Hurairah radliallahu 'anhu] berkata; Telah bersabda Rasulullah Shallallahu'alaihiwasallam: \"Tidak ada seorang anak pun yang terlahir kecuali dia dilahirkan dalam keadaan fithrah. Maka kemudian kedua orang tuanyalah yang akan menjadikan anak itu menjadi Yahudi, Nashrani atau Majusi sebagaimana binatang ternak yang melahirkan binatang ternak dengan sempurna. Apakah kalian melihat ada cacat padanya\". Kemudian Abu Hurairah radliallahu 'anhu berkata, (mengutip firman Allah subhanahu wata'ala QS Ar-Ruum: 30 yang artinya: ('Sebagai fitrah Allah yang telah menciptakan manusia menurut fitrah itu. Tidak ada perubahan pada fitrah Allah. (Itulah) agama yang lurus\")."},"1272":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنِي أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ أَبِيهِ أَنَّهُ أَخْبَرَهُ أَنَّهُلَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ جَاءَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَ عِنْدَهُ أَبَا جَهْلِ بْنَ هِشَامٍ وَعَبْدَ اللَّهِ بْنَ أَبِي أُمَيَّةَ بْنِ الْمُغِيرَةِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَبِي طَالِبٍ يَا عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ كَلِمَةً أَشْهَدُ لَكَ بِهَا عِنْدَ اللَّهِ فَقَالَ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ أَتَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ فَلَمْ يَزَلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْرِضُهَا عَلَيْهِ وَيَعُودَانِ بِتِلْكَ الْمَقَالَةِ حَتَّى قَالَ أَبُو طَالِبٍ آخِرَ مَا كَلَّمَهُمْ هُوَ عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ وَأَبَى أَنْ يَقُولَ لَا إِلَهَ إِلَّا اللَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا وَاللَّهِ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْكَ فَأَنْزَلَ اللَّهُ تَعَالَى فِيهِ{ مَا كَانَ لِلنَّبِيِّ }الْآيَةَ","id":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Ya'qub bin Ibrahim] berkata, telah menceritakan [apakku] kepadaku dari [Shalih] dari [Ibnu Syihab] berkata, telah mengabarkan kepada saya telah mengabarkan kepada saya [Sa'id bin Al Musayyab] dari [bapaknya] bahwasanya dia mengabarkan kepadanya: \"Ketika menjelang wafatnya Abu Tholib, Rasulullah Shallallahu'alaihiwasallam mendatanginya dan ternyata sudah ada Abu Jahal bin Hisyam dan 'Abdullah bin Abu Umayyah bin Al Mughirah. Maka Rasulullah Shallallahu'alaihiwasallam berkata, kepada Abu Tholib: \"Wahai pamanku katakanlah laa ilaaha illallah, suatu kalimat yang dengannya aku akan menjadi saksi atasmu di sisi Allah\". Maka berkata, Abu Jahal dan 'Abdullah bin Abu Umayyah: \"Wahai Abu Thalib, apakah kamu akan meninggalkan agama 'Abdul Muthalib?\". Rasulullah Shallallahu'alaihiwasallam terus menawarkan kalimat syahadat kepada Abu Tholib dan bersamaan itu pula kedua orang itu mengulang pertanyaannya yang berujung Abu Tholib pada akhir ucapannya tetap mengikuti agama 'Abdul Muthalib dan enggan untuk mengucapkan laa ilaaha illallah. Maka berkatalah Rasulullah Shallallahu'alaihiwasallam: \"Adapun aku akan tetap memintakan ampun buatmu selama aku tidak dilarang\". Maka turunlah firman Allah subhanahu wata'ala tentang peristiwa ini: (\"Tidak patut bagi Nabi …\") dalam QS AT-Taubah ayat 113)."},"1273":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ مَرَّ بِقَبْرَيْنِ يُعَذَّبَانِ فَقَالَ إِنَّهُمَا لَيُعَذَّبَانِ وَمَا يُعَذَّبَانِ فِي كَبِيرٍ أَمَّا أَحَدُهُمَا فَكَانَ لَا يَسْتَتِرُ مِنْ الْبَوْلِ وَأَمَّا الْآخَرُ فَكَانَ يَمْشِي بِالنَّمِيمَةِ ثُمَّ أَخَذَ جَرِيدَةً رَطْبَةً فَشَقَّهَا بِنِصْفَيْنِ ثُمَّ غَرَزَ فِي كُلِّ قَبْرٍ وَاحِدَةً فَقَالُوا يَا رَسُولَ اللَّهِ لِمَ صَنَعْتَ هَذَا فَقَالَ لَعَلَّهُ أَنْ يُخَفَّفَ عَنْهُمَا مَا لَمْ يَيْبَسَا","id":"Telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Mujahid] dari [Thawus] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata, dari Nabi Shallallahu'alaihiwasallam bahwasanya Beliau berjalan melewati dua kuburan yang penghuninya sedang disiksa, lalu Beliau bersabda: \"Keduanya sungguh sedang disiksa, dan tidaklah keduanya disiksa disebabkan karena berbuat dosa besar. Yang satu disiksa karena tidak bersuci setelah kencing sedang yang satunya lagi karena selalu mengadu domba\" Kemudian Beliau mengambil sebatang dahan kurma yang masih basah daunnya lalu membelahnya menjadi dua bagian kemudian menancapkannya pada masing-masing kuburan tersebut. Mereka bertanya: \"Kenapa anda melakukan ini?\". Nabi Shallallahu'alaihiwasallam menjawab: \"Semoga diringankan (siksanya) selama batang pohon ini basah\". "},"1274":{"ar":"حَدَّثَنَا عُثْمَانُ قَالَ حَدَّثَنِي جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا فِي جَنَازَةٍ فِي بَقِيعِ الْغَرْقَدِ فَأَتَانَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَعَدَ وَقَعَدْنَا حَوْلَهُ وَمَعَهُ مِخْصَرَةٌ فَنَكَّسَ فَجَعَلَ يَنْكُتُ بِمِخْصَرَتِهِ ثُمَّ قَالَ مَا مِنْكُمْ مِنْ أَحَدٍ مَا مِنْ نَفْسٍ مَنْفُوسَةٍ إِلَّا كُتِبَ مَكَانُهَا مِنْ الْجَنَّةِ وَالنَّارِ وَإِلَّا قَدْ كُتِبَ شَقِيَّةً أَوْ سَعِيدَةً فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَفَلَا نَتَّكِلُ عَلَى كِتَابِنَا وَنَدَعُ الْعَمَلَ فَمَنْ كَانَ مِنَّا مِنْ أَهْلِ السَّعَادَةِ فَسَيَصِيرُ إِلَى عَمَلِ أَهْلِ السَّعَادَةِ وَأَمَّا مَنْ كَانَ مِنَّا مِنْ أَهْلِ الشَّقَاوَةِ فَسَيَصِيرُ إِلَى عَمَلِ أَهْلِ الشَّقَاوَةِ قَالَ أَمَّا أَهْلُ السَّعَادَةِ فَيُيَسَّرُونَ لِعَمَلِ السَّعَادَةِ وَأَمَّا أَهْلُ الشَّقَاوَةِ فَيُيَسَّرُونَ لِعَمَلِ الشَّقَاوَةِ ثُمَّ قَرَأَ{ فَأَمَّا مَنْ أَعْطَى وَاتَّقَى وَصَدَّقَ بِالْحُسْنَى }الْآيَةَ","id":"Telah menceritakan kepada kami ['Utsman] telah menceritakan kepada saya [Jarir] dari [Manshur] dari [Sa'ad bin 'Ubaidah] dari [Abu 'Abdurrahman] dari ['Ali radliallahu 'anhu] berkata,: Kami pernah berada di dekat kuburan Baqi' Al Ghorqad yang kemudian Nabi Shallallahu'alaihiwasallam mendatangi kami, lalu Beliau duduk maka kami pun ikut duduk dekat Beliau. Beliau membawa sebuah tongkat kecil yang dengan tongkat itu Beliau memukul-mukul permukaan tanah dan mengorek-ngoreknya seraya berkata,: \"Tidak ada seorangpun dari kalian dan juga tidak satupun jiwa yang bernafas melainkan telah ditentukan tempatnya di surga atau di neraka dan melainkan sudah ditentukan jalan sengsaranya atau bahagianya\". Kemudian ada seorang yang berkata,: \"Wahai Rasulullah, dengan begitu apakah kita tidak pasrah saja menunggu apa yang sudah ditentukan buat kita dan kita tidak perlu beramal?. Karena barangsiapa diantara kita yang telah ditentukan sebagai orang yang berbahagia, maka pasti dia sampai kepada amalan orang yang berbahagia, sebaliknya siapa diantara kita yang telah ditentukan sebagai orang yang sengsara maka pasti dia akan sampai kepada amalan orang yang sengsara\". Maka Beliau bersabda: \"(Tidak begitu). Akan tetapi siapa yang telah ditetapkan sebagai orang yang berbahagia, dia akan dimudahkan untuk beramal amalan orang yang berbahagia dan sebaliknya orang yang telah ditetapkan sebagai orang yang akan sengsara maka dia pasti akan dimudahkan beramal amalan orang yang sengsara\". Kemudian Beliau membaca firman Allah subhanahu wata'ala QS Al Lail ayat 5 - 6 yang artinya: (\"Adapun orang yang memberikan (hartanya di jalan Allah) dan bertakwa serta membenarkan adanya pahala yang terbaik (syurga) \"). "},"1275":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا خَالِدٌ عَنْ أَبِي قِلَابَةَ عَنْ ثَابِتِ بْنِ الضَّحَّاكِ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ مَنْ حَلَفَ بِمِلَّةٍ غَيْرِ الْإِسْلَامِ كَاذِبًا مُتَعَمِّدًا فَهُوَ كَمَا قَالَ وَمَنْ قَتَلَ نَفْسَهُ بِحَدِيدَةٍ عُذِّبَ بِهِ فِي نَارِ جَهَنَّمَوَقَالَ حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ الْحَسَنِ حَدَّثَنَا جُنْدَبٌ رَضِيَ اللَّهُ عَنْهُ فِي هَذَا الْمَسْجِدِ فَمَا نَسِينَا وَمَا نَخَافُ أَنْ يَكْذِبَ جُنْدَبٌ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ بِرَجُلٍ جِرَاحٌ فَقَتَلَ نَفْسَهُ فَقَالَ اللَّهُ بَدَرَنِي عَبْدِي بِنَفْسِهِ حَرَّمْتُ عَلَيْهِ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Khalid] dari [Abu Qalabah] dari [Tsabit bin Adh-Dhahhak radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang bersumpah setia dengan agama selain Islam secara dusta dan sengaja, maka dia seperti apa yang dikatakannya, dan barangsiapa membunuh dirinya sendiri dengan besi, maka dia akan disiksa di dalam nereka Jahanam\". Dan berkata, Hajjaj bin Minhal telah menceritakan kepada kami Jarir bin Hazim dari Al Hasan telah menceritakan kepada kami Jundab radliallahu 'anhu: \"Didalam masjid ini tidak akan kami lupakan dan kami tidak takut bahwa Jundab akan berdusta atas nama Nabi Shallallahu'alaihiwasallam, dia berkata,: \"Pernah ada seorang yang terluka lalu dia bunuh diri maka Allah Shallallahu'alaihiwasallam berfirman: \"HambaKu mendahului aku dalam hal nyawanya sehingga aku haramkan baginya surga\"."},"1276":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي يَخْنُقُ نَفْسَهُ يَخْنُقُهَا فِي النَّارِ وَالَّذِي يَطْعُنُهَا يَطْعُنُهَا فِي النَّارِ","id":"Telah menceritakan kepada kami [Abu AL Yaman] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] berkata; Telah bersabda Nabi Shallallahu'alaihiwasallam: \"Barangsiapa yang mencekik dirinya (hingga mati) maka dia akan dicekik di neraka dan barangsiapa yang menikam dirinya (hingga mati) maka dia akan di tikam di neraka\"."},"1277":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنِي اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُمْ أَنَّهُ قَالَلَمَّا مَاتَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ دُعِيَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَلَمَّا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَثَبْتُ إِلَيْهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتُصَلِّي عَلَى ابْنِ أُبَيٍّ وَقَدْ قَالَ يَوْمَ كَذَا وَكَذَا كَذَا وَكَذَا أُعَدِّدُ عَلَيْهِ قَوْلَهُ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَخِّرْ عَنِّي يَا عُمَرُ فَلَمَّا أَكْثَرْتُ عَلَيْهِ قَالَ إِنِّي خُيِّرْتُ فَاخْتَرْتُ لَوْ أَعْلَمُ أَنِّي إِنْ زِدْتُ عَلَى السَّبْعِينَ يُغْفَرُ لَهُ لَزِدْتُ عَلَيْهَا قَالَ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ انْصَرَفَ فَلَمْ يَمْكُثْ إِلَّا يَسِيرًا حَتَّى نَزَلَتْ الْآيَتَانِ مِنْ بَرَاءَةٌ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا إِلَى قَوْلِهِ وَهُمْ فَاسِقُونَ }قَالَ فَعَجِبْتُ بَعْدُ مِنْ جُرْأَتِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ وَاللَّهُ وَرَسُولُهُ أَعْلَمُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada saya [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah] dari [Ibnu 'Abbas] dari ['Umar bin Al Khaththab radliallahu 'anhu] bahwasanya dia berkata,: \"Ketika 'Abdullah bin Ubay bin Salul meninggal dunia, Rasulullah Shallallahu'alaihiwasallam diminta untuk menyolatkannya. Ketika Beliau sudah berdiri hendak shalat aku hampiri Beliau lalu aku berkata: \"Wahai Rasulullah, apakah anda akan menyolatkan anak Ubay padahal dia suatu hari pernah mengatakan begini begini, begini dan begini, (aku mengulang-ulang ucapan bin Ubay yang dahulu pernah dilontarkan kepada Nabi) \". Ternyata Rasulullah Shallallahu'alaihiwasallam malah tersenyum seraya berkata,: \"Cukupkanlah ucapanmu dariku wahai 'Umar. Ketika aku terus berbicara kepada Beliau, Beliau berkata,: \"Sungguh aku diberi pilihan dan aku memilih seandainya aku mengetahui bila aku menambah lebih dari tujuh puluh kali permohonan ampun baginya dia akan diampuni, pasti aku akan tambah (permohonan ampun baginya) \". 'Umar berkata,: \"Maka kemudian Rasulullah Shallallahu'alaihiwasallam menyolatkannya hingga selesai, tak lama setelah Beliau terdiam, turunlah firman Allah subhanahu wata'ala QS At-Taubah ayat 84 yang artinya (\"Dan janganlah kamu menyolatkan siapa yang mati dari mereka selamanya\" hingga ayat \"mereka mati dalam keadaan fasiq\")."},"1278":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُمَرُّوا بِجَنَازَةٍ فَأَثْنَوْا عَلَيْهَا خَيْرًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَبَتْ ثُمَّ مَرُّوا بِأُخْرَى فَأَثْنَوْا عَلَيْهَا شَرًّا فَقَالَ وَجَبَتْ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ مَا وَجَبَتْ قَالَ هَذَا أَثْنَيْتُمْ عَلَيْهِ خَيْرًا فَوَجَبَتْ لَهُ الْجَنَّةُ وَهَذَا أَثْنَيْتُمْ عَلَيْهِ شَرًّا فَوَجَبَتْ لَهُ النَّارُ أَنْتُمْ شُهَدَاءُ اللَّهِ فِي الْأَرْضِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami ['Abdul 'Aziz bin Shuhaib] berkata; aku mendengar [Anas bin Malik radliallahu 'anhu] berkata,: \"Mereka (para sahabat) pernah melewati satu jenazah lalu mereka menyanjungnya dengan kebaikan. Maka Nabi Shallallahu'alaihiwasallam bersabda: \"Pasti baginya\". Kemudian mereka melewati jenazah yang lain lalu mereka menyebutnya dengan keburukan, maka Beliaupun bersabda: \"Pasti baginya\". Maka kemudian 'Umar bin Al Khaththab radliallahu 'anhu bertanya: \"Apa yang dimaksud pasti baginya?\". Beliau menjawab: \"Jenazah pertama kalian sanjung dengan kebaikan, maka pasti baginya masuk surga sedang jenazah kedua kalian menyebutnya dengan keburukan, berarti dia masuk neraka karena kalian adalah saksi-saksi Allah di muka bumi\"."},"1279":{"ar":"حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ هُوَ الصَّفَّارُ حَدَّثَنَا دَاوُدُ بْنُ أَبِي الْفُرَاتِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِي الْأَسْوَدِ قَالَقَدِمْتُ الْمَدِينَةَ وَقَدْ وَقَعَ بِهَا مَرَضٌ فَجَلَسْتُ إِلَى عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ فَمَرَّتْ بِهِمْ جَنَازَةٌ فَأُثْنِيَ عَلَى صَاحِبِهَا خَيْرًا فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ وَجَبَتْ ثُمَّ مُرَّ بِأُخْرَى فَأُثْنِيَ عَلَى صَاحِبِهَا خَيْرًا فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ وَجَبَتْ ثُمَّ مُرَّ بِالثَّالِثَةِ فَأُثْنِيَ عَلَى صَاحِبِهَا شَرًّا فَقَالَ وَجَبَتْ فَقَالَ أَبُو الْأَسْوَدِ فَقُلْتُ وَمَا وَجَبَتْ يَا أَمِيرَ الْمُؤْمِنِينَ قَالَ قُلْتُ كَمَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا مُسْلِمٍ شَهِدَ لَهُ أَرْبَعَةٌ بِخَيْرٍ أَدْخَلَهُ اللَّهُ الْجَنَّةَ فَقُلْنَا وَثَلَاثَةٌ قَالَ وَثَلَاثَةٌ فَقُلْنَا وَاثْنَانِ قَالَ وَاثْنَانِ ثُمَّ لَمْ نَسْأَلْهُ عَنْ الْوَاحِدِ","id":"Telah menceritakan kepada kami ['Affan bin Muslim, dia dijuluki Ash-Shaffar] telah menceritakan kepada kami [Daud bin Abu Al Furat] dari ['Abdullah bin Buraidah] dari [Abu Al Aswad] berkata,: \"Aku pernah berkunjung ke kota Madinah saat sedang berjangkitnya penyakit. Saat aku sedang duduk dekat ['Umar bin Al Khaththab radliallahu 'anhu] tiba-tiba ada jenazah yang lewat di hadapan mereka lalu mereka menyanjungnya dengan kebaikan. Maka 'Umar radliallahu 'anhu berkata,: \"Pasti baginya\". Tak lama kemudian lewat jenazah yang lain lalu jenazah itu pun disanjung dengan kebaikan. Maka 'Umar radliallahu 'anhu berkata, lagi: \"Pasti baginya\". Kemudian lewat jenazah yang ketiga lalu jenazah itu disebut dengan keburukan, maka 'Umar radliallahu 'anhu pun berkata,: \"Pasti baginya\". Berkata, Abu Al Aswad; maka aku bertanya: \"Apa yang dimaksud pasti baginya, wahai Amirul mu'minin?\". Maka dia berkata,: \"Aku mengatakannya seperti yang dikatakan oleh Nabi Shallallahu'alaihiwasallam: \"Bilamana seorang muslim (meninggal dunia) lalu disaksikan (disanjung) oleh empat orang muslim lainnya dengan kebaikan maka pasti Allah akan memasukakannya ke dalam surga\". Maka kami bertanya kepadanya: \"Bagaimana kalau tiga orang muslim?\". Dia menjawab; \"Juga oleh tiga orang\". Kami berkata lagi: \"Bagaimana kalau dua orang muslim?\". Dia menjawab; \"Juga oleh dua orang\". Dan kami tidak menanyakannya lagi bagaimana kalau satu orang\"."},"1280":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أُقْعِدَ الْمُؤْمِنُ فِي قَبْرِهِ أُتِيَ ثُمَّ شَهِدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَذَلِكَ قَوْلُهُ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ }حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ بِهَذَا وَزَادَ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا }نَزَلَتْ فِي عَذَابِ الْقَبْرِ","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] telah menceritakan kepada kami [Syu'bah] dari ['Alqamah bin Martsad] dari [Sa'ad bin 'Ubadah] dari [Al Bara' bin 'Azib radliallahu 'anhuma] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Apabila (jenazah) seorang muslim sudah didudukkan dalam kuburnya maka dia akan dihadapkan (pertanyaan malaikat), kemudian ia bersaksi bahwa tidak ada ilah yang berhak disembah kecuali Allah dan Muhammad utusan Allah. Itulah perkataan seorang muslim sebagaimana firman Allah subhanahu wata'ala (QS Ibrahim ayat 27 yang artinya): (\"Allah akan meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh itu\"). Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] seperti riwayat ini lalu menambahkannya (firman Allah subhanahu wata'ala): (\"Allah akan meneguhkan (iman) orang-orang yang beriman…\") ayat ini turun berkenaan dengan masalah siksa kubur\"."},"1281":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنِي أَبِي عَنْ صَالِحٍ حَدَّثَنِي نَافِعٌ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُ قَالَاطَّلَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَهْلِ الْقَلِيبِ فَقَالَ وَجَدْتُمْ مَا وَعَدَ رَبُّكُمْ حَقًّا فَقِيلَ لَهُ تَدْعُو أَمْوَاتًا فَقَالَ مَا أَنْتُمْ بِأَسْمَعَ مِنْهُمْ وَلَكِنْ لَا يُجِيبُونَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepadaku [bapakku] dari [Shalih] telah menceritakan kepada saya [Nafi'] bahwa [Ibnu 'Umar radliallahu 'anhuma] mengabarkannya berkata; Nabi Shallallahu'alaihiwasallam mendatangi para penghuni sumur (kaum musyrikin) yang terbunuh dalam perang Badar lalu bersabda: \"Kalian telah mendapatkan apa yang dijanjkan Rabb kalian adalah benar\". Lalu Beliau ditanya: \"Anda memanggil mereka (yang sudah mati)?\". Maka Beliau menjawab: \"Tidaklah kalian lebih bisa mendengar daripada mereka, hanya saja mereka tidak dapat menjawab\"."},"1282":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْإِنَّمَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُمْ لَيَعْلَمُونَ الْآنَ أَنَّ مَا كُنْتُ أَقُولُ لَهُمْ حَقٌّ وَقَدْ قَالَ اللَّهُ تَعَالَى{ إِنَّكَ لَا تُسْمِعُ الْمَوْتَى }","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Sufyan] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah radliallahu 'anha] berkata; Nabi Shallallahu'alaihiwasallam bersabda: \"Mereka (kaum musyrikin yang terbunuh dalam perang Badar) telah mengetahui sekarang bahwa apa yang aku katakan (terbukti) benar dan Allah telah berfirman (QS An-Naml ayat 80 yang artinya): (\"Sungguh kamu tidak akan dapat menjadikan orang yang sudah mati bisa mendengar\")."},"1283":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنِي أَبِي عَنْ شُعْبَةَ سَمِعْتُ الْأَشْعَثَ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ يَهُودِيَّةً دَخَلَتْ عَلَيْهَا فَذَكَرَتْ عَذَابَ الْقَبْرِ فَقَالَتْ لَهَا أَعَاذَكِ اللَّهُ مِنْ عَذَابِ الْقَبْرِ فَسَأَلَتْ عَائِشَةُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ عَذَابِ الْقَبْرِ فَقَالَ نَعَمْ عَذَابُ الْقَبْرِ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا فَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدُ صَلَّى صَلَاةً إِلَّا تَعَوَّذَ مِنْ عَذَابِ الْقَبْرِزَادَ غُنْدَرٌ عَذَابُ الْقَبْرِ حَقٌّ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan [bapakku] kepadaku nd [Syu'bah]; aku mendengar [Al Asy'ats] dari [Bapaknya] dari [Masruq] dari ['Aisyah radliallahu 'anha] (berkata); ada seorang wanita Yahudi menemuinya lalu menceritakan perihal siksa kubur kemudian berkata (kepada Aisyah radliallahu 'anha); \"Semoga Allah melindungimu dari siksa kubur\". Kemudian setelah itu 'Aisyah radliallahu 'anha bertanya kepada Rasulullah Shallallahu'alaihiwasallam perihal siksa kubur, maka Beliau menjawab: \"Ya benar, siksa kubur itu ada\". Kemudian 'Aisyah radliallahu 'anha berkata: \"Maka sejak itu aku tidak melihat Rasulullah Shallallahu'alaihiwasallam setelah melaksanakan shalat kecuali Beliau memohon perlindungan dari siksa kubur\". [Ghundar] menambhakan: \"Siksa kubur itu benar adanya\"."},"1284":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّهُ سَمِعَ أَسْمَاءَ بِنْتَ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا تَقُولُقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطِيبًا فَذَكَرَ فِتْنَةَ الْقَبْرِ الَّتِي يَفْتَتِنُ فِيهَا الْمَرْءُ فَلَمَّا ذَكَرَ ذَلِكَ ضَجَّ الْمُسْلِمُونَ ضَجَّةً","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] telah menceritakan kepada kami [Ibnu Wahb] berkata, telah menceritakan kepada saya [Yunus] dari [Ibnu Syihab] telah mengabarkan kepada saya ['Urwah bin Az Zubair] bahwasanya dia mendengar [Asma' binti Abu Bakar radliallahu 'anhuma] berkata,: \"Suatu hari Rasulullah Shallallahu'alaihiwasallam berdiri menyampaikan khuthbah lalu menyebut perihal fitnah kubur yang setiap orang akan diuji karennaya. Ketika Beliau menyebutkan hal tersebut kaum muslimun menjadi gaduh dan berteriak\"."},"1285":{"ar":"حَدَّثَنَا عَيَّاشُ بْنُ الْوَلِيدِ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ حَدَّثَهُمْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْعَبْدَ إِذَا وُضِعَ فِي قَبْرِهِ وَتَوَلَّى عَنْهُ أَصْحَابُهُ وَإِنَّهُ لَيَسْمَعُ قَرْعَ نِعَالِهِمْ أَتَاهُ مَلَكَانِ فَيُقْعِدَانِهِ فَيَقُولَانِ مَا كُنْتَ تَقُولُ فِي هَذَا الرَّجُلِ لِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَّا الْمُؤْمِنُ فَيَقُولُ أَشْهَدُ أَنَّهُ عَبْدُ اللَّهِ وَرَسُولُهُ فَيُقَالُ لَهُ انْظُرْ إِلَى مَقْعَدِكَ مِنْ النَّارِ قَدْ أَبْدَلَكَ اللَّهُ بِهِ مَقْعَدًا مِنْ الْجَنَّةِ فَيَرَاهُمَا جَمِيعًا قَالَ قَتَادَةُ وَذُكِرَ لَنَا أَنَّهُ يُفْسَحُ لَهُ فِي قَبْرِهِ ثُمَّ رَجَعَ إِلَى حَدِيثِ أَنَسٍ قَالَ وَأَمَّا الْمُنَافِقُ وَالْكَافِرُ فَيُقَالُ لَهُ مَا كُنْتَ تَقُولُ فِي هَذَا الرَّجُلِ فَيَقُولُ لَا أَدْرِي كُنْتُ أَقُولُ مَا يَقُولُ النَّاسُ فَيُقَالُ لَا دَرَيْتَ وَلَا تَلَيْتَ وَيُضْرَبُ بِمَطَارِقَ مِنْ حَدِيدٍ ضَرْبَةً فَيَصِيحُ صَيْحَةً يَسْمَعُهَا مَنْ يَلِيهِ غَيْرَ الثَّقَلَيْنِ","id":"Telah menceritakan kepada kami ['Ayyasy bion Al Walid] telah menceritakan kepada kami ['Abdul A'laa] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas bin Malik radliallahu 'anhu] bahwasanya dia menceritakan kepada mereka bahwa Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika seorang hamba (jenazahnya) sudah diletakkan didalam kuburnya dan teman-temannya sudah berpaling dan pergi meninggalkannya dan dia dapat mendengar gerak langkah sandal sandal mereka, maka akan datang kepadanya dua malaikat yang keduanya akan mendudukkannya seraya keduanya berkata, kepadanya: \"Apa yang kamu ketahui tentang laki-laki ini, Muhammad Shallallahu'alaihiwasallam?\". bila seorang mu'min dia akan menjawab: \"Aku bersaksi bahwa dia adalah hamba Allah dan utusanNya\". Maka dikatakan kepadanya: \"Lihatlah tempat dudukmu di neraka yang Allah telah menggantinya dengan tempat duduk di surga. Maka dia dapat melihat keduanya\".\". Qatadah berkata,: \"Dan diceritakan kepada kami bahwa dia (hamba mu'min itu) akan dilapangkan dalam kuburnya\". Kemudian dia kembali melanjutkan hadits Anas radliallahu 'anhu.: \" Dan adapun (jenazah) orang kafir atau munafiq akan dikatakan kepadanya apa yang kamu ketahui tentang laki-laki ini?\". Maka dia akan menjawab: \"Aku tidak tahu, aku hanya berkata, mengikuti apa yang dikatakan kebanyakan orang\". Maka dikatakan kepadanya: \"Kamu tidak mengetahuinya dan tidak mengikuti orang yang mengerti\". Kemudian dia dipukul dengan palu godam besar terbuat dari besi sehingga mengeluarkan suara teriakan yang dapat didengar oleh yang ada di sekitarnya kecuali oleh dua makhluq (jin dan manusia) \". "},"1286":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي عَوْنُ بْنُ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ عَنْ الْبَرَاءِ بْنِ عَازِبٍ عَنْ أَبِي أَيُّوبَ رَضِيَ اللَّهُ عَنْهُمْ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ وَجَبَتْ الشَّمْسُ فَسَمِعَ صَوْتًا فَقَالَ يَهُودُ تُعَذَّبُ فِي قُبُورِهَاوَقَالَ النَّضْرُ أَخْبَرَنَا شُعْبَةُ حَدَّثَنَا عَوْنٌ سَمِعْتُ أَبِي سَمِعْتُ الْبَرَاءَ عَنْ أَبِي أَيُّوبَ رَضِيَ اللَّهُ عَنْهُمَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada saya ['Aun bin Abu Juhaifah] dari [Bapaknya] dari [Al Bara' bin 'Azib] dari [Abu Ayyub radliallahu 'anhum] berkata,: Suatu hari Nabi Shallallahu'alaihiwasallam keluar saat matahri sudah meninggi lalu Beliau mendengar suara, maka Beliau bersabda: \"Orang Yahudi sedang disiksa didalam kuburnya\". Dan berkata, [An-Nadhar] telah mengabarkan kepada kami [Syu'bah] telah menceritakan kepada kami ['Aun] aku mendengar [Bapakku], (berkata,) Aku mendengar [Al Bara'] dari [Abu Ayyub radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam."},"1287":{"ar":"حَدَّثَنَا مُعَلًّى حَدَّثَنَا وُهَيْبٌ عَنْ مُوسَى بْنِ ع��قْبَةَ قَالَ حَدَّثَتْنِي ابْنَةُ خَالِدِ بْنِ سَعِيدِ بْنِ الْعَاصِأَنَّهَا سَمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَتَعَوَّذُ مِنْ عَذَابِ الْقَبْرِ","id":"Telah menceritakan kepada kami [Mu'allaa] telah menceritakan kepada kami [Wuhaib] dari [Musa bin 'Uqbah] berkata, telah menceritakan kepada saya dari [Khalid bin Sa'id bin Al 'Ash] bahwa dia mendengar Nabi Shallallahu'alaihiwasallam ketika Beliau berlindung dari siksa kubur."},"1288":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو وَيَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَمِنْ عَذَابِ النَّارِ وَمِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ وَمِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Yahya] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] berkata, Rasulullah Shallallahu'alaihiwasallam berdo'a: \"Allahumma innii 'A'uudzu bika min 'adzaabil qabri wa min 'adzaabin naar wa min fitnatil mahyaa wal mamaati wa min fitmatil masiihid dajjaal\" (artinya): (\"Ya Allah aku berlindung kepadaMu dari suksa kubur dan dari siksa api neraka dan dari fitnah kehidupan dan kematian dan dari fitnah Al Masihid Dajjal\"). "},"1289":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَامَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى قَبْرَيْنِ فَقَالَ إِنَّهُمَا لَيُعَذَّبَانِ وَمَا يُعَذَّبَانِ مِنْ كَبِيرٍ ثُمَّ قَالَ بَلَى أَمَّا أَحَدُهُمَا فَكَانَ يَسْعَى بِالنَّمِيمَةِ وَأَمَّا أَحَدُهُمَا فَكَانَ لَا يَسْتَتِرُ مِنْ بَوْلِهِ قَالَ ثُمَّ أَخَذَ عُودًا رَطْبًا فَكَسَرَهُ بِاثْنَتَيْنِ ثُمَّ غَرَزَ كُلَّ وَاحِدٍ مِنْهُمَا عَلَى قَبْرٍ ثُمَّ قَالَ لَعَلَّهُ يُخَفَّفُ عَنْهُمَا مَا لَمْ يَيْبَسَا","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Mujahid] dari [Thowus] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa: Nabi Shallallahu'alaihiwasallam berjalan melewati dua kuburan lalu Beliau bersabda: \"Keduanya sungguh sedang disiksa, dan tidaklah keduanya disiksa disebabkan karena berbuat dosa besar. Kemudian Beliau bersabda: \"Demikianlah. Adapun yang satu disiksa karena selalu mengadu domba sedang yang satunya lagi tidak bersuci setelah kencing.\" Ibnu 'Abbas radliallahu 'anhu: \"Kemudian Beliau mengambil sebatang dahan kurma lalu membelahnya menjadi dua bagian kemudian menancapkannya pada masing-masing kuburan tersebut seraya berkata,: \"Semoga diringankan (siksanya) selama batang pohon ini masih basah\". "},"1290":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَحَدَكُمْ إِذَا مَاتَ عُرِضَ عَلَيْهِ مَقْعَدُهُ بِالْغَدَاةِ وَالْعَشِيِّ إِنْ كَانَ مِنْ أَهْلِ الْجَنَّةِ فَمِنْ أَهْلِ الْجَنَّةِ وَإِنْ كَانَ مِنْ أَهْلِ النَّارِ فَمِنْ أَهْلِ النَّارِ فَيُقَالُ هَذَا مَقْعَدُكَ حَتَّى يَبْعَثَكَ اللَّهُ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang dari kalian meninggal dunia maka akan ditampakkan kepadanya tempat duduk (tinggal) nya setiap pagi dan petang hari. Jika dia termasuk penduduk surga, maka akan (melihat kedudukannya) sebagai penduduk surga dan jika dia termasuk penduduk neraka, maka akan (melihat kedudukannya) sebagai penduduk neraka lalu dikatakan kepadanya inilah tempat duduk tinggalmu hingga nanti Allah membangkitkanmu pada hari qiyamat\"."},"1291":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وُضِعَتْ الْجِنَازَةُ فَاحْتَمَلَهَا الرِّجَالُ عَلَى أَعْنَاقِهِمْ فَإِنْ كَانَتْ صَالِحَةً قَالَتْ قَدِّمُونِي قَدِّمُونِي وَإِنْ كَانَتْ غَيْرَ صَالِحَةٍ قَالَتْ يَا وَيْلَهَا أَيْنَ يَذْهَبُونَ بِهَا يَسْمَعُ صَوْتَهَا كُلُّ شَيْءٍ إِلَّا الْإِنْسَانَ وَلَوْ سَمِعَهَا الْإِنْسَانُ لَصَعِقَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Sa'id bin Abu Sa'id] dari [bapaknya] bahwa dia mendengar [Abu Sa'id AL Khudriy radliallahu 'anhu] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika jenazah diletakkan lalu dibawa oleh para pemandu di atas pundak mereka, maka jika jenazah tersebut termasuk orang shalih (semasa hidupnya) maka dia akan berkata; \"Bersegeralah kalian, bersegeralah kalian (membawa aku). Dan jika ia bukan dari orang shalih, maka dia akan berkata; \"Celaka, kemana mereka akan membawanya?. Suara jenazah itu didengar oleh setiap makhluq kecuali manusia dan seandainya ada manusia yang mendengarnya tentu dia akan jatuh pingsan\"."},"1292":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ عُلَيَّةَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ النَّاسِ مُسْلِمٌ يَمُوتُ لَهُ ثَلَاثَةٌ مِنْ الْوَلَدِ لَمْ يَبْلُغُوا الْحِنْثَ إِلَّا أَدْخَلَهُ اللَّهُ الْجَنَّةَ بِفَضْلِ رَحْمَتِهِ إِيَّاهُمْ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Ibnu 'Ulayyah] telah menceritakan kepada kami ['Abdul 'Aziz bin Shuhaib] dari [Anas bin Malik radliallahu 'anhu] berkata; Nabi Shallallahu'alaihiwasallam telah bersabda: \"Tidak seorang muslimpun yang ditinggal wafat oleh tiga orang anaknya yang belum baligh kecuali Allah memasukkannya ke dalam surga karena limpahan rahmatNya kepada mereka\"."},"1293":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ أَنَّهُ سَمِعَ الْبَرَاءَ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا تُوُفِّيَ إِبْرَاهِيمُ عَلَيْهِ السَّلَام قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لَهُ مُرْضِعًا فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari ['Adiy bin Tsabit] bahwa dia mendengar [Al Bara' radliallahu 'anhu] berkata; Ketika Ibrahim (putra Nabi Shallallahu'alaihiwasallam) meninggal dunia, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Baginya akan ada yang menyusuinya di surga\"."},"1294":{"ar":"حَدَّثَنِي حِبَّانُ بْنُ مُوسَى أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمْ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَوْلَادِ الْمُشْرِكِينَ فَقَالَ اللَّهُ إِذْ خَلَقَهُمْ أَعْلَمُ بِمَا كَانُوا عَامِلِينَ","id":"Telah menceritakan kepada kami [Hibban bin Musa] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Syu'bah] dari [Abu Bisyir] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata,: Ketika Rasulullah Shallallahu'alaihiwasallam ditanya tentang anak-anak orang musyrikin (yang meninggal dunia), Beliau bersabda: \"Allah subhanahu wata'ala ketika menciptakan mereka, lebih mengetahui apa yang mereka kerjakan\"."},"1295":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عَطَاءُ بْنُ يَزِيدَ اللَّيْثِيُّ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَرَارِيِّ الْمُشْرِكِينَ فَقَالَ اللَّهُ أَعْلَمُ بِمَا كَانُوا عَامِلِينَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya ['Atha' bin Yazid Al Laitsiy] bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] berkata,: Ketika Rasulullah Shallallahu'alaihiwasallam ditanya tentang keturunan orang musyrikin (yang meninggal dunia), Beliau bersabda: \"Allah subhanahu wata'ala ketika menciptakan mereka lebih mengetahui apa yang telah mereka kerjakan\"."},"1296":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مَوْلُودٍ يُولَدُ عَلَى الْفِطْرَةِ فَأَبَوَاهُ يُهَوِّدَانِهِ أَوْ يُنَصِّرَانِهِ أَوْ يُمَجِّسَانِهِ كَمَثَلِ الْبَهِيمَةِ تُنْتَجُ الْبَهِيمَةَ هَلْ تَرَى فِيهَا جَدْعَاءَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Ibnu Abu Dza'bi] dari [Az Zuhriy] dari [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah radliallahu 'anhu] berkata; Nabi Shallallahu'alaihiwasallam bersabda: \"Setiap anak dilahirkan dalam keadaan fithrah. Kemudian kedua orang tunyalah yang akan menjadikan anak itu menjadi Yahudi, Nashrani atau Majusi sebagaimana binatang ternak yang melahirkan binatang ternak dengan sempurna. Apakah kalian melihat ada cacat padanya?\""},"1297":{"ar":"بَاب حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنَا أَبُو رَجَاءٍ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى صَلَاةً أَقْبَلَ عَلَيْنَا بِوَجْهِهِ فَقَالَ مَنْ رَأَى مِنْكُمْ اللَّيْلَةَ رُؤْيَا قَالَ فَإِنْ رَأَى أَحَدٌ قَصَّهَا فَيَقُولُ مَا شَاءَ اللَّهُ فَسَأَلَنَا يَوْمًا فَقَالَ هَلْ رَأَى أَحَدٌ مِنْكُمْ رُؤْيَا قُلْنَا لَا قَالَ لَكِنِّي رَأَيْتُ اللَّيْلَةَ رَجُلَيْنِ أَتَيَانِي فَأَخَذَا بِيَدِي فَأَخْرَجَانِي إِلَى الْأَرْضِ الْمُقَدَّسَةِ فَإِذَا رَجُلٌ جَالِسٌ وَرَجُلٌ قَائِمٌ بِيَدِهِ كَلُّوبٌ مِنْ حَدِيدٍ قَالَ بَعْضُ أَصْحَابِنَا عَنْ مُوسَى إِنَّهُ يُدْخِلُ ذَلِكَ الْكَلُّوبَ فِي شِدْقِهِ حَتَّى يَبْلُغَ قَفَاهُ ثُمَّ يَفْعَلُ بِشِدْقِهِ الْآخَرِ مِثْلَ ذَلِكَ وَيَلْتَئِمُ شِدْقُهُ هَذَا فَيَعُودُ فَيَصْنَعُ مِثْلَهُ قُلْتُ مَا هَذَا قَالَا انْطَلِقْ فَانْطَلَقْنَا حَتَّى أَتَيْنَا عَلَى رَجُلٍ مُضْطَجِعٍ عَلَى قَفَاهُ وَرَجُلٌ قَائِمٌ عَلَى رَأْسِهِ بِفِهْرٍ أَوْ صَخْرَةٍ فَيَشْدَخُ بِهِ رَأْسَهُ فَإِذَا ضَرَبَهُ تَدَهْدَهَ الْحَجَرُ فَانْطَلَقَ إِلَيْهِ لِيَأْخُذَهُ فَلَا يَرْجِعُ إِلَى هَذَا حَتَّى يَلْتَئِمَ رَأْسُهُ وَعَادَ رَأْسُهُ كَمَا هُوَ فَعَادَ إِلَيْهِ فَضَرَبَهُ قُلْتُ مَنْ هَذَا قَالَا انْطَلِقْ فَانْطَلَقْنَا إِلَى ثَقْبٍ مِثْلِ التَّنُّورِ أَعْلَاهُ ضَيِّقٌ وَأَسْفَلُهُ وَاسِعٌ يَتَوَقَّدُ تَحْتَهُ نَارًا فَإِذَا اقْتَرَبَ ارْتَفَعُوا حَتَّى كَادَ أَنْ يَخْرُجُوا فَإِذَا خَمَدَتْ رَجَعُوا فِيهَا وَفِيهَا رِجَالٌ وَنِسَاءٌ عُرَاةٌ فَقُلْتُ مَنْ هَذَا قَالَا انْطَلِقْ فَانْطَلَقْنَا حَتَّى أَتَيْنَا عَلَى نَهَرٍ مِنْ دَمٍ فِيهِ رَجُلٌ قَائِمٌ عَلَى وَسَطِ النَّهَرِقَالَ يَزِيدُ وَوَهْبُ بْنُ جَرِيرٍ عَنْ جَرِيرِ بْنِ حَازِمٍ وَعَلَى شَطِّ النَّهَرِ رَجُلٌ بَيْنَ يَدَيْهِ حِجَارَةٌ فَأَقْبَلَ الرَّجُلُ الَّذِي فِي النَّهَرِ فَإِذَا أَرَادَ أَنْ يَخْرُجَ رَمَى الرَّجُلُ بِحَجَرٍ فِي فِيهِ فَرَدَّهُ حَيْثُ كَانَ فَجَعَلَ كُلَّمَا جَاءَ لِيَخْرُجَ رَمَى فِي فِيهِ بِحَجَرٍ فَيَرْجِعُ كَمَا كَانَ فَقُلْتُ مَا هَذَا قَالَا انْطَلِقْ فَانْطَلَقْنَا حَتَّى انْتَهَيْنَا إِلَى رَوْضَةٍ خَضْرَاءَ فِيهَا شَجَرَةٌ عَظِيمَةٌ وَفِي أَصْلِهَا شَيْخٌ وَصِبْيَانٌ وَإِذَا رَجُلٌ قَرِيبٌ مِنْ الشَّجَرَةِ بَيْنَ يَدَيْهِ نَارٌ يُوقِدُهَا فَصَعِدَا بِي فِي الشَّجَرَةِ وَأَدْخَلَانِي دَارًا لَمْ أَرَ قَطُّ أَحْسَنَ مِنْهَا فِيهَا رِجَالٌ شُيُوخٌ وَشَبَابٌ وَنِسَاءٌ وَصِبْيَانٌ ثُمَّ أَخْرَجَانِي مِنْهَا فَصَعِدَا بِي الشَّجَرَةَ فَأَدْخَلَانِي دَارًا هِيَ أَحْسَنُ وَأَفْضَلُ فِيهَا شُيُوخٌ وَشَبَابٌ قُلْتُ طَوَّفْتُمَانِي اللَّيْلَةَ فَأَخْبِرَانِي عَمَّا رَأَيْتُ قَالَا نَعَمْ أَمَّا الَّذِي رَأَيْتَهُ يُشَقُّ شِدْقُهُ فَكَذَّابٌ يُحَدِّثُ بِالْكَذْبَةِ فَتُحْمَلُ عَنْهُ حَتَّى تَبْلُغَ الْآفَاقَ فَيُصْنَعُ بِهِ إِلَى يَوْمِ الْقِيَامَةِ وَالَّذِي رَأَيْتَهُ يُشْدَخُ رَأْسُهُ فَرَجُلٌ عَلَّمَهُ اللَّهُ الْقُرْآنَ فَنَامَ عَنْهُ بِاللَّيْلِ وَلَمْ يَعْمَلْ فِيهِ بِالنَّهَارِ يُفْعَلُ بِهِ إِلَى يَوْمِ الْقِيَامَةِ وَالَّذِي رَأَيْتَهُ فِي الثَّقْبِ فَهُمْ الزُّنَاةُ وَالَّذِي رَأَيْتَهُ فِي النَّهَرِ آكِلُوا الرِّبَا وَالشَّيْخُ فِي أَصْلِ الشَّجَرَةِ إِبْرَاهِيمُ عَلَيْهِ السَّلَام وَالصِّبْيَانُ حَوْلَهُ فَأَوْلَادُ النَّاسِ وَالَّذِي يُوقِدُ النَّارَ مَالِكٌ خَازِنُ النَّارِ وَالدَّارُ الْأُولَى الَّتِي دَخَلْتَ دَارُ عَامَّةِ الْمُؤْمِنِينَ وَأَمَّا هَذِهِ الدَّارُ فَدَارُ الشُّهَدَاءِ وَأَنَا جِبْرِيلُ وَهَذَا مِيكَائِيلُ فَارْفَعْ رَأْسَكَ فَرَفَعْتُ رَأْسِي فَإِذَا فَوْقِي مِثْلُ السَّحَابِ قَالَا ذَاكَ مَنْزِلُكَ قُلْتُ دَعَانِي أَدْخُلْ مَنْزِلِي قَالَا إِنَّهُ بَقِيَ لَكَ عُمُرٌ لَمْ تَسْتَكْمِلْهُ فَلَوْ اسْتَكْمَلْتَ أَتَيْتَ مَنْزِلَكَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Jarir bin Hazim] telah menceritakan kepada kami [Abu Raja'] dari [Samrah bin Jundab] berkata; Sudah menjadi kebiasaan Nabi Shallallahu'alaihiwasallam bila selesai melaksanakan suatu shalat, Beliau menghadapkan wajahnya kepada kami lalu berkata,: \"Siapa diantara kalian yang tadi malam bermimpi\". Dia (Samrah bin Jundab) berkata,: \"Jika ada seorang yang bermimpi maka orang itu akan menceritakan, saat itulah Beliau berkata,: \"Maa sya-allah\" (atas kehendak Allah) \". Pada suatu hari yang lain Beliau bertanya kepada kami: \"Apakah ada diantara kalian yang bermimpi?\". Kami menjawab: \"Tidak ada\". Beliau berkata,: \"Tetapi aku tadi malam bermimpi yaitu ada dua orang laki-laki yang mendatangiku kemudian keduanya memegang tanganku lalu membawaku ke negeri yang disucikan (Al Muqaddasah), ternyata disana ada seorang laki-laki yang sedang berdiri dan yang satunya lagi duduk yang di tangannya memegang sebatang besi yang ujungnya bengkok (biasanya untuk menggantung sesuatu). Sebagian dari sahabat kami berkata, dari Musa bahwa: batang besi tersebut dimasukkan ke dalam satu sisi mulut (dari geraham) orang itu hingga menembus tengkuknya. Kemudian dilakukan hal yang sama pada sisi mulut yang satunya lagi, lalu dilepas dari mulutnya dan dimasukkan kembali dan begitu seterusnya diperlakukan. Aku bertanya: \"Apa ini maksudnya?\". Kedua orang yang membawaku berkata,: \"Berangkatlah\". Maka kami berangkat ke tempat lain dan sampai kepada seorang laki-laki yang sedang berbaring bersandar pada tengkuknya, sedang ada laki-laki lain yang berdiri diatas kepalanya memegang batu atau batu besar untuk menghancurkan kepalanya. Ketika dipukulkan, batu itu menghancurkan kepala orang itu, Maka orang itu menghampirinya untuk mengambilnya dan dia tidak berhenti melakukan ini hingga kepala orang itu kembali utuh seperti semula, kemudian dipukul lagi dengan batu hingga hancur. Aku bertanya: \"Siapakah orang ini?\". Keduanya menjawab: \"Berangkatlah\". Maka kamipun berangkat hingga sampai pada suatu lubang seperti dapur api dimana bagian atasnya sempit dan bagian bawahnya lebar dan dibawahnya dinyalakan api yang apabila api itu didekatkan, mereka (penghuninya) akan terangkat dan bila dipadamkan penghuninya akan kembali kepadanya, penghuninya itu terdiri dari laki-laki dan perempuan. Aku bertanya: \"Siapakah mereka itu?\". Keduanya menjawab: \"Berangkatlah\". Maka kami pun berangkat hingga sampai di sebuah sungai yang airnya adalah darah, disana ada seorang laki-laki yang berdiri di tengah-tengah sungai\". Berkata, [Yazid] dan [Wahb bin Jarir] dari [Jarir bin Hazim]: 'Dan di tepi sungai ada seorang laki-laki yang memegang batu. Ketika orang yang berada di tengah sungai menghadapnya dan bermaksud hendak keluar dari sungai maka laki-laki yang memegang batu melemparnya dengan batu kearah mulutnya hingga dia kembali ke tempatnya semula di tengah sungai, dan terjadilah seterusnya begitu, setiap dia hendak keluar dari sungai, akan dilempar dengan batu sehingga kembali ke tempatnya semula. Aku bertanya: \"Apa maksudnya ini?\" Keduanya menjawab: \"Berangkatlah\". Maka kamipun berangkat hingga sampai ke suatu taman yang hijau, didalamnya penuh dengan pepohonan yang besar-besar sementara dibawahnya ada satu orang tua dan anak-anak dan ada seorang yang berada dekat dengan pohon yang memegang api, manakala dia menyalakan api maka kedua orang yang membawaku naik membawaku memanjat pohon lalu keduanya memasukkan aku ke sebuah rumah (perkampungan) yang belum pernah aku melihat seindah itu sebelumnya dan didalamnya ada para orang laki-laki, orang-orang tua, pemuda, wanita dan anak-anak lalu keduanya membawa aku keluar dari situ lalu membawaku naik lagi ke atas pohon, lalu memasukkan aku ke dalam suatu rumah yang lebih baik dan lebih indah, didalamnya ada orang-orang tua dan para pemuda. Aku berkata: \"Ajaklah aku keliling malam ini dan terangkanlah tentang apa yang aku sudah lihat tadi\". Maka keduanya berkata,: \"Baiklah. Adapun orang yang kamu lihat mulutnya ditusuk dengan besi adalah orang yang suka berdusta dan bila berkata selalu berbohong, maka dia dibawa hingga sampai ke ufuq lalu dia diperlakukan seperti itu hingga hari qiyamat. Adapun orang yang kamu lihat kepalanya dipecahkan adalah seorang yang telah diajarkan Al Qur'an oleh Allah lalu dia tidur pada suatu malam namun tidak melaksanakan Al Qur'an pada siang harinya, lalu dia diperlakukan seperti itu hingga hari qiyamat. Dan orang-orang yang kamu lihat berada didalam dapur api mereka adalah para pezina sedangkan orang yang kamu lihat berada di tengah sungai adalah mereka yang memakan riba' sementara orang tua yang berada dibawah pohon adalah Nabi Ibrahim 'alaihissalam, sedangkan anak-anak yang ada disekitarnnya adalah anak-anak kecil manusia. Adapun orang yang menyalakan api adalah malaikat penunggu neraka sedangkan rumah pertama yang kamu masuki adalah rumah bagi seluruh kaum mu'minin sedangkan rumah yang ini adalah perkampungan para syuhada' dan aku adalah Jibril dan ini adalah Mika'il, maka angkatlah kepalamu. Maka aku mengangkat kepalaku ternyata diatas kepalaku ada sesuatu seperti awan. Keduanya berkata,: \"Itulah tempatmu\". Aku berkata: \"Biarkanlah aku memasuki rumahku\". Keduanya berkata,: \" Umurmu masih tersisa dan belum selesai dan seandainya sudah selesai waktunya kamu pasti akan memasuki rumahmu\"."},"1298":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْدَخَلْتُ عَلَى أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَقَالَ فِي كَمْ كَفَّنْتُمْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ فِي ثَلَاثَةِ أَثْوَابٍ بِيضٍ سَحُولِيَّةٍ لَيْسَ فِيهَا قَمِيصٌ وَلَا عِمَامَةٌ وَقَالَ لَهَا فِي أَيِّ يَوْمٍ تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ يَوْمَ الِاثْنَيْنِ قَالَ فَأَيُّ يَوْمٍ هَذَا قَالَتْ يَوْمُ الِاثْنَيْنِ قَالَ أَرْجُو فِيمَا بَيْنِي وَبَيْنَ اللَّيْلِ فَنَظَرَ إِلَى ثَوْبٍ عَلَيْهِ كَانَ يُمَرَّضُ فِيهِ بِهِ رَدْعٌ مِنْ زَعْفَرَانٍ فَقَالَ اغْسِلُوا ثَوْبِي هَذَا وَزِيدُوا عَلَيْهِ ثَوْبَيْنِ فَكَفِّنُونِي فِيهَا قُلْتُ إِنَّ هَذَا خَلَقٌ قَالَ إِنَّ الْحَيَّ أَحَقُّ بِالْجَدِيدِ مِنْ الْمَيِّتِ إِنَّمَا هُوَ لِلْمُهْلَةِ فَلَمْ يُتَوَفَّ حَتَّى أَمْسَى مِنْ لَيْلَةِ الثُّلَاثَاءِ وَدُفِنَ قَبْلَ أَنْ يُصْبِحَ","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] telah menceritakan kepada kami [Wuhaib] dari [Hisyam] dari [bapaknya] dari ['Aisyah radliallahu 'anha] berkata,: \"Aku pernah masuk menemui Abu Bakar radliallahu 'anhu lalu dia berkata,: \"Berapa lembar kain kalian mengafani Nabi Shallallahu'alaihiwasallam?\". Dia berkata,: \"Dalam tiga lembar kain putih buatan negeri Yaman dan tidak dipakaikan baju dan juga tidak sorban\". Kemudian Abu Bakar radliallahu 'anhu berkata kepadanya: \"Hari apakah Rasulullah Shallallahu'alaihiwasallam wafat?\". 'Aisyah radliallahu 'anha menjawab: Hari Senin\". Lalu dia berkata, lagi: \"Sekarang ini hari apa?\". Dia 'Aisyah radliallahu 'anha menjawab: \"Sekarang hari Senin\". Abu Bakar berkata,: \"Aku berharap umurku sampai malam ini saja\". Lalu dia memandang baju yang dipakainya sejak dia menderita sakit yang ketika itu bajunya sudah kotor terkena minyak za'faran (kunyit) pada sebagiannya kemudian berkata,: \"Cucilah bajuku ini dan tambahkanlah dengan dua baju lain untuk mengafaniku dengannya\". Aku berkata: \"Baju ini sudah usang\". Maka dia menjawab: \"Orang yang hidup lebih pantas untuk mengenakan yang baru dari pada orang yang sudah mati. Kain itu hanya untuk mewadahi nanah mayat\". Kemudian dia tidak wafat hingga menjelang malam Selasa (dimana akhirnya wafat) lalu ia dikuburkan sebelum pagi\"."},"1299":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ أَخْبَرَنِي هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَجُلًا قَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أُمِّي افْتُلِتَتْ نَفْسُهَا وَأَظُنُّهَا لَوْ تَكَلَّمَتْ تَصَدَّقَتْ فَهَلْ لَهَا أَجْرٌ إِنْ تَصَدَّقْتُ عَنْهَا قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah mengabarkan kepada saya [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah radliallahu 'anha] bahwa ada seorang laki-laki berkata, kepada Nabi Shallallahu'alaihiwasallam: \"Ibuku meninggal dunia dengan mendadak, dan aku menduga seandainya dia sempat berbicara dia akan bershadaqah. Apakah dia akan memperoleh pahala jika aku bershadaqah untuknya (atas namanya)?\". Beliau menjawab: \"Ya, benar\"."},"1300":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي سُلَيْمَانُ عَنْ هِشَامٍ ح و حَدَّثَنِي مُحَمَّدُ بْنُ حَرْبٍ حَدَّثَنَا أَبُو مَرْوَانَ يَحْيَى بْنُ أَبِي زَكَرِيَّاءَ عَنْ هِشَامٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْإِنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَتَعَذَّرُ فِي مَرَضِهِ أَيْنَ أَنَا الْيَوْمَ أَيْنَ أَنَا غَدًا اسْتِبْطَاءً لِيَوْمِ عَائِشَةَ فَلَمَّا كَانَ يَوْمِي قَبَضَهُ اللَّهُ بَيْنَ سَحْرِي وَنَحْرِي وَدُفِنَ فِي بَيْتِي","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada saya [Sulaiman] dari [Hisyam] dan diriwayatkan pula dari jalan lain, telah menceritakan kepada saya [Muhammad bin Harb] telah menceritakan kepada kami [Abu Marwan Yahya bin Abu Zakariya'] dari [Hisyam] dari ['Urwah] dari ['Aisyah radliallahu 'anha] berkata,: Ketika Rasulullah Shallallahu'alaihiwasallam dalam keadaan sakit dan meminta udzur untuk giliran tinggal dengan isteri-isterinya (Beliau bertanya): \"dimana aku hari ini dan dimana kesokannya?\", saat itu rupanya Beliau menginginkan berlama-lama berada dalam giliran 'Aisyah radliallahu 'anha. Saat Beliau giliran di rumahku, Allah mencabut nyawa Beliau yang berada dalam dekapan dadaku dan pangkuanku, lalu Beliau dikebumikan di rumahku\"."},"1301":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ هِلَالٍ هُوَ الْوَزَّانُ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرَضِهِ الَّذِي لَمْ يَقُمْ مِنْهُ لَعَنَ اللَّهُ الْيَهُودَ وَالنَّصَارَى اتَّخَذُوا قُبُورَ أَنْبِيَائِهِمْ مَسَاجِدَ لَوْلَا ذَلِكَ أُبْرِزَ قَبْرُهُ غَيْرَ أَنَّهُ خَشِيَ أَوْ خُشِيَ أَنَّ يُتَّخَذَ مَسْجِدًاوَعَنْ هِلَالٍ قَالَ كَنَّانِي عُرْوَةُ بْنُ الزُّبَيْرِ وَلَمْ يُولَدْ لِي","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] dari [Hilal] dia adalah Al Wazzan dari ['Urwah] dari ['Aisyah radliallahu 'anha] berkata; Nabi shallallahu 'alaihi wasallam bersabda ketika beliau sakit yang setelah itu beliau tidak bangun lagi (wafat): \"Allah melaknat orang-orang Yahudi dan Nashrani disebabkan mereka menjadikan quburan para nabi mereka sebagai masjid\". 'Aisyah radliallahu 'anha; \"Kalau bukan karena ada sabda beliau tersebut tentu aku pindahkan qubur beliau (dari dalam rumahnya), namun aku tetap khawatir nantinya akan dijadikan masjid\". Dan dari Hilal berkata; \"'Urwah bin Az Zubair pernah memberikan kuniyah (nama panggilan yang dinisbatkan kepada anak) kepadaku namun aku tidak punya anak.\""},"1302":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ سُفْيَانَ التَّمَّارِ أَنَّهُ حَدَّثَهُأَنَّهُ رَأَى قَبْرَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسَنَّمًا","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Abu Bakar bin 'Iyyasy] dari [Sufyan At-Tamar] bahwa dia melihat kuburan Nabi Shallallahu'alaihiwasallam sudah ditinggikan tanahnya sedikit.\" "},"1303":{"ar":"حَدَّثَنَا فَرْوَةُ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِلَمَّا سَقَطَ عَلَيْهِمْ الْحَائِطُ فِي زَمَانِ الْوَلِيدِ بْنِ عَبْدِ الْمَلِكِ أَخَذُوا فِي بِنَائِهِ فَبَدَتْ لَهُمْ قَدَمٌ فَفَزِعُوا وَظَنُّوا أَنَّهَا قَدَمُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا وَجَدُوا أَحَدًا يَعْلَمُ ذَلِكَ حَتَّى قَالَ لَهُمْ عُرْوَةُ لَا وَاللَّهِ مَا هِيَ قَدَمُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا هِيَ إِلَّا قَدَمُ عُمَرَ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Farwah] telah menceritakan kepada kami ['Ali bin Mushir] dari [Hisyam bin 'Urwah] dari [bapaknya]; Ketika tembok runtuh menimpa kuburan Nabi Shallallahu'alaihiwasallam pada masa kekhilafahan Al Walid bin 'Abdul-Malik, orang-orang mulai membangun kembali. Saat itu mereka menemukan sebuah kaki yang terputus, mereka mengira bahwa itu adalah kaki Nabi Shallallahu'alaihiwasallam. Mereka tidak menemui seseorang yang mengetahui hal itu, hingga akhirnya 'Urwah berkata kepada mereka: \"Demi Allah itu bukanlah kaki Nabi Shallallahu'alaihiwasallam, itu adalah kaki Umar radliallahu 'anhu."},"1304":{"ar":"وَعَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّهَا أَوْصَتْ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ رَضِيَ اللَّهُ عَنْهُمَا لَا تَدْفِنِّي مَعَهُمْ وَادْفِنِّي مَعَ صَوَاحِبِي بِالْبَقِيعِ لَا أُزَكَّى بِهِ أَبَدًا","id":"Dan dari [Hisyam] dari [bapaknya] dari ['Aisyah radliallahu 'anha] bahwa ia berwasiat kepada 'Abdullah bin Az Zubair radliallahu 'anhuma: \"Janganlah kamu mengubur aku bersama mereka, namun kuburkanlah aku bersama para isteri Nabi Shallallahu'alaihiwasallam di Baqi' agar aku tidak dikeramatkan seorangpun selama-lamanya\"."},"1305":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ حَدَّثَنَا حُصَيْنُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَمْرِو بْنِ مَيْمُونٍ الْأَوْدِيِّ قَالَ رَأَيْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ قَالَيَا عَبْدَ اللَّهِ بْنَ عُمَرَ اذْهَبْ إِلَى أُمِّ الْمُؤْمِنِينَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَقُلْ يَقْرَأُ عُمَرُ بْنُ الْخَطَّابِ عَلَيْكِ السَّلَامَ ثُمَّ سَلْهَا أَنْ أُدْفَنَ مَعَ صَاحِبَيَّ قَالَتْ كُنْتُ أُرِيدُهُ لِنَفْسِي فَلَأُوثِرَنَّهُ الْيَوْمَ عَلَى نَفْسِي فَلَمَّا أَقْبَلَ قَالَ لَهُ مَا لَدَيْكَ قَالَ أَذِنَتْ لَكَ يَا أَمِيرَ الْمُؤْمِنِينَ قَالَ مَا كَانَ شَيْءٌ أَهَمَّ إِلَيَّ مِنْ ذَلِكَ الْمَضْجَعِ فَإِذَا قُبِضْتُ فَاحْمِلُونِي ثُمَّ سَلِّمُوا ثُمَّ قُلْ يَسْتَأْذِنُ عُمَرُ بْنُ الْخَطَّابِ فَإِنْ أَذِنَتْ لِي فَادْفِنُونِي وَإِلَّا فَرُدُّونِي إِلَى مَقَابِرِ الْمُسْلِمِينَ إِنِّي لَا أَعْلَمُ أَحَدًا أَحَقَّ بِهَذَا الْأَمْرِ مِنْ هَؤُلَاءِ النَّفَرِ الَّذِينَ تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَنْهُمْ رَاضٍ فَمَنْ اسْتَخْلَفُوا بَعْدِي فَهُوَ الْخَلِيفَةُ فَاسْمَعُوا لَهُ وَأَطِيعُوا فَسَمَّى عُثْمَانَ وَعَلِيًّا وَطَلْحَةَ وَالزُّبَيْرَ وَعَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ وَسَعْدَ بْنَ أَبِي وَقَّاصٍ وَوَلَجَ عَلَيْهِ شَابٌّ مِنْ الْأَنْصَارِ فَقَالَ أَبْشِرْ يَا أَمِيرَ الْمُؤْمِنِينَ بِبُشْرَى اللَّهِ كَانَ لَكَ مِنْ الْقَدَمِ فِي الْإِسْلَامِ مَا قَدْ عَلِمْتَ ثُمَّ اسْتُخْلِفْتَ فَعَدَلْتَ ثُمَّ الشَّهَادَةُ بَعْدَ هَذَا كُلِّهِ فَقَالَ لَيْتَنِي يَا ابْنَ أَخِي وَذَلِكَ كَفَافًا لَا عَلَيَّ وَلَا لِي أُوصِي الْخَلِيفَةَ مِنْ بَعْدِي بِالْمُهَاجِرِينَ الْأَوَّلِينَ خَيْرًا أَنْ يَعْرِفَ لَهُمْ حَقَّهُمْ وَأَنْ يَحْفَظَ لَهُمْ حُرْمَتَهُمْ وَأُوصِيهِ بِالْأَنْصَارِ خَيْرًا{ الَّذِينَ تَبَوَّءُوا الدَّارَ وَالْإِيمَانَ }أَنْ يُقْبَلَ مِنْ مُحْسِنِهِمْ وَيُعْفَى عَنْ مُسِيئِهِمْ وَأُوصِيهِ بِذِمَّةِ اللَّهِ وَذِمَّةِ رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُوفَى لَهُمْ بِعَهْدِهِمْ وَأَنْ يُقَاتَلَ مِنْ وَرَائِهِمْ وَأَنْ لَا يُكَلَّفُوا فَوْقَ طَاقَتِهِمْ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Jarir bin 'Abdul Hamid] telah menceritakan kepada kami [Hushain bin 'Abdurrahman] dari ['Amru bin Maimun Al Audiy] berkata,: \"Aku melihat ['Umar bin Al Khaththab] radliallahu 'anhu berkata,: \"Wahai 'Abdullah bin Umar temuilah Ummul Mu'minin 'Aisyah radliallahu 'anha lalu sampaikan bahwa 'Umar bin Al Khaththab menyampaikan salam kepadamu, kemudian mintalah agar aku dikubur bersama kedua temanku. 'Aisyah berkata; \"Aku dulu menginginkan tempat itu untukku, namun sekarang aku lebih mengutamakannya daripada diriku. Ketika ia pulang, Umar berkata, kepadanya: \"Jawaban apa yang kamu bawa?\". Ia menjawab; \"Engkau telah mendapat izin wahai Amirul Mu'minin, lalu ia berkata,: \"Tidak ada sesuatu yang lebih aku cintai daripada tempat berbaring itu, dan jika aku sudah meninggal, bawalah aku kepadanya lalu sampaikan salam dan katakan bahwa 'Umar bin Al Khaththab telah meminta izin, dan jika diizinkan maka kuburkanlah aku disana, dan jika tidak, maka kuburlah aku dipekuburan kaum muslimin. Sebab aku tidak mengetahui seseorang yang lebih berhak pada perkara ini daripada mereka, orang-orang yang ketika beliau meninggal maka Rasulullah Shallallahu'alaihiwasallam telah meridhai mereka, maka barangsiapa yang menggantikan aku setelahku dialah khalifah, wajib dengar dan taatlah padanya. Lalu ia menyebut nama 'Utsman, 'Ali, Thalhah, Az Zubair, 'Abdur-Rahman bin 'Auf, Saad bin Abi Waqqas. Kemudian seorang pemuda Anshar datang kepadanya, ia berkata,: \"Wahai Amirul Mu'minin, berilah kabar gembira yang diberikan Allah kepadamu karena masuk Islam pertama kali seperti yang telah engkau ketahui, lalu engkau diangkat menjadi khalifah dan setelah ini semua engkau akan mati syahid?\". Da menjawab: \"Barangkali cukuplah yang engkau katakan itu wahai anak saudaraku, aku berwasiat kebaikan kepada khalifah setelahku terhadap orang-orang yang pertama-tama berhijrah, agar ia mengerti hak-hak mereka dan menjaga kehormatan mereka, dan aku berwasiat kebaikan kepadanya terhadap orang-orang Anshar, yang mereka telah menempati Madinah dan beriman kepada Allah Ta'ala, agar ia terima orang-orang yang baik diantara mereka dan memaafkan orang-orang yang berbuat buruk diantara mereka, dan aku berwasiat kepadanya akan tanggungan Allah dan RasulNya Shallallahu'alaihiwasallam agar ia menepati perjanjian dengannya, dan ia berperang dibelakangnya, serta tidak membebani mereka dengan apa yang tidak mereka mampu\"."},"1306":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسُبُّوا الْأَمْوَاتَ فَإِنَّهُمْ قَدْ أَفْضَوْا إِلَى مَا قَدَّمُواوَرَوَاهُ عَبْدُ اللَّهِ بْنُ عَبْدِ الْقُدُّوسِ عَنْ الْأَعْمَشِ وَمُحَمَّدُ بْنُ أَنَسٍ عَنْ الْأَعْمَشِ تَابَعَهُ عَلِيُّ بْنُ الْجَعْدِ وَابْنُ عَرْعَرَةَ وَابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Al A'masy] dari [Mujahid] dari ['Aisyah radliallahu 'anha] berkata; Nabi Shallallahu'alaihiwasallam telah bersabda: \"Janganlah kalian mencela mayat karena mereka telah sampai (mendapatkan) apa yang telah mereka kerjakan\". Dan diriwayatkan oleh ['Abdullah bin 'Abdul Quddus] dari [Al A'masy] dan [Muhammad bin Anas] dari [Al A'masy] yang dikuatkan oleh ['Ali bin Al Ja'di] dari [Ibnu'Ar'arah] dari [Ibnu 'Adiy] dari [Syu'bah]."},"1307":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنِي عَمْرُو بْنُ مُرَّةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ أَبُو لَهَبٍ عَلَيْهِ لَعْنَةُ اللَّهِ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَبًّا لَكَ سَائِرَ الْيَوْمِ فَنَزَلَتْ{ تَبَّتْ يَدَا أَبِي لَهَبٍ وَتَبَّ }","id":"Telah menceritakan kepada kami ['Umar bin Hafsh] telah menceritakan [bapakku] kepada kami bapakku telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada saya ['Amru bin Murrah] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata,: \"Abu Lahab, laknat Allah atasnya, kepada Nabi Shallallahu'alaihiwasallam: \"Celaka kamu sepanjang jari ini\". Maka turunlah QS Al Lahab (yang artinya): (\"Binasalah kedua tangan Abu Lahab dan sesungguhnya dia akan binasa\")."},"1308":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ الضَّحَّاكُ بْنُ مَخْلَدٍ عَنْ زَكَرِيَّاءَ بْنِ إِسْحَاقَ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ صَيْفِيٍّ عَنْ أَبِي مَعْبَدٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ مُعَاذًا رَضِيَ اللَّهُ عَنْهُ إِلَى الْيَمَنِ فَقَالَ ادْعُهُمْ إِلَى شَهَادَةِ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ فَإِنْ هُمْ أَطَاعُوا لِذَلِكَ فَأَعْلِمْهُمْ أَنَّ اللَّهَ قَدْ افْتَرَضَ عَلَيْهِمْ خَمْسَ صَلَوَاتٍ فِي كُلِّ يَوْمٍ وَلَيْلَةٍ فَإِنْ هُمْ أَطَاعُوا لِذَلِكَ فَأَعْلِمْهُمْ أَنَّ اللَّهَ افْتَرَضَ عَلَيْهِمْ صَدَقَةً فِي أَمْوَالِهِمْ تُؤْخَذُ مِنْ أَغْنِيَائِهِمْ وَتُرَدُّ عَلَى فُقَرَائِهِمْ","id":"Telah menceritakan kepada kami [Abu 'Ashim Adh-Dlohhak bin Makhlad] dari [Zakariya' bin Ishaq] dari [Yahya bin 'Abdullah bin Shayfiy] dari [Abu Ma'bad] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa ketika Nabi Shallallahu'alaihiwasallam mengutus Mu'adz radliallahu 'anhu ke negeri Yaman, Beliau berkata,: \"Ajaklah mereka kepada syahadah (persaksian) tidak ada ilah yang berhak disembah kecuali Allah dan bahwa aku adalah utusan Allah. Jika mereka telah mentaatinya, maka beritahukanlah bahwa Allah mewajibkan atas mereka shalat lima waktu sehari semalam. Dan jika mereka telah mena'atinya, maka beritahukanlah bahwa Allah telah mewajibkan atas mereka shadaqah (zakat) dari harta mereka yang diambil dari orang-orang kaya mereka dan diberikan kepada orang-orang faqir mereka\"."},"1309":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ أَبِي أَيُّوبَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا قَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبِرْنِي بِعَمَلٍ يُدْخِلُنِي الْجَنَّةَ قَالَ مَا لَهُ مَا لَهُ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَبٌ مَا لَهُ تَعْبُدُ اللَّهَ وَلَا تُشْرِكُ بِهِ شَيْئًا وَتُقِيمُ الصَّلَاةَ وَتُؤْتِي الزَّكَاةَ وَتَصِلُ الرَّحِمَوَقَالَ بَهْزٌ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ وَأَبُوهُ عُثْمَانُ بْنُ عَبْدِ اللَّهِ أَنَّهُمَا سَمِعَا مُوسَى بْنَ طَلْحَةَ عَنْ أَبِي أَيُّوبَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا قَالَ أَبُو عَبْد اللَّهِ أَخْشَى أَنْ يَكُونَ مُحَمَّدٌ غَيْرَ مَحْفُوظٍ إِنَّمَا هُوَ عَمْرٌو","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin 'Utsman bin 'Abdullah bin Mawhab] dari [Musa bin Thalhah] dari [Abu Ayyub radliallahu 'anhu]; Bahwa ada seseorang laki-laki berkata, kepada Nabi Shallallahu'alaihiwasallam: \"Kabarkan kepadaku suatu amal yang akan memasukkan aku kedalam surga\". Dia berkata,: \"Apakah itu, apakah itu?. Dan Nabi Shallallahu'alaihiwasallam bersabda: \"Dia membutuhkannya. Yaitu kamu menyembah Allah dengan tidak menyekutukanNya dengan suatu apapun, kamu mendirikan shalat, kamu tunaikan zakat, kamu sambung hubungan kerabat (shilaturrahim) \". Dan berkata, [Bahz] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Muhammad bin 'Utsman] dan bapaknya ['Utsman bin 'Abdullah] bahwa keduanya mendengar [Musa bin Thalhah] dari [Abu Ayyub] dari Nabi Shallallahu'alaihiwasallam dengan lafadz seperti ini. Berkata, Abu 'Abdullah Al Bukhariy: \"Aku ragu bahwa Muhammad bin 'Utsman yang menghafalnya dari (Syu'bah) akan tetapi yang benar adalah 'Amru bin 'Utsman."},"1310":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا وُهَيْبٌ عَنْ يَحْيَى بْنِ سَعِيدِ بْنِ حَيَّانَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ أَعْرَابِيًّا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ دُلَّنِي عَلَى عَمَلٍ إِذَا عَمِلْتُهُ دَخَلْتُ الْجَنَّةَ قَالَ تَعْبُدُ اللَّهَ لَا تُشْرِكُ بِهِ شَيْئًا وَتُقِيمُ الصَّلَاةَ الْمَكْتُوبَةَ وَتُؤَدِّي الزَّكَاةَ الْمَفْرُوضَةَ وَتَصُومُ رَمَضَانَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَا أَزِيدُ عَلَى هَذَا فَلَمَّا وَلَّى قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَرَّهُ أَنْ يَنْظُرَ إِلَى رَجُلٍ مِنْ أَهْلِ الْجَنَّةِ فَلْيَنْظُرْ إِلَى هَذَاحَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى عَنْ أَبِي حَيَّانَ قَالَ أَخْبَرَنِي أَبُو زُرْعَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا","id":"Telah menceritakan kepada saya [Muhammad bin 'Abdur Rahim] telah menceritakan kepada kami ['Affan bin Muslim] telah menceritakan kepada kami [Wuhaib] dari [Yahya bin Sa'id bin Hayyan] dari [Abu Zur'ah] dari [Abu Hurairah radliallahu 'anhu]; Ada seorang Arab Badui menemui Nabi Shallallahu'alaihiwasallam lalu berkata,: \"Tunjukkan kepadaku suatu amal yang bila aku kerjakan akan memasukkan aku kedalam surga\". Nabi Shallallahu'alaihiwasallam bersabda: \"Kamu menyembah Allah dengan tidak menyekutukanNya dengan suatu apapun, kamu mendirikan shalat yang diwajibkan, kamu tunaikan zakat yang wajib, kamu mengerjakan shaum (puasa) bulan Ramadhan. Kemudian orang Badui itu berkata,: \"Demi Dzat yang jiwaku berada di tanganNya, aku tidak akan menambah dari perintah-perintah ini\". Ketika hendak pergi, Nabi Shallallahu'alaihiwasallam bersabda: \"Siapa yang berkeinginan melihat laki-laki penghuni surga maka hendaklah dia melihat orang ini\". Telah menceritakan kepada kami [Musaddad] dari [Yahya] dari [Abu Hayyan] berkata, telah mengabarkan kepada saya [Abu Zur'ah] dari Nabi Shallallahu'alaihiwasallam sepeti hadits ini."},"1311":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَبُو جَمْرَةَ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُقَدِمَ وَفْدُ عَبْدِ الْقَيْسِ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّ هَذَا الْحَيَّ مِنْ رَبِيعَةَ قَدْ حَالَتْ بَيْنَنَا وَبَيْنَكَ كُفَّارُ مُضَرَ وَلَسْنَا نَخْلُصُ إِلَيْكَ إِلَّا فِي الشَّهْرِ الْحَرَامِ فَمُرْنَا بِشَيْءٍ نَأْخُذُهُ عَنْكَ وَنَدْعُو إِلَيْهِ مَنْ وَرَاءَنَا قَالَ آمُرُكُمْ بِأَرْبَعٍ وَأَنْهَاكُمْ عَنْ أَرْبَعٍ الْإِيمَانِ بِاللَّهِ وَشَهَادَةِ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَعَقَدَ بِيَدِهِ هَكَذَا وَإِقَامِ الصَّلَاةِ وَإِيتَاءِ الزَّكَاةِ وَأَنْ تُؤَدُّوا خُمُسَ مَا غَنِمْتُمْ وَأَنْهَاكُمْ عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالنَّقِيرِ وَالْمُزَفَّتِوَقَالَ سُلَيْمَانُ وَأَبُو النُّعْمَانِ عَنْ حَمَّادٍ الْإِيمَانِ بِاللَّهِ شَهَادَةِ أَنْ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Abu Jamrah] berkata, aku mendengar [Ibnu 'Abbas radliallahu 'anhuma] berkata; telah datang utusan suku 'Abdul Qais kepada Rasulullah Shallallahu'alaihiwasallam lalu mereka berkata,: \"Wahai Rasulullah, kami ini dari suku Rabi'ah, dan antara tempat tinggal kami dan Baginda ada suku Mudhar yang kafir dan kami tidak dapat mengunjungi anda kecuali pada bulan haram. Maka perintahlah kami dengan satu perintah yang kami ambil dari Baginda dan kami dapat mengajak kepada perintah itu orang-orang lain di belakang kami. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Aku perintahkan kalian dengan empat perkara dan aku larang dari empat perkara. (Yaitu) Iman kepada Allah dan persaksian (syahadah) tidak ada ilah yang berhak disembah kecuali Allah. Lalu Beliau Shallallahu'alaihiwasallam mengisyaratkan dengan mengepalkan tangannya, mendirikan shalat, menunaikan zakat, shaum Ramadhan dan kalian mengeluarkan seperlima dari harta rampasan perang\". Dan aku melarang kalian dari (meminum sesuatu) dari labu kering, guci hijau, pohon kurma (yang diukir) dan sesuatu yang dilumuri tir\". Dan berkata, [Sulaiman] dan [Abu an-Nu'man] dari [Hammad]: \"Iman kepada Allah persaksian (syahadah) tidak ada ilah kecuali Allah\". "},"1312":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبُ بْنُ أَبِي حَمْز��ةَ عَنْ الزُّهْرِيِّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُقَالَ لَمَّا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ وَكَفَرَ مَنْ كَفَرَ مِنْ الْعَرَبِ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ كَيْفَ تُقَاتِلُ النَّاسَ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَمَنْ قَالَهَا فَقَدْ عَصَمَ مِنِّي مَالَهُ وَنَفْسَهُ إِلَّا بِحَقِّهِ وَحِسَابُهُ عَلَى اللَّهِ فَقَالَ وَاللَّهِ لَأُقَاتِلَنَّ مَنْ فَرَّقَ بَيْنَ الصَّلَاةِ وَالزَّكَاةِ فَإِنَّ الزَّكَاةَ حَقُّ الْمَالِ وَاللَّهِ لَوْ مَنَعُونِي عَنَاقًا كَانُوا يُؤَدُّونَهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَاتَلْتُهُمْ عَلَى مَنْعِهَاقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فَوَاللَّهِ مَا هُوَ إِلَّا أَنْ قَدْ شَرَحَ اللَّهُ صَدْرَ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَعَرَفْتُ أَنَّهُ الْحَقُّ","id":"Telah menceritakan kepada kami [Abu Al Yaman Al Hakam bin Nafi'] telah mengabarkan kepada kami [Syu'aib bin Abu Hamzah] dari [Az Zuhriy] telah menceritakan kepada kami ['Ubaidullah bin 'Abdullah bin 'Utbah bin Mas'ud] bahwa [Abu Hurairah radliallahu 'anhu] berkata; Setelah Rasulullah Shallallahu'alaihiwasallam wafat yang kemudian Abu Bakar radliallahu 'anhu menjadi khalifah maka beberapa orang 'Arab ada yang kembali menjadi kafir (dengan enggan menunaikan zakat). Maka (ketika Abu Bakar radliallahu 'anhu hendak memerangi mereka), ['Umar bin Al Khaththab] radliallahu 'anhu bertanya: \"Bagaimana anda memerangi orang padahal Rasulullah Shallallahu'alaihiwasallam telah bersabda: \"Aku diperintahkan untuk memerangi manusia hingga mereka mgucapkan laa ilaaha illallah. Maka barangsiapa telah mengucapkannya berarti terlindunglah dariku darah dan hartanya kecuali dengan haknya sedangkan perhitungannya ada pada Allah\". Maka [Abu Bakar Ash-Shidiq radliallahu 'anhu] berkata: \"Demi Allah, aku pasti akan memerangi siapa yang memisahkan antara kewajiban shalat dan zakat, karena zakat adalah hak harta. Demi Allah, seandainya mereka enggan membayarkan anak kambing yang dahulu mereka menyerahkannya kepada Rasulullah Shallallahu'alaihiwasallam, pasti akan aku perangi mereka disebabkan keengganan itu\". Berkata, 'Umar bin Al Khaththab radliallahu 'anhu: \"Demi Allah, ketegasan dia ini tidak lain selain Allah telah membukakan hati Abu Bakar Ash-Shidiq radliallahu 'anhu dan aku menyadari bahwa dia memang benar\"."},"1313":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ قَالَ حَدَّثَنِي أَبِي حَدَّثَنَا إِسْمَاعِيلُ عَنْ قَيْسٍ قَالَ قَالَ جَرِيرُ بْنُ عَبْدِ اللَّهِبَايَعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى إِقَامِ الصَّلَاةِ وَإِيتَاءِ الزَّكَاةِ وَالنُّصْحِ لِكُلِّ مُسْلِمٍ","id":"Telah menceritakan kepada kami [Ibnu Numair] berkata, telah menceritakan [bapakku] kepadaku, telah menceritakan kepada kami [Isma'il] dari [Qais] berkata; [Jarir bin 'Abdullah] berkata,: \"Aku berbai'at kepada Nabi Shallallahu'alaihiwasallam untuk mendirikan shalat, menunaikan zakat dan untuk selalu setia (loyal) kepada setiap muslim\"."},"1314":{"ar":"حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ هُرْمُزَ الْأَعْرَجَ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَأْتِي الْإِبِلُ عَلَى صَاحِبِهَا عَلَى خَيْرِ مَا كَانَتْ إِذَا هُوَ لَمْ يُعْطِ فِيهَا حَقَّهَا تَطَؤُهُ بِأَخْفَافِهَا وَتَأْتِي الْغَنَمُ عَلَى صَاحِبِهَا عَلَى خَيْرِ مَا كَانَتْ إِذَا لَمْ يُعْطِ فِيهَا حَقَّهَا تَطَؤُهُ بِأَظْلَافِهَا وَتَنْطَحُهُ بِقُرُونِهَا وَقَالَ وَمِنْ حَقِّهَا أَنْ تُحْلَبَ عَلَى الْمَاءِ قَالَ وَلَا يَأْتِي أَحَدُكُمْ يَوْمَ الْقِيَامَةِ بِشَاةٍ يَحْمِلُهَا عَلَى رَقَبَتِهِ لَهَا يُعَارٌ فَيَقُولُ يَا مُحَمَّدُ فَأَقُولُ لَا أَمْلِكُ لَكَ شَيْئًا قَدْ بَلَّغْتُ وَلَا يَأْتِي بِبَعِيرٍ يَحْمِلُهُ عَلَى رَقَبَتِهِ لَهُ رُغَاءٌ فَيَقُولُ يَا مُحَمَّدُ فَأَقُولُ لَا أَمْلِكُ لَكَ مِنْ اللَّهِ شَيْئًا قَدْ بَلَّغْتُ","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az Zanad] bahwa ['Adur Rahman bin Hurmuz Al A'raj] menceritakan kepadanya bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] berkata; Telah bersabda Nabi Shallallahu'alaihiwasallam: \"(Pada hari qiyamat nanti) akan datang seekor unta dalam bentuknya yang paling baik kepada pemiliknya yang ketika di dunia dia tidak menunaikan haknya (zakatnya). Maka unta itu akan menginjak-injaknya dengan kakinya. Begitu juga akan datang seekor kambing dalam bentuknya yang paling baik kepada pemiliknya yang ketika di dunia dia tidak menunaikan haknya (zakatnya). Maka kambing itu akan menginjak-injaknya dengan kakinya dan menyeruduknya dengan tanduknya\". Dan Beliau berkata,: \"Dan diantara haknya adalah memerah air susunya (lalu diberikan kepada faqir miskin) \". Beliau Shallallahu'alaihiwasallam melanjutkan: \"Dan pada hari qiyamat tidak seorangpun dari kalian yang datang membawa seekor kambing di pundaknya kecuali kambing tersebut terus bersuara, lalu orang itu berkata,: \"Wahai Muhammad!\". Maka aku menjawab: \"Aku sedikitpun tidak punya kekuasaan atasmu karena aku dahulu sudah menyampaikan (masalah zakat ini). Dan tidak seorangpun dari kalian yang datang membawa seekor unta di pundaknya kecuali unta tersebut terus bersuara, lalu orang itu berkata,: \"Wahai Muhammad!\". Maka aku berkata: \"Aku sedikitpun tidak punya kekuasaan atasmu karena aku dahulu sudah menyampaikan (masalah zakat ini) \"."},"1315":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِيهِ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ آتَاهُ اللَّهُ مَالًا فَلَمْ يُؤَدِّ زَكَاتَهُ مُثِّلَ لَهُ مَالُهُ يَوْمَ الْقِيَامَةِ شُجَاعًا أَقْرَعَ لَهُ زَبِيبَتَانِ يُطَوَّقُهُ يَوْمَ الْقِيَامَةِ ثُمَّ يَأْخُذُ بِلِهْزِمَتَيْهِ يَعْنِي بِشِدْقَيْهِ ثُمَّ يَقُولُ أَنَا مَالُكَ أَنَا كَنْزُكَ ثُمَّ تَلَا{ لَا يَحْسِبَنَّ الَّذِينَ يَبْخَلُونَ }الْآيَةَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Hasyim bin Aal Qasim] telah menceritakan kepada kami ['Abdurrahman bin 'Abdullah bin Dinar] dari [bapaknya] dari [Abu Shalih As-Saman] dari [Abu Hurairah radliallahu 'anhu] berkata,: Rasulullah Shallallahu'alaihiwasallam telah bersabda: \"Barangsiapa yang Allah berikan harta namun tidak mengeluarkan zakatnya maka pada hari qiyamat hartanya itu akan berubah wujud menjadi seekor ular jantan yang bertanduk dan memiliki dua taring lalu melilit orang itu pada hari qiyamat lalu ular itu memakannya dengan kedua rahangnya, yaitu dengan mulutnya seraya berkata,: 'Aku inilah hartamu, akulah harta simpananmu\". Kemudian Beliau membaca firman Allah subhanahu wata'ala QS Alu 'Imran ayat 180 yang artinya \"(Sekali-kali janganlah orang-orang yang bakhil dengan harta yang Allah berikan kepada mereka dari karuniaNya menyangka, ……\")."},"1316":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ شَبِيبِ بْنِ سَعِيدٍ حَدَّثَنَا أَبِي عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ خَالِدِ بْنِ أَسْلَمَ قَالَ خَرَجْنَا مَعَ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَافَقَالَ أَعْرَابِيٌّ أَخْبِرْنِي عَنْ قَوْلِ اللَّهِ{ وَالَّذِينَ يَكْنِزُونَ الذَّهَبَ وَالْفِضَّةَ وَلَا يُنْفِقُونَهَا فِي سَبِيلِ اللَّهِ }قَالَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا مَنْ كَنَزَهَا فَلَمْ يُؤَدِّ زَكَاتَهَا فَوَيْلٌ لَهُ ��ِنَّمَا كَانَ هَذَا قَبْلَ أَنْ تُنْزَلَ الزَّكَاةُ فَلَمَّا أُنْزِلَتْ جَعَلَهَا اللَّهُ طُهْرًا لِلْأَمْوَالِ","id":"Telah menceritakan kepada kami [Ahmad bin Syabib bin Sa'id] telah menceritakan [bapakku] kepadaku dari [Yunus] dari [Ibnu Syihab] dari [Khalid bin Aslam] berkata; Kami keluar bersama ['Abdullah bin 'Umar] radliallahu 'anhuma, lalu seorang Badui berkata,: \"Kabari aku akan firman Allah: \" walladziina yaknizuunadz dzahaba wal fidhdhata walaa yunfiquunahaa fii sabiilillah\" (dan orang-orang yang menyimpan emas dan perak dan tidak menafkahkannya pada jalan Allah), \" Ibn 'Umar radliallahu 'anhuma berkata,: \"Barangsiapa yang menyimpannya dan ia tidak menunaikan zakatnya maka celakalah ia. Namun ayat ini turun sebelum diturunkannya ayat zakat, ketika aturan zakat sudah diturunkan maka Allah subhanahu wata'ala menjadikannya ketentuan ayat ini sebagai perintah pensucian harta\"."},"1317":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ يَزِيدَ أَخْبَرَنَا شُعَيْبُ بْنُ إِسْحَاقَ أَخْبَرَنَا الْأَوْزَاعِيُّ أَخْبَرَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ أَنَّ عَمْرَو بْنَ يَحْيَى بْنِ عُمَارَةَ أَخْبَرَهُ عَنْ أَبِيهِ يَحْيَى بْنِ عُمَارَةَ بْنِ أَبِي الْحَسَنِ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ فِيمَا دُونَ خَمْسِ أَوَاقٍ صَدَقَةٌ وَلَيْسَ فِيمَا دُونَ خَمْسِ ذَوْدٍ صَدَقَةٌ وَلَيْسَ فِيمَا دُونَ خَمْسِ أَوْسُقٍ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Ishaq bin Yazid] telah mengabarkan kepada kami [Syu'aib bin Ishaq] telah mengabarkan kepada kami [Al Awza'iy] telah mengabarkan kepada saya [Yahya bin Abu Katsir] bahwa ['Amru bin Yahya bin 'Umarah] telah mengabarkannya dari bapaknya [Yahya bin 'Umarah bin Abu Al Hasan] bahwa dia mendengar [Abu Sa'id radliallahu 'anhu] berkata; Nabi Shallallahu'alaihiwasallam telah bersabda: \"Tidak ada zakat harta dibawah lima wasaq, tidak ada zakat pada unta dibawah lima ekor dan tidak ada zakat pada hasil tanaman dibawah lima wasaq\". "},"1318":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ أَبِي هَاشِمٍ سَمِعَ هُشَيْمًا أَخْبَرَنَا حُصَيْنٌ عَنْ زَيْدِ بْنِ وَهْبٍ قَالَ مَرَرْتُ بِالرَّبَذَةِ فَإِذَا أَنَا بِأَبِي ذَرٍّ رَضِيَ اللَّهُ عَنْهُ فَقُلْتُ لَهُمَا أَنْزَلَكَ مَنْزِلكَ هَذَا قَالَ كُنْتُ بِالشَّأْمِ فَاخْتَلَفْتُ أَنَا وَمُعَاوِيَةُ فِي{ الَّذِينَ يَكْنِزُونَ الذَّهَبَ وَالْفِضَّةَ وَلَا يُنْفِقُونَهَا فِي سَبِيلِ اللَّهِ }قَالَ مُعَاوِيَةُ نَزَلَتْ فِي أَهْلِ الْكِتَابِ فَقُلْتُ نَزَلَتْ فِينَا وَفِيهِمْ فَكَانَ بَيْنِي وَبَيْنَهُ فِي ذَاكَ وَكَتَبَ إِلَى عُثْمَانَ رَضِيَ اللَّهُ عَنْهُ يَشْكُونِي فَكَتَبَ إِلَيَّ عُثْمَانُ أَنْ اقْدَمْ الْمَدِينَةَ فَقَدِمْتُهَا فَكَثُرَ عَلَيَّ النَّاسُ حَتَّى كَأَنَّهُمْ لَمْ يَرَوْنِي قَبْلَ ذَلِكَ فَذَكَرْتُ ذَاكَ لِعُثْمَانَ فَقَالَ لِي إِنْ شِئْتَ تَنَحَّيْتَ فَكُنْتَ قَرِيبًا فَذَاكَ الَّذِي أَنْزَلَنِي هَذَا الْمَنْزِلَ وَلَوْ أَمَّرُوا عَلَيَّ حَبَشِيًّا لَسَمِعْتُ وَأَطَعْتُ","id":"Telah menceritakan kepada kami ['Ali bin Abu Hasyim] dia mendengar [Husyaim] yang telah mengabarkan kepada kami [Hushain] dari [Zaid bin Wahab] berkata; \"Saat aku melewati Zabdah, aku bertemu dengan [Abu Dzar] radliallahu 'anhu, lalu aku bertanya kepadanya; \"Apa yang menyebabkanmu sampai menetap di tempat ini?\". Dia menjawab: \"Sebelumnya aku tinggal di Syam, namun aku berselisih dengan Mu'awiyah tentang ayat; \"walladziina yaknizuunadz dzahaba wal fidhdhata walaa yunfiquunahaa fii sabiilillah\". Muawiyah berkata, ayat ini turun pada Ahli kitab, sedangkan aku berkata, ayat ini turun kepada kita dan mereka. Hal inilah yang menjadikan aku berselisih dengannya. Lalu dia mengirim surat kepada 'Utsman radliallahu 'anhu mengeluhkanku. Akhirnya 'Utsman radliallahu 'anhu mengirim surat kepadaku agar aku datang ke Madinah. Lalu aku mendatanginya, kemudian orang-orang mengerumuniku seakan-akan mereka belum pernah melihatku sebelumnya, lalu aku mengabarkan hal itu kepada Utsman. Lalu ia mengatakan kepadaku: \"Jika engkau mau, engkau boleh meninggalkannya, dan engkau akan menjadi lebih dekat (denganku) \". Kejadian itulah yang menjadikan aku tinggal disini. Seandainya seorang budak Habsyi memerintahku, sungguh aku akan mendengar dan mentaatinya\". "},"1319":{"ar":"حَدَّثَنَا عَيَّاشٌ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا الْجُرَيْرِيُّ عَنْ أَبِي الْعَلَاءِ عَنْ الْأَحْنَفِ بْنِ قَيْسٍ قَالَ جَلَسْتُ ح و حَدَّثَنِي إِسْحَاقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنِي أَبِي حَدَّثَنَا الْجُرَيْرِيُّ حَدَّثَنَا أَبُو الْعَلَاءِ بْنُ الشِّخِّيرِ أَنَّ الْأَحْنَفَ بْنَ قَيْسٍ حَدَّثَهُمْ قَالَ جَلَسْتُ إِلَى مَلَإٍ مِنْ قُرَيْشٍ فَجَاءَ رَجُلٌخَشِنُ الشَّعَرِ وَالثِّيَابِ وَالْهَيْئَةِ حَتَّى قَامَ عَلَيْهِمْ فَسَلَّمَ ثُمَّ قَالَ بَشِّرْ الْكَانِزِينَ بِرَضْفٍ يُحْمَى عَلَيْهِ فِي نَارِ جَهَنَّمَ ثُمَّ يُوضَعُ عَلَى حَلَمَةِ ثَدْيِ أَحَدِهِمْ حَتَّى يَخْرُجَ مِنْ نُغْضِ كَتِفِهِ وَيُوضَعُ عَلَى نُغْضِ كَتِفِهِ حَتَّى يَخْرُجَ مِنْ حَلَمَةِ ثَدْيِهِ يَتَزَلْزَلُ ثُمَّ وَلَّى فَجَلَسَ إِلَى سَارِيَةٍ وَتَبِعْتُهُ وَجَلَسْتُ إِلَيْهِ وَأَنَا لَا أَدْرِي مَنْ هُوَ فَقُلْتُ لَهُ لَا أُرَى الْقَوْمَ إِلَّا قَدْ كَرِهُوا الَّذِي قُلْتَ قَالَ إِنَّهُمْ لَا يَعْقِلُونَ شَيْئًا قَالَ لِي خَلِيلِي قَالَ قُلْتُ مَنْ خَلِيلُكَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا ذَرٍّ أَتُبْصِرُ أُحُدًا قَالَ فَنَظَرْتُ إِلَى الشَّمْسِ مَا بَقِيَ مِنْ النَّهَارِ وَأَنَا أُرَى أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرْسِلُنِي فِي حَاجَةٍ لَهُ قُلْتُ نَعَمْ قَالَ مَا أُحِبُّ أَنَّ لِي مِثْلَ أُحُدٍ ذَهَبًا أُنْفِقُهُ كُلَّهُ إِلَّا ثَلَاثَةَ دَنَانِيرَ وَإِنَّ هَؤُلَاءِ لَا يَعْقِلُونَ إِنَّمَا يَجْمَعُونَ الدُّنْيَا لَا وَاللَّهِ لَا أَسْأَلُهُمْ دُنْيَا وَلَا أَسْتَفْتِيهِمْ عَنْ دِينٍ حَتَّى أَلْقَى اللَّهَ","id":"Telah menceritakan kepada kami ['Ayyasy] telah menceritakan kepada kami ['Abdul A'laa] telah menceritakan kepada kami [Al Jurairiy] dari [Abu Al 'Alaa'] dari [Al Ahnaf bin Qais] berkata; Aku duduk bermajelis. Dan juga diriwayatkan, telah menceritakan kepada saya [Ishaq bin Manshur] telah mengabarkan kepada kami ['Abdush Shamad] berkata, telah menceritakan kepadaku [bapakku] telah menceritakan kepada kami [Al Jurairiy] telah menceritakan kepada kami [Abu Al 'Alaa' bin Asy-Syikhkhir] bahwa [Al Ahnaf bin Qais] menceritakan kepada mereka, katanya: Aku duduk bersama para pembesar orang-orang Quraisy kemudian datanglah [seseorang] yang rambut pakaian dan penampilannya berantakan hingga ia berdiri diantara mereka lalu ia mengucapkan salam dan berkata,: \"Berilah kabar gembira kepada orang-orang yang menimbun hartanya dengan batu yang diseterikakan kepadanya di neraka Jahannam, lalu diletakkan pada daerah (susu) nya diantara mereka hingga ia keluar dari ujung tulang pundaknya, lalu diletakkan pada ujung tulang pundaknya hingga ia keluar pada bagian (susu) nya hingga ia berguncang. Kemudian orang itu pergi lalu duduk bersandar pada tiang. Aku mengikutinya lalu duduk disampingnya, sedangkan aku tidak mengenali siapa dia. Kemudian aku berkata, kepadanya: \"Aku tidak melihat orang-orang itu kecuali mereka membenci apa yang engkau katakan\". Dia menjawab: \"Sesungguhnya mereka itu tidak berakal sama sekali, perkataanku tadi itu seperti yang dikatakan kekasihku\". Dia (Al Ahnaf bin Qais) berkata; Aku bertanya: \"Siapa kekasihmu itu?\". Dia menjawab: \"Nabi Shallallahu'alaihiwasallam, yang Beliau pernah berkata kepadaku: \"Wahai Abu Dzar, apakah engkau melihat Uhud?\". Dia (Al Ahnaf bin Qais) berkata,: \"Maka aku memandang matahari yang ternyata masih siang hari, dan aku melihat bahwa Rasulullah Shallallahu'alaihiwasallam berkehendak mengutusku untuk memenuhi keperluannya. Maka aku menjawab: \"Ya, siap\". Lalu Beliau bersabda: \"Aku tidak menyukai bila aku memiliki emas sebesar gunung Uhud lalu aku membelanjakannya semua kecuali tiga dinar saja (yang aku suka memilikinya) \". Dan sungguh mereka tidak berakal sama sekali, yang mereka hanya mengumpulkan dunia. Tidak, demi Allah aku tidak akan meminta dunia kepada mereka, dan aku tidak akan memberikan fatwa agama ini untuk mereka hingga aku menemui Allah\". "},"1320":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى عَنْ إِسْمَاعِيلَ قَالَ حَدَّثَنِي قَيْسٌ عَنْ ابْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا حَسَدَ إِلَّا فِي اثْنَتَيْنِ رَجُلٍ آتَاهُ اللَّهُ مَالًا فَسَلَّطَهُ عَلَى هَلَكَتِهِ فِي الْحَقِّ وَرَجُلٍ آتَاهُ اللَّهُ حِكْمَةً فَهُوَ يَقْضِي بِهَا وَيُعَلِّمُهَا","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya] dari [Isma'il] berkata, telah menceritakan kepada saya [Qais] dari [Ibnu Mas'ud radliallahu 'anhu] berkata; Aku mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Tidak boleh iri (dengki) kecuali kepada dua hal. (Yaitu kepada) seorang yang Allah berikan kepadanya harta lalu dia menguasainya dan membelanjakannya di jalan yang haq (benar) dan seorang yang Allah berikan hikmah (ilmu) lalu dia melaksanakannya dan mengajarkannya (kepada orang lain) \"."},"1321":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُنِيرٍ سَمِعَ أَبَا النَّضْرِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ هُوَ ابْنُ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِيهِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَصَدَّقَ بِعَدْلِ تَمْرَةٍ مِنْ كَسْبٍ طَيِّبٍ وَلَا يَقْبَلُ اللَّهُ إِلَّا الطَّيِّبَ وَإِنَّ اللَّهَ يَتَقَبَّلُهَا بِيَمِينِهِ ثُمَّ يُرَبِّيهَا لِصَاحِبِهِ كَمَا يُرَبِّي أَحَدُكُمْ فَلُوَّهُ حَتَّى تَكُونَ مِثْلَ الْجَبَلِتَابَعَهُ سُلَيْمَانُ عَنْ ابْنِ دِينَارٍ وَقَالَ وَرْقَاءُ عَنْ ابْنِ دِينَارٍ عَنْ سَعِيدِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَاهُ مُسْلِمُ بْنُ أَبِي مَرْيَمَ وَزَيْدُ بْنُ أَسْلَمَ وَسُهَيْلٌ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdullah bin Munir] dia mendengar dari [Abu An-Nadhir]. Telah menceritakan kepada kami ['Abdurrahman] dia adalah putra dari 'Abdullah bin Dinar dari [bapaknya] dari [Abu Shalih] dari [Abu Hurairah radliallahu 'anhu] berkata,: Rasulullah Shallallahu'alaihiwasallam telah bersabda: \"Barangsiapa yang bershadaqah dengan sebutir kurma hasil dari usahanya sendiri yang baik (halal), sedangkan Allah tidak menerima kecuali yang baik saja, maka sungguh Allah akan menerimanya dengan tangan kananNya lalu mengasuhnya untuk pemiliknya sebagaimana jika seorang dari kalian mengasuh anak kudanya hingga membesar seperti gunung\". Hadits ini juga dikuatkan oleh [Sulaiman] dari [Ibnu Dinar] dan berkata, [Warqa'] dari [Ibnu Dinar] dari [Sa'id bin Yasar] dari [Abu Hurairah radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam. Dan diriwayatkanoleh [Muslim bin Abu Maryam] dan [Zaid bin Aslam] dan [Suhail] dari [Abu Shalih] dari [Abu Hurairah radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam."},"1322":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مَعْبَدُ بْنُ خَالِدٍ قَالَ سَمِعْتُ حَارِثَةَ بْنَ وَهْبٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَصَدَّقُوا فَإِنَّهُ يَأْتِي عَلَيْكُمْ زَمَانٌ يَمْشِي الرَّجُلُ بِصَدَقَتِهِ فَلَا يَجِدُ مَنْ يَقْبَلُهَا يَقُولُ الرَّجُلُ لَوْ جِئْتَ بِهَا بِالْأَمْسِ لَقَبِلْتُهَا فَأَمَّا الْيَوْمَ فَلَا حَاجَةَ لِي بِهَا","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Ma'bad bin Khalid] berkata; Aku mendengar [Haritsah bin Wahab] berkata; Aku mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Bershadaqalah, karena nanti akan datang kepada kalian suatu zaman yang ketika itu seseorang berkeliling dengan membawa shadaqahnya namun dia tidak mendapatkan seorangpun yang menerimanya. Lalu seseorang berkata,: \"Seandainya kamu datang membawanya kemarin pasti aku akan terima. Adapun hari ini aku tidak membutuhkannya lagi\"."},"1323":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ ع��لَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى يَكْثُرَ فِيكُمْ الْمَالُ فَيَفِيضَ حَتَّى يُهِمَّ رَبَّ الْمَالِ مَنْ يَقْبَلُ صَدَقَتَهُ وَحَتَّى يَعْرِضَهُ فَيَقُولَ الَّذِي يَعْرِضُهُ عَلَيْهِ لَا أَرَبَ لِي","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az Zanad] dari ['Abdurrahman] dari [Abu Hurairah radliallahu 'anhu] berkata; Nabi Shallallahu'alaihiwasallam bersabda: \"Tidak akan terjadi hari qiyamat hingga terjadi pada kalian harta yang banyak melimpah kemudian timbul kekacauan. Saat itu pemilik harta berharap ada orang yang mau menerima shadaqahnya dan hingga dia menawar-nawarkannya, lalu berkata, orang yang ditawarkan; aku tidak membutuhkannya\"."},"1324":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو عَاصِمٍ النَّبِيلُ أَخْبَرَنَا سَعْدَانُ بْنُ بِشْرٍ حَدَّثَنَا أَبُو مُجَاهِدٍ حَدَّثَنَا مُحِلُّ بْنُ خَلِيفَةَ الطَّائِيُّ قَالَ سَمِعْتُ عَدِيَّ بْنَ حَاتِمٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُكُنْتُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَهُ رَجُلَانِ أَحَدُهُمَا يَشْكُو الْعَيْلَةَ وَالْآخَرُ يَشْكُو قَطْعَ السَّبِيلِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا قَطْعُ السَّبِيلِ فَإِنَّهُ لَا يَأْتِي عَلَيْكَ إِلَّا قَلِيلٌ حَتَّى تَخْرُجَ الْعِيرُ إِلَى مَكَّةَ بِغَيْرِ خَفِيرٍ وَأَمَّا الْعَيْلَةُ فَإِنَّ السَّاعَةَ لَا تَقُومُ حَتَّى يَطُوفَ أَحَدُكُمْ بِصَدَقَتِهِ لَا يَجِدُ مَنْ يَقْبَلُهَا مِنْهُ ثُمَّ لَيَقِفَنَّ أَحَدُكُمْ بَيْنَ يَدَيْ اللَّهِ لَيْسَ بَيْنَهُ وَبَيْنَهُ حِجَابٌ وَلَا تَرْجُمَانٌ يُتَرْجِمُ لَهُ ثُمَّ لَيَقُولَنَّ لَهُ أَلَمْ أُوتِكَ مَالًا فَلَيَقُولَنَّ بَلَى ثُمَّ لَيَقُولَنَّ أَلَمْ أُرْسِلْ إِلَيْكَ رَسُولًا فَلَيَقُولَنَّ بَلَى فَيَنْظُرُ عَنْ يَمِينِهِ فَلَا يَرَى إِلَّا النَّارَ ثُمَّ يَنْظُرُ عَنْ شِمَالِهِ فَلَا يَرَى إِلَّا النَّارَ فَلْيَتَّقِيَنَّ أَحَدُكُمْ النَّارَ وَلَوْ بِشِقِّ تَمْرَةٍ فَإِنْ لَمْ يَجِدْ فَبِكَلِمَةٍ طَيِّبَةٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Abu 'Ashim an-Nabil] telah mengabarkan kepada kami [Sa'dan bin Bisyir] telah menceritakan kepada kami [Abu Mujahid] telah menceritakan kepada kami [Muhilla bin Khalifah ath-Tha'iy] berkata; aku mendengar ['Adiy bin Hatim radliallahu 'anhu] berkata; \"Aku pernah bersama Nabi shallallahu 'alaihi wasallam tiba-tiba datang dua orang yang seorang diantaranya mengeluhkan kefaqiran yang menimpanya dan yang seorang lagi mengadukan tentang para perampok di jalanan. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Adapun para perampok, dia tidak akan datang kepada kalian kecuali sedikit hingga rambongan dagang berangkat menuju Makkah tanpa gangguan. Adapun kefaqiran, tidak akan terjadi hari qiyamat hingga terjadi seseorang dari kalian berkeliling membawa shadaqahnya namun dia tidak mendapatkan orang yang mau menerimanya. Kemudian (pada hari qiyamat) pasti setiap orang dari kalian akan berdiri di hadapan Allah dimana antara dirinya dan Allah tidak ada tabir dan tidak ada penterjemah yang akan menjadi juru bicara baginya. Lalu Allah pasti akan berfirman: \"Bukakankah aku sudah memberimu harta?\". Lalu orang itu berkata,: \"Benar\". Kemudian Allah berfirman lagi: \"Bukankah aku sudah mengutus seeorang rasul kepadamu?\". Orang itu berkata; \"Benar\". Maka orang itu memandang ke sebelah kanannya namun dia tidak melihat sesuatu kecuali neraka. Lalu dia melihat ke sebelah kirinya namun dia juga tidak melihat sesuatu kecuali neraka. Karena itu, jagalah kalian dari neraka sekalipun dengan (bershadaqah) sebutir kurma. Jika dia tidak memilikinya maka dengan berkata yang baik\"."},"1325":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيَأْتِيَنَّ عَلَى النَّاسِ زَمَانٌ يَطُوفُ الرَّجُلُ فِيهِ بِالصَّدَقَةِ مِنْ الذَّهَبِ ثُمَّ لَا يَجِدُ أَحَدًا يَأْخُذُهَا مِنْهُ وَيُرَى الرَّجُلُ الْوَاحِدُ يَتْبَعُهُ أَرْبَعُونَ امْرَأَةً يَلُذْنَ بِهِ مِنْ قِلَّةِ الرِّجَالِ وَكَثْرَةِ النِّسَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Alaa'] telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Pasti akan datang pada manusia suatu zaman yang ketika seseorang berkeliling membawa shadaqah emas, lalu ia tidak mendapati seseorang yang mau menerimanya lagi. Lalu akan terlihat satu orang laki-laki akan diikuti oleh empat puluh orang wanita, yang mereka mencari kepuasan dengannya karena sedikitnya jumlah laki-laki dan banyaknya wanita.\""},"1326":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو النُّعْمَانِ الْحَكَمُ هُوَ ابْنُ عَبْدِ اللَّهِ الْبَصْرِيُّ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَتْ آيَةُ الصَّدَقَةِ كُنَّا نُحَامِلُ فَجَاءَ رَجُلٌ فَتَصَدَّقَ بِشَيْءٍ كَثِيرٍ فَقَالُوا مُرَائِي وَجَاءَ رَجُلٌ فَتَصَدَّقَ بِصَاعٍ فَقَالُوا إِنَّ اللَّهَ لَغَنِيٌّ عَنْ صَاعِ هَذَا فَنَزَلَتْ{ الَّذِينَ يَلْمِزُونَ الْمُطَّوِّعِينَ مِنْ الْمُؤْمِنِينَ فِي الصَّدَقَاتِ وَالَّذِينَ لَا يَجِدُونَ إِلَّا جُهْدَهُمْ }الْآيَةَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Sa'id] telah menceritakan kepada kami [Abu An-Nu'man Al Hakam] dia adalah putra dari 'Abdullah Al Bashriy telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dari [Abu Wa'il] dari [Abu Mas'ud radliallahu 'anhu] berkata; \"Ketika ayat shadaqah turun, kami berlomba-lomba, lalu datanglah seseorang dengan membawa shadaqah yang banyak dan orang-orang berkata, ia orang yang pamer. Kemudian datanglah seseorang lalu ia bershadaqah dengan satu sha'. Orang-orang berkata; \"Sesungguhnya Allah lebih kaya daripada satu sha' ini\". Maka turunlah aya QS At-Taubah ayat: \"Alladziina yalmizuunal muththawwi'iina minal mu'miniina fishshadaqati walladziina laa yajiduuna illa juhdahum\". (\"Orang-orang (munafik itu) yang mencela orang-orang beriman yang memberi sedekah dengan sukarela dan (mencela) orang-orang yang tidak memperoleh (untuk disedekahkan) selain sekedar kesanggupannya\")."},"1327":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَمَرَنَا بِالصَّدَقَةِ انْطَلَقَ أَحَدُنَا إِلَى السُّوقِ فَيُحَامِلُ فَيُصِيبُ الْمُدَّ وَإِنَّ لِبَعْضِهِمْ الْيَوْمَ لَمِائَةَ أَلْفٍ","id":"Telah menceritakan kepada kami [Sa'id bin Yahya] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Abu Mas'ud Al Anshariy radliallahu 'anhu] berkata,: \"Adalah Nabi Shallallahu'alaihiwasallam bila memerintahkan kami bershadaqah, maka seseorang dari kami akan berangkat menuju pasar lalu dia bekerja dengan sungguh-sungguh hingga mendapatkan rezeki satu mud. Adapun hari ini sebagian dari mereka bisa mendapatkan seratus ribu kalinya\". "},"1328":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مَعْقِلٍ قَالَ سَمِعْتُ عَدِيَّ بْنَ حَاتِمٍ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اتَّقُوا النَّارَ وَلَوْ بِشِقِّ تَمْرَةٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] berkata, aku mendengar ['Abdullah bin Ma'qil] berkata, aku mendengar ['Adiy bin Hatim radliallahu 'anhu] berkata, aku mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jagalah kalian dari neraka sekalipun dengan (bershadaqah) sebutir kurma\". "},"1329":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُحَمَّدٍ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي بَكْرِ بْنِ حَزْمٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْدَخَلَتْ امْرَأَةٌ مَعَهَا ابْنَتَانِ لَهَا تَسْأَلُ فَلَمْ تَجِدْ عِنْدِي شَيْئًا غَيْرَ تَمْرَةٍ فَأَعْطَيْتُهَا إِيَّاهَا فَقَسَمَتْهَا بَيْنَ ابْنَتَيْهَا وَلَمْ تَأْكُلْ مِنْهَا ثُمَّ قَامَتْ فَخَرَجَتْ فَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْنَا فَأَخْبَرْتُهُ فَقَالَ مَنْ ابْتُلِيَ مِنْ هَذِهِ الْبَنَاتِ بِشَيْءٍ كُنَّ لَهُ سِتْرًا مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Bisyir bin Muhammad] berkata, telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhriy] berkata, telah menceritakan kepada saya ['Abdullah bin Abu Bakar bin Hazm] dari ['Urwah] dari ['Aisyah radliallahu 'anha] berkata; Telah datang seorang wanita bersama dua putrinya menemuiku untuk meminta sesuatu namun aku tidak mempunyai apa-apa selain sebutir kurma lalu aku berikan kepadanya. Lalu wanita itu membagi kurma itu menjadi dua bagian yang diberikannya untuk kedua putrinya sedangkan dia tidak memakan sedikitpun. Lalu wanita itu berdiri untuk segera pergi. Saat itulah Nabi Shallallahu'alaihiwasallam datang kepada kami, lalu aku kabarkan masalah itu, maka Beliau bersabda: \"Siapa yang memberikan sesuatu kepada anak-anak ini, maka mereka akan menjadi pelindung dari api neraka baginya\"."},"1330":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا عُمَارَةُ بْنُ الْقَعْقَاعِ حَدَّثَنَا أَبُو زُرْعَةَ حَدَّثَنَا أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَيُّ الصَّدَقَةِ أَعْظَمُ أَجْرًا قَالَ أَنْ تَصَدَّقَ وَأَنْتَ صَحِيحٌ شَحِيحٌ تَخْشَى الْفَقْرَ وَتَأْمُلُ الْغِنَى وَلَا تُمْهِلُ حَتَّى إِذَا بَلَغَتْ الْحُلْقُومَ قُلْتَ لِفُلَانٍ كَذَا وَلِفُلَانٍ كَذَا وَقَدْ كَانَ لِفُلَانٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami ['Umarah banal Qa'qa'] telah menceritakan kepada kami [Abu Zur'ah] telah menceritakan kepada kami [Abu Hurairah radliallahu 'anhu] berkata,: \"Seorang laki-laki datang kepada Nabi Shallallahu'alaihiwasallam dan berkata,: \"Wahai Rasulullah, shadaqah apakah yang paling besar pahalanya?\". Beliau menjawab: \"Kamu bershadaqah ketika kamu dalam keadaan sehat dan kikir, takut menjadi faqir dan berangan-angan jadi orang kaya. Maka janganlah kamu menunda-nundanya hingga tiba ketika nyawamu berada di tenggorakanmu. Lalu kamu berkata, si fulan begini (punya ini) dan si fulan begini. Padahal harta itu milik si fulan\"."},"1331":{"ar":"بَاب حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ فِرَاسٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ بَعْضَ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْنَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّنَا أَسْرَعُ بِكَ لُحُوقًا قَالَ أَطْوَلُكُنَّ يَدًا فَأَخَذُوا قَصَبَةً يَذْرَعُونَهَا فَكَانَتْ سَوْدَةُ أَطْوَلَهُنَّ يَدًا فَعَلِمْنَا بَعْدُ أَنَّمَا كَانَتْ طُولَ يَدِهَا الصَّدَقَةُ وَكَانَتْ أَسْرَعَنَا لُحُوقًا بِهِ وَكَانَتْ تُحِبُّ الصَّدَقَةَ","id":"Bab. Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] dari [Firas] dari [As-Sya'biy] dari [Masruq] dari ['Aisyah radliallahu 'anha]; Sebagian isteri-isteri Nabi Shallallahu'alaihiwasallam berkata kepada Nabi Shallallahu'alaihiwasallam: \"Siapakan diantara kami yang segera menyusul anda (setelah kematian)?\". Beliau bersabda: \"Siapa yang paling panjang lengannya diantara kalian\". Maka mereka segera mengambil tongkat untuk mengukur panjang lengan mereka. Ternyata Saudah radliallahu 'anha yang paling panjang tangannya diantara mereka. Setelah itu kami mengetahui bahwa yang dimaksud dengan panjang lengan adalah yang paling gemar bershadaqah, dan ternyata Saudah radliallahu 'anha yang lebih dahulu menyusul kematian Beliau, dan dia juga paling gemar bershedeqah\". "},"1332":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ ��َسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ رَجُلٌ لَأَتَصَدَّقَنَّ بِصَدَقَةٍ فَخَرَجَ بِصَدَقَتِهِ فَوَضَعَهَا فِي يَدِ سَارِقٍ فَأَصْبَحُوا يَتَحَدَّثُونَ تُصُدِّقَ عَلَى سَارِقٍ فَقَالَ اللَّهُمَّ لَكَ الْحَمْدُ لَأَتَصَدَّقَنَّ بِصَدَقَةٍ فَخَرَجَ بِصَدَقَتِهِ فَوَضَعَهَا فِي يَدَيْ زَانِيَةٍ فَأَصْبَحُوا يَتَحَدَّثُونَ تُصُدِّقَ اللَّيْلَةَ عَلَى زَانِيَةٍ فَقَالَ اللَّهُمَّ لَكَ الْحَمْدُ عَلَى زَانِيَةٍ لَأَتَصَدَّقَنَّ بِصَدَقَةٍ فَخَرَجَ بِصَدَقَتِهِ فَوَضَعَهَا فِي يَدَيْ غَنِيٍّ فَأَصْبَحُوا يَتَحَدَّثُونَ تُصُدِّقَ عَلَى غَنِيٍّ فَقَالَ اللَّهُمَّ لَكَ الْحَمْدُ عَلَى سَارِقٍ وَعَلَى زَانِيَةٍ وَعَلَى غَنِيٍّ فَأُتِيَ فَقِيلَ لَهُ أَمَّا صَدَقَتُكَ عَلَى سَارِقٍ فَلَعَلَّهُ أَنْ يَسْتَعِفَّ عَنْ سَرِقَتِهِ وَأَمَّا الزَّانِيَةُ فَلَعَلَّهَا أَنْ تَسْتَعِفَّ عَنْ زِنَاهَا وَأَمَّا الْغَنِيُّ فَلَعَلَّهُ يَعْتَبِرُ فَيُنْفِقُ مِمَّا أَعْطَاهُ اللَّهُ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu]; Rasulullah Shallallahu'alaihiwasallam berkata,: \"Ada seorang laki-laki berkata,: Aku pasti akan bershadaqah. Lalu dia keluar dengan membawa shadaqahnya dan ternyata jatuh ke tangan seorang pencuri. Keesokan paginya orang-orang ramai membicarakan bahwa dia telah memberikan shadaqahnya kepada seorang pencuri. Mendengar hal itu orang itu berkata,: \"Ya Allah segala puji bagiMu, aku pasti akan bershadaqah lagi\". Kemudian dia keluar dengan membawa shadaqahnya lalu ternyata jatuh ke tangan seorang pezina. Keesokan paginya orang-orang ramai membicarakan bahwa dia tadi malam memberikan shadaqahnya kepada seorang pezina. Maka orang itu berkata, lagi: Ya Allah segala puji bagiMu, (ternyata shadaqahku jatuh) kepada seorang pezina, aku pasti akan bershadaqah lagi. Kemudian dia keluar lagi dengan membawa shadaqahnya lalu ternyata jatuh ke tangan seorang yang kaya. Keesokan paginya orang-orang kembali ramai membicarakan bahwa dia memberikan shadaqahnya kepada seorang yang kaya. Maka orang itu berkata,: Ya Allah segala puji bagiMu, (ternyata shadaqahku jatuh) kepada seorang pencuri, pezina, dan orang kaya. Setelah itu orang tadi bermimpi dan dikatakan padanya: \"Adapun shadaqah kamu kepada pencuri, mudah-mudahan dapat mencegah si pencuri dari perbuatannya, sedangkan shadaqah kamu kepada pezina, mudah-mudahan dapat mencegahnya berbuat zina kembali dan shadaqah kamu kepada orang yang kaya mudah-mudahan dapat memberikan pelajaran baginya agar menginfaqkan harta yang diberikan Allah kepadanya\"."},"1333":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو الْجُوَيْرِيَةِ أَنَّ مَعْنَ بْنَ يَزِيدَ رَضِيَ اللَّهُ عَنْهُ حَدَّثَهُ قَالَبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَأَبِي وَجَدِّي وَخَطَبَ عَلَيَّ فَأَنْكَحَنِي وَخَاصَمْتُ إِلَيْهِ وَكَانَ أَبِي يَزِيدُ أَخْرَجَ دَنَانِيرَ يَتَصَدَّقُ بِهَا فَوَضَعَهَا عِنْدَ رَجُلٍ فِي الْمَسْجِدِ فَجِئْتُ فَأَخَذْتُهَا فَأَتَيْتُهُ بِهَا فَقَالَ وَاللَّهِ مَا إِيَّاكَ أَرَدْتُ فَخَاصَمْتُهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَكَ مَا نَوَيْتَ يَا يَزِيدُ وَلَكَ مَا أَخَذْتَ يَا مَعْنُ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Isra'il] telah menceritakan kepada kami [Abu Al Juwairiyah] bahwa [Ma'an bin Yazid radliallahu 'anhu] menceritakan kepadanya, katanya: \"Aku, bapakku dan kakekku sudah berbai'at kepada Rasulullah Shallallahu'alaihiwasallam. Aku juga pernah dilamarkan seseorang buatku dan Beliau menikahkanku. Aku juga bersumpah setia (untuk mengembalikan setiap urusanku) kepada Beliau. Suatu hari bapakku, Yazid mengeluarkan dinar untuk dishadaqahkan, lalu dia meletakkannya di samping seseorang yang berada di masjid. Kemudian aku datang, aku ambil dan aku bawa kepadanya, lalu bapakku berkata,: \"Demi Allah, bukan kamu yang aku tuju\". Lalu masalah ini aku adukan kepada Rasulullah Shallallahu'alaihiwasallam, maka Beliau berkata,: \"Bagimu apa yang sudah kamu niatkan wahai Yazid, sedangkan bagimu apa yang telah kamu ambil wahai Ma'an\"."},"1334":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي خُبَيْبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَبْعَةٌ يُظِلُّهُمْ اللَّهُ تَعَالَى فِي ظِلِّهِ يَوْمَ لَا ظِلَّ إِلَّا ظِلُّهُ إِمَامٌ عَدْلٌ وَشَابٌّ نَشَأَ فِي عِبَادَةِ اللَّهِ وَرَجُلٌ قَلْبُهُ مُعَلَّقٌ فِي الْمَسَاجِدِ وَرَجُلَانِ تَحَابَّا فِي اللَّهِ اجْتَمَعَا عَلَيْهِ وَتَفَرَّقَا عَلَيْهِ وَرَجُلٌ دَعَتْهُ امْرَأَةٌ ذَاتُ مَنْصِبٍ وَجَمَالٍ فَقَالَ إِنِّي أَخَافُ اللَّهَ وَرَجُلٌ تَصَدَّقَ بِصَدَقَةٍ فَأَخْفَاهَا حَتَّى لَا تَعْلَمَ شِمَالُهُ مَا تُنْفِقُ يَمِينُهُ وَرَجُلٌ ذَكَرَ اللَّهَ خَالِيًا فَفَاضَتْ عَيْنَاهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] berkata, telah menceritakan kepada saya [Khubaib bin 'Abdurrahman] dari [Hafsh bin 'Ashim] dari [Abu Hurairah radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Ada tujuh (golongan orang beriman) yang akan mendapat naungan (perlindungan) dari Allah dibawah naunganNya (pada hari qiyamat) yang ketika tidak ada naungan kecuali naunganNya. Yaitu; Pemimpin yang adil, seorang pemuda yang menyibukkan dirinya dengan 'ibadah kepada Rabnya, seorang laki-laki yang hatinya terpaut dengan masjid, dua orang laki-laki yang saling mencintai karena Allah, keduanya bertemu karena Allah dan berpisah karena Allah, seorang laki-laki yang diajak berbuat maksiat oleh seorang wanita kaya lagi cantik lalu dia berkata, \"aku takut kepada Allah\", seorang yang bersedekah dengan menyembunyikannya hingga tangan kirinya tidak mengetahui apa yang diinfaqkan oleh tangan kanannya, dan seorang laki-laki yang berdzikir kepada Allah dengan mengasingkan diri sendirian hingga kedua matanya basah karena menangis\"."},"1335":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْجَعْدِ أَخْبَرَنَا شُعْبَةُ قَالَ أَخْبَرَنِي مَعْبَدُ بْنُ خَالِدٍ قَالَ سَمِعْتُ حَارِثَةَ بْنَ وَهْبٍ الْخُزَاعِيَّ رَضِيَ اللَّهُ عَنْهُ يَقُولُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَصَدَّقُوا فَسَيَأْتِي عَلَيْكُمْ زَمَانٌ يَمْشِي الرَّجُلُ بِصَدَقَتِهِ فَيَقُولُ الرَّجُلُ لَوْ جِئْتَ بِهَا بِالْأَمْسِ لقَبِلْتُهَا مِنْكَ فَأَمَّا الْيَوْمَ فَلَا حَاجَةَ لِي فِيهَا","id":"Telah menceritakan kepada kami ['Ali bin Al Ja'di] telah mengabarkan kepada kami [Syu'bah] berkata, telah mengabarkan kepada saya [Ma'bad bin Khalid] berkata; Aku mendengar [Haritsah bin Wahab Al Khaza'i radliallahu 'anhu] berkata; Aku mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Bershadaqalah, karena nanti akan datang kepada kalian suatu zaman yang ketika itu seseorang berjalan dengan membawa shadaqahnya lalu seseorang berkata,: \"Seandainya kamu datang membawanya kemarin pasti aku akan terima. Adapun hari ini aku tidak membutuhkannya lagi\"."},"1336":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ شَقِيقٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَنْفَقَتْ الْمَرْأَةُ مِنْ طَعَامِ بَيْتِهَا غَيْرَ مُفْسِدَةٍ كَانَ لَهَا أَجْرُهَا بِمَا أَنْفَقَتْ وَلِزَوْجِهَا أَجْرُهُ بِمَا كَسَبَ وَلِلْخَازِنِ مِثْلُ ذَلِكَ لَا يَنْقُصُ بَعْضُهُمْ أَجْرَ بَعْضٍ شَيْئًا","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Syaqiq] dari [Masruq] dari ['Aisyah radliallahu 'anha] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika seorang wanita bershadaqah dari makanan yang ada di rumah (suami) nya bukan bermaksud menimbulkan kerusakan maka baginya pahala atas apa yang diinfaqkan dan bagi suaminya pahala atas apa yang diusahakannya. Demikian juga bagi seorang penjaga harta/bendahara (akan mendapatkan pahala) dengan tidak dikurangi sedikitpun pahala masing-masing dari mereka\"."},"1337":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ الصَّدَقَةِ مَا كَانَ عَنْ ظَهْرِ غِنًى وَابْدَأْ بِمَنْ تَعُولُ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami ['Abdullah] dari [Yunus] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya [Sa'id bin Al Musayyab] bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam berkata,: \"Shadaqah yang paling baik adalah dari orang yang sudah cukup (untuk kebutuhan dirinya). Maka mulailah untuk orang-orang yang menjadi tanggunganmu\"."},"1338":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ حَكِيمِ بْنِ حِزَامٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى وَابْدَأْ بِمَنْ تَعُولُ وَخَيْرُ الصَّدَقَةِ عَنْ ظَهْرِ غِنًى وَمَنْ يَسْتَعْفِفْ يُعِفَّهُ اللَّهُ وَمَنْ يَسْتَغْنِ يُغْنِهِ اللَّهُوَعَنْ وُهَيْبٍ قَالَ أَخْبَرَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Hisyam] dari [bapaknya] dari [Hakim bin Hiram radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam berkata,: \"Tangan yang diatas lebih baik dari pada tangan yang di bawah, maka mulailah untuk orang-orang yang menjadi tanggunganmu dan shadaqah yang paling baik adalah dari orang yang sudah cukup (untuk kebutuhan dirinya). Maka barangsiapa yang berusaha memelihara dirinya, Allah akan memeliharanya dan barangsiapa yang berusaha mencukupkan dirinya maka Allah akan mencukupkannya\". Dan dari [Wuhaib] berkata, telah mengabarkan kepada kami [Hisyam] dari [bapaknya] dari [Abu Hurairah radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam seperti ini\"."},"1339":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَهُوَ عَلَى الْمِنْبَرِ وَذَكَرَ الصَّدَقَةَ وَالتَّعَفُّفَ وَالْمَسْأَلَةَ الْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى فَالْيَدُ الْعُلْيَا هِيَ الْمُنْفِقَةُ وَالسُّفْلَى هِيَ السَّائِلَةُ","id":"Telah menceritakan kepada kami [Abu An-Nu'man] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] berkata; Aku mendengar Nabi Shallallahu'alaihiwasallam. Dan telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhua] bahwa Rasulullah Shallallahu'alaihiwasallam bersabda ketika berada di atas mimbar, diantaranya Beliau menyebut tentang shadaqah dan masalah tangan yang diatas lebih baik dari pada tangan yang di bawah. Tangan yang diatas adalah yang memberi (mengeluarkan infaq) sedangkan tangan yang di bawah adalah yang meminta\"."},"1340":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ عُمَرَ بْنِ سَعِيدٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ أَنَّ عُقْبَةَ بْنَ الْحَارِثِ رَضِيَ اللَّهُ عَنْهُ حَدَّثَهُ قَالَصَلَّى بِنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ فَأَسْرَعَ ثُمَّ دَخَلَ الْبَيْتَ فَلَمْ يَلْبَثْ أَنْ خَرَجَ فَقُلْتُ أَوْ قِيلَ لَهُ فَقَالَ كُنْتُ خَلَّفْتُ فِي الْبَيْتِ تِبْرًا مِنْ الصَّدَقَةِ فَكَرِهْتُ أَنْ أُبَيِّتَهُ فَقَسَمْتُهُ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari ['Umar bin Said] dari [Ibnu Abu Mulaikah] bahwa ['Uqbah bin Al Harits] radliallahu 'anhu menceritakan kepadanya, katanya: \"Nabi Shallallahu'alaihiwasallam shalat 'Ashar berjama'ah bersama kami. Tiba-tiba Beliau dengan tergesa-gesa memasuki rumah. Tidak lama kemudian Beliau keluar, dan aku bertanya atau dikatakan kepada Beliau tentang ketergesaannya itu. Maka Beliau berkata,: \"Aku tinggalkan dalam rumah sebatang emas dari harta shadaqah. Aku tidak mau bila sampai bermalam, maka aku bagi-bagikan\"."},"1341":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَدِيٌّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ عِيدٍ فَصَلَّى رَكْعَتَيْنِ لَمْ يُصَلِّ قَبْلُ وَلَا بَعْدُ ثُمَّ مَالَ عَلَى النِّسَاءِ وَمَعَهُ بِلَالٌ فَوَعَظَهُنَّ وَأَمَرَهُنَّ أَنْ يَتَصَدَّقْنَ فَجَعَلَتْ الْمَرْأَةُ تُلْقِي الْقُلْبَ وَالْخُرْصَ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami ['Adiy] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; Nabi Shallallahu'alaihiwasallam keluar pada hari 'Ied lalu shalat dua raka'at dan Beliau tidak shalat lain sebelum maupun sesudahnya, kemudian Beliau mendatangi jama'ah wanita bersama Bilal, lalu Beliau memberikan nasehat dan memerintahkan mereka untuk bershadaqah. Maka diantara mereka ada yang memberikan gelang dan antingnya\". "},"1342":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا أَبُو بُرْدَةَ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ حَدَّثَنَا أَبُو بُرْدَةَ بْنُ أَبِي مُوسَى عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَاءَهُ السَّائِلُ أَوْ طُلِبَتْ إِلَيْهِ حَاجَةٌ قَالَ اشْفَعُوا تُؤْجَرُوا وَيَقْضِي اللَّهُ عَلَى لِسَانِ نَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا شَاءَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami [Abu Burdah bin 'Abdullah bin Abu Burdah] telah menceritakan kepada kami [Abu Burdah bin Musa] dari [bapaknya radliallahu 'anhu] berkata; 'Rasulullah Shallallahu'alaihiwasallam jika datang kepadanya seorang yang meminta atau memerlukan sesuatu Beliau bersabda: \"Penuhilah oleh kalian, nanti kalian akan diberikan pahala, sedangkan Allah pasti akan menetapkan apa yang dikehendaki-Nya melalui lisan NabiNya\". "},"1343":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا عَبْدَةُ عَنْ هِشَامٍ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُوكِي فَيُوكَى عَلَيْكِحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ عَنْ عَبْدَةَ وَقَالَ لَا تُحْصِي فَيُحْصِيَ اللَّهُ عَلَيْكِ","id":"Telah menceritakan kepada kami [Shadaqah bin Al Fadhal] telah mengabarkan kepada kami ['Abdah] dari [Hisyam] dari [Fathimah] dari [Asma' radliallahu 'anha] berkata; Nabi Shallallahu'alaihiwasallam berkata, kepadaku: \"Janganlah kamu tahan tanganmu dari berinfaq karena takut miskin, sebab nanti Allah menyempitkan reziki bagimu\". Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] dari ['Abdah] dan Beliau Shallallahu'alaihiwasallam berkata,: \"Janganlah kamu menghitung-hitung untuk bershadaqah karena takut miskin, sebab nanti Allah menyempitkan rezeki bagimu\"."},"1344":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ ح و حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ عَنْ حَجَّاجِ بْنِ مُحَمَّدٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي ابْنُ أَبِي مُلَيْكَةَ عَنْ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ أَخْبَرَهُ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهَا جَاءَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا تُوعِي فَيُوعِيَ اللَّهُ عَلَيْكِ ارْضَخِي مَا اسْتَطَعْتِ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij]. Dan diriwayatkanpula telah menceritakan kepada saya [Muhammad bin 'Abdur Rahim] dari [Hajjaj bin Muhammad] dari [Ibnu Juraij] berkata, telah mengabarkan kepada saya [Ibnu Abu Mulaikah] dari ['Abbad bin 'Abdullah bin Az Zubair] bahwa dia mengabarkannya dari [Asma' binti Abu Bakar radliallahu 'anhuma] bahwa dia menemui Nabi Shallallahu'alaihiwasallam lalu Beliau bersabda: \"Janganlah kamu berkarung-karung (kamu kumpulkan harta dalam karung lalu kamu kikir untuk menginfaqkannya) sebab Allah akan menyempitkan reziki bagimu dan berinfaqlah dengan ringan sebatas kemampuanmu \"."},"1345":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ ال��أَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ أَيُّكُمْ يَحْفَظُ حَدِيثَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْفِتْنَةِ قَالَ قُلْتُ أَنَا أَحْفَظُهُ كَمَا قَالَ قَالَ إِنَّكَ عَلَيْهِ لَجَرِيءٌ فَكَيْفَ قَالَ قُلْتُ فِتْنَةُ الرَّجُلِ فِي أَهْلِهِ وَوَلَدِهِ وَجَارِهِ تُكَفِّرُهَا الصَّلَاةُ وَالصَّدَقَةُ وَالْمَعْرُوفُ قَالَ سُلَيْمَانُ قَدْ كَانَ يَقُولُ الصَّلَاةُ وَالصَّدَقَةُ وَالْأَمْرُ بِالْمَعْرُوفِ وَالنَّهْيُ عَنْ الْمُنْكَرِ قَالَ لَيْسَ هَذِهِ أُرِيدُ وَلَكِنِّي أُرِيدُ الَّتِي تَمُوجُ كَمَوْجِ الْبَحْرِ قَالَ قُلْتُ لَيْسَ عَلَيْكَ بِهَا يَا أَمِيرَ الْمُؤْمِنِينَ بَأْسٌ بَيْنَكَ وَبَيْنَهَا بَابٌ مُغْلَقٌ قَالَ فَيُكْسَرُ الْبَابُ أَوْ يُفْتَحُ قَالَ قُلْتُ لَا بَلْ يُكْسَرُ قَالَ فَإِنَّهُ إِذَا كُسِرَ لَمْ يُغْلَقْ أَبَدًا قَالَ قُلْتُ أَجَلْ فَهِبْنَا أَنْ نَسْأَلَهُ مَنْ الْبَابُ فَقُلْنَا لِمَسْرُوقٍ سَلْهُ قَالَ فَسَأَلَهُ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ قَالَ قُلْنَا فَعَلِمَ عُمَرُ مَنْ تَعْنِي قَالَ نَعَمْ كَمَا أَنَّ دُونَ غَدٍ لَيْلَةً وَذَلِكَ أَنِّي حَدَّثْتُهُ حَدِيثًا لَيْسَ بِالْأَغَالِيطِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Wa'il] dari [Hudzaifah radliallahu 'anhu] berkata; \"Pada suatu hari 'Umar radliallahu 'anhu berkata,: \"Siapa diantara kalian yang masih hafal hadits Rasulullah Shallallahu'alaihiwasallam tentang masalah fitnah? Hudzaifah berkata,: \"Aku, masih hafal sebagaimana disabdakan Beliau\". 'Umar berkata,: \"Apakah kamu bersama Beliau saat itu atau hanya mendengar sabda Beliau? Dan bagaimana yang disabdakannya?\". Aku berkata,: \"Yaitu suatu fitnah seseorang dalam keluarganya, harta, anak dan tetangganya. Fitnah itu akan terhapus oleh shalat, shaum. shadaqah dan berbuat kebaikan (ma'ruf) \". Berkata, Sulaiman; \"Dia mengatakan shalat, shaum. shadaqah dan amar ma'ruf dan nahiy munkar\". Lalu 'Umar berkata,: \"Bukan itu yang aku mau. Tapi fitnah yang meluas seperti melubernya air lautan. Hudzaifah berkata,: \"Kalau begitu baiklah, tidak masalah buat anda wahai Amirul Mu'minin. Sesungguhnya antara engkau dan fitnah itu ada satu pintu yang tertutup\". 'Umar bertanya: \"Pintu tersebut harus didobrak atau langsung bisa dibuka?. Hudzaifah berkata,: \"Tidak, akan tetapi dia pintu yang harus didobrak\". 'Umar berkata,: \"Kalau begitu bila pintu itu harus didobrak berarti tidak akan bisa ditutup selamanya\" Aku berkata; \"Benar apa katamu. Maka persilakanlah kami untuk bertanya kepadanya tentang maksud pintu tersebut. Maka kami berkata, kepada (Masruq): \"Tanyakanlah!\". Dia berkata,: Maka dia berkata, kepadanya. Maka 'Umar radliallahu 'anhu pun berkata,. Dia berkata,: Maka kami berkata,: \"Apakah 'Umar mengerti siapa yang dimaksud dengannya\". Hudzaifah berkata,: \"Ya, dia mengerti. Sebagaimana mengertinya dia bahwa setelah besok pasti ada malam hari. Dan yang demikian itu karena aku menceritakan kepadanya suatu hadits yang tidak ada kerancuannya. "},"1346":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامٌ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ حَكِيمِ بْنِ حِزَامٍ رَضِيَ اللَّهُ عَنْهُ قَالَ قُلْتُيَا رَسُولَ اللَّهِ أَرَأَيْتَ أَشْيَاءَ كُنْتُ أَتَحَنَّثُ بِهَا فِي الْجَاهِلِيَّةِ مِنْ صَدَقَةٍ أَوْ عَتَاقَةٍ وَصِلَةِ رَحِمٍ فَهَلْ فِيهَا مِنْ أَجْرٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْلَمْتَ عَلَى مَا سَلَفَ مِنْ خَيْرٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhriy] dari ['Urwah] dari [Hakim bin Hiram radliallahu 'anhu] berkata; Aku berkata,: \"Wahai Rasulullah, bagaimana pendapatmu, saat masih di zaman Jahiliyah aku sering ber'ibadah mendekatkan diri dengan cara bershadaqah, membebaskan budak dan juga menyambung silaturrahim, apakah dari itu semuanya aku akan mendapatkan pahala?\". Maka Nabi Shallallahu'alaihiwasallam bersabda: \"Kamu akan menerima dari kebaikan yang dahulu kamu lakukan\"."},"1347":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَصَدَّقَتْ الْمَرْأَةُ مِنْ طَعَامِ زَوْجِهَا غَيْرَ مُفْسِدَةٍ كَانَ لَهَا أَجْرُهَا وَلِزَوْجِهَا بِمَا كَسَبَ وَلِلْخَازِنِ مِثْلُ ذَلِك","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Wa'il] dari [Masruq] dari ['Aisyah radliallahu 'anha] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika seorang wanita bershadaqah dari makanan suaminya dan bukan bermaksud menimbulkan kerusakan maka baginya pahala atas apa yang diinfaqkan, dan bagi suaminya pahala atas apa yang diusahakannya. Demikian juga bagi seorang penjaga harta/bendahara (akan mendapatkan pahala) \"."},"1348":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَازِنُ الْمُسْلِمُ الْأَمِينُ الَّذِي يُنْفِذُ وَرُبَّمَا قَالَ يُعْطِي مَا أُمِرَ بِهِ كَامِلًا مُوَفَّرًا طَيِّبًا بِهِ نَفْسُهُ فَيَدْفَعُهُ إِلَى الَّذِي أُمِرَ لَهُ بِهِ أَحَدُ الْمُتَصَدِّقَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Alaa'] telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin 'Abdullah] dari [Abu Burdah] dari [Abu Musa] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Seorang bendahara muslim yang amanah adalah orang yang melaksanakan tugasnya (dengan baik) \". Dan seolah Beliau bersabda: \"Dia melaksanakan apa yang diperintahkan kepadanya dengan sempurna dan jujur serta memiliki jiwa yang baik, dia mengeluarkannya (shadaqah) kepada orang yang berhak sebagaimana diperintahkan adalah termasuk salah satu dari Al Mutashaddiqin\"."},"1349":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مَنْصُورٌ وَالْأَعْمَشُ عَنْ أَبِي وَائِلٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعْنِي إِذَا تَصَدَّقَتْ الْمَرْأَةُ مِنْ بَيْتِ زَوْجِهَا حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَإِذَا أَطْعَمَتْ الْمَرْأَةُ مِنْ بَيْتِ زَوْجِهَا غَيْرَ مُفْسِدَةٍ كَانَ لَهَا أَجْرُهَا وَلَهُ مِثْلُهُ وَلِلْخَازِنِ مِثْلُ ذَلِكَ لَهُ بِمَا اكْتَسَبَ وَلَهَا بِمَا أَنْفَقَتْ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Manshur] dan [Al A'masy] dari [Abu Wa'il] dari [Masruq] dari ['Aisyah radliallahu 'anha] dari Nabi Shallallahu'alaihiwasallam yaitu: \"Jika seorang wanita bershadaqah dari (harta) rumah suaminya\". Dan telah menceritakan kepada kami ['Umar bin Hafsh] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] dari [Saqiq] dari [Masruq] dari ['Aisyah radliallahu 'anha] berkata; Nabi Shallallahu'alaihiwasallam bersabda: \"Jika seorang wanita (isteri) memberikan makanan dari makanan rumah suaminya dan bukan bermaksud menimbulkan kerusakan maka baginya pahala atas apa yang diinfaqkan dan bagi suaminya dan juga bagi seorang penjaga harta/bendahara, akan mendapatkan pahala dari apa yang diusahakannya dan bagi isterinya pahala dari apa yang diinfaqkannya\"."},"1350":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ شَقِيقٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَنْفَقَتْ الْمَرْأَةُ مِنْ طَعَامِ بَيْتِهَا غَيْرَ مُفْسِدَةٍ فَلَهَا أَجْرُهَا وَلِلزَّوْجِ بِمَا اكْتَسَبَ وَلِلْخَازِنِ مِثْلُ ذَلِكَ","id":"Telah menceritakan kepada kami [Yanya bin Yahya] telah mengabarkan kepada kami [Jarir] dari [Manshur] dari [Saqiq] dari [Masruq] dari ['Aisyah radliallahu 'anha] dari Nabi Shallallahu'alaihiwasallam berkata,: \"Jika seorang wanita (isteri) berinfaq dari makanan rumahnya dan bukan bermaksud menimbulkan kerusakan maka baginya pahala dan bagi suaminya (pahala) dari yang diusahakannya dan juga bagi seorang penjaga harta/bendahara akan mendapatkan pahala seperti itu\"."},"1351":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ مُعَاوِيَةَ بْنِ أَبِي مُزَرِّدٍ عَنْ أَبِي الْحُبَابِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ يَوْمٍ يُصْبِحُ الْعِبَادُ فِيهِ إِلَّا مَلَكَانِ يَنْزِلَانِ فَيَقُولُ أَحَدُهُمَا اللَّهُمَّ أَعْطِ مُنْفِقًا خَلَفًا وَيَقُولُ الْآخَرُ اللَّهُمَّ أَعْطِ مُمْسِكًا تَلَفًا","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada saya [saudaraku] dari [Sulaiman] dari [Mu'awiyah bin Abu Muzarrid] dari [Abu Al Hubab] dari [Abu Hurairah radliallahu 'anhu] bahwa Nabi Shallallahu'alaihiwasallam bersabda: \"Tidak ada suatu hari pun ketika seorang hamba melewati paginya kecuali akan turun (datang) dua malaikat kepadanya lalu salah satunya berkata; \"Ya Allah berikanlah pengganti bagi siapa yang menafkahkan hartanya\", sedangkan yang satunya lagi berkata; \"Ya Allah berikanlah kehancuran (kebinasaan) kepada orang yang menahan hartanya (bakhil) \"."},"1352":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْبَخِيلِ وَالْمُتَصَدِّقِ كَمَثَلِ رَجُلَيْنِ عَلَيْهِمَا جُبَّتَانِ مِنْ حَدِيدٍو حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ أَنَّ عَبْدَ الرَّحْمَنِ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَثَلُ الْبَخِيلِ وَالْمُنْفِقِ كَمَثَلِ رَجُلَيْنِ عَلَيْهِمَا جُبَّتَانِ مِنْ حَدِيدٍ مِنْ ثُدِيِّهِمَا إِلَى تَرَاقِيهِمَا فَأَمَّا الْمُنْفِقُ فَلَا يُنْفِقُ إِلَّا سَبَغَتْ أَوْ وَفَرَتْ عَلَى جِلْدِهِ حَتَّى تُخْفِيَ بَنَانَهُ وَتَعْفُوَ أَثَرَهُ وَأَمَّا الْبَخِيلُ فَلَا يُرِيدُ أَنْ يُنْفِقَ شَيْئًا إِلَّا لَزِقَتْ كُلُّ حَلْقَةٍ مَكَانَهَا فَهُوَ يُوَسِّعُهَا وَلَا تَتَّسِعُ تَابَعَهُ الْحَسَنُ بْنُ مُسْلِمٍ عَنْ طَاوُسٍ فِي الْجُبَّتَيْنِ وَقَالَ حَنْظَلَةُ عَنْ طَاوُسٍ جُنَّتَانِ وَقَالَ اللَّيْثُ حَدَّثَنِي جَعْفَرٌ عَنْ ابْنِ هُرْمُزَ سَمِعْتُ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جُنَّتَانِ","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu Thawus] dari [bapaknya] dari [Abu Hurairah radliallahu 'anhu] berkata; Nabi Shallallahu'alaihiwasallam bersabda: \"Perumpamaan orang bakhil dengan orang yang bershadaqah seperti dua orang yang masing-masing mengenakan baju jubah terbuat dari besi\". Dan telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az Zanad] bahwa ['Abdurrahman] menceritakan kepadanya bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] bahwa dia mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Perumpamaan bakhil (orang pelit bershadaqah) dengan munfiq (orang yang suka berinfaq) seperti dua orang yang masing-masing mengenakan baju jubah terbuat dari besi yang hanya menutupi buah dada hingga tulang selangka keduanya. Adapun orang yang suka berinfaq, tidaklah dia berinfaq melainkan bajunya akan melonggar atau menjauh dari kulitnya hingga akhirnya menutupi seluruh badannya sampai kepada ujung kakinya. Sedangkan orang yang bakhil, setiap kali dia tidak mau berinfaq dengan suatu apapun maka baju besinya akan menyempit sehingga menempel ketat pada setiap kulitnya dan ketika dia mencoba untuk melonggarkannya maka dia tidak dapat melonggarkannya\". Hadits ini dikuatkan pula oleh [Al Hasan bin Muslim] dari [Thawus] (dengan redaksi): \"… pada dua baju\". Dan berkata, [Hanzhalah] dari [Thawus]: \"…… mengenakan jubah\". Dan berkata, [Al Laits] telah menceritakan kepada saya [Ja'far] dari [Ibnu Hurmuz]; Aku mendengar [Abu Hurairah radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam: \"…… mengenakan jubah\". "},"1353":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا سَعِيدُ بْنُ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَى كُلِّ مُسْلِمٍ صَدَقَةٌ فَقَالُوا يَا نَبِيَّ اللَّهِ فَمَنْ لَمْ يَجِدْ قَالَ يَعْمَلُ بِيَدِهِ فَيَنْفَعُ نَفْسَهُ وَيَتَصَدَّقُ قَالُوا فَإِنْ لَمْ يَجِدْ قَالَ يُعِينُ ذَا الْحَاجَةِ الْمَلْهُوفَ قَالُوا فَإِنْ لَمْ يَجِدْ قَالَ فَلْيَعْمَلْ بِالْمَعْرُوفِ وَلْيُمْسِكْ عَنْ الشَّرِّ فَإِنَّهَا لَهُ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Sa'id bin Abu Burdah] dari [bapaknya] dari [kakeknya] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Wajib bagi setiap muslim bershadaqah\". Mereka (para sahabat) bertanya: \"Wahai Nabi Allah, bagaimana kalau ada yang tidak sanggup?\". Beliau menjawab: \"Dia bekerja dengan tangannya sehingga bermanfaat bagi dirinya lalu dia bershadaqah\". Mereka bertanya lagi: \"Bagaimana kalau tidak sanggup juga?\". Beliau menjawab: \"Dia membantu orang yang sangat memerlukan bantuan\". Mereka bertanya lagi: \"Bagaimana kalau tidak sanggup juga?\". Beliau menjawab: \"Hendaklah dia berbuat kebaikan (ma'ruf) dan menahan diri dari keburukan karena yang demikian itu berarti shodaqah baginya\"."},"1354":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو شِهَابٍ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْبُعِثَ إِلَى نُسَيْبَةَ الْأَنْصَارِيَّةِ بِشَاةٍ فَأَرْسَلَتْ إِلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا مِنْهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَكُمْ شَيْءٌ فَقُلْتُ لَا إِلَّا مَا أَرْسَلَتْ بِهِ نُسَيْبَةُ مِنْ تِلْكَ الشَّاةِ فَقَالَ هَاتِ فَقَدْ بَلَغَتْ مَحِلَّهَا","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Abu Syihab] dari [Khalid Al Hadzdza'] dari [Hafshah binti Sirin] dari [Ummu 'Athiyah radliallahu 'anha] berkata,: Telah diberikan seekor kambing kepada Nusaibah Al Anshariyyah (seorang wanita Anshar) lalu dia mengirim sebagian dagingnya kepada 'Aisyah radliallahu 'anha. Nabi Shallallahu'alaihiwasallam bertanya: \"Apakah ada sesuatu yang kalian miliki (untuk dimakan)?\". Aku menjawab: \"Tidak ada, kecuali apa yang dikirim oleh Nusaibah dari daging kambing itu\". Maka Beliau berkata,: \"Bawalah kemari, karena shadaqah itu telah sampai kepada tempatnya\"."},"1355":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَمْرِو بْنِ يَحْيَى الْمَازِنِيِّ عَنْ أَبِيهِ قَالَ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ فِيمَا دُونَ خَمْسِ ذَوْدٍ صَدَقَةٌ مِنْ الْإِبِلِ وَلَيْسَ فِيمَا دُونَ خَمْسِ أَوَاقٍ صَدَقَةٌ وَلَيْسَ فِيمَا دُونَ خَمْسَةِ أَوْسُقٍ صَدَقَةٌحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ قَالَ أَخْبَرَنِي عَمْرٌو سَمِعَ أَبَاهُ عَنْ أَبِي سَعِيدٍ رَضِيَ اللَّهُ عَنْهُ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari ['Amru bin Yaha Al Maziniy] dari [bapaknya] berkata; Aku mendengar [Abu Sa'id Al Khudriy] berkata; Nabi Shallallahu'alaihiwasallam telah bersabda: \"Tidak ada zakat pada unta dibawah lima ekor, tidak ada zakat harta dibawah lima wasaq dan tidak ada zakat pada hasil tanaman dibawah lima wasaq\". Telah menceritakan kepada kami [Muhammad Al Mutsanna] telah menceritakan kepada kami ['Abdul Wahhab] berkata, telah menceritakan kepada saya [Yahya bin Sa'id] berkata, telah mengabarkan kepada saya ['Amru] dia mendengar dari [bapaknya] dari [Abu Sa'id radliallahu 'anhu] dia mendengar dari Nabi Shallallahu'alaihiwasallam seperti hadits ini."},"1356":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي ثُمَامَةُ أَنَّ أَنَسًا رَضِيَ اللَّهُ عَنْهُ حَدَّثَهُأَنَّ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ كَتَبَ لَهُ الَّتِي أَمَرَ اللَّهُ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَلَغَتْ صَدَقَتُهُ بِنْتَ مَخَاضٍ وَلَيْسَتْ عِنْدَهُ وَعِنْدَهُ بِنْتُ لَبُونٍ فَإِنَّهَا تُقْبَلُ مِنْهُ وَيُعْطِيهِ الْمُصَدِّقُ عِشْرِينَ دِرْهَمًا أَوْ شَاتَيْنِ فَإِنْ لَمْ يَكُنْ عِنْدَهُ بِنْتُ مَخَاضٍ عَلَى وَجْهِهَا وَعِنْدَهُ ابْنُ لَبُونٍ فَإِنَّهُ يُقْبَلُ مِنْهُ وَلَيْسَ مَعَهُ شَيْءٌ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah] berkata, telah menceritakan kepadaku [bapakku] berkata, telah menceritakan kepada saya [Tsumaamah] bahwa [Anas radliallahu 'anhu] menceritakan kepadanya bahwa [Abu Bakar radliallahu 'anhu] telah menulis surat kepadanya (tentang aturan zakat) sebagaimana apa yang telah diperintahkan Allah dan rasulNya, yaitu; \"Barangsiapa yang terkena kewajiban zakat bintu makhadh namun dia tidak memilikinya sedang yang ada dimilikinya bintu labun, maka zakatnya bisa diterima dengan bintu labun dan dia diberi (menerima) dua puluh dirham atau dua ekor kambing. Jadi jika ia tidak memiliki bintu makhadh (yang wajib dizakatkan sesuai ketentuan) sedangkan yang ada padanya bintu labun maka zakatnya bisa diterima dengan bintu labun itu karena dia tidak memiliki yang lain\"."},"1357":{"ar":"حَدَّثَنَا مُؤَمَّلٌ حَدَّثَنَا إِسْمَاعِيلُ عَنْ أَيُّوبَ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ قَالَ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَشْهَدُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَصَلَّى قَبْلَ الْخُطْبَةِ فَرَأَى أَنَّهُ لَمْ يُسْمِعْ النِّسَاءَ فَأَتَاهُنَّ وَمَعَهُ بِلَالٌ نَاشِرَ ثَوْبِهِ فَوَعَظَهُنَّ وَأَمَرَهُنَّ أَنْ يَتَصَدَّقْنَ فَجَعَلَتْ الْمَرْأَةُ تُلْقِي وَأَشَارَ أَيُّوبُ إِلَى أُذُنِهِ وَإِلَى حَلْقِهِ","id":"Telah menceritakan kepada kami [Mu'ammal] telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari ['Atha' bin Abu Rabah] berkata; [Ibnu 'Abbas radliallahu 'anhu] berkata,: \"Aku ikut menyaksikan Rasulullah Shallallahu'alaihiwasallam melaksanakan shalat 'Ied sebelum khuthbah dan Beliau menganggap bahwa khuthbahnya tidak terdengar oleh jama'ah wanita. Akhirnya Beliau mendatangi mereka bersama Bilal yang membentangkan pakainnya lalu Beliau memberi nasehat kepada mereka serta memerintahkan mereka untuk bershadaqah. Maka ada seorang wanita diantara mereka yang memberi shadaqah\". Ayyub menunjuk pada telinga dan tenggorokannya\" (maksudnya bersedekah dengan anting dan kalung). "},"1358":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي ثُمَامَةُ أَنَّ أَنَسًا رَضِيَ اللَّهُ عَنْهُ حَدَّثَهُأَنَّ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ كَتَبَ لَهُ الَّتِي فَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا يُجْمَعُ بَيْنَ مُتَفَرِّقٍ وَلَا يُفَرَّقُ بَيْنَ مُجْتَمِعٍ خَشْيَةَ الصَّدَقَةِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah Al Anshariy] berkata, telah menceritakan [bapakku] kepadaku, dia berkata, telah menceritakan kepada saya [Tsumamah] bahwa [Anas radliallahu 'anhu] menceritakan kepadanya bahwa Abu Bakar radliallahu 'anhu telah menulis surat kepadanya berupa ketentuan zakat sebagaimana telah diwajibkan oleh Rasulullah Shallallahu'alaihiwasallam: \"Janganlah kamu menggabungkan ternak yang terpisah dan jangan pula memisahkan yang sudah berkumpul, karena ingin menghindari atau meminimalisir pengeluaran shadaqah (zakat) \"."},"1359":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي ثُمَامَةُ أَنَّ أَنَسًا حَدَّثَهُأَنَّ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ كَتَبَ لَهُ الَّتِي فَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا كَانَ مِنْ خَلِيطَيْنِ فَإِنَّهُمَا يَتَرَاجَعَانِ بَيْنَهُمَا بِالسَّوِيَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah] berkata, telah menceritakan [bapakku] kepadaku dia berkata, telah menceritakan kepada saya [Tsumamah] bahwa [Anas radliallahu 'anhu] menceritakan kepadanya bahwa Abu Bakar radliallahu 'anhu telah menulis surat kepadanya berupa ketentuan zakat sebagaimana telah diwajibkan oleh Rasulullah Shallallahu'alaihiwasallam: \"Dua orang yang telah bercampur (hewan ternak keduanya) hendaklah keduanya berdamai dengan menanggung beban yang sama\"."},"1360":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ أَعْرَابِيًّا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْهِجْرَةِ فَقَالَ وَيْحَكَ إِنَّ شَأْنَهَا شَدِيدٌ فَهَلْ لَكَ مِنْ إِبِلٍ تُؤَدِّي صَدَقَتَهَا قَالَ نَعَمْ قَالَ فَاعْمَلْ مِنْ وَرَاءِ الْبِحَارِ فَإِنَّ اللَّهَ لَنْ يَتِرَكَ مِنْ عَمَلِكَ شَيْئًا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Al Awza'i] berkata, telah menceritakan kepada saya [Ibnu Syihab] dari ['Atha' bin Yazid] dari [Abu Sa'id Al Khudriy radliallahu 'anhu] bahwa ada seorang 'Arab Badui bertanya kepada Rasulullah Shallallahu'alaihiwasallam tentang ('amal) hijrah. Maka Beliau menjawab: \"Janganlah begitu, sungguh hijrah itu 'amal yang berat. Apakah kamu memiliki unta yang wajib kamu keluarkan shadaqahnya?\". Orang itu menjawab: \"Ya, punya\". Maka Beliau berkata,: \"Maka amalkanlah sekalipun dari balik lautan, karena Allah tidak akan menyia-nyiakan amalmu sedikitpun\"."},"1361":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي ثُمَامَةُ أَنَّ أَنَسًا رَضِيَ اللَّهُ عَنْهُ حَدَّثَهُأَنَّ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ كَتَبَ لَهُ فَرِيضَةَ الصَّدَقَةِ الَّتِي أَمَرَ اللَّهُ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ بَلَغَتْ عِنْدَهُ مِنْ الْإِبِلِ صَدَقَةُ الْجَذَعَةِ وَلَيْسَتْ عِنْدَهُ جَذَعَةٌ وَعِنْدَهُ حِقَّةٌ فَإِنَّهَا تُقْبَلُ مِنْهُ الْحِقَّةُ وَيَجْعَلُ مَعَهَا شَاتَيْنِ إِنْ اسْتَيْسَرَتَا لَهُ أَوْ عِشْرِينَ دِرْهَمًا وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ الْحِقَّةِ وَلَيْسَتْ عِنْدَهُ الْحِقَّةُ وَعِنْدَهُ الْجَذَعَةُ فَإِنَّهَا تُقْبَلُ مِنْهُ الْجَذَعَةُ وَيُعْطِيهِ الْمُصَدِّقُ عِشْرِينَ دِرْهَمًا أَوْ شَاتَيْنِ وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ الْحِقَّةِ وَلَيْسَتْ عِنْدَهُ إِلَّا بِنْتُ لَبُونٍ فَإِنَّهَا تُقْبَلُ مِنْهُ بِنْتُ لَبُونٍ وَيُعْطِي شَاتَيْنِ أَوْ عِشْرِينَ دِرْهَمًا وَمَنْ بَلَغَتْ صَدَقَتُهُ بِنْتَ لَبُونٍ وَعِنْدَهُ حِقَّةٌ فَإِنَّهَا تُقْبَلُ مِنْهُ الْحِقَّةُ وَيُعْطِيهِ الْمُصَدِّقُ عِشْرِينَ دِرْهَمًا أَوْ شَاتَيْنِ وَمَنْ بَلَغَتْ صَدَقَتُهُ بِنْتَ لَبُونٍ وَلَيْسَتْ عِنْدَهُ وَعِنْدَهُ بِنْتُ مَخَاضٍ فَإِنَّهَا تُقْبَلُ مِنْهُ بِنْتُ مَخَاضٍ وَيُعْطِي مَعَهَا عِشْرِينَ دِرْهَمًا أَوْ شَاتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah] berkata, telah menceritakan kepadaku [bapakku] dia berkata, telah menceritakan kepada [Tsumaamah] bahwa [Anas radliallahu 'anhu] menceritakan kepadanya bahwa Abu Bakar radliallahu 'anhu telah menulis surat kepadanya (tentang aturan zakat) sebagaimana apa yang telah diperintahkan Allah dan rasulNya Shallallahu'alaihiwasallam, yaitu; \"Barangsiapa yang memiliki unta dan terkena kewajiban zakat jadza'ah sedangkan dia tidak memiliki jadza'ah dan yang dia miliki hanya hiqqah, maka dibolehkan dia mengeluarkan hiqqah sebagai zakat namun dia harus menyerahkan pula bersamanya dua ekor kambing atau dua puluh dirham, dan barangsiapa yang telah sampai kepadanya kewajiban zakat hiqqah sedangkan dia tidak memiliki hiqqah namun dia memiliki jadza'ah maka diterima zakat darinya berupa jadza'ah dan dia menerima (diberi) dua puluh dirham atau dua ekor kambing, dan barangsiapa telah sampai kepadanya kewajiban zakat hiqqah namun dia tidak memilikinya kecuali bintu labun maka diterima zakat darinya berupa bintu labun namun dia wajib menyerahkan bersamanya dua ekor kambing atau dua puluh dirham, dan barangsiapa telah sampai kepadanya kewajiban zakat bintu labun dan dia hanya memiliki hiqqah maka diterima zakat darinya berupa hiqqah dan dia menerima dua puluh dirham atau dua ekor kambing, dan barangsiapa yang telah sampai kepadanya kewajiban zakat bintu labun sedangkan dia tidak memilikinya kecuali bintu makhadh maka diterima zakat darinya berupa bintu makhadh namun dia wajib menyerahkan bersamanya dua piluh dirham atau dua ekor kambing\"."},"1362":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُثَنَّى الْأَنْصَارِيُّ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي ثُمَامَةُ بْنُ عَبْدِ اللَّهِ بْنِ أَنَسٍ أَنَّ أَنَسًا حَدَّثَهُأَنَّ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ كَتَبَ لَهُ هَذَا الْكِتَابَ لَمَّا وَجَّهَهُ إِلَى الْبَحْرَيْنِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ هَذِهِ فَرِيضَةُ الصَّدَقَةِ الَّتِي فَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمُسْلِمِينَ وَالَّتِي أَمَرَ اللَّهُ بِهَا رَسُولَهُ فَمَنْ سُئِلَهَا مِنْ الْمُسْلِمِينَ عَلَى وَجْهِهَا فَلْيُعْطِهَا وَمَنْ سُئِلَ فَوْقَهَا فَلَا يُعْطِ فِي أَرْبَعٍ وَعِشْرِينَ مِنْ الْإِبِلِ فَمَا دُونَهَا مِنْ الْغَنَمِ مِنْ كُلِّ خَمْسٍ شَاةٌ إِذَا بَلَغَتْ خَمْسًا وَعِشْرِينَ إِلَى خَمْسٍ وَثَلَاثِينَ فَفِيهَا بِنْتُ مَخَاضٍ أُنْثَى فَإِذَا بَلَغَتْ سِتًّا وَثَلَاثِينَ إِلَى خَمْسٍ وَأَرْبَعِينَ فَفِيهَا بِنْتُ لَبُونٍ أُنْثَى فَإِذَا بَلَغَتْ سِتًّا وَأَرْبَعِينَ إِلَى سِتِّينَ فَفِيهَا حِقَّةٌ طَرُوقَةُ الْجَمَلِ فَإِذَا بَلَغَتْ وَاحِدَةً وَسِتِّينَ إِلَى خَمْسٍ وَسَبْعِينَ فَفِيهَا جَذَعَةٌ فَإِذَا بَلَغَتْ يَعْنِي سِتًّا وَسَبْعِينَ إِلَى تِسْعِينَ فَفِيهَا بِنْتَا لَبُونٍ فَإِذَا بَلَغَتْ إِحْدَى وَتِسْعِينَ إِلَى عِشْرِينَ وَمِائَةٍ فَفِيهَا حِقَّتَانِ طَرُوقَتَا الْجَمَلِ فَإِذَا زَادَتْ عَلَى عِشْرِينَ وَمِائَةٍ فَفِي كُلِّ أَرْبَعِينَ بِنْتُ لَبُونٍ وَفِي كُلِّ خَمْسِينَ حِقَّةٌ وَمَنْ لَمْ يَكُنْ مَعَهُ إِلَّا أَرْبَعٌ مِنْ الْإِبِلِ فَلَيْسَ فِيهَا صَدَقَةٌ إِلَّا أَنْ يَشَاءَ رَبُّهَا فَإِذَا بَلَغَتْ خَمْسًا مِنْ الْإِبِلِ فَفِيهَا شَاةٌ وَفِي صَدَقَةِ الْغَنَمِ فِي سَائِمَتِهَا إِذَا كَانَتْ أَرْبَعِينَ إِلَى عِشْرِينَ وَمِائَةٍ شَاةٌ فَإِذَا زَادَتْ عَلَى عِشْرِينَ وَمِائَةٍ إِلَى مِائَتَيْنِ شَاتَانِ فَإِذَا زَادَتْ عَلَى مِائَتَيْنِ إِلَى ثَلَاثِ مِائَةٍ فَفِيهَا ثَلَاثُ شِيَاهٍ فَإِذَا زَادَتْ عَلَى ثَلَاثِ مِائَةٍ فَفِي كُلِّ مِائَةٍ شَاةٌ فَإِذَا كَانَتْ سَائِمَةُ الرَّجُلِ نَاقِصَةً مِنْ أَرْبَعِينَ شَاةً وَاحِدَةً فَلَيْسَ فِيهَا صَدَقَةٌ إِلَّا أَنْ يَشَاءَ رَبُّهَا وَفِي الرِّقَّةِ رُبْعُ الْعُشْرِ فَإِنْ لَمْ تَكُنْ إِلَّا تِسْعِينَ وَمِائَةً فَلَيْسَ فِيهَا شَيْءٌ إِلَّا أَنْ يَشَاءَ رَبُّهَا","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Al Mutsanna Al Anshariy] berkata, telah menceritakan kepadaku [bapakku] dia berkata, telah menceritakan kepada saya [Tsumamah bin 'Abdullah bin Anas] bahwa [Anas] menceritakan kepadanya bahwa Abu Bakar radliallahu 'anhu telah menulis surat ini kepadanya (tentang aturtan zakat) ketika dia mengutusnya ke negeri Bahrain: \"Bismillahir rahmaanir rahiim. Inilah kewajiban zakat yang telah diwajibkan oleh Rasulullah Shallallahu'alaihiwasallam terhadap kaum Muslimin dan seperti yang diperintahklan oleh Allah dan rasulNya tentangnya, maka barangsiapa dari kaum Muslimin diminta tentang zakat sesuai ketentuan maka berikanlah dan bila diminta melebihi ketentuan maka jangan memberinya, yaitu (dalam ketentuan zakat unta) pada setiap dua puluh empat ekor unta dan yang kurang dari itu zakatnya dengan kambing. Setiap lima ekor unta zakatnya adalah seekor kambing. Bila mencapai dua puluh lima hingga tiga puluh lima ekor unta maka zakatnya satu ekor bintu makhadh betina. Bila mencapai tiga puluh enam hingga empat puluh lima ekor unta maka zakatnya 1 ekor bintu labun betina, jika mencapai empat puluh enam hingga enam puluh ekor unta maka zakatnya satu ekor hiqqah yang sudah siap dibuahi oleh unta pejantan. Jika telah mencapai enam puluh satu hingga tujuh puluh lima ekor unta maka zakatnya satu ekor jadza'ah. Jika telah mencapai tujuh puluh enam hingga sembilan puluh ekor unta maka zakatnya dua ekor bintu labun. Jika telah mencapai sembilan puluh satu hingga seratus dua puluh ekor unta maka zakatnya dua ekor hiqqah yang sudah siap dibuahi unta jantan. Bila sudah lebih dari seratus dua puluh maka ketentuannya adalah pada setiap kelipatan empat puluh ekornya, zakatnya satu ekor bintu labun dan setiap kelipatan lima puluh ekornya zakatnya satu ekor hiqqah. Dan barangsiapa yang tidak memiliki unta kecuali hanya empat ekor saja maka tidak ada kewajiban zakat baginya kecuali bila pemiliknya mau mengeluarkan zakatnya karena hanya pada setiap lima ekor unta baru ada zakatnya yaitu seekor kambing. Dan untuk zakat kambing yang digembalakan di ea radliallahu 'anhu bukan dipelihara di kandang, ketentuannya adalah bila telah mencapai jumlah empat puluh hingga seratus dua puluh ekor maka zakatnya adalah satu ekor kambing, bila lebih dari seratus dua puluh hingga dua ratus ekor maka zakatnya dua ekor kambing, bila lebih dari dua ratus hingga tiga ratus ekor maka zakatnya tiga ekor kambing, bila lebih dari tiga ratus ekor, maka pada setiap kelipatan seratus ekor zakatnya satu ekor kambing. Dan bila seorang pengembala memiliki kurang satu ekor saja dari empat puluh ekor kambing maka tidak ada kewajiban zakat baginya kecuali bila pemiliknya mau mengeluarkannya. Dan untuk zakat uang perak (dirham) maka ketentuannya seperempat puluh bila (telah mencapai dua ratus dirham) dan bila tidak mencapai jumlah itu namun hanya seratus sembilan puluh maka tidak ada kewajiban zakatnya kecuali bila pemiliknya mau mengeluarkannya\"."},"1363":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي ثُمَامَةُ أَنَّ أَنَسًا رَضِيَ اللَّهُ عَنْهُ حَدَّثَهُأَنَّ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ كَتَبَ لَهُ الصَّدَقَةَ الَّتِي أَمَرَ اللَّهُ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا يُخْرَجُ فِي الصَّدَقَةِ هَرِمَةٌ وَلَا ذَاتُ عَوَارٍ وَلَا تَيْسٌ إِلَّا مَا شَاءَ الْمُصَدِّقُ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah] berkata, telah menceritakan [bapakku] kepadaku dia berkata, telah menceritakan kepada saya [Tsumamah] bahwa [Anas] radliallahu 'anhu menceritakan kepadanya bahwa Abu Bakar radliallahu 'anhu telah menulis ketepatan tentang zakat sebagaimana yang telah diperintahkan oleh Allah dan rasulNya Shallallahu'alaihiwasallam (yaitu); \"Jangan mengeluarkan zakat kambing yang sudah berumur tua, yang buta sebelah (cacat) dan jangan pula kambing bibit kecuali bila orang yang berzakat mau mengeluarkannya\"."},"1364":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ ح وَقَالَ اللَّيْثُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ قَالَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُوَاللَّهِ لَوْ مَنَعُونِي عَنَاقًا كَانُوا يُؤَدُّونَهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَاتَلْتُهُمْ عَلَى مَنْعِهَاقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فَمَا هُوَ إِلَّا أَنْ رَأَيْتُ أَنَّ اللَّهَ شَرَحَ صَدْرَ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ بِالْقِتَالِ فَعَرَفْتُ أَنَّهُ الْحَقُّ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy]. Dan telah diceritakan pula bahwa [Al Laits] berkata, telah menceritakan kepada saya ['Abdurrahman bin Khalid] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah bin 'Utbah bin Mas'ud] bahwa [Abu Hurairah radliallahu 'anhu] berkata; [Abu Bakar Ash-Shidiq radliallahu 'anhu] berkata,: \"Demi Allah, bila mereka tidak mau menyerahkan zakat berupa 'inaqa sedangkan dahulu mereka menyerahkannya kepada Rasulullah Shallallahu'alaihiwasallam, pasti aku akan perangi mereka disebabkan keengganan mengeluarkan zakat tersebut\". Berkata, 'Umar bin Al Khaththab radliallahu 'anhu: \"Ketegasan dia ini tidak lain kecuali aku melihat bahwa Allah telah membukakan hati Abu Bakar radliallahu 'anhu untuk melakukan perang dan aku menyadari bahwa dia memang benar\"."},"1365":{"ar":"حَدَّثَنَا أُمَيَّةُ بْنُ بِسْطَامٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا رَوْحُ بْنُ الْقَاسِمِ عَنْ إِسْمَاعِيلَ بْنِ أُمَيَّةَ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ صَيْفِيٍّ عَنْ أَبِي مَعْبَدٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا بَعَثَ مُعَاذًا رَضِيَ اللَّهُ عَنْهُ عَلَى الْيَمَنِ قَالَ إِنَّكَ تَقْدَمُ عَلَى قَوْمٍ أَهْلِ كِتَابٍ فَلْيَكُنْ أَوَّلَ مَا تَدْعُوهُمْ إِلَيْهِ عِبَادَةُ اللَّهِ فَإِذَا عَرَفُوا اللَّهَ فَأَخْبِرْهُمْ أَنَّ اللَّهَ قَدْ فَرَضَ عَلَيْهِمْ خَمْسَ صَلَوَاتٍ فِي يَوْمِهِمْ وَلَيْلَتِهِمْ فَإِذَا فَعَلُوا فَأَخْبِرْهُمْ أَنَّ اللَّهَ فَرَضَ عَلَيْهِمْ زَكَاةً مِنْ أَمْوَالِهِمْ وَتُرَدُّ عَلَى فُقَرَائِهِمْ فَإِذَا أَطَاعُوا بِهَا فَخُذْ مِنْهُمْ وَتَوَقَّ كَرَائِمَ أَمْوَالِ النَّاسِ","id":"Telah menceritakan kepada kami [Umayyah bin Bistham] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Rauh bin Al Qasim] dari [Isma'il bin Umayyah] dari [Yahya bin 'Abdullah bin Shayfiy] dari [Abu Ma'bad] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa ketika Nabi Shallallahu'alaihiwasallam mengutus Mu'adz radliallahu 'anhu ke negeri Yaman, Beliau berkata,: \"Kamu akan mendatangi Ahlul Kitab, maka hendaklah da'wah yang pertama kali lakukan kepada mereka adalah mengajak mereka untuk ber'ibadah kepada Allah. Jika mereka telah mengenal Allah, maka beritahukanlah bahwa Allah mewajibkan atas mereka shalat lima waktu sehari semalam. Dan jika mereka telah melaksanakannya, maka beritahukanlah bahwa Allah telah mewajibkan atas mereka shadaqah (zakat) dari harta mereka yang akan diberikan kepada orang-orang faqir dari mereka. Jika mereka telah menaatinya, maka ambillah dari mereka (sesuai ketentuannya) dan peliharalah kesucian harta manusia\"."},"1366":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ الْمَازِنِيِّ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ فِيمَا دُونَ خَمْسَةِ أَوْسُقٍ مِنْ التَّمْرِ صَدَقَةٌ وَلَيْسَ فِيمَا دُونَ خَمْسِ أَوَاقٍ مِنْ الْوَرِقِ صَدَقَةٌ وَلَيْسَ فِيمَا دُونَ خَمْسِ ذَوْدٍ مِنْ الْإِبِلِ صَدَقَةٌ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Muhammad bin 'Abdurrahman] dari [Abu Sha'sha'ah Al Maziniy] dari bapaknya dari [Abu Sa'id Al Khudriy] bahwa Nabi Shallallahu'alaihiwasallam telah bersabda: \"Tidak ada zakat pada hasil tanaman kurma dibawah lima wasaq, tidak ada zakat harta dibawah lima wasaq dan tidak ada zakat pada unta dibawah lima ekor\". "},"1367":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ الْمَعْرُورِ بْنِ سُوَيْدٍ عَنْ أَبِي ذَرٍّ رَضِيَ اللَّهُ عَنْهُ قَالَانْتَهَيْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ أَوْ وَالَّذِي لَا إِلَهَ غَيْرُهُ أَوْ كَمَا حَلَفَ مَا مِنْ رَجُلٍ تَكُونُ لَهُ إِبِلٌ أَوْ بَقَرٌ أَوْ غَنَمٌ لَا يُؤَدِّي حَقَّهَا إِلَّا أُتِيَ بِهَا يَوْمَ الْقِيَامَةِ أَعْظَمَ مَا تَكُونُ وَأَسْمَنَهُ تَطَؤُهُ بِأَخْفَافِهَا وَتَنْطَحُهُ بِقُرُونِهَا كُلَّمَا جَازَتْ أُخْرَاهَا رُدَّتْ عَلَيْهِ أُولَاهَا حَتَّى يُقْضَى بَيْنَ النَّاسِرَوَاهُ بُكَيْرٌ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh bin Ghiyats] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] dari [Al Ma'rur bin Suwaid] dari [Abu Dzar radliallahu 'anhu] berkata,: \"Aku sampai didekat Nabi Shallallahu'alaihiwasallam ketika Beliau sedang bersumpah: \"Demi Dzat yang jiwaku berada di tanganNya atau demi Dzat yang tidakada ilah selain Dia, atau sebagaimana Beliau bersumpah, tidak ada seorangpun yang memiliki unta atau sapi atau kambing lalu dia tidak mengeluarkan haqnya (zakat) melainkanhewan-hewan itu akan diatangkan kepadanya pada hari qiyamat dalam rupa yang paling besar dan paling gemuk lalu hewan itu akan menginjak-injaknya dengan kakinya dan menyeruduknya dengan tanduknya. Setiap kali hewan lain itu selesai maka hewan yang pertama akan kembali melakukan seperti itu hingga datang keputusan untuk manusia\". Dan diriwayatkan pula oleh [Bukair] dari [Abu Shalih] dari [Abu Hurairah radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam."},"1368":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُكَانَ أَبُو طَلْحَةَ أَكْثَرَ الْأَنْصَارِ بِالْمَدِينَةِ مَالًا مِنْ نَخْلٍ وَكَانَ أَحَبُّ أَمْوَالِهِ إِلَيْهِ بَيْرُحَاءَ وَكَانَتْ مُسْتَقْبِلَةَ الْمَسْجِدِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْخُلُهَا وَيَشْرَبُ مِنْ مَاءٍ فِيهَا طَيِّبٍ قَالَ أَنَسٌ فَلَمَّا أُنْزِلَتْ هَذِهِ الْآيَةُ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }قَامَ أَبُو طَلْحَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَقُولُ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }وَإِنَّ أَحَبَّ أَمْوَالِي إِلَيَّ بَيْرُحَاءَ وَإِنَّهَا صَدَقَةٌ لِلَّهِ أَرْجُو بِرَّهَا وَذُخْرَهَا عِنْدَ اللَّهِ فَضَعْهَا يَا رَسُولَ اللَّهِ حَيْثُ أَرَاكَ اللَّهُ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَخٍ ذَلِكَ مَالٌ رَابِحٌ ذَلِكَ مَالٌ رَابِحٌ وَقَدْ سَمِعْتُ مَا قُلْتَ وَإِنِّي أَرَى أَنْ تَجْعَلَهَا فِي الْأَقْرَبِينَ فَقَالَ أَبُو طَلْحَةَ أَفْعَلُ يَا رَسُولَ اللَّهِ فَقَسَمَهَا أَبُو طَلْحَةَ فِي أَقَارِبِهِ وَبَنِي عَمِّهِتَابَعَهُ رَوْحٌ وَقَالَ يَحْيَى بْنُ يَحْيَى وَإِسْمَاعِيلُ عَنْ مَالِكٍ رَايِحٌ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ishaq bin 'Abdullah bin Abu Thalhah] bahwa dia mendengar [Anas bin Malik radliallahu 'anhu] berkata; Abu Thalhah adalah orang yang paling banyak hartanya dari kalangan Anshar di kota Madinah berupa kebun pohon kurma dan harta benda yang paling dicintainya adalah Bairuha' (sumur yang ada di kebun itu) yang menghadap ke masjid dan Rasulullah Shallallahu'alaihiwasallam sering mamemasuki kebun itu dan meminum airnya yang baik tersebut. Berkata, Anas; Ketika turun firman Allah Ta'ala (QS Alu 'Imran: 92 yang artinya): \"Kamu sekali-kali tidak akan sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sehahagian harta yang kamu cintai\", Abu Thalhah mendatangi Rasulullah Shallallahu'alaihiwasallam lalu berkata; \"Wahai Rasulullah, sesungguhnya Allah Ta'ala telah berfirman: \"Kamu sekali-kali tidak akan sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sehahagian harta yang kamu cintai\", dan sesungguhnya harta yang paling aku cintai adalah Bairuha' itu dan aku menshadaqahkannya di jalan Allah dengan berharap kebaikan dan simpanan pahala di sisiNya, maka ambillah wahai Rasulullah sebagaimana petunjuk Allah kepadanu\". Dia (Anas) berkata,: \"Maka Rasulullah Shallallahu'alaihiwasallam bersabda: Wah, inilah harta yang menguntungkan, inilah harta yang menguntungkan. Sungguh aku sudah mendengar apa yang kamu niyatkan dan aku berpendapat sebaiknya kamu shadaqahkan buat kerabatmu\". Maka Abu Thalhah berkata,: \"Aku akan laksanakan wahai Rasululloloh. Maka Abu Thalhah membagi untuk kerabatnya dan anak-anak pamannya\". Hadits ini juga dikuatkan oleh [Rauh] dan berkata, [Yaha bin Yahya] dan [Isma'il] dari [Malik]: \"Pahalanya mengalir terus\"."},"1369":{"ar":"حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ أَخْبَرَنِي زَيْدٌ هُوَ ابْنُ أَسْلَمَ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَضْحًى أَوْ فِطْرٍ إِلَى الْمُصَلَّى ثُمَّ انْصَرَفَ فَوَعَظَ النَّاسَ وَأَمَرَهُمْ بِالصَّدَقَةِ فَقَالَ أَيُّهَا النَّاسُ تَصَدَّقُوا فَمَرَّ عَلَى النِّسَاءِ فَقَالَ يَا مَعْشَرَ النِّسَاءِ تَصَدَّقْنَ فَإِنِّي رَأَيْتُكُنَّ أَكْثَرَ أَهْلِ النَّارِ فَقُلْنَ وَبِمَ ذَلِكَ يَا رَسُولَ اللَّهِ قَالَ تُكْثِرْنَ اللَّعْنَ وَتَكْفُرْنَ الْعَشِيرَ مَا رَأَيْتُ مِنْ نَاقِصَاتِ عَقْلٍ وَدِينٍ أَذْهَبَ لِلُبِّ الرَّجُلِ الْحَازِمِ مِنْ إِحْدَاكُنَّ يَا مَعْشَرَ النِّسَاءِ ثُمَّ انْصَرَفَ فَلَمَّا صَارَ إِلَى مَنْزِلِهِ جَاءَتْ زَيْنَبُ امْرَأَةُ ابْنِ مَسْعُودٍ تَسْتَأْذِنُ عَلَيْهِ فَقِيلَ يَا رَسُولَ اللَّهِ هَذِهِ زَيْنَبُ فَقَالَ أَيُّ الزَّيَانِبِ فَقِيلَ امْرَأَةُ ابْنِ مَسْعُودٍ قَالَ نَعَمْ ائْذَنُوا لَهَا فَأُذِنَ لَهَا قَالَتْ يَا نَبِيَّ اللَّهِ إِنَّكَ أَمَرْتَ الْيَوْمَ بِالصَّدَقَةِ وَكَانَ عِنْدِي حُلِيٌّ لِي فَأَرَدْتُ أَنْ أَتَصَدَّقَ بِهِ فَزَعَمَ ابْنُ مَسْعُودٍ أَنَّهُ وَوَلَدَهُ أَحَقُّ مَنْ تَصَدَّقْتُ بِهِ عَلَيْهِمْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَ ابْنُ مَسْعُودٍ زَوْجُكِ وَوَلَدُكِ أَحَقُّ مَنْ تَصَدَّقْتِ بِهِ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Ibnu Abu Maryam] telah mengabarkan kepada kami [Muhammad bin Ja'far] berkata, telah mengabarkan kepada saya [Zaid] dia adalah putra Aslam dari ['Iyadh bin 'Abdullah] dari [Abu Sa'id Al Khurdri radliallahu 'anhu]; Rasulullah Shallallahu'alaihiwasallam keluar menuju lapangan tempat shalat untuk melaksanakan shalat 'Iedul Adhha atau 'Iedul Fithri. Setelah selesai Beliau memberi nasehat kepada manusia dan memerintahkan mereka untuk menunaikan zakat seraya bersabda: \"Wahai manusia, bershadaqahlah (berzakatlah) \". Kemudian Beliau mendatangi jama'ah wanita lalu bersabda: \"Wahai kaum wanita, bershadaqahlah. Sungguh aku melihat kalian adalah yang paling banyak akan menjadi penghuni neraka\". Mereka bertanya: \"Mengapa begitu, wahai Rasulullah?\". Beliau menjawab: \"Kalian banyak melaknat dan mengingkari pemberian (suami). Tidaklah aku melihat orang yang lebih kurang akal dan agamanya melebihi seorang dari kalian, wahai para wanita\". Kemudian Beliau mengakhiri khuthbahnya lalu pergi. Sesampainya Beliau di tempat tinggalnya, datanglah Zainab, isteri Ibu Mas'ud meminta izin kepada Beliau, lalu dikatakan kepada Beliau; \"Wahai Rasulullah Shallallahu'alaihiwasallam, ini adalah Zainab\". Beliau bertanya: \"Zainab siapa?\". Dikatakan: \"Zainab isteri dari Ibnu Mas'ud\". Beliau berkata,: \"Oh ya, persilakanlah dia\". Maka dia diizinkan kemudian berkata,: \"Wahai Nabi Allah, sungguh anda hari ini sudah memerintahkan shadaqah (zakat) sedangkan aku memiliki emas yang aku berkendak menzakatkannya namun Ibnu Mas'ud mengatakan bahwa dia dan anaknya lebih berhak terhadap apa yang akan aku sedekahkan ini dibandingkan mereka (mustahiq). Maka Nabi Shallallahu'alaihiwasallam bersabda: \"Ibnu Mas'ud benar, suamimu dan anak-anakmu lebih barhak kamu berikan shadaqah dari pada mereka\"."},"1370":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ قَالَ سَمِعْتُ سُلَيْمَانَ بْنَ يَسَارٍ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ عَلَى الْمُسْلِمِ فِي فَرَسِهِ وَغُلَامِهِ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami ['Abdullah bin Dinar] berkata; Aku mendengar [Sulaiman bin Yasar] dari ['Irak bin Malik] dari [Abu Hurairah radliallahu 'anhu] berkata; Nabi Shallallahu'alaihiwasallam bersabda: \"Tidak ada kewajiban zakat bagi seorang muslim pada kuda dan budaknya\"."},"1371":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ خُثَيْمِ بْنِ عِرَاكٍ قَالَ حَدَّثَنِي أَبِي عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا وُهَيْبُ بْنُ خَالِدٍ حَدَّثَنَا خُثَيْمُ بْنُ عِرَاكِ بْنِ مَالِكٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ عَلَى الْمُسْلِمِ صَدَقَةٌ فِي عَبْدِهِ وَلَا فِي فَرَسِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Khutsaim bin 'Irak] berkata, telah menceritakan [bapakku] kepadaku dari [Abu Hurairah radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam. Dan diriwayatkan pula, telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Wuhaib bin Khalid] telah menceritakan kepada kami [Khutsaim bin 'Irak bin Malik] dari [bapaknya] dari [Abu Hurairah radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam: \"Tidak ada kewajiban zakat bagi seorang muslim pada budak dan kudanya\"."},"1372":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ حَدَّثَنَا عَطَاءُ بْنُ يَسَارٍ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُ يُحَدِّثُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَلَسَ ذَاتَ يَوْمٍ عَلَى الْمِنْبَرِ وَجَلَسْنَا حَوْلَهُ فَقَالَ إِنِّي مِمَّا أَخَافُ عَلَيْكُمْ مِنْ بَعْدِي مَا يُفْتَحُ عَلَيْكُمْ مِنْ زَهْرَةِ الدُّنْيَا وَزِينَتِهَا فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَوَيَأْتِي الْخَيْرُ بِالشَّرِّ فَسَكَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقِيلَ لَهُ مَا شَأْنُكَ تُكَلِّمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا يُكَلِّمُكَ فَرَأَيْنَا أَنَّهُ يُنْزَلُ عَلَيْهِ قَالَ فَمَسَحَ عَنْهُ الرُّحَضَاءَ فَقَالَ أَيْنَ السَّائِلُ وَكَأَنَّهُ حَمِدَهُ فَقَالَ إِنَّهُ لَا يَأْتِي الْخَيْرُ بِالشَّرِّ وَإِنَّ مِمَّا يُنْبِتُ الرَّبِيعُ يَقْتُلُ أَوْ يُلِمُّ إِلَّا آكِلَةَ الْخَضْرَاءِ أَكَلَتْ حَتَّى إِذَا امْتَدَّتْ خَاصِرَتَاهَا اسْتَقْبَلَتْ عَيْنَ الشَّمْسِ فَثَلَطَتْ وَبَالَتْ وَرَتَعَتْ وَإِنَّ هَذَا الْمَالَ خَضِرَةٌ حُلْوَةٌ فَنِعْمَ صَاحِبُ الْمُسْلِمِ مَا أَعْطَى مِنْهُ الْمِسْكِينَ وَالْيَتِيمَ وَابْنَ السَّبِيلِ أَوْ كَمَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّهُ مَنْ يَأْخُذُهُ بِغَيْرِ حَقِّهِ كَالَّذِي يَأْكُلُ وَلَا يَشْبَعُ وَيَكُونُ شَهِيدًا عَلَيْهِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadhalah] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Hilal bin Abu Maimunah] telah menceritakan kepada kami ['Atha' bin Yasar] bahwa dia mendengar [Abu Sa'id Al Khudriy radliallahu 'anhu] menceritakan bahwa Nabi Shallallahu'alaihiwasallam suatu hari duduk diatas mimbar dan kami pun duduk didekatnya lalu Beliau berkata,: \"Sesungguhnya diantara yang aku khawatirkan terjadi pada kalian sepeninggalku adalah apabila telah dibuka untuk kalian (keindahan) dunia serta perhiasannya\". Tiba-tiba ada seorang laki-laki berkata,: \"Wahai Rasulullah, apakah kebaikan dapat mendatangkan keburukan?\". Maka Nabi Shallallahu'alaihiwasallam terdiam. Dikatakan kepada orang yang bertanya tadi; \"Apa yang telah kamu lakukan, kamu mengajak Nabi Shallallahu'alaihiwasallam berbicara yang membuat Beliau tidak berbicara kepadamu\". Maka kami melihat bahwa wahyu sedang turun kepada Beliau. Abu Said berkata,: \"Beliau mengusap keringatnya yang banyak lalu berkata,: \"Mana orang yang bertanya tadi?\". Lalu nampak Beliau memuji Allah seraya bersabda: \"Kebaikan tidak akan mendatangkan keburukan. Sesungguhnya apa yang ditumbuhkan pada musim semi dapat membinasakan atau dapat mendekatkan kepada kematian kecuali seperti (ternak) pemakan dedaunan hijau yang apabila sudah kenyang dia akan memandang matahari lalu mencret kemudian kencing lalu dia kembali merumput (makan lagi). Dan sungguh harta itu seperti dedaunan hijau yang manis. Maka beruntunglah seorang muslim yang dengan hartanya dia memberi orang-orang miskin, anak yatim dan ibnu sabil (musafir yang kehabisan bekal) \". Atau seperti yang didabdakan oleh Nabi Shallallahu'alaihiwasallam: \"Dan sesungguhnya barangsiapa yang mengambil harta dunia tanpa hak ia seperti orang yang memakan namun tidak pernah kenyang dan harta itu akan menjadi saksi yang menuntutnya pada hari qiyamat\"."},"1373":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي شَقِيقٌ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ زَيْنَبَ امْرَأَةِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَ فَذَكَرْتُهُ لِإِبْرَاهِيمَ ح فَحَدَّثَنِي إِبْرَاهِيمُ عَنْ أَبِي عُبَيْدَةَ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ زَيْنَبَ امْرَأَةِ عَبْدِ اللَّهِ بِمِثْلِهِ سَوَاءً قَالَتْكُنْتُ فِي الْمَسْجِدِ فَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ تَصَدَّقْنَ وَلَوْ مِنْ حُلِيِّكُنَّ وَكَانَتْ زَيْنَبُ تُنْفِقُ عَلَى عَبْدِ اللَّهِ وَأَيْتَامٍ فِي حَجْرِهَا قَالَ فَقَالَتْ لِعَبْدِ اللَّهِ سَلْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَجْزِي عَنِّي أَنْ أُنْفِقَ عَلَيْكَ وَعَلَى أَيْتَامٍ فِي حَجْرِي مِنْ الصَّدَقَةِ فَقَالَ سَلِي أَنْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدْتُ امْرَأَةً مِنْ الْأَنْصَارِ عَلَى الْبَابِ حَاجَتُهَا مِثْلُ حَاجَتِي فَمَرَّ عَلَيْنَا بِلَالٌ فَقُلْنَا سَلْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَجْزِي عَنِّي أَنْ أُنْفِقَ عَلَى زَوْجِي وَأَيْتَامٍ لِي فِي حَجْرِي وَقُلْنَا لَا تُخْبِرْ بِنَا فَدَخَلَ فَسَأَلَهُ فَقَالَ مَنْ هُمَا قَالَ زَيْنَبُ قَالَ أَيُّ الزَّيَانِبِ قَالَ امْرَأَةُ عَبْدِ اللَّهِ قَالَ نَعَمْ لَهَا أَجْرَانِ أَجْرُ الْقَرَابَةِ وَأَجْرُ الصَّدَقَةِ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada saya [Syaqiq] dari ['Amru bin Al Harits] dari [Zainab] isteri 'Abdullah radliallahu 'anhuma berkata,, lalu dia menceritakannya kepada Ibrahim. Dan diriwayatkan pula, telah menceritakan kepada saya [Ibrahim] dari [Abu 'Ubaidah] dari ['Amru bin Al Harits] dari [Zainab] isteri 'Abdullah radliallahu 'anhua sama seperti ini, berkata,: \"Aku pernah berada di masjid lalu aku melihat Nabi Shallallahu'alaihiwasallam. Kemudian Beliau bersabda: \"Bershadaqahlah kalian walau dari perhiasan kalian\". Pada saat itu Zainab berinfaq untuk 'Abdullah dan anak-anak yatim di rumahnya. Dia ('Amru bin Al Harits) berkata,:; Zainab berkata, kepada 'Abdullah: \"Tanyakanlah kepada Rasulullah Shallallahu'alaihiwasallam apakah aku akan mendapat pahala bila aku menginfaqkan shadaqah (zakat) ku kepadamu dan kepada anak-anak yatim dalam rumahku\". Maka 'Abdullah berkata,: \"Tanyakanlah sendiri kepada Rasulullah Shallallahu'alaihiwasallam \". Maka aku berangkat untuk menemui Nabi Shallallahu'alaihiwasallam dan aku mendapatkan seorang wanita Anshar di depan pintu yang sedang menyampaikan keperluannya seperti keperluanku. Kemudian Bilal lewat di hadapan kami maka kami berkata: \"Tolong tanyakan kepada Nabi Shallallahu'alaihiwasallam, apakah aku akan mendapat pahala bila aku meninfaqkan shadaqah (zakat) ku kepada suamiku dan kepada anak-anak yatim yang aku tanggung dalam rumahku?\". Dan kami tambahkan agar dia (Bilal) tidak menceritakan siapa kami. Maka Bilal masuk lalu bertanya kepada Beliau. Lalu Beliau bertanya: \"Siapa kedua wanita itu?\". Bilal berkata,: \"Zainab\". Beliau bertanya lagi: \"Zainab yang mana?\". Dikatakan: \"Zainab isteri 'Abdullah\". Maka Beliau bersabda: \"Ya benar, baginya dua pahala, yaitu pahala (menyambung) kekerabatan dan pahala zakatnya\"."},"1374":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ أَلِيَ أَجْرٌ أَنْ أُنْفِقَ عَلَى بَنِي أَبِي سَلَمَةَ إِنَّمَا هُمْ بَنِيَّ فَقَالَ أَنْفِقِي عَلَيْهِمْ فَلَكِ أَجْرُ مَا أَنْفَقْتِ عَلَيْهِمْ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami ['Abdah] dari [Hisyam] dari [bapaknya] dari [Zainab binti Ummu Salalah] dari [Ummu Salamah] berkata; Aku berkata,: \"Wahai Rasulullah, apakah bagiku pahala bila aku menginfaqkan harta untuk anak-anak Abu Salamah padahal mereka itu anak-anakku?\". Maka Beliau bersabda: \"Berinfaqlah untuk mereka dan kamu akan mendapatkan pahala dari apa yang kamu infaqkan buat mereka\"."},"1375":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّدَقَةِ فَقِيلَ مَنَعَ ابْنُ جَمِيلٍ وَخَالِدُ بْنُ الْوَلِيدِ وَعَبَّاسُ بْنُ عَبْدِ الْمُطَّلِبِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَنْقِمُ ابْنُ جَمِيلٍ إِلَّا أَنَّهُ كَانَ فَقِيرًا فَأَغْنَاهُ اللَّهُ وَرَسُولُهُ وَأَمَّا خَالِدٌ فَإِنَّكُمْ تَظْلِمُونَ خَالِدًا قَدْ احْتَبَسَ أَدْرَاعَهُ وَأَعْتُدَهُ فِي سَبِيلِ اللَّهِ وَأَمَّا الْعَبَّاسُ بْنُ عَبْدِ الْمُطَّلِبِ فَعَمُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهِيَ عَلَيْهِ صَدَقَةٌ وَمِثْلُهَا مَعَهَاتَابَعَهُ ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ وَقَالَ ابْنُ إِسْحَاقَ عَنْ أَبِي الزِّنَادِ هِيَ عَلَيْهِ وَمِثْلُهَا مَعَهَا وَقَالَ ابْنُ جُرَيْجٍ حُدِّثْتُ عَنِ الْأَعْرَجِ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah Shallallahu'alaihiwasallam memerintahkan untuk menunaikan shadaqah (zakat). Lalu dikatakan kepada Beliau bahwa Ibnu Jamil, Khalid bin Al Walid dan 'Abbas bin 'Abdul Muthalib tidak mau mengeluarkan zakat. Maka Nabi Shallallahu'alaihiwasallam bersabda: \"Apa yang bisa mengingkari Ibnul jamil tidak mengeluarkan zakatnya sebab dahulunya dia faqir namun kemudian Allah dan RasulNya menjadikannya kaya? Adapun Khalid, sungguh kalian telah menzhalimi Khalid, padahal dia telah menghabiskan baju-baju besi dan peralatan perangnya untuk berjuang di jalan Allah. Adapun 'Abbas bin 'Abdul Muthalib dia adalah paman Rasulullah Shallallahu'alaihiwasallam, namun demikian dia tetap wajib berzakat dan juga kewajiban lain serupa zakat (sebagai kemuliaan) \". Dan hadits ini diperkuat oleh [Ibnu Abu Az Zinad] dari [Bapaknya], dan [Ibnu Ishaq] berkata dari [Abu Az Zinad]; \"Baginya tetap wajib berzakat dan juga kewajiban lain serupa zakat\", dan [Ibnu Juraij] berkata; \"Telah diriwayatkan kepadaku dari Al A'raj dengan hadits yang serupa."},"1376":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُإِنَّ نَاسًا مِنْ الْأَنْصَارِ سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَاهُمْ ثُمَّ سَأَلُوهُ فَأَعْطَاهُمْ ثُمَّ سَأَلُوهُ فَأَعْطَاهُمْ حَتَّى نَفِدَ مَا عِنْدَهُ فَقَالَ مَا يَكُونُ عِنْدِي مِنْ خَيْرٍ فَلَنْ أَدَّخِرَهُ عَنْكُمْ وَمَنْ يَسْتَعْفِفْ يُعِفَّهُ اللَّهُ وَمَنْ يَسْتَغْنِ يُغْنِهِ اللَّهُ وَمَنْ يَتَصَبَّرْ يُصَبِّرْهُ اللَّهُ وَمَا أُعْطِيَ أَحَدٌ عَطَاءً خَيْرًا وَأَوْسَعَ مِنْ الصَّبْرِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari ['Atha' bin Yazid Al Laitsiy] dari [Abu Sa'id Al Khudriy radliallahu 'anhu] bahwa ada beberapa orang dari kalangan Anshar meminta (pemberian shodaqah) kepada Rasulullah Shallallahu'alaihiwasallam, maka Beliau memberi. Kemudian mereka meminta kembali, lalu Beliau memberi. Kemudian mereka meminta kembali lalu Beliau memberi lagi hingga habis apa yang ada pada Beliau. Kemudian Beliau bersabda: \"Apa-apa yang ada padaku dari kebaikan (harta) sekali-kali tidaklah aku akan meyembunyikannya dari kalian semua. Namun barangsiapa yang menahan (menjaga diri dari meminta-minta), maka Allah akan menjaganya dan barangsiapa yang meminta kecukupan maka Allah akan mencukupkannya dan barangsiapa yang mensabar-sabarkan dirinya maka Allah akan memberinya kesabaran. Dan tidak ada suatu pemberian yang diberikan kepada seseorang yang lebih baik dan lebih luas daripada (diberikan) kesabaran\". "},"1377":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَأَنْ يَأْخُذَ أَحَدُكُمْ حَبْلَهُ فَيَحْتَطِبَ عَلَى ظَهْرِهِ خَيْرٌ لَهُ مِنْ أَنْ يَأْتِيَ رَجُلًا فَيَسْأَلَهُ أَعْطَاهُ أَوْ مَنَعَهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah Shallallahu'alaihiwasallam bersabda: \"Demi Dzat yang jiwaku berada di tanganNya, sungguh seorang dari kalian yang mengambil talinya lalu dia mencari kayu bakar dan dibawa dengan punggungnya lebih baik baginya daripada dia mendatangi seseorang lalu meminta kepadanya, baik orang itu memberi atau menolak\"."},"1378":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ الزُّبَيْرِ بْنِ الْعَوَّامِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَأَنْ يَأْخُذَ أَحَدُكُمْ حَبْلَهُ فَيَأْتِيَ بِحُزْمَةِ الْحَطَبِ عَلَى ظَهْرِهِ فَيَبِيعَهَا فَيَكُفَّ اللَّهُ بِهَا وَجْهَهُ خَيْرٌ لَهُ مِنْ أَنْ يَسْأَلَ النَّاسَ أَعْطَوْهُ أَوْ مَنَعُوهُ","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Hisyam] dari [bapaknya] dari [Az Zubair bin Al 'Awam radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Demi Dzat yang jiwaku berada di tanganNya, sungguh seorang dari kalian yang mengambil talinya lalu dia mencari seikat kayu bakar dan dibawa dengan punggungnya kemudian dia menjualnya lalu Allah mencukupkannya dengan kayu itu lebih baik baginya daripada dia meminta-minta kepada manusia, baik manusia itu memberinya atau menolaknya\"."},"1379":{"ar":"و حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ وَسَعِيدِ بْنِ الْمُسَيَّبِ أَنَّ حَكِيمَ بْنَ حِزَامٍ رَضِيَ اللَّهُ عَنْهُ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ قَالَ يَا حَكِيمُ إِنَّ هَذَا الْمَالَ خَضِرَةٌ حُلْوَةٌ فَمَنْ أَخَذَهُ بِسَخَاوَةِ نَفْسٍ بُورِكَ لَهُ فِيهِ وَمَنْ أَخَذَهُ بِإِشْرَافِ نَفْسٍ لَمْ يُبَارَكْ لَهُ فِيهِ كَالَّذِي يَأْكُلُ وَلَا يَشْبَعُ الْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى قَالَ حَكِيمٌ فَقُلْتُ يَا رَسُولَ اللَّهِ وَالَّذِي بَعَثَكَ بِالْحَقِّ لَا أَرْزَأُ أَحَدًا بَعْدَكَ شَيْئًا حَتَّى أُفَارِقَ الدُّنْيَا فَكَانَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ يَدْعُو حَكِيمًا إِلَى الْعَطَاءِ فَيَأْبَى أَنْ يَقْبَلَهُ مِنْهُ ثُمَّ إِنَّ عُمَرَ رَضِيَ اللَّهُ عَنْهُ دَعَاهُ لِيُعْطِيَهُ فَأَبَى أَنْ يَقْبَلَ مِنْهُ شَيْئًا فَقَالَ عُمَرُ إِنِّي أُشْهِدُكُمْ يَا مَعْشَرَ الْمُسْلِمِينَ عَلَى حَكِيمٍ أَنِّي أَعْرِضُ عَلَيْهِ حَقَّهُ مِنْ هَذَا الْفَيْءِ فَيَأْبَى أَنْ يَأْخُذَهُ فَلَمْ يَرْزَأْ حَكِيمٌ أَحَدًا مِنْ النَّاسِ بَعْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى تُوُفِّيَ","id":"Dan telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhriy] dari ['Urwah bin Az Zubair] dan [Sa'id bin Al Musayyab] bahwa [Hakim bin Hizam radliallahu 'anhu] berkata,: \"Aku pernah meminta sesuatu kepada Rasulullah Shallallahu'alaihiwasallam lalu Beliau memberiku. Kemudian aku meminta lagi, maka Beliau pun memberiku kembali. Kemudian aku meminta lagi, maka Beliu pun masih memberiku lag seraya Beliau bersabda: \"Wahai Hakim, sesungguhnya harta itu hijau lagi manis, maka barangsiapa yang mencarinya untuk kedermawanan dirinya maka harta itu akan memberkahinya. Namun barangsiapa yang mencarinya untuk keserakahan maka harta itu tidak akan memberkahinya, seperti orang yang makan namun tidak kenyang. Tangan yang di atas lebih baik daripada tangan yang di bawah\". Hakim berkata; \"Lalu aku berkata, (kepada Beliau); \"Wahai Rasulullah, demi Dzat yang telah mengutusmu dengan benar, aku tidak akan mengurangi hak seorangpun (yang meminta) setelah engkau hingga aku meninggalkan dunia ini\". Suatu kali Abu Bakar pernah memanggil Hakim untuk diberikan sesuatu agar dia datang dan menerima pemberiannya. Kemudian 'Umar radliallahu 'anhu juga pernah memanggil Hakim untuk memberikan sesuatu namun Hakim tidak memenuhinya. Maka 'Umar radliallahu 'anhu berkata,: \"Aku bersaksi kepada kalian, wahai kaum Muslimin, tentang Hakim. Sungguh aku pernah menawarkan kepadanya haknya dari harta fa'iy (harta musuh tanpa peperangan) ini agar dia datang dan mengambilnya. Sungguh Hakim tidak pernah mengurangi hak seorangpun setelah Rasulullah Shallallahu'alaihiwasallam hingga dia wafat\"."},"1380":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَ سَمِعْتُ عُمَرَ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْطِينِي الْعَطَاءَ فَأَقُولُ أَعْطِهِ مَنْ هُوَ أَفْقَرُ إِلَيْهِ مِنِّي فَقَالَ خُذْهُ إِذَا جَاءَكَ مِنْ هَذَا الْمَالِ شَيْءٌ وَأَنْتَ غَيْرُ مُشْرِفٍ وَلَا سَائِلٍ فَخُذْهُ وَمَا لَا فَلَا تُتْبِعْهُ نَفْسَكَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Az Zuhriy] dari [Salim] bahwa ['Abdullah bin 'Umar radliallahu 'anhuma] berkata; Aku mendengar ['Umar] berkata,: \"Rasulullah Shallallahu'alaihiwasallam pernah memberiku suatu pemberian lalu aku berkata kepada Beliau: \"Berikanlah kepada orang yang lebih faqir dariku\". Maka Beliau bersabda: \"Ambillah. Jika telah datang kepadamu dari harta ini sedangkan kamu bukan orang yang akan menghambur-hamburkannya dan tidak pula meminta-mintanya, maka ambillah. Selain dari itu maka janganlah kamu menuruti nafsumu\"."},"1381":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ قَالَ سَمِعْتُ حَمْزَةَ بْنَ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَزَالُ الرَّجُلُ يَسْأَلُ النَّاسَ حَتَّى يَأْتِيَ يَوْمَ الْقِيَامَةِ لَيْسَ فِي وَجْهِهِ مُزْعَةُ لَحْمٍ وَقَالَ إِنَّ الشَّمْسَ تَدْنُو يَوْمَ الْقِيَامَةِ حَتَّى يَبْلُغَ الْعَرَقُ نِصْفَ الْأُذُنِ فَبَيْنَا هُمْ كَذَلِكَ اسْتَغَاثُوا بِآدَمَ ثُمَّ بِمُوسَى ثُمَّ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَزَادَ عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي ابْنُ أَبِي جَعْفَرٍ فَيَشْفَعُ لِيُقْضَى بَيْنَ الْخَلْقِ فَيَمْشِي حَتَّى يَأْخُذَ بِحَلْقَةِ الْبَابِ فَيَوْمَئِذٍ يَبْعَثُهُ اللَّهُ مَقَامًا مَحْمُودًا يَحْمَدُهُ أَهْلُ الْجَمْعِ كُلُّهُمْ وَقَالَ مُعَلًّى حَدَّثَنَا وُهَيْبٌ عَنْ النُّعْمَانِ بْنِ رَاشِدٍ عَنْ عَبْدِ اللَّهِ بْنِ مُسْلِمٍ أَخِي الزُّهْرِيِّ عَنْ حَمْزَةَ سَمِعَ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْأَلَةِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Ubaidullah bin Abu Ja'far] berkata; Aku mendengar [Hamzah bin 'Abdullah bin 'Umar] berkata; Aku mendengar: ['Abdullah bin 'Umar radliallahu 'anhu] berkata; Nabi Shallallahu'alaihiwasallam bersabda: \"Senantiasa ada seorang yang suka meminta-minta kepada orang lain hingga pada hari qiyamat dia datang dalam keadaan wajahnya terpotong (bagian) dagingnya\". Dan Beliau juga bersabda: \"Matahari akan didekatkan pada hari qiyamat hingga keringat akan mencapai ketinggian setengah telinga. Karena kondisi mereka seperti itu, maka orang-orang memohon bantuan (do'a) kepada nabi Adam, Musa, kemudian Muhammad Shallallahu'alaihiwasallam\". ['Abdullah bin Shalih] menambahkan telah menceritakan kepada saya [Al Laits] telah menceritakan kepada saya [Ibnu Abu Ja'far]: \"Maka Beliau memberi syafa'at untuk memutuskan perkara diantara manusia hingga akhirnya Beliau mengambil tali pintu (surga). Dan pada hari itulah Allah menempatkan Beliau pada kedudukan yang terpuji yang dipuji oleh seluruh makhluq yang berkumpul\". Dan berkata, [Mu'allaa] telah menceritakan kepada kami [Wuhaib] dari [An-Nu'man bin Rasyid] dari ['Abdullah bin Muslim saudara dari Az Zuhriy] dari [Hamzah] bahwa dia mendengar [Ibnu 'Umar radliallahu 'anhuma] dari Nabi Shallallahu'alaihiwasallam tentang masalah ini\"."},"1382":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي مُحَمَّدُ بْنُ زِيَادٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ الْمِسْكِينُ الَّذِي تَرُدُّهُ الْأُكْلَةَ وَالْأُكْلَتَانِ وَلَكِنْ الْمِسْكِينُ الَّذِي لَيْسَ لَهُ غِنًى وَيَسْتَحْيِي أَوْ لَا يَسْأَلُ النَّاسَ إِلْحَافًا","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepada saya [Muhammad bin Ziad] berkata; Aku mendengar [Abu Hurairah radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam: \"Bukanlah disebut miskin orang yang bisa diatasi dengan satu atau dua suap makanan. Akan tetapi yang disebut miskin adalah orang yang tidak memiliki kecukupan namun dia menahan diri (malu) atau orang yang tidak meminta-minta secara mendesak\"."},"1383":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عُلَيَّةَ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ ابْنِ أَشْوَعَ عَنْ الشَّعْبِيِّ حَدَّثَنِي كَاتِبُ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَ كَتَبَ مُعَاوِيَةُ إِلَى الْمُغِيرَةِ بْنِ شُعْبَةَأَنْ اكْتُبْ إِلَيَّ بِشَيْءٍ سَمِعْتَهُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَتَبَ إِلَيْهِ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ كَرِهَ لَكُمْ ثَلَاثًا قِيلَ وَقَالَ وَإِضَاعَةَ الْمَالِ وَكَثْرَةَ السُّؤَالِ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] telah menceritakan kepada kami [Khalid Al Hadzdza'] dari [Ibnu Asywa'] dari [Asy-Sya'biy] telah menceritakan kepada saya [Penulis Al Mughirah bin Syu'bah] berkata; Mu'awiyah menulis surat kepada [Al Mughirah bin Syu'bah] (yang isinya); \"Tuliskanlah untuk aku sesuatu yang kamu dengar dari Nabi Shallallahu'alaihiwasallam \". Maka dia menulis untuknya: \"Aku mendengar Nabi Shallallahu'alaihiwasallam bersabda: \" Allah membenci untuk kalian tiga hal: \"Orang yang menyampaikan setiap hal yang didengarnya, menyia-nyiakan harta dan banyak bertanya\"."},"1384":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ غُرَيْرٍ الزُّهْرِيُّ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ عَنْ أَبِيهِ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَامِرُ بْنُ سَعْدٍ عَنْ أَبِيهِ قَالَأَعْطَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَهْطًا وَأَنَا جَالِسٌ فِيهِمْ قَالَ فَتَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ رَجُلًا لَمْ يُعْطِهِ وَهُوَ أَعْجَبُهُمْ إِلَيَّ فَقُمْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَارَرْتُهُ فَقُلْتُ مَا لَكَ عَنْ فُلَانٍ وَاللَّهِ إِنِّي لَأَرَاهُ مُؤْمِنًا قَالَ أَوْ مُسْلِمًا قَالَ فَسَكَتُّ قَلِيلًا ثُمَّ غَلَبَنِي مَا أَعْلَمُ فِيهِ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا لَكَ عَنْ فُلَانٍ وَاللَّهِ إِنِّي لَأَرَاهُ مُؤْمِنًا قَالَ أَوْ مُسْلِمًا قَالَ فَسَكَتُّ قَلِيلًا ثُمَّ غَلَبَنِي مَا أَعْلَمُ فِيهِ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا لَكَ عَنْ فُلَانٍ وَاللَّهِ إِنِّي لَأَرَاهُ مُؤْمِنًا قَالَ أَوْ مُسْلِمًا يَعْنِي فَقَالَ إِنِّي لَأُعْطِي الرَّجُلَ وَغَيْرُهُ أَحَبُّ إِلَيَّ مِنْهُ خَشْيَةَ أَنْ يُكَبَّ فِي النَّارِ عَلَى وَجْهِهِوَعَنْ أَبِيهِ عَنْ صَالِحٍ عَنْ إِسْمَاعِيلَ بْنِ مُحَمَّدٍ أَنَّهُ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ بِهَذَا فَقَالَ فِي حَدِيثِهِ فَضَرَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ فَجَمَعَ بَيْنَ عُنُقِي وَكَتِفِي ثُمَّ قَالَ أَقْبِلْ أَيْ سَعْدُ إِنِّي لَأُعْطِي الرَّجُلَ قَالَ أَبُو عَبْد اللَّهِ{ فَكُبْكِبُوا }قُلِبُوا فَكُبُّوا{ مُكِبًّا }أَكَبَّ الرَّجُلُ إِذَا كَانَ فِعْلُهُ غَيْرَ وَاقِعٍ عَلَى أَحَدٍ فَإِذَا وَقَعَ الْفِعْلُ قُلْتَ كَبَّهُ اللَّهُ لِوَجْهِهِ وَكَبَبْتُهُ أَنَا","id":"Telah menceritakan kepada kami [Muhammad bin Ghurair Az Zuhri] telah menceritakan kepada kami [Ya'qub bin Ibrahim] dari [bapaknya] dari [Shalih bin Kaisan] dari [Ibnu Syihab] berkata, telah mengabarkan kepada saya ['Amir bin Sa'ad] dari [bapaknya] berkata; \"Rasulullah Shallallahu'alaihiwasallam memberikan suatu harta dari shadaqah sedangkan saat itu aku sedang duduk di tengah-tengah mereka. Saat itu Rasulullah Shallallahu'alaihiwasallam membiarkan dan tidak memberi seorang pun dari mereka, padahal orang itu adalah yang paling menakjubkan aku diantara mereka yang hadir. Maka aku menemui Rasulullah Shallallahu'alaihiwasallam dan aku mendekati beliau seraya aku bertanya: \"Wahai Rasulullah Shallallahu'alaihiwasallam, bagaimana dengan si fulan?. Demi Allah sungguh aku memandangnya dia sebagai seorang mu'min. Nabi Shallallahu'alaihiwasallam membalas: \"atau dia muslim?\". Kemudian aku terdiam sejenak lalu aku terdorang untuk lebih mengetahui apa yang dimaksud Beliau Shallallahu'alaihiwasallam, maka aku ulangi ucapanku: \"Wahai Rasululloh Shallallahu'alaihiwasallam bagaimana dengan si fulan?\". Demi Allah, sungguh aku memandangnya sebagai seorang mu'min. Nabi Shallallahu'alaihiwasallam membalas: atau dia muslim? Aku masih terdiam sejenak lalu aku terdorang lagi untuk lebih memastikan apa yang dimaksudnya hingga aku ulangi lagi pertanyaanku: \"Wahai Rasululloh Shallallahu'alaihiwasallam bagaimana dengan si fulan?\". Demi Allah, sungguh aku memandangnya sebagai seorang mu'min. Lalu Nabi Shallallahu'alaihiwasallam menjelaskan: \"Sungguh aku memberikan kepada seseorang atau selain dia lebih aku sukai dari pada memberi kepada dia karena aku takut kalau dia akan dicampakkan mukanya ke neraka\". Dan dari [bapaknya] dari [Shalih] dari [Isma'il bin Muhammad] bahwa dari berkata; Aku mendengar [bapakku] menceritakan sepereti ini yang dia ceritakan dalam hadits yang diceritakannya: Maka Rasulullah Shallallahu'alaihiwasallam memukulkan kedua tangannya lalu mengumpulkannya diantara leher dan pundaknya kemudian bersabda: \"Dengarlah Sa'ad, sungguh aku memberikan kepada seseorang ….\". Berkata, Abu 'Abdullah Al Bukhariy: (QS. Asy-Syu'ara ayat 94) artinya: \"Dibalik (wajah mereka) lalu dibenamkan\". Sedangkan (Al Mulk ayat 22) artinya: \"Seseorang dikatakan terjungkal bila perbuatannya tidak realistis dan jika dia benar berbuat kamu akan mengatakannya Allah menjungkalkan wajah orang itu begitu juga aku\"."},"1385":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ الْمِسْكِينُ الَّذِي يَطُوفُ عَلَى النَّاسِ تَرُدُّهُ اللُّقْمَةُ وَاللُّقْمَتَانِ وَالتَّمْرَةُ وَالتَّمْرَتَانِ وَلَكِنْ الْمِسْكِينُ الَّذِي لَا يَجِدُ غِنًى يُغْنِيهِ وَلَا يُفْطَنُ بِهِ فَيُتَصَدَّقُ عَلَيْهِ وَلَا يَقُومُ فَيَسْأَلُ النَّاسَ","id":"Telah menceritakan kepada kami [Isma'il bin 'Abdullah] berkata, telah menceritakan kepada saya [Malik] dari [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah Shallallahu'alaihiwasallam bersabda: \"Bukanlah disebut miskin orang berkeliling meminta-minta kepada manusia dan bisa diatasi dengan satu atau dua suap makanan atau satu dua butir kurma. Akan tetapi yang disebut miskin adalah orang yang tidak mendapatkan seseorang yang bisa memenuhi kecukupannya, atau yang kondisinya tidak diketahui orang sehingga siapa tahu ada yang memberinya shedaqah atau orang yang tidak meminta-minta kepada manusia\"."},"1386":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَأَنْ يَأْخُذَ أَحَدُكُمْ حَبْلَهُ ثُمَّ يَغْدُوَ أَحْسِبُهُ قَالَ إِلَى الْجَبَلِ فَيَحْتَطِبَ فَيَبِيعَ فَيَأْكُلَ وَيَتَصَدَّقَ خَيْرٌ لَهُ مِنْ أَنْ يَسْأَلَ النَّاسَقَالَ أَبُو عَبْد اللَّهِ صَالِحُ بْنُ كَيْسَانَ أَكْبَرُ مِنْ الزُّهْرِيِّ وَهُوَ قَدْ أَدْرَكَ ابْنَ عُمَرَ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh bin Ghiats] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Abu Shalih] dari [Abu Hurairah radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Sungguh seorang dari kalian yang mengambil talinya lalu pergi. Kata Beliau; ke gunung lalu dia mencari kayu bakar kemudian dia menjualnya lalu dari dia dapat makan dan bershadaqah lebih baik baginya daripada meminta manusia\". Berkata, Abu 'Abdullah Al Bukhariy: Shalih bin Kaisan lebih tua dari pada Az Zuhriy dan dia semasa hidupnya bertemu dengan Ibnu'Umar radliallahu 'anhuma."},"1387":{"ar":"حَدَّثَنَا سَهْلُ بْنُ بَكَّارٍ حَدَّثَنَا وُهَيْبٌ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ عَبَّاسٍ السَّاعِدِيِّ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ قَالَغَزَوْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزْوَةَ تَبُوكَ فَلَمَّا جَاءَ وَادِيَ الْقُرَى إِذَا امْرَأَةٌ فِي حَدِيقَةٍ لَهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ اخْرُصُوا وَخَرَصَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشَرَةَ أَوْسُقٍ فَقَالَ لَهَا أَحْصِي مَا يَخْرُجُ مِنْهَا فَلَمَّا أَتَيْنَا تَبُوكَ قَالَ أَمَا إِنَّهَا سَتَهُبُّ اللَّيْلَةَ رِيحٌ شَدِيدَةٌ فَلَا يَقُومَنَّ أَحَدٌ وَمَنْ كَانَ مَعَهُ بَعِيرٌ فَلْيَعْقِلْهُ فَعَقَلْنَاهَا وَهَبَّتْ رِيحٌ شَدِيدَةٌ فَقَامَ رَجُلٌ فَأَلْقَتْهُ بِجَبَلِ طَيِّءٍ وَأَهْدَى مَلِكُ أَيْلَةَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَغْلَةً بَيْضَاءَ وَكَسَاهُ بُرْدًا وَكَتَبَ لَهُ بِبَحْرِهِمْ فَلَمَّا أَتَى وَادِيَ الْقُرَى قَالَ لِلْمَرْأَةِ كَمْ جَاءَ حَدِيقَتُكِ قَالَتْ عَشَرَةَ أَوْسُقٍ خَرْصَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي مُتَعَجِّلٌ إِلَى الْمَدِينَةِ فَمَنْ أَرَادَ مِنْكُمْ أَنْ يَتَعَجَّلَ مَعِي فَلْيَتَعَجَّلْ فَلَمَّا قَالَ ابْنُ بَكَّارٍ كَلِمَةً مَعْنَاهَا أَشْرَفَ عَلَى الْمَدِينَةِ قَالَ هَذِهِ طَابَةُ فَلَمَّا رَأَى أُحُدًا قَالَ هَذَا جُبَيْلٌ يُحِبُّنَا وَنُحِبُّهُ أَلَا أُخْبِرُكُمْ بِخَيْرِ دُورِ الْأَنْصَارِ قَالُوا بَلَى قَالَ دُورُ بَنِي النَّجَّارِ ثُمَّ دُورُ بَنِي عَبْدِ الْأَشْهَلِ ثُمَّ دُورُ بَنِي سَاعِدَةَ أَوْ دُورُ بَنِي الْحَارِثِ بْنِ الْخَزْرَجِ وَفِي كُلِّ دُورِ الْأَنْصَارِ يَعْنِي خَيْرًاوَقَالَ سُلَيْمَانُ بْنُ بِلَالٍ حَدَّثَنِي عَمْرٌو ثُمَّ دَارُ بَنِي الْحَارِثِ ثُمَّ بَنِي سَاعِدَةَ وَقَالَ سُلَيْمَانُ عَنْ سَعْدِ بْنِ سَعِيدٍ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ عَبَّاسٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُحُدٌ جَبَلٌ يُحِبُّنَا وَنُحِبُّهُ قَالَ أَبُو عَبْد اللَّهِ كُلُّ بُسْتَانٍ عَلَيْهِ حَائِطٌ فَهُوَ حَدِيقَةٌ وَمَا لَمْ يَكُنْ عَلَيْهِ حَائِطٌ لَمْ يُقَلْ حَدِيقَةٌ","id":"Telah menceritakan kepada kami [Sahal bin Bakkar] telah menceritakan kepada kami [Wuhaib] dari ['Amru bin Yahya] dari ['Abbas As Sa'adiy] dari [Abu Humaid As Sa'adiy] berkata; Kami mengikuti perang Tabuk bersama Nabi shallallahu 'alaihi wasallam. Ketika sampai di lembah perkampungan suatu kaum, disana ada seorang wanita yang sedang berada di kebunnya. Maka Nabi shallallahu 'alaihi wasallam berkata, kepada para sahabatnya: \"Taksirlah buah pohon kurma ini?\". Maka Rasulullah shallallahu 'alaihi wasallam menaksir pohon kurma itu sekitar sepuluh wasaq. Lalu Beliau berkata, kepada wanita itu: \"Hitunglah berapa kira-kira yang harus kamu keluarkan zakat dari kebun kurmamu itu\". Ketika kami sampai di Tabuk, Beliau bersabda: \"Malam ini akan berhembus angin yang sangat kencang. Oleh karena itu jangan ada yang keluar seorangpun dari kalian yang berdiri dan bagi yang membawa unta agar mengikatnya\". Kamipun mengikat unta-unta kami dan kemudian angin berhembus. Tiba-tiba ada seseorang berdiri hingga angin menerbangkanya ke gunung Thoy'i. Kemudian raja negeri Ailah menghadiahkan seekor baghol putih kepada Nabi shallallahu 'alaihi wasallam dan memberi Beliau pakaian burdah (pakaian selimut untuk melindungi Beliau dari udara dingin) dan Beliau menulis surat untuknya di negeri mereka. Ketika Beliau kembali ke perkampungan kaum, Beliau berkata, kepada wanita tadi: \"Berapa banyak kurma kebunmu?\". Wanita itu menjawab: \"Sepuluh wasaq sesuai taksiran Rasulullah shallallahu 'alaihi wasallam. Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Aku ingin segera kembali ke Madinah. Siapa yang mau segera kembalike Madinah bersamaku, maka berkemaslah\". Ketika Ibnu Bakkar mengucapkan sesuatu kalimat yang maknanya memuji Madinah, Beliau berkata: \"Ini adalah Thabah\" (sebutan untuk kota Madinah). Ketika melihat gunung Uhud, Beliau berkata: \"Ini adalah sebuah gunung yang kita mencintainya dan diapun mencintai kita. Maukah kalian aku beritahu tentang rumah orang Anshar yang paling baik?\". Mereka menjawab: \"Mau\". Maka Beliau berkata: \"Rumah Bani An-Najjar, kemudian Bani 'Abdul Ashal kemudian Bani Sa'adah atau Bani Al Harits bin Al Khazraj dan untuk setiap rumah Anshar ada kebaikan padanya\". Dan berkata [Sulaiman bin Bilal]; dari ['Amru]; \"kemudian rumah Bani Al Harits, kemudian Bani Sa'idah.\" Dan berkata [Sulaiman]; dari [Sa'ad bin Sa'id] dari ['Umarah bin Ghoziyah] dari ['Abbas] dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam berkata: \"Uhud adalah gunung yang mencintai kami dan kamipun mencintainya\". Berkata, Abu 'Abdullah Al Bukhariy: \"Setiap kebun yang ada pagar pembatasnya disebut hadiqah. Sedang yang tidak memiliki pagar pembatas tidak disebut hadiqah\"."},"1388":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ الزُّهْرِيِّ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِيمَا سَقَتْ السَّمَاءُ وَالْعُيُونُ أَوْ كَانَ عَثَرِيًّا الْعُشْرُ وَمَا سُقِيَ بِالنَّضْحِ نِصْفُ الْعُشْرِقَالَ أَبُو عَبْد اللَّهِ هَذَا تَفْسِيرُ الْأَوَّلِ لِأَنَّهُ لَمْ يُوَقِّتْ فِي الْأَوَّلِ يَعْنِي حَدِيثَ ابْنِ عُمَرَ وَفِيمَا سَقَتْ السَّمَاءُ الْعُشْرُ وَبَيَّنَ فِي هَذَا وَوَقَّتَ وَالزِّيَادَةُ مَقْبُولَةٌ وَالْمُفَسَّرُ يَقْضِي عَلَى الْمُبْهَمِ إِذَا رَوَاهُ أَهْلُ الثَّبَتِ كَمَا رَوَى الْفَضْلُ بْنُ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يُصَلِّ فِي الْكَعْبَةِوَقَالَ بِلَالٌ قَدْ صَلَّى فَأُخِذَ بِقَوْلِ بِلَالٍ وَتُرِكَ قَوْلُ الْفَضْلِ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maram] telah menceritakan kepada kami ['Abdullah bin Wahb] berkata, telah mengabarkan kepada saya [Yunus bin Zaid] dari [Az Zuhriy] dari [Salim bin 'Abdullah] dari [bapaknya radliallahu 'anhu] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Pada tanaman yang diairi dengan air hujan, mata air, atau air tanah maka zakatnya sepersepuluh, adapun yang diairi dengan menggunakan tenaga maka zakatnya seperduapuluh\". Abu Abdullah Al Bukhari berkata; \"Ini adalah tafsiran pertama karena Beliau tidak menentukannya saat waktu pertama kali, yakni hadits Ibn Umar; \"Pada setiap tanaman yang diairi dengan hujan adalah sepersepuluh\". Lalu Beliau menjelaskan hal ini; \"Dan menentukan waktu dan tambahan ini bisa diterima, dan penafsiran adalah suatu tuntutan suatu hal yang belum jelas, jika diriwayatkan oleh orang-orang terpercaya. Seperti Fadhal bin 'Abbas pernah meriwayatkan bahwa Nabi Shallallahu'alaihiwasallam tidak shalat di dalam Ka'bah namun Bilal berkata, bahwa Beliau shalat disana. Maka perkataan Bilal diambil, sedangkan perkataan Fadhl ditinggal."},"1389":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى حَدَّثَنَا مَالِكٌ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ فِيمَا أَقَلُّ مِنْ خَمْسَةِ أَوْسُقٍ صَدَقَةٌ وَلَا فِي أَقَلَّ مِنْ خَمْسَةٍ مِنْ الْإِبِلِ الذَّوْدِ صَدَقَةٌ وَلَا فِي أَقَلَّ مِنْ خَمْسِ أَوَاقٍ مِنْ الْوَرِقِ صَدَقَةٌقَالَ أَبُو عَبْد اللَّهِ هَذَا تَفْسِيرُ الْأَوَّلِ إِذَا قَالَ لَيْسَ فِيمَا دُونَ خَمْسَةِ أَوْسُقٍ صَدَقَةٌ وَيُؤْخَذُ أَبَدًا فِي الْعِلْمِ بِمَا زَادَ أَهْلُ الثَّبَتِ أَوْ بَيَّنُوا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Malik] berkata, telah menceritakan kepada saya [Muhammad bin 'Abdullah bin 'Abdurrahman bin Abu Sha'sha'ah] dari [bapaknya] dari [Abu Sa'id Al Khudriy] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Tidak ada zakat pada hasil tanaman kurang dari lima wasaq, tidak ada zakat unta yang kurang dari lima ekor dan tidak ada zakat pada harta (uang) kurang dari lima waaq \". Berkata, Abu 'Abdullah Al Bukhari: \"Ini tafsiran awal ketika Beliau bersabda: \"\"Tidak ada zakat pada hasil tanaman kurang dari lima wasaq\". Kemudian yang dijadikan pegangan dalam masalah ilmu selamanya adalah apa yang ditambahkan oleh perawi yang dikenal kuat atau ang mereka jelaskan\". "},"1390":{"ar":"حَدَّثَنَا عُمَرُ بْنُ مُحَمَّدِ بْنِ الْحَسَنِ الْأَسَدِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُؤْتَى بِالتَّمْرِ عِنْدَ صِرَامِ النَّخْلِ فَيَجِيءُ هَذَا بِتَمْرِهِ وَهَذَا مِنْ تَمْرِهِ حَتَّى يَصِيرَ عِنْدَهُ كَوْمًا مِنْ تَمْرٍ فَجَعَلَ الْحَسَنُ وَالْحُسَيْنُ رَضِيَ اللَّهُ عَنْهُمَا يَلْعَبَانِ بِذَلِكَ التَّمْرِ فَأَخَذَ أَحَدُهُمَا تَمْرَةً فَجَعَلَهَا فِي فِيهِ فَنَظَرَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْرَجَهَا مِنْ فِيهِ فَقَالَ أَمَا عَلِمْتَ أَنَّ آلَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَأْكُلُونَ الصَّدَقَةَ","id":"Telah menceritakan kepada kami ['Umar bin Muhammad bin Al Hasan Al Asadi] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ibrahim bin Thahman] dari [Muhammad bin Ziyad] dari [Abu Hurairah radliallahu 'anhu] berkata; \"Suatu hari Rasulullah Shallallahu'alaihiwasallam pernah diberikan (menerima) zakat kurma ketika masa panen yang ketika itu seseorang membawa zakat kurmanya dan yang lain juga membawa zakat kurmanya sehingga kurma-kurma itu menumpuk karena sangat banyaknya. Tumpukan itu menjadi tempat bermainnya Hasan dan Husein radliallahu 'anhuma. Satu diantara kedua anak itu lantas mengambil sebutir kurma tersebut lalu memasukkannya ke dalam mulutnya. Lalu Rasulullah Shallallahu'alaihiwasallam melihatnya kemudian mengeluarkannya dari mulutnya seraya bersabda: \"Tidak tahukah kamu bahwa keluarga Muhammad Shallallahu'alaihiwasallam tidak boleh memakan shadaqah (zakat)?\"."},"1391":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ دِينَارٍ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَانَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الثَّمَرَةِ حَتَّى يَبْدُوَ صَلَاحُهَا وَكَانَ إِذَا سُئِلَ عَنْ صَلَاحِهَا قَالَ حَتَّى تَذْهَبَ عَاهَتُهُ","id":"Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepada saya ['Abdullah bin Dinar]; Aku mendengar [Ibnu'Umar radliallahu 'anhuma] (berkata,): Nabi Shallallahu'alaihiwasallam melarang menjual kurma sampai nampak kebaikannya (matang) dan bila ditanya tentang kebaikannya Beliau menjawab bila hama (suatu yang nampak sebagai resiko) sudah hilang\". "},"1392":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي خَالِدُ بْنُ يَزِيدَ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَانَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الثِّمَارِ حَتَّى يَبْدُوَ صَلَاحُهَا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada saya [Al Laits] telah menceritakan kepada saya [Khalid bin Yazid] dari ['Atha' bin Abu Rabah] dari [Jabir bin 'Abdullah radliallahu 'anhua]; Bahwa Nabi Shallallahu'alaihiwasallam melarang menjual kurma hingga nampak kebagusannya\". "},"1393":{"ar":"حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الثِّمَارِ حَتَّى تُزْهِيَ قَالَ حَتَّى تَحْمَ��رَّ","id":"Telah menceritakan kepada kami [Qutaibah] dari [Malik] dari [Humaid] dari [Anas bin Malik radliallahu 'anhu] bahwa Rasulullah Shallallahu'alaihiwasallam melarang menjual kurma hingga kurma itu berkembang baik\". Dia (Anas bin Malik radliallahu 'anhu) berkata,: \"Hingga memerah\". "},"1394":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا كَانَ يُحَدِّثُأَنَّ عُمَرَ بْنَ الْخَطَّابِ تَصَدَّقَ بِفَرَسٍ فِي سَبِيلِ اللَّهِ فَوَجَدَهُ يُبَاعُ فَأَرَادَ أَنْ يَشْتَرِيَهُ ثُمَّ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَأْمَرَهُ فَقَالَ لَا تَعُدْ فِي صَدَقَتِكَ فَبِذَلِكَ كَانَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا لَا يَتْرُكُ أَنْ يَبْتَاعَ شَيْئًا تَصَدَّقَ بِهِ إِلَّا جَعَلَهُ صَدَقَةً","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Salim] bahwa ['Abdullah bin 'Umar radliallahu 'anhua] menceritakan bahwa 'Umar bin Al Khaththab radliallahu 'anhu menshadaqahkan kudanya yang digunakannya untuk berperang di jalan Allah, lalu dia mendapatkan shadaqah kudanya itu dijual. Kemudian dia berkendak membelinya kembali. Maka dia menemui Nabi Shallallahu'alaihiwasallam dengan tujuan meminta saran. Maka Beliau Shallallahu'alaihiwasallam bersabda: \"Jangan kamu mengambil kembali shadaqahmu\". Oleh karena itu 'Abdullah bin 'Umar radliallahu 'anhuma tidak pernah membeli kembali apa yang telah dishadaqahkannya karena sudah dijadikannya sebagai shadaqah\"."},"1395":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكُ بْنُ أَنَسٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ قَالَ سَمِعْتُ عُمَرَ رَضِيَ اللَّهُ عَنْهُ يَقُولُحَمَلْتُ عَلَى فَرَسٍ فِي سَبِيلِ اللَّهِ فَأَضَاعَهُ الَّذِي كَانَ عِنْدَهُ فَأَرَدْتُ أَنْ أَشْتَرِيَهُ وَظَنَنْتُ أَنَّهُ يَبِيعُهُ بِرُخْصٍ فَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا تَشْتَرِي وَلَا تَعُدْ فِي صَدَقَتِكَ وَإِنْ أَعْطَاكَهُ بِدِرْهَمٍ فَإِنَّ الْعَائِدَ فِي صَدَقَتهِ كَالْعَائِدِ فِي قَيْئِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik bin Anas] dari [Zaid bin Aslam] dari [bapaknya] berkata; Aku mendengar ['Umar bin Al Khaththab radliallahu 'anhu] berkata,: \"Aku memberi (sesorang) kuda yang aku biasa gunakan untuk berperang di jalan Allah lalu orang itu tidak memanfaatkan sebagaimana mestinya. Kemudian aku berniat membelinya kembali karena aku menganggap membelinya lagi adalah suatu hal yang (diringankan) dibolehkan. Lalu aku tanyakan hal ini kepada Nabi Shallallahu'alaihiwasallam, maka Beliau bersabda: \"Jangan kamu membelinya dan jangan kamu mengambil kembali shadaqah (zakat) mu sekalipun orang itu menjualnya dengan harga satu dirham, karena orang yang mengambil kembali shadaqahnya seperti orang yang menjilat kembali ludahnya\". "},"1396":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَأَخَذَ الْحَسَنُ بْنُ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُمَا تَمْرَةً مِنْ تَمْرِ الصَّدَقَةِ فَجَعَلَهَا فِي فِيهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كِخْ كِخْ لِيَطْرَحَهَا ثُمَّ قَالَ أَمَا شَعَرْتَ أَنَّا لَا نَأْكُلُ الصَّدَقَةَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Muhammad bin Ziyad] berkata; Aku mendengar [Abu Hurairah radliallahu 'anhu] berkata; \"Suatu hari Al Hasan bin 'Ali radliallahu 'anhuma mengambil kurma dari kurma-kurma shadaqah (zakat) lalu memasukkannya ke dalam mulutnya, maka Nabi Shallallahu'alaihiwasallam bersabda: \"Hei, hei\". Maksudnya supaya ia membuangnya dari mulutnya. Selanjutnya Beliau bersabda: \"Tidakkah kamu menyadari bahwa kita tidak boleh memakan zakat\"."},"1397":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَوَجَدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاةً مَيِّتَةً أُعْطِيَتْهَا مَوْلَاةٌ لِمَيْمُونَةَ مِنْ الصَّدَقَةِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلَّا انْتَفَعْتُمْ بِجِلْدِهَا قَالُوا إِنَّهَا مَيْتَةٌ قَالَ إِنَّمَا حَرُمَ أَكْلُهَا","id":"Telah menceritakan kepada kami [Sa'id bin 'Uqair] telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] telah menceritakan kepada saya ['Ubaidullah bin 'Abdullah] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata,: Nabi Shallallahu'alaihiwasallam mendapatkan seekor kambing yang diberikan oleh seorang sahaya wanita Maimunah sebagai zakatnya dalam keadaan mati. Maka Nabi Shallallahu'alaihiwasallam bersabda: \"Kenapa kalian tidak memanfaatkan kulitnya? '. Orang-orang berkata,: \"Kambing itu sudah jadi bangkai\". Beliau SHAlLAlLAHU'AlAIHIWASAlLAM menjawab: \"Yang diharamkan itu memakannya\"."},"1398":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا الْحَكَمُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّهَا أَرَادَتْ أَنْ تَشْتَرِيَ بَرِيرَةَ لِلْعِتْقِ وَأَرَادَ مَوَالِيهَا أَنْ يَشْتَرِطُوا وَلَاءَهَا فَذَكَرَتْ عَائِشَةُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرِيهَا فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ قَالَتْ وَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَحْمٍ فَقُلْتُ هَذَا مَا تُصُدِّقَ بِهِ عَلَى بَرِيرَةَ فَقَالَ هُوَ لَهَا صَدَقَةٌ وَلَنَا هَدِيَّةٌ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Al Hakam] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah radliallahu 'anha] bahwa dia berkehendak membeli Barirah untuk dimerdekakan namun tuannya mengajukan syarat agar dia ('Aisyah radliallahu 'anha) menjad tuan dari sahaya yang dibebaskannya itu. Maka ('Aisyah radliallahu 'anha) menceritaklan hal itu kepada Nabi Shallallahu'alaihiwasallam, maka Nabi Shallallahu'alaihiwasallam berkata, kepadanya: \"Belilah, dan wala' dari sahaya adalah siapa yang membebaskannya\". ('Aisyah radliallahu 'anha) berkata,: Kepada Nabi Shallallahu'alaihiwasallam pernah diberikan sepotong daging lalu aku katakan bahwa daging ini dari zakat yang diterima Barirah. Maka Beliau Shallallahu'alaihiwasallam bersabda: \"Baginya ini zakat tapi bagi kita ini hadiah\"."},"1399":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا خَالِدٌ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ الْأَنْصَارِيَّةِ رَضِيَ اللَّهُ عَنْهَا قَالَتْدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَقَالَ هَلْ عِنْدَكُمْ شَيْءٌ فَقَالَتْ لَا إِلَّا شَيْءٌ بَعَثَتْ بِهِ إِلَيْنَا نُسَيْبَةُ مِنْ الشَّاةِ الَّتِي بَعَثَتْ بِهَا مِنْ الصَّدَقَةِ فَقَالَ إِنَّهَا قَدْ بَلَغَتْ مَحِلَّهَا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Khalid] dari [Hafshah binti Sirin] dari [Ummu 'Athiyah Al Anshariyyah radliallahu 'anhuma] berkata,: Nabi Shallallahu'alaihiwasallam menemui 'Aisyah radliallahu 'anha lalu berkata,: \"Apakah ada sesuatu yang kalian miliki (untuk dimakan)?\". Dia 'Aisyah radliallahu 'anha berkata,: \"Tidak ada, kecuali apa yang dikirim buat kita oleh Nusaibah dari daging kambing yang diperuntukkan untuknya sebagai zakat\". Maka Beliau berkata,: \"Shadaqah itu telah sampai kepada tempatnya\"."},"1400":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِلَحْمٍ تُصُدِّقَ بِهِ عَلَى بَرِيرَةَ فَقَالَ هُوَ عَلَيْهَا صَدَقَةٌ وَهُوَ لَنَا هَدِيَّةٌوَقَالَ أَبُو دَاوُدَ أَنْبَأَنَا شُعْبَةُ عَنْ قَتَادَةَ سَمِعَ أَنَسًا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Musa] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas radliallahu 'anhu] bahwa kepada Nabi Shallallahu'alaihiwasallam diberikan sepotong daging dari zakat yang diberikan kepada Barirah. Maka Beliau bersabda: \"Daging ini baginya shadaqah (zakat) dan bagi kita ini sebagai hadiah\". Dan berkata, [Abu Daud]: [Syu'bah] menceritakan kepada kami dari [Qatadah] bahwa dia mendengar [Anas] dari Nabi Shallallahu'alaihiwasallam."},"1401":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا زَكَرِيَّاءُ بْنُ إِسْحَاقَ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ صَيْفِيٍّ عَنْ أَبِي مَعْبَدٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمُعَاذِ بْنِ جَبَلٍ حِينَ بَعَثَهُ إِلَى الْيَمَنِ إِنَّكَ سَتَأْتِي قَوْمًا أَهْلَ كِتَابٍ فَإِذَا جِئْتَهُمْ فَادْعُهُمْ إِلَى أَنْ يَشْهَدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَإِنْ هُمْ أَطَاعُوا لَكَ بِذَلِكَ فَأَخْبِرْهُمْ أَنَّ اللَّهَ قَدْ فَرَضَ عَلَيْهِمْ خَمْسَ صَلَوَاتٍ فِي كُلِّ يَوْمٍ وَلَيْلَةٍ فَإِنْ هُمْ أَطَاعُوا لَكَ بِذَلِكَ فَأَخْبِرْهُمْ أَنَّ اللَّهَ قَدْ فَرَضَ عَلَيْهِمْ صَدَقَةً تُؤْخَذُ مِنْ أَغْنِيَائِهِمْ فَتُرَدُّ عَلَى فُقَرَائِهِمْ فَإِنْ هُمْ أَطَاعُوا لَكَ بِذَلِكَ فَإِيَّاكَ وَكَرَائِمَ أَمْوَالِهِمْ وَاتَّقِ دَعْوَةَ الْمَظْلُومِ فَإِنَّهُ لَيْسَ بَيْنَهُ وَبَيْنَ اللَّهِ حِجَابٌ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Zakariya' bin Ishaq] dari [Yahya bin 'Abdullah bin Shayfiy] dari [Abu Ma'bad] sahayanya [Ibnu 'Abbas radliallahu 'anhuma] berkata; Rasulullah Shallallahu'alaihiwasallam berkata, kepada Mu'adz bin Jabal Radhiyalahu'anhu ketika Beliau mengutusnya ke negeri Yaman: \"Sesungguhnya kamu akan mendatangi kaum Ahlul Kitab, jika kamu sudah mendatangi mereka maka ajaklah mereka untuk bersaksi tidak ada ilah yang berhak disembah kecuali Allah dan bahwa Muhammad adalah utusan Allah. Jika mereka telah mentaati kamu tentang hal itu, maka beritahukanlah mereka bahwa Allah mewajibkan bagi mereka shalat lima waktu pada setiap hari dan malamnya. Jika mereka telah mena'ati kamu tentang hal itu maka beritahukanlah mereka bahwa Allah mewajibkan bagi mereka zakat yang diambil dari kalangan orang mampu dari mereka dan dibagikan kepada kalangan yang faqir dari mereka. Jika mereka mena'ati kamu dalam hal itu maka janganlah kamu mengambil harta-harta terhormat mereka dan takutlah terhadap do'anya orang yang terzholimi karena antara dia dan Allah tidak ada hijab (pembatas yang menghalangi) nya\"."},"1402":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَاهُ قَوْمٌ بِصَدَقَتِهِمْ قَالَ اللَّهُمَّ صَلِّ عَلَى آلِ فُلَانٍ فَأَتَاهُ أَبِي بِصَدَقَتِهِ فَقَالَ اللَّهُمَّ صَلِّ عَلَى آلِ أَبِي أَوْفَى","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] telah menceritakan kepada kami [Syu'bah] dari ['Amru] dari ['Abdullah bin Abu Awfaa] berkata; Adalah Nabi shallallahu 'alaihi wasallam bila suatu kaum datang kepadanya dengan membawa shadaqah mereka, Beliau mendo'akannya: \"Allahumma shalli 'alaa aali fulan\" (Ya Allah berilah shalawat kepada keluarga fulan\"). Maka bapakku mendatangi Beliau dengan membawa zakatnya., maka Beliau mendo'akanya: \"Allahumma shalli 'alaa aalii abu awfaa\". (Ya Allah, berilah shalawat kepada keluarga Abu Awfaa\")."},"1403":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَعَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعَجْمَاءُ جُبَارٌ وَالْبِئْرُ جُبَارٌ وَالْمَعْدِنُ جُبَارٌ وَفِي الرِّكَازِ الْخُمُسُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al Musayab] dan dari [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah radliallahu 'anhu]; bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Binatang gembalaan yang mencelakai tidaklah dapat dituntut belanya (dendanya), begitu juga menggali sumur dan mencelakai, tidaklah dapat dituntut belanya (dendanya) dan menggali barang tanbang dan mencelakai, tidaklah dapat dituntut belanya (dendanya). Sedangkan harta terpendam (bila ditemukan seseorang) zakatnya seperlima\"."},"1404":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا أَبُو أُسَامَةَ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَاسْتَعْمَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا مِنْ الْأَسْدِ عَلَى صَدَقَاتِ بَنِي سُلَيْمٍ يُدْعَى ابْنَ اللُّتْبِيَّةِ فَلَمَّا جَاءَ حَاسَبَهُ","id":"Telah menceritakan kepada kami [Yusuf bin Musa] telah menceritakan kepada kami [Abu Usamah] telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [bapaknya] dari [Abu Humaid As-Sa'adiy radliallahu 'anhu] berkata: \"Rasulullah shallallahu 'alaihi wasallam memperkerjakan seorang laki-laki untuk mengurus zakat Bani Sulaim yang dikenal dengan sebutan Ibnu Al Latbiyah. Ketika orang itu kembali, Beliau memberinya (upah dari bagian zakat) \"."},"1405":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ نَاسًا مِنْ عُرَيْنَةَ اجْتَوَوْا الْمَدِينَةَ فَرَخَّصَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَأْتُوا إِبِلَ الصَّدَقَةِ فَيَشْرَبُوا مِنْ أَلْبَانِهَا وَأَبْوَالِهَا فَقَتَلُوا الرَّاعِيَ وَاسْتَاقُوا الذَّوْدَ فَأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُتِيَ بِهِمْ فَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَرَ أَعْيُنَهُمْ وَتَرَكَهُمْ بِالْحَرَّةِ يَعَضُّونَ الْحِجَارَةَتَابَعَهُ أَبُو قِلَابَةَ وَحُمَيْدٌ وَثَابِتٌ عَنْ أَنَسٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Syu'bah] telah menceritakan kepada kami [Qatadah] dari [Anas radliallahu 'anhu] bahwa ada sekelompok orang dari 'Urainah yang sakit terkena udara dingin kota Madinah. Maka Rasulullah shallallahu 'alaihi wasallam mengobati mereka dengan memberi bagian dari zakat unta, yang mereka meminum susu-susunya dan air kencingnya. Namun kemudian orang-orang itu membunuh pengembala unta tersebut dan mencuri unta-untanya sejumlah antara tiga hingga sepuluh. Maka Rasulullah shallallahu 'alaihi wasallam mengutus seseorang. Akhirnya mereka dibawa ke hadapan Beliau, lalu kemudian Beliau memotong tangan dan kaki mereka serta mencongkel mata-mata mereka dengan besi panas lalu menjemur mereka dibawah panas dan ditindih dengan bebatuan\". Hadits ini dikuatkan juga oleh [Abu Qalabah] dan [Humaid] dari [Tsabit] dari [Anas]."},"1406":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا أَبُو عَمْرٍو الْأَوْزَاعِيُّ حَدَّثَنِي إِسْحَاقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَغَدَوْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ لِيُحَنِّكَهُ فَوَافَيْتُهُ فِي يَدِهِ الْمِيسَمُ يَسِمُ إِبِلَ الصَّدَقَةِ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Al Walid] telah menceritakan kepada kami [Abu 'Amru Al Awza'iy] telah menceritakan kepada saya [Ishaq bin 'Abdullah bin Abu Tholhah] telah menceritakan kepada saya [Anas bin Malik radliallahu 'anhu] berkata: \"Aku berangkat di pagi hari bersama 'Abdullah bin Abu Tholhah menemui Rasulullah shallallahu 'alaihi wasallam untuk mentahniknya dan aku dapati di tangan Beliau ada stempel besi yang biasanya untuk memberikan tanda pada unta (dari hasil zakat)."},"1407":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُحَمَّدِ بْنِ السَّكَنِ حَدَّثَنَا مُحَمَّدُ بْنُ جَهْضَمٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ عُمَرَ بْنِ نَافِعٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَفَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَكَاةَ الْفِطْرِ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ عَلَى الْعَبْدِ وَالْحُرِّ وَالذَّكَرِ وَالْأُنْثَى وَالصَّغِيرِ وَالْكَبِيرِ مِنْ الْمُسْلِمِينَ وَأَمَرَ بِهَا أَنْ تُؤَدَّى قَبْلَ خُرُوجِ النَّاسِ إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami [Yahya bin Muhammad bin As-Sakkan] telah menceritakan kepada kami [Muhammad bin Jahdham] telah menceritakan kepada kami [Isma'il bin Ja'far] dari ['Umar bin Nafi'] dari [bapaknya] dari ['Abdullah bin 'Umar radliallahu 'anhua] berkata: \"Rasulullah shallallahu 'alaihi wasallam mewajibkan zakat fithri satu sha' dari kurma atau sha' dari gandum bagi setiap hamba sahaya (budak) maupun yang merdeka, laki-laki maupun perempuan, kecil maupun besar dari kaum Muslimin. Dan Beliau memerintahkan agar menunaikannya sebelum orang-orang berangkat untuk shalat ('Ied) \"."},"1408":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَضَ زَكَاةَ الْفِطْرِ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ عَلَى كُلِّ حُرٍّ أَوْ عَبْدٍ ذَكَرٍ أَوْ أُنْثَى مِنْ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam mewajibkan zakat fithri satu sha' dari kurma atau sha' dari gandum bagi setiap orang yang merdeka maupun hamba sahaya (budak), laki-laki maupun perempuan dari kaum Muslimin. "},"1409":{"ar":"حَدَّثَنَا قَبِيصَةُ بْنُ عُقْبَةَ حَدَّثَنَا سُفْيَانُ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا نُطْعِمُ الصَّدَقَةَ صَاعًا مِنْ شَعِيرٍ","id":"Telah menceritakan kepada kami [Qabishah bin 'Uqbah] telah menceritakan kepada kami [Sufyan] dari [Zaid bin Aslam] dari ['Iyadh bin 'Abdullah] dari [Abu Sa'id radliallahu 'anhu] berkata: \"Kami memberi makan (orang miskin) dari zakat dengan satu sha' dari gandum\"."},"1410":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ بْنِ سَعْدِ بْنِ أَبِي سَرْحٍ الْعَامِرِيِّ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُ يَقُولُكُنَّا نُخْرِجُ زَكَاةَ الْفِطْرِ صَاعًا مِنْ طَعَامٍ أَوْ صَاعًا مِنْ شَعِيرٍ أَوْ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ أَقِطٍ أَوْ صَاعًا مِنْ زَبِيبٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Zaid bin Aslam] dari ['Iyadh bin 'Abdullah bin Sa'ad bin Abu Sarhi Al 'Amiriy] bahwa dia mendengar [Abu Sa'id Al Khudriy radliallahu 'anhu] berkata: \"Kami mengeluarkan zakat fithri satu sha' dari makanan atau satu sha' dari gandum atau satu sha' dari kurma atau satu sha' dari keju (mentega) atau satu sha'dari kismis (anggur kering) \"."},"1411":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِزَكَاةِ الْفِطْرِ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ قَالَ عَبْدُ اللَّهِ رَضِيَ اللَّهُ عَنْهُ فَجَعَلَ النَّاسُ عِدْلَهُ مُدَّيْنِ مِنْ حِنْطَةٍ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Al Laits] dari [Nafi'] bahwa ['Abdullah bin 'Umar radliallahu 'anhua] berkata: Nabi shallallahu 'alaihi wasallam memerintahkan kami tentang zakat fithri berupa satu sha' dari kurma atau satu sha' dari gandum\". Berkata, 'Abdullah radliallahu 'anhu: \"Kemudian orang-orang menyamakannya dengan dua mud untuk biji gandum\". "},"1412":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُنِيرٍ سَمِعَ يَزِيدَ بْنَ أَبِي حَكِيمٍ الْعَدَنِيَّ حَدَّثَنَا سُفْيَانُ عَنْ زَيْدِ بْنِ أَسْلَمَ قَالَ حَدَّثَنِي عِيَاضُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي سَرْحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا نُعْطِيهَا فِي زَمَانِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَاعًا مِنْ طَعَامٍ أَوْ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ أَوْ صَاعًا مِنْ زَبِيبٍ فَلَمَّا جَاءَ مُعَاوِيَةُ وَجَاءَتْ السَّمْرَاءُ قَالَ أُرَى مُدًّا مِنْ هَذَا يَعْدِلُ مُدَّيْنِ","id":"Telah menceritakan kepada kami ['Abdullah bin Munir] dia mendengar [Yazid bin Abu Hakim Al 'Adaniy] telah menceritakan kepada kami [Sufyan] dari [Zaid bin Aslam] berkata, telah menceritakan kepada saya ['Iyadh bin 'Abdullah bin Abu Sarhi] dari [Abu Sa'id Al Khudriy radliallahu 'anhu] berkata: \"Pada zaman Nabi shallallahu 'alaihi wasallam kami memberi makan (mengeluarkan zakat fithri) satu sha' dari makanan atau satu sha' dari kurma atau satu sha' dari gandum atau satu sha' dari sha'dari kismis (anggur kering). Ketika Mu'awiyah datang (untuk melaksanakanhajji) dan gandum dari negeri Syam, dia berkata: \"Aku menganggap satu mud ini (kurna) sama dengan dua mud (gandum negeri Syam) \"."},"1413":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا حَفْصُ بْنُ مَيْسَرَةَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِزَكَاةِ الْفِطْرِ قَبْلَ خُرُوجِ النَّاسِ إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Hafsh bin Maisarah] telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] bahwa Nabi shallallahu 'alaihi wasallam memerintahkan (untuk menunaikan) zakat fithri sebelum orang-orang keluar untuk shalat ('Ied) \"."},"1414":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا أَبُو عُمَرَ حَفْصُ بْنُ مَيْسَرَةَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ بْنِ سَعْدٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا نُخْرِجُ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفِطْرِ صَاعًا مِنْ طَعَامٍ وَقَالَ أَبُو سَعِيدٍ وَكَانَ طَعَامَنَا الشَّعِيرُ وَالزَّبِيبُ وَالْأَقِطُ وَالتَّمْرُ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadhalah] telah menceritakan kepada kami [Abu 'Umar Hafsh bin Maisarah] dari [Zaid bin Aslam] dari ['Iyadh bin 'Abdullah bin Sa'ad] dari [Abu Sa'id Al Khudriy radliallahu 'anhu] berkata: \"Pada zaman Nabi shallallahu 'alaihi wasallam kami mengeluarkan (zakat fithri) pada hari Raya 'Iedul fithri satu sha' dari makanan\". Dan berkata, Abu Sa'id: \"Dan saat itu makanan kami adalah gandum, kismis, biji-bijian atau kurma\"."},"1415":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَفَرَضَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَةَ الْفِطْرِ أَوْ قَالَ رَمَضَانَ عَلَى الذَّكَرِ وَالْأُنْثَى وَالْحُرِّ وَالْمَمْلُوكِ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ فَعَدَلَ النَّاسُ بِهِ نِصْفَ صَاعٍ مِنْ بُرٍّ فَكَانَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يُعْطِي التَّمْرَ فَأَعْوَزَ أَهْلُ الْمَدِينَةِ مِنْ التَّمْرِ فَأَعْطَى شَعِيرًا فَكَانَ ابْنُ عُمَرَ يُعْطِي عَنْ الصَّغِيرِ وَالْكَبِيرِ حَتَّى إِنْ كَانَ لِيُعْطِي عَنْ بَنِيَّ وَكَانَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يُعْطِيهَا الَّذِينَ يَقْبَلُونَهَا وَكَانُوا يُعْطُونَ قَبْلَ الْفِطْرِ بِيَوْمٍ أَوْ يَوْمَيْنِ","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] berkata: Nabi shallallahu 'alaihi wasallam mewajibkan zakat fithri, atau katanya zakat Ramadhan bagi setiap laki-laki maupun perempuan, orang merdeka maupun budak satu sha' dari kurma atau satu sha' dari gandum\". Kemudian orang-orang menyamakannya dengan setengah sha' untuk biji gandum. Adalah Ibnu 'Umar radliallahu 'anhuma bila berzakat dia memberikannya dengan kurma. Kemudian penduduk Madinah kesulitan mendapatkan kurma akhirnya mereka mengeluarkan gandum. Ibnu 'Umar radliallahu 'anhuma memberikan zakatnya atas nama anak kecil maupun dewasa hingga atas nama bayi sekalipun dan Ibnu 'Umar radliallahu 'anhuma memberikannya kepada orang-orang yang berhak menerimanya dan dia mengeluarkan zakatnya itu sehari atau dua hari sebelum hari Raya 'Iedul Fithri."},"1416":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُ قَالَفَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَةَ الْفِطْرِ صَاعًا مِنْ شَعِيرٍ أَوْ صَاعًا مِنْ تَمْرٍ عَلَى الصَّغِيرِ وَالْكَبِيرِ وَالْحُرِّ وَالْمَمْلُوكِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] berkata, telah menceritakan kepada saya [Nafi'] dari [Ibnu 'Umar radliallahu 'anhu] berkata; \"Rasulullah shallallahu 'alaihi wasallam mewajibkan zakat fithri satu sha' dari gandum atau sha' dari kurma bagi setiap anak kecil maupun dewasa, orang yang merdeka maupun hamba sahaya (budak) \"."},"1417":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ الْفَضْلُ رَدِيفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَتْ امْرَأَةٌ مِنْ خَشْعَمَ فَجَعَلَ الْفَضْلُ يَنْظُرُ إِلَيْهَا وَتَنْظُرُ إِلَيْهِ وَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْرِفُ وَجْهَ الْفَضْلِ إِلَى الشِّقِّ الْآخَرِ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ فَرِيضَةَ اللَّهِ عَلَى عِبَادِهِ فِي الْحَجِّ أَدْرَكَتْ أَبِي شَيْخًا كَبِيرًا لَا يَثْبُتُ عَلَى الرَّاحِلَةِ أَفَأَحُجُّ عَنْهُ قَالَ نَعَمْ وَذَلِكَ فِي حَجَّةِ الْوَدَاعِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Sulaiman bin Yasar] dari ['Abdullah bin 'Abbas radliallahu 'anhu] berkata: \"Suatu saat Al Fadhal membonceng di belakang Rasulullah shallallahu 'alaihi wasallam lalu datang seorang wanita dari suku Khasy'am yang membuat Al Fadhal memandang kepada wanita tersebut. Maka Nabi shallallahu 'alaihi wasallam memalingkan wajah Al Fadhal ke arah yang lain. Wanita itu berkata: \"Wahai Rasulullah, sesungguhnya kewajiban dari Allah untuk berhajji bagi hamba-hambaNya datang saat bapakku sudah tua renta dan dia tidak akan kuat menempuh perjalanannya. Apakah aku boleh menghajjikan atas namanya?\". Beliau menjawab: \"Boleh\". Peristiwa ini terjadi ketika hajji wada' (perpisahan)."},"1418":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عِيسَى حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ أَنَّ سَالِمَ بْنَ عَبْدِ اللَّهِ بْنِ عُمَرَ أَخْبَرَهُ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْكَبُ رَاحِلَتَهُ بِذِي الْحُلَيْفَةِ ثُمَّ يُهِلُّ حَتَّى تَسْتَوِيَ بِهِ قَائِمَةً","id":"Telah menceritakan kepada kami [Ahmad bin 'Isa] telah menceritakan kepada kami [Ibnu Wahab] dari [Yunus] dari [Ibnu Syihab] bahwa [Salim bin 'Abdullah bin 'Umar] mengabarkannya bahwa [Ibnu 'Umar radliallahu 'anhuma] berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam menunggang hewan tunggangannya di Dzul Hulaifah kemudian Beliau bertalbiyyah (memulia niat hajji) ketika tunggangannya itu berdiri tegak\"."},"1419":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا الْوَلِيدُ حَدَّثَنَا الْأَوْزَاعِيُّ سَمِعَ عَطَاءً يُحَدِّثُ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ إِهْلَالَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ ذِي الْحُلَيْفَةِ حِينَ اسْتَوَتْ بِهِ رَاحِلَتُهُرَوَاهُ أَنَسٌ وَابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمْ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Al Walid] telah menceritakan kepada kami [Al Awza'iy] bahwa dia mendengar ['Atho'] menceritakan dari [Jabir bin 'Abdullah radliallahu 'anhua]: \"Sesungguhnya awal dimulainya hajji (dengan niat dan bertalbiyah) Rasulullah shallallahu 'alaihi wasallam dimulai dari Dzul Hulaifah ketika tunggangannya itu sudah berdiri tegak\". Hadits ini diriwayatkan oleh Anas dan Ibnu 'Abbas radliallahu 'anhum. "},"1420":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا عَزْرَةُ بْنُ ثَابِتٍ عَنْ ثُمَامَةَ بْنِ عَبْدِ اللَّهِ بْنِ أَنَسٍ قَالَ حَجَّ أَنَسٌعَلَى رَحْلٍ وَلَمْ يَكُنْ شَحِيحًا وَحَدَّثَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَجَّ عَلَى رَحْلٍ وَكَانَتْ زَامِلَتَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakar] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami ['Azrah bin Tsabit] dari [Tsumamah bin 'Abdullah bin Anas] berkata: \" [Anas] berhajji dengan menunggang kendaraannya dan ketika itu ia bukanlah seorang yang kikir. Ia juga menceritakan bahwa Rasulullah shallallahu 'alaihi wasallam berhaji mengendarai tunggangannya yang membawa perbekalannya."},"1421":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا أَيْمَنُ بْنُ نَابِلٍ حَدَّثَنَا الْقَاسِمُ بْنُ مُحَمَّدٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْيَا رَسُولَ اللَّهِ اعْتَمَرْتُمْ وَلَمْ أَعْتَمِرْ فَقَالَ يَا عَبْدَ الرَّحْمَنِ اذْهَبْ بِأُخْتِكَ فَأَعْمِرْهَا مِنْ التَّنْعِيمِ فَأَحْقَبَهَا عَلَى نَاقَةٍ فَاعْتَمَرَتْ","id":"Telah menceritakan kepada kami ['Amru bin 'Ali] telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Aiman bin Nabil] telah menceritakan kepada kami [Al Qasim bin Muhammad] dari ['Aisyah radliallahu 'anha] bahwa dia berkata: \"Wahai Rasulullah, Kalian sudah ber'umrah sedangkan aku belum\". Maka Beliau berkata: \"Wahai 'Abdurrahman, pergilah bersama saudaramu ini dan ber'umrahlah dari Tan'im\". Maka dia ('Abdurrahman) menaikkan 'Aisyah radliallahu 'anha ke atas untanya kemudian 'Aisyah radliallahu 'anha melaksanakan 'umrah."},"1422":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ إِيمَانٌ بِاللَّهِ وَرَسُولِهِ قِيلَ ثُمَّ مَاذَا قَالَ جِهَادٌ فِي سَبِيلِ اللَّهِ قِيلَ ثُمَّ مَاذَا قَالَ حَجٌّ مَبْرُورٌ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Az Zuhriy] dari [Sa'id bin Al Musayab] dari [Abu Hurairah radliallahu 'anhu] berkata; Ditanyakan kepada Nabi Shallallahu'alaihiwasallam: \"'Amal apakah yang paling utama?\". Beliau menjawab: \"Iman kepada Allah dan rasulNya\". Kemudian ditanya lagi: \"Kemudian apa?\" Beliau menjawab: \"Al Jihad fii sabiilillah\". Kemudian ditanya lagi: \"Kemudian apa lagi?\" Beliau menjawab: \"Hajji mabrur\"."},"1423":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْمُبَارَكِ حَدَّثَنَا خَالِدٌ أَخْبَرَنَا حَبِيبُ بْنُ أَبِي عَمْرَةَ عَنْ عَائِشَةَ بِنْتِ طَلْحَةَ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْيَا رَسُولَ اللَّهِ نَرَى الْجِهَادَ أَفْضَلَ الْعَمَلِ أَفَلَا نُجَاهِدُ قَالَ لَا لَكِنَّ أَفْضَلَ الْجِهَادِ حَجٌّ مَبْرُورٌ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Al Mubarak] telah menceritakan kepada kami [Khalid] telah mengabarkan kepada kami [Habib bin Abu 'Amrah] dari [Aisyah binti Tholhah] dari ['Aisyah Ummul Mukminin radliallahu 'anha] ia berkata: \"Wahai Rasulullah, kami memandang bahwa jihad adalah sebaik-baiknya amal, maka apakah kami tidak boleh berjihad?\". Beliau bersabda: \"Tidak, namun sebaik-baik jihad bagi kalian (para wanita) adalah haji mabrur\"."},"1424":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا سَيَّارٌ أَبُو الْحَكَمِ قَالَ سَمِعْتُ أَبَا حَازِمٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ حَجَّ لِلَّهِ فَلَمْ يَرْفُثْ وَلَمْ يَفْسُقْ رَجَعَ كَيَوْمِ وَلَدَتْهُ أُمُّهُ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Sayyar Abu Al Hakam] berkata; aku mendengar [Abu Hazim] berkata; aku mendengar [Abu Hurairah radliallahu 'anhu] berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melaksanakan hajji lalu dia tidak berkata, -kata kotor dn tidak berbuat fasik maka dia kembali seperti hari saat dilahirkan oleh ibunya\". "},"1425":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنِي زَيْدُ بْنُ جُبَيْرٍ أَنَّهُ أَتَى عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَافِي مَنْزِلِهِ وَلَهُ فُسْطَاطٌ وَسُرَادِقٌ فَسَأَلْتُهُ مِنْ أَيْنَ يَجُوزُ أَنْ أَعْتَمِرَ قَالَ فَرَضَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَهْلِ نَجْدٍ قَرْنًا وَلِأَهْلِ الْمَدِينَةِ ذَا الْحُلَيْفَةِ وَلِأَهْلِ الشَّأْمِ الْجُحْفَةَ","id":"Telah menceritakan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Zuhair] berkata, telah menceritakan kepada saya [Zaid bin Jubair] bahwa dia menemui ['Abdullah bin 'Umar radliallahu 'anha] di tempat menginapnya berupa tenda yang besar lagi tertutup rapat. Maka aku bertanya kepadanya: \"Dari manakah dibolehkan memulai 'umrah?\". Dia menjawab: \"Rasulullah shallallahu 'alaihi wasallam telah mewajibkan bahwa untuk penduduk Najed memulainya dari Qarnul Manazil, bagi penduduk Madinah dari Dzul Hulaifah dan bagi penduduk Syam dari Al Juhfah\"."},"1426":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بِشْرٍ حَدَّثَنَا شَبَابَةُ عَنْ وَرْقَاءَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ أَهْلُ الْيَمَنِ يَحُجُّونَ وَلَا يَتَزَوَّدُونَ وَيَقُولُونَ نَحْنُ الْمُتَوَكِّلُونَ فَإِذَا قَدِمُوا مَكَّةَ سَأَلُوا النَّاسَ فَأَنْزَلَ اللَّهُ تَعَالَى{ وَتَزَوَّدُوا فَإِنَّ خَيْرَ الزَّادِ التَّقْوَى }رَوَاهُ ابْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ عِكْرِمَةَ مُرْسَلًا","id":"Telah menceritakan kepada kami [Yahya bin Bisir] telah menceritakan kepada kami [Syababah] dari [Warqa'] dari ['Amru bin Dinar] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] ia berkata; \"Dahulu para penduduk Yaman berhajji namun mereka tidak membawa bekal dan mereka berkata, kami adalah orang-orang yang bertawakal. Ketika mereka tiba di Makkah, mereka meminta-minta kepada manusia. Maka Allah Ta'ala menurunkan ayat 197 dari QS Al Baqarah) yang artinya (\"Berbekallah, dan sesungguhnya sebaik-baik bekal adalah takwa\".) Dan diriwayatkan pula oleh [Ibnu 'Uyainah] dari ['Amru] dari ['Ikrimah] secara mursal."},"1427":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَّتَ لِأَهْلِ الْمَدِينَةِ ذَا الْحُلَيْفَةِ وَلِأَهْلِ الشَّأْمِ الْجُحْفَةَ وَلِأَهْلِ نَجْدٍ قَرْنَ الْمَنَازِلِ وَلِأَهْلِ الْيَمَنِ يَلَمْلَمَ هُنَّ لَهُنَّ وَلِمَنْ أَتَى عَلَيْهِنَّ مِنْ غَيْرِهِنَّ مِمَّنْ أَرَادَ الْحَجَّ وَالْعُمْرَةَ وَمَنْ كَانَ دُونَ ذَلِكَ فَمِنْ حَيْثُ أَنْشَأَ حَتَّى أَهْلُ مَكَّةَ مِنْ مَكَّةَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu Thowus] dari [bapaknya] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Nabi Shallallahu'alaihiwasallam menetapkan miqat bagi penduduk Madinah di Dzul Hulaifah, bagi penduduk Syam di Al Juhfah, bagi penduduk Najed di Qarnul Manazil dan bagi penduduk Yaman di Yalamlam. Itulah ketentuan masing-masing bagi setiap penduduk negeri-negeri tersebut dan juga bagi mereka yang bukan penduduk negeri-negeri tersebut bila melewati tempat-tempat tersebut dan berniat untuk hajji dan 'umrah. Sedangkan bagi orang-orang selain itu (yang tinggal lebih dekat ke Makkah dari pada tempat-tempat itu), maka dia memulai dari kediamannya, dan bagi penduduk Makkah, mereka memulainya dari (rumah mereka) di Makkah\". "},"1428":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُهِلُّ أَهْلُ الْمَدِينَةِ مِنْ ذِي الْحُلَيْفَةِ وَيُهِلُّ أَهْلُ الشَّأْمِ مِنْ الْجُحْفَةِ وَأَهْلُ نَجْدٍ مِنْ قَرْنٍ قَالَ عَبْدُ اللَّهِ وَبَلَغَنِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَيُهِلُّ أَهْلُ الْيَمَنِ مِنْ يَلَمْلَمَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhua] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagi penduduk Madinah bertalbiyah (memulai hajji) di Dzul Hulaifah, bagi penduduk Syam bertalbiyah di Al Juhfah, bagi penduduk Najed di Qarnul Manazil\". Berkata, 'Abdullah; telah sampai berita kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam juga bersabda: \"Dan bagi penduduk Yaman di Yalamlam\"."},"1429":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادٌ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَوَقَّتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَهْلِ الْمَدِينَةِ ذَا الْحُلَيْفَةِ وَلِأَهْلِ الشَّأْمِ الْجُحْفَةَ وَلِأَهْلِ نَجْدٍ قَرْنَ الْمَنَازِلِ وَلِأَهْلِ الْيَمَنِ يَلَمْلَمَ فَهُنَّ لَهُنَّ وَلِمَنْ أَتَى عَلَيْهِنَّ مِنْ غَيْرِ أَهْلِهِنَّ لِمَنْ كَانَ يُرِيدُ الْحَجَّ وَالْعُمْرَةَ فَمَنْ كَانَ دُونَهُنَّ فَمُهَلُّهُ مِنْ أَهْلِهِ وَكَذَاكَ حَتَّى أَهْلُ مَكَّةَ يُهِلُّونَ مِنْهَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad] dari ['Amru bin Dinar] dari [Thowus] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Nabi shallallahu 'alaihi wasallam telah menetapkan miqat bagi penduduk Madinah di Dzul Hulaifah, bagi penduduk Syam di Al Juhfah, bagi penduduk Najed di Qarnul Manazil dan bagi penduduk Yaman di Yalamlam. Itulah ketentuan masing-masing bagi setiap penduduk negeri-negeri tersebut dan juga bagi yang bukan penduduk negeri-negeri tersebut bila datang melewati tempat-tempat tersebut dan berniat untuk hajji dan 'umrah. Sedangkan bagi orang-orang selain itu, maka mereka memulai dari tempat tinggalnya (keluarga) dan begitulah ketentuannya sehingga bagi penduduk Makkah, mereka memulainya (bertalbiah) dari (rumah mereka) di Makkah\". "},"1430":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ حَفِظْنَاهُ مِنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ وَقَّتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا أَحْمَدُ بْنُ عِيسَى حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مُهَلُّ أَهْلِ الْمَدِينَةِ ذُو الْحُلَيْفَةِ وَمُهَلُّ أَهْلِ الشَّأْمِ مَهْيَعَةُ وَهِيَ الْجُحْفَةُ وَأَهْلِ نَجْدٍ قَرْنٌقَالَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا زَعَمُوا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَلَمْ أَسْمَعْهُ وَمُهَلُّ أَهْلِ الْيَمَنِ يَلَمْلَمُ","id":"Telah menceritakan kepada kami ['Ali] telah menceritakan kepada kami [Sufyan] kami menghafalnya dari [Az Zuhriy] dari [Salim] dari [bapaknya] bahwa Nabi shallallahu 'alaihi wasallam telah menetapkan miqat. Telah menceritakan kepada kami [Ahmad bin 'Isa] telah menceritakan kepada kami [Ibnu Wahab] berkata, telah mengabarkan kepada saya [Yunus] dari [Ibnu Syihab] dari [Salim bin 'Abdullah] dari [bapaknya] radliallahu 'anhu; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: Tempat memulai hajji (bertalbiyah) bagi penduduk Madinah adalah di Dzul Hulaifah, bagi penduduk Syam bertalbiyah di Mahya'ah yaitu Al Juhfah, bagi penduduk Najed di Qarnul Manazil\". Berkata, Ibnu 'Umar radliallahu 'anhuma; \"Orang-orang menganggap bahwa Nabi shallallahu 'alaihi wasallam bersabda sedangkan aku tidak mendengarnya langsung: \"Dan bagi penduduk Yaman di Yalamlam\"."},"1431":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادٌ عَنْ عَمْرٍو عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَّتَ لِأَهْلِ الْمَدِينَةِ ذَا الْحُلَيْفَةِ وَلِأَهْلِ الشَّأْمِ الْجُحْفَةَ وَلِأَهْلِ الْيَمَنِ يَلَمْلَمَ وَلِأَهْلِ نَجْدٍ قَرْنًا فَهُنَّ لَهُنَّ وَلِمَنْ أَتَى عَلَيْهِنَّ مِنْ غَيْرِ أَهْلِهِنَّ مِمَّنْ كَانَ يُرِيدُ الْحَجَّ وَالْعُمْرَةَ فَمَنْ كَانَ دُونَهُنَّ فَمِنْ أَهْلِهِ حَتَّى إِنَّ أَهْلَ مَكَّةَ يُهِلُّونَ مِنْهَا","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad] dari ['Amru] dari [Thawus] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Bahwa Nabi shallallahu 'alaihi wasallam telah menetapkan miqat bagi penduduk Madinah di Dzul Hulaifah, bagi penduduk Syam di Al Juhfah, bagi penduduk Yaman di Yalamlam dan bagi penduduk Najed di Qarnul Manazil. Itulah ketentuan masing-masing bagi setiap penduduk negeri-negeri tersebut dan juga bagi yang bukan penduduk negeri-negeri tersebut bila datang melewati tempat-tempat tersebut dan berniat untuk hajji dan 'umrah. Sedangkan bagi orang-orang selain itu, maka mereka memulai dari tempat tinggalnya (keluarga) dan begitulah ketentuannya sehingga bagi penduduk Makkah, mereka memulainya (bertalbiyah) dari (rumah mereka) di Makkah\". "},"1432":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ عَبْدِ اللَّهِ بْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَّتَ لِأَهْلِ الْمَدِينَةِ ذَا الْحُلَيْفَةِ وَلِأَهْلِ الشَّأْمِ الْجُحْفَةَ وَلِأَهْلِ نَجْدٍ قَرْنَ الْمَنَازِلِ وَلِأَهْلِ الْيَمَنِ يَلَمْلَمَ هُنَّ لِأَهْلِهِنَّ وَلِكُلِّ آتٍ أَتَى عَلَيْهِنَّ مِنْ غَيْرِهِمْ مِمَّنْ أَرَادَ الْحَجَّ وَالْعُمْرَةَ فَمَنْ كَانَ دُونَ ذَلِكَ فَمِنْ حَيْثُ أَنْشَأَ حَتَّى أَهْلُ مَكَّةَ مِنْ مَكَّةَ","id":"Telah menceritakan kepada kami [Mu'allaa bin Asad] telah menceritakan kepada kami [Wuhaib] dari ['Abdullah bin Thowus] dari [bapaknya] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa Nabi shallallahu 'alaihi wasallam telah menetapkan miqat bagi penduduk Madinah di Dzul Hulaifah, bagi penduduk Syam di Al Juhfah, bagi penduduk Najed di Qarnul Manazil dan bagi penduduk Yaman di Yalamlam. Tempat-tempat itu bagi masing-masing penduduk negeri-negeri tersebut dan juga bagi mereka melewati tempat-tempat tersebut dan berniat untuk hajji dan 'umrah. Sedangkan bagi orang-orang selain itu, maka dia memulai dari kediamannya sehingga bagi penduduk Makkah, mereka memulainya (bertalbiyah) dari (rumah mereka) di Makkah\". "},"1433":{"ar":"حَدَّثَنِي عَلِيُّ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا فُتِحَ هَذَانِ الْمِصْرَانِ أَتَوْا عُمَرَ فَقَالُوا يَا أَمِيرَ الْمُؤْمِنِينَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّ لِأَهْلِ نَجْدٍ قَرْنًا وَهُوَ جَوْرٌ عَنْ طَرِيقِنَا وَإِنَّا إِنْ أَرَدْنَا قَرْنًا شَقَّ عَلَيْنَا قَالَ فَانْظُرُوا حَذْوَهَا مِنْ طَرِيقِكُمْ فَحَدَّ لَهُمْ ذَاتَ عِرْقٍ","id":"Telah menceritakan kepada saya ['Ali bin Muslim] telah menceritakan kepada kami ['Abdullah bin Namir] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] berkata: Ketika negeri Mesir telah ditaklukan, penduduknya datang menghadap 'Umar lalu mereka berkata: \"Wahai Amirul Mukminin, Rasulullah shallallahu 'alaihi wasallam telah menetapkan batas miqat bagi penduduk Nejd di Qarnul Manazil, dan itu sangat jauh bila dilihat dari jalan kami, dan bila kami ingin menempuh ke sana sangat memberatkan kami\". Maka dia ('Umar) berkata: \"Perhatikanlah batas sejajarnya dari jalan kalian\". Lalu dia menetapkan miqat mereka di Dzatu 'Irqi. "},"1434":{"ar":"بَاب حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَاخَ بِالْبَطْحَاءِ بِذِي الْحُلَيْفَةِ فَصَلَّى بِهَا وَكَانَ عَبْدُ اللَّهِ بْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَفْعَلُ ذَلِكَ","id":"Bab. Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhua] bahwa Rasulullah shallallahu 'alaihi wasallam singgah di Bathha' di daerah Dzul Hulaifah lalu Beliau shalat disitu. Dan 'Abdullah bin 'Umar radliallahu 'anhua juga melakukannya seperti itu. "},"1435":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْرُجُ مِنْ طَرِيقِ الشَّجَرَةِ وَيَدْخُلُ مِنْ طَرِيقِ الْمُعَرَّسِ وَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا خَرَجَ إِلَى مَكَّةَ يُصَلِّي فِي مسْجِدِ الشَّجَرَةِ وَإِذَا رَجَعَ صَلَّى بِذِي الْحُلَيْفَةِ بِبَطْنِ الْوَادِي وَبَاتَ حَتَّى يُصْبِحَ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Anas bin 'Iyadh] dari ['Ubaidullah] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhua] bahwa Rasulullah shallallahu 'alaihi wasallam pernah keluar (dari Madinah) melalui jalur Asy-Syajarah dan memasuki (Ka'bah) melalui jalur Al Mu'arras. Dan bahwa Rasulullah shallallahu 'alaihi wasallam jika keluar menuju Makkah, Beliau shalat di masjid Asy-Syajarah dan jika kembali Beliau shalat di Dzul Hulaifah di dasar lembah dan bermalam disana hingga shubuh."},"1436":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا الْوَلِيدُ وَبِشْرُ بْنُ بَكْرٍ التِّنِّيسِيُّ قَالَا حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى قَالَ حَدَّثَنِي عِكْرِمَةُ أَنَّهُ سَمِعَ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُ إِنَّهُ سَمِعَ عُمَرَ رَضِيَ اللَّهُ عَنْهُ يَقُولُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِوَادِي الْعَقِيقِ يَقُولُ أَتَانِي اللَّيْلَةَ آتٍ مِنْ رَبِّي فَقَالَ صَلِّ فِي هَذَا الْوَادِي الْمُبَارَكِ وَقُلْ عُمْرَةً فِي حَجَّةٍ","id":"Telah menceritakan kepada kami [Al Humaidiy] telah menceritakan kepada kami [Al Walid] dan [Bisyir bin Bakar At-Tinnisiy] keduanya berkata, telah menceritakan kepada kami [Al Awza'iy] berkata, telah menceritakan kepada saya [Yahya] berkata, telah menceritakan kepada saya ['Ikrimah] bahwa dia mendengar [Ibnu 'Abbas radliallahu 'anhuma] berkata, bahwa dia mendengar ['Umar radliallahu 'anhu] berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam ketika berada di lembah Al 'Aqiq: \"Malaikat yag diutus oleh Rabbku datang kepadaku dan berkata: \"Shalatlah di lembah yang penuh barakah ini dan katakanlah: \"Aku berniat melaksanakan 'umrah dalam 'ibadah hajji ini\"."},"1437":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ حَدَّثَنَا فُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ قَالَ حَدَّثَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ رُئِيَ وَهُوَ فِي مُعَرَّسٍ بِذِي الْحُلَيْفَةِ بِبَطْنِ الْوَادِي قِيلَ لَهُ إِنَّكَ بِبَطْحَاءَ مُبَارَكَةٍ وَقَدْ أَنَاخَ بِنَا سَالِمٌ يَتَوَخَّى بِالْمُنَاخِ الَّذِي كَانَ عَبْدُ اللَّهِ يُنِيخُ يَتَحَرَّى مُعَرَّسَ رَسُولِ اللَّه صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ أَسْفَلُ مِنْ الْمَسْجِدِ الَّذِي بِبَطْنِ الْوَادِي بَيْنَهُمْ وَبَيْنَ الطَّرِيقِ وَسَطٌ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakar] telah menceritakan kepada kami [Fudhail bin Sulaiman] telah menceritakan kepada kami [Musa bin 'Uqbah] berkata, telah menceritakan kepada saya [Salim bin 'Abdullah] dari [bapaknya] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam: \"Diperlihatkan kepada Beliau ketika Beliau singgah untuk beristirahat di Dzul Hulaifah di dasar lembah dan dikatakan kepada Beliau; \"Sesungguhnya kamu sekarang sedang berada di Bathha' yang penuh berkah\". Saat itu Salim beristirahat bersama kami di tempat singgahnya 'Abdullah ketika sedang mencari tempat singgah yang tepat untuk peristirahatan Rasulullah Shallallahu'alaihiwasallam, yaitu pada posisi bawah dari masjid yang ada di dasar lembah itu. Yang letaknya berada di tengah antara mereka dan jalan yang mereka lalui."},"1438":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ كَانَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَدَّهِنُ بِالزَّيْتِ فَذَكَرْتُهُ لِإِبْرَاهِيمَ قَالَ مَا تَصْنَعُ بِقَوْلِهِ حَدَّثَنِي الْأَسْوَدُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَأَنِّي أَنْظُرُ إِلَى وَبِيصِ الطِّيبِ فِي مَفَارِقِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُحْرِمٌ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] berkata, telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Sa'id bin Jubair] berkata; [Ibnu 'Umar radliallahu 'anhuma] pernah meminyaki rambutnya dengan wewangian (saat berihram) lalu hal ini aku ceritaklan kepada [Ibrahim]. Maka dia berkata: \"Bagaimana pendapatmu dengan apa yang disampaikannya; telah menceritakan kepada saya [Al Aswad] dari ['Aisyah radliallahu 'anha] berkata; \"Seakan aku melihat kilau minyak wangi pada bagian rambut Rasulullah shallallahu 'alaihi wasallam saat Beliau sedang berihram\". "},"1439":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكُنْتُ أُطَيِّبُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِإِحْرَامِهِ حِينَ يُحْرِمُ وَلِحِلِّهِ قَبْلَ أَنْ يَطُوفَ بِالْبَيْتِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari ['Abdurrahman bin Al Qasim] dari [bapaknya] dari ['Aisyah radliallahu 'anha] isteri Nabi shallallahu 'alaihi wasallam berkata: \"Aku pernah memakaikan wewangian kepada Rasulullah shallallahu 'alaihi wasallam untuk ihramnya saat Beliau berihram dan untuk hilalnya (tahallulnya) sebelum thawaf mengelilingi Ka'bah di Baitullah\". "},"1440":{"ar":"حَدَّثَنَا أَصْبَغُ أَخْبَرَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُهِلُّ مُلَبِّدًا","id":"Telah menceritakan kepada kami [Ashbagh] telah mengabarkan kepada kami [Ibnu Wahab] dari [Yunus] dari [Ibnu Syihab] dari [Salim] dari [bapaknya] radliallahu 'anhu berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam membaca talbiyyah (saat memulai ihram) dalam keadaan merekatkan rambutnya\". "},"1441":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ سَمِعْتُ سَالِمَ بْنَ عَبْدِ اللَّهِ قَالَ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ أَنَّهُ سَمِعَ أَبَاهُ يَقُولُمَا أَهَلَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا مِنْ عِنْدِ الْمَسْجِدِ يَعْنِي مَسْجِدَ ذِي الْحُلَيْفَةِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufan] telah menceritakan kepada kami [Musa bvin 'Uqbah]; aku mendengar [Salim bin 'Abdullah] berkata; Aku mendengar [Ibnu 'Umar radliallahu 'anhuma]. Dan diriwayatkan pula, telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Musa bin 'Uqbah] dari [Salim bin 'Abdullah] bahwa dia mendengar [bapaknya] berkata: \"Tidaklah Rasulullah shallallahu 'alaihi wasallam memulai ihram (bertalbiyah) melainkan dari masjid yaitu masjid yang ada di Dzul Hulaifah\". "},"1442":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ مَا يَلْبَسُ الْمُحْرِمُ مِنْ الثِّيَابِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَلْبَسُ الْقُمُصَ وَلَا الْعَمَائِمَ وَلَا السَّرَاوِيلَاتِ وَلَا الْبَرَانِسَ وَلَا الْخِفَافَ إِلَّا أَحَدٌ لَا يَجِدُ نَعْلَيْنِ فَلْيَلْبَسْ خُفَّيْنِ وَلْيَقْطَعْهُمَا أَسْفَلَ مِنْ الْكَعْبَيْنِ وَلَا تَلْبَسُوا مِنْ الثِّيَابِ شَيْئًا مَسَّهُ الزَّعْفَرَانُ أَوْ وَرْسٌ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhua] bahwa ada seorang laki-laki berkata, kepada Rasulullah Shallallahu'alaihiwasallam: \"Pakaian apa yang harus dikenakan oleh seorang muhrim (yang sedang berihram)?. Rasulullah shallallahu 'alaihi wasallam menjawab: \"Dia tidak boleh mengenakan baju, topi (sorban), celana, mantel kecuali sesorang yang tidak memiliki sandal, dia boleh mengenakan sapatu tapi dipotongnya hingga berada dibawah mata kaki dan tidak boleh pula memakai pakaian yang diberi minyak wangi atau wewangian dari daun tumbuhan\". "},"1443":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي عَنْ يُونُسَ الْأَيْلِيِّ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ أُسَامَةَ رَضِيَ اللَّهُ عَنْهُ كَانَ رِدْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عَرَفَةَ إِلَى الْمُزْدَلِفَةِ ثُمَّ أَرْدَفَ الْفَضْلَ مِنْ الْمزْدَلِفَةِ إِلَى مِنًى قَالَ فَكِلَاهُمَا قَالَ لَمْ يَزَلْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُلَبِّي حَتَّى رَمَى جَمْرَةَ الْعَقَبَةِ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Wahab bin Jarir] telah menceritakan kepada kami [bapakku] dari [Yunus Al Ailiyya] dari [Az Zuhriy] dari ['Ubaidullah bin 'Abdullah] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa [Usamah radliallahu 'anhu] pernah berboncengan dengan Nabi shallallahu 'alaihi wasallam dari 'Arafah hingga ke Al Muzdalifah, kemudian Beliau membonceng [Al Fadhal] dari Al Muzdalifah hingga ke Mina. Dia berkata; Pada kedua perjalanan itu senantiasa Nabi shallallahu 'alaihi wasallam bertalbiyyah hingga Beliau melempar jumrah Al 'Aqabah."},"1444":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا فُضَيْلُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي مُوسَى بْنُ عُقْبَةَ قَالَ أَخْبَرَنِي كُرَيْبٌ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَانْطَلَقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمَدِينَةِ بَعْدَ مَا تَرَجَّلَ وَادَّهَنَ وَلَبِسَ إِزَارَهُ وَرِدَاءَهُ هُوَ وَأَصْحَابُهُ فَلَمْ يَنْهَ عَنْ شَيْءٍ مِنْ الْأَرْدِيَةِ وَالْأُزُرِ تُلْبَسُ إِلَّا الْمُزَعْفَرَةَ الَّتِي تَرْدَعُ عَلَى الْجِلْدِ فَأَصْبَحَ بِذِي الْحُلَيْفَةِ رَكِبَ رَاحِلَتَهُ حَتَّى اسْتَوَى عَلَى الْبَيْدَاءِ أَهَلَّ هُوَ وَأَصْحَابُهُ وَقَلَّدَ بَدَنَتَهُ وَذَلِكَ لِخَمْسٍ بَقِينَ مِنْ ذِي الْقَعْدَةِ فَقَدِمَ مَكَّةَ لِأَرْبَعِ لَيَالٍ خَلَوْنَ مِنْ ذِي الْحَجَّةِ فَطَافَ بِالْبَيْتِ وَسَعَى بَيْنَ الصَّفَا وَالْمَرْوَةِ وَلَمْ يَحِلَّ مِنْ أَجْلِ بُدْنِهِ لِأَنَّهُ قَلَّدَهَا ثُمَّ نَزَلَ بِأَعْلَى مَكَّةَ عِنْدَ الْحَجُونِ وَهُوَ مُهِلٌّ بِالْحَجِّ وَلَمْ يَقْرَبْ الْكَعْبَةَ بَعْدَ طَوَافِهِ بِهَا حَتَّى رَجَعَ مِنْ عَرَفَةَ وَأَمَرَ أَصْحَابَهُ أَنْ يَطَّوَّفُوا بِالْبَيْتِ وَبَيْنَ الصَّفَا وَالْمَرْوَةِ ثُمَّ يُقَصِّرُوا مِنْ رُءُوسِهِمْ ثُمَّ يَحِلُّوا وَذَلِكَ لِمَنْ لَمْ يَكُنْ مَعَهُ بَدَنَةٌ قَلَّدَهَا وَمَنْ كَانَتْ مَعَهُ امْرَأَتُهُ فَهِيَ لَهُ حَلَالٌ وَالطِّيبُ وَالثِّيَابُ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakar Al Muqaddamiy] telah menceritakan kepada kami [Fudhail bin Sulaiman] berkata, telah menceritakan kepada saya [Musa bin 'Uqbah] berkata, telah mengabarkan kepada saya [Kuraib] dari ['Abdullah bin 'Abbas RAa] berkata: \"Nabi shallallahu 'alaihi wasallam berangkat dari Madinah setelah Beliau menyisir rambutnya dan memolesnya dengan minyak zaitun. Dan Beliau mengenakan baju dan rida'nya, begitu juga para sahabat Beliau. Beliau tidak melarang apapun mengenai rida' (selendang panjang) dan baju untuk dipakai kecuali minyak wangi (za'faran) yang masih tersisa pada kulit badan. Ketika paginya berada di Dzul Hulaifah, Beliau berangkat dengan mengendarai tunggangannya hingga sampai di padang sahara saat siang hari. Maka disitulah Beliau memulai ihram dengan bertalbiyyah begitu juga para sahabatnya. Lalu Beliau menandai hewan qurbannya. Ini terjadi pada lima hari terakhir dari bulan Dzul Qa'dah. Lalu Beliau sampai di Makkah pada malam keempat dari bulan Dzul Hijjah lalu Beliau melaksanakan thowaf di Baitulloh, lalu sa'i antara bukit Shafaa dan Marwah dan Beliau belum lagi bertahallul karena Beliau membawa hewan qurban yang telah ditandainya. Kemudian Beliau singgah di tempat yang tinggi di kota Makkah di Al Hajjun, yang dari tempat itu Beliau berniat memulai hajji. Beliau tidak mendekati Ka'bah setelah melaksanakan thowafnya disana hingga Beliau kembali dari 'Arafah lalu Beliau memerintahkan para sahabatnya agar melaksanakan thowaf di Baitulloh dan sa'iy antara bukit Shafaa dan Marwah kemudian memerintahkan pula agar mereka memotong rambut mereka lalu bertahallul. Ketentuan ini berlaku bagi mereka yang tidak membawa hewan sembelihan (qurban). Maka barangsiapa yang ada isterinya bersamanya, isterinya itu halal baginya begitu juga memakai wewangian dan pakaian (baju)."},"1445":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ أَخْبَرَنَا ابْنُ جُرَيْجٍ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُنْكَدِرِ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ أَرْبَعًا وَبِذِي الْحُلَيْفَةِ رَكْعَتَيْنِ ثُمَّ بَاتَ حَتَّى أَصْبَحَ بِذِي الْحُلَيْفَةِ فَلَمَّا رَكِبَ رَاحِلَتَهُ وَاسْتَوَتْ بِهِ أَهَلَّ","id":"Telah menceritakan kepada saya ['Abdullah bin Muhammad] telah menceritakan kepada kami [Hisam bin Yusuf] telah mengabarkan kepada kami [Ibnu Juraij] telah menceritakan kepada kami [Muhammad bin Al Munkadir] dari [Anas bin Malik radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam melaksanakan shalat di Madinah empat raka'at dan di Dzul Hulaifah dua raka'at kemudian bermalam di Dzul Hulaifah sampai pagi. Ketika Beliau berangkat dengan tunggangannya dan sampai siang hari, Beliau memulai ihram\"."},"1446":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ بِالْمَدِينَةِ أَرْبَعًا وَصَلَّى الْعَصْرَ بِذِي الْحُلَيْفَةِ رَكْعَتَيْنِ قَالَ وَأَحْسِبُهُ بَاتَ بِهَا حَتَّى أَصْبَحَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami ['Abdul Wahhab] telah menceritakan kepada kami [Ayyub] dari [Abu Qalabah] dari [Anas bin Malik radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam melaksanakan shalat Zhuhur di Madinah empat raka'at dan shalat 'Ashar di Dzul Hulaifah dua raka'at. Dia (Abu Qalabah) berkata: \"Aku menduga dia berkata; Beliau Shallallahu'alaihiwasallam bermalam disana hingga pagi\"."},"1447":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ الظُّهْرَ أَرْبَعًا وَالْعَصْرَ بِذِي الْحُلَيْفَةِ رَكْعَتَيْنِ وَسَمِعْتُهُمْ يَصْرُخُونَ بِهِمَا جَمِيعًا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qalabah] dari [Anas radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam melaksanakan shalat Zhuhur di Madinah empat raka'at dan shalat 'Ashar di Dzul Hulaifah dua raka'at. Dan aku mendengar mereka melakukan talbiyah dengan mengeraskan suara mereka pada keduanya (hajji dan 'umrah)."},"1448":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ تَلْبِيَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ لَبَّيْكَ لَا شَرِيكَ لَكَ لَبَّيْكَ إِنَّ الْحَمْدَ وَالنِّعْمَةَ لَكَ وَالْمُلْكَ لَا شَرِيكَ لَكَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhua] bahwa cara talbiyah Rasulullah shallallahu 'alaihi wasallam adalah: \"Labbaikallahumma labbaik. Labbaika laa syariika laka labbaik. Innal hamda wan ni'mata laka wal mulk. Laa syariika lak\". (\"Aku datang memenuhi panggilanMu ya Allah. Aku datang memenuhi panggilanMu tidak ada sekutu bagiMu. Sesungguhnya segala puji, nikmat milikMU begitu pula kerajaan. Tidak ada sekutu bagiMu\")."},"1449":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ عَنْ أَبِي عَطِيَّةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْإِنِّي لَأَعْلَمُ كَيْفَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُلَبِّي لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ لَبَّيْكَ لَا شَرِيكَ لَكَ لَبَّيْكَ إِنَّ الْحَمْدَ وَالنِّعْمَةَ لَكَتَابَعَهُ أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ وَقَالَ شُعْبَةُ أَخْبَرَنَا سُلَيْمَانُ سَمِعْتُ خَيْثَمَةَ عَنْ أَبِي عَطِيَّةَ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari ['Umarah] dari [Abu 'Athiyyah] dari ['Aisyah radliallahu 'anha] berkata; Sungguh aku mengetahui bagaimana cara Nabi shallallahu 'alaihi wasallam bertalbiyah: bahwa cara talbiyah Rasulullah shallallahu 'alaihi wasallam adalah: \"Labbaikallahumma labbaik. Labbaika laa syariika laka labbaik. Innal hamda wan ni'mata \". (\"Aku datang memenuhi panggilanMu ya Allah. Aku datang memenuhi panggilanMu tidak ada sekutu bagiMu. Sesungguhnya segala puji, nikmat milikMu\"). Hadits ini dikuatkan pula oleh [Abu Mu'awiyah] dari [Al A'masy] dan berkata, [Syu'bah] telah mengabarkan kepada kami [Sulaiman] aku mendengar [Khaitsamah] dari [Abu 'Athiyyah] aku mendengar dari ['Aisyah radliallahu 'anha]."},"1450":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ مَعَهُ بِالْمَدِينَةِ الظُّهْرَ أَرْبَعًا وَالْعَصْرَ بِذِي الْحُلَيْفَةِ رَكْعَتَيْنِ ثُمَّ بَاتَ بِهَا حَتَّى أَصْبَحَ ثُمَّ رَكِبَ حَتَّى اسْتَوَتْ بِهِ عَلَى الْبَيْدَاءِ حَمِدَ اللَّهَ وَسَبَّحَ وَكَبَّرَ ثُمَّ أَهَلَّ بِحَجٍّ وَعُمْرَةٍ وَأَهَلَّ النَّاسُ بِهِمَا فَلَمَّا قَدِمْنَا أَمَرَ النَّاسَ فَحَلُّوا حَتَّى كَانَ يَوْمُ التَّرْوِيَةِ أَهَلُّوا بِالْحَجِّ قَالَ وَنَحَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَدَنَاتٍ بِيَدِهِ قِيَامًا وَذَبَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ كَبْشَيْنِ أَمْلَحَيْنِقَالَ أَبُو عَبْد اللَّهِ قَالَ بَعْضُهُمْ هَذَا عَنْ أَيُّوبَ عَنْ رَجُلٍ عَنْ أَنَسٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ayyub] dari [Abu Qalabah] dari [Anas radliallahu 'anhu] berkata; Bahwa Nabi shallallahu 'alaihi wasallam melaksanakan shalat Zhuhur, sedangkan kami bersama Beliau, di Madinah empat raka'at dan shalat 'Ashar di Dzul Hulaifah dua raka'at. Kemudian Beliau Shallallahu'alaihiwasallam bermalam disana hingga pagi. Kemudian mengendara tunggangannya hingga siang hari saat tiba di adang sahara lalu Beliau memuji Allah, bertasbih dan bertakbir kemudian berihram (berniat) hajji dan 'umrah begitu juga orang-orang ikut berihran. Ketika kami telah tiba (di Makkah), Beliau memerintahkan orang-orang agar bertahallul hingga tiba hari tarwiah (tanggal 8 Dzul Hijjah), orang-orang berihram untuk niat hajji. Anas radliallahu 'anhu berkata: \"Kemudian Nabi shallallahu 'alaihi wasallam berqurban dua ekor sapi dengan tangan Beliau sendiri sambil berdiri. Rasulullah shallallahu 'alaihi wasallam juga menyembelih dua ekor kambing yang gemuk\". Berkata, Abu 'Abdullah Al Bukhari; Sebagian mereka berkata, hadits ini dari Ayyub dari seseorang dari Anas radliallahu 'anhu."},"1451":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي صَالِحُ بْنُ كَيْسَانَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَهَلَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ اسْتَوَتْ بِهِ رَاحِلَتُهُ قَائِمَةً","id":"Telah menceritakan kepada kami [Abu 'Ashim] telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepada saya [Shalih bin Kaisan] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] berkata; \"Nabi shallallahu 'alaihi wasallam berihram ketika hewan tunggangannya sedang berdiri tegak\"."},"1452":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ أَبُو الرَّبِيعِ حَدَّثَنَا فُلَيْحٌ عَنْ نَافِعٍ قَالَ كَانَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاإِذَا أَرَادَ الْخُرُوجَ إِلَى مَكَّةَ ادَّهَنَ بِدُهْنٍ لَيْسَ لَهُ رَائِحَةٌ طَيِّبَةٌ ثُمَّ يَأْتِي مَسْجِدَ ذِي الْحُلَيْفَةِ فَيُصَلِّي ثُمَّ يَرْكَبُ وَإِذَا اسْتَوَتْ بِهِ رَاحِلَتُهُ قَائِمَةً أَحْرَمَ ثُمَّ قَالَ هَكَذَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Abu Ar-Rabi'] telah menceritakan kepada kami [Filaih] dari [Nafi'] berkata; \"Adalah [Ibnu 'Umar radliallahu 'anhuma] apabila hendak keluar menuju Makkah (untuk berhajji) dia memakai pakaian yang tidak menggunakan wewangian kemudian memasuki masjid Dzul Halaifah lalu shalat kemudian menaiki tunggangannya. Dan apabila tunggangannya sudah berdiri tegak dia memulai ihram kemudian berkata: \"Beginilah aku melihat Nabi shallallahu 'alaihi wasallam melaksanakannya\" (memulai ihram untuk hajji). "},"1453":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنِي ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ عَوْنٍ عَنْ مُجَاهِدٍ قَالَ كُنَّا عِنْدَ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَافَذَكَرُوا الدَّجَّالَ أَنَّهُ قَالَ مَكْتُوبٌ بَيْنَ عَيْنَيْهِ كَافِرٌ فَقَالَ ابْنُ عَبَّاسٍ لَمْ أَسْمَعْهُ وَلَكِنَّهُ قَالَ أَمَّا مُوسَى كَأَنِّي أَنْظُرُ إِلَيْهِ إِذْ انْحَدَرَ فِي الْوَادِي يُلَبِّي","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsannaa] berkata, telah menceritakan kepadaku [Ibnu Abu 'Adiy] dari [Ibnu 'Aun] dari [Mujahid] berkata; Kami pernah bersama [Ibnu 'Abbas radliallahu 'anhuma] lalu orang-orang menyebut tentang Dajjal bahwasanya Beliau Shallallahu'alaihiwasallam menceritakan bahwa diantara kedua mata ad-Dajjal tertulis kata \"kafir\". Maka Ibnu 'Abbas radliallahu 'anhuma berkata: \"Aku belum pernah mendengarnya. Akan tetapi Beliau bersabda: \"Adapun Musa Alaihissalam seolah aku melihatnya ketika menuruni lembah dia bertalbiyah\"."},"1454":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْخَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ فَأَهْلَلْنَا بِعُمْرَةٍ ثُمَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ مَعَهُ هَدْيٌ فَلْيُهِلَّ بِالْحَجِّ مَعَ الْعُمْرَةِ ثُمَّ لَا يَحِلَّ حَتَّى يَحِلَّ مِنْهُمَا جَمِيعًا فَقَدِمْتُ مَكَّةَ وَأَنَا حَائِضٌ وَلَمْ أَطُفْ بِالْبَيْتِ وَلَا بَيْنَ الصَّفَا وَالْمَرْوَةِ فَشَكَوْتُ ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ انْقُضِي رَأْسَكِ وَامْتَشِطِي وَأَهِلِّي بِالْحَجِّ وَدَعِي الْعُمْرَةَ فَفَعَلْتُ فَلَمَّا قَضَيْنَا الْحَجَّ أَرْسَلَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ إِلَى التَّنْعِيمِ فَاعْتَمَرْتُ فَقَالَ هَذِهِ مَكَانَ عُمْرَتِكِ قَالَتْ فَطَافَ الَّذِينَ كَانُوا أَهَلُّوا بِالْعُمْرَةِ بِالْبَيْتِ وَبَيْنَ الصَّفَا وَالْمَرْوَةِ ثُمَّ حَلُّوا ثُمَّ طَافُوا طَوَافًا آخَرَ بَعْدَ أَنْ رَجَعُوا مِنْ مِنًى وَأَمَّا الَّذِينَ جَمَعُوا الْحَجَّ وَالْعُمْرَةَ فَإِنَّمَا طَافُوا طَوَافًا وَاحِدًا","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari ['Aisyah radliallahu 'anha], isteri Nabi shallallahu 'alaihi wasallam berkata: \"Kami keluar bersama Nabi shallallahu 'alaihi wasallam saat hajji wada' lalu kami berihram untuk 'umrah. Nabi shallallahu 'alaihi wasallam kemudian berkata: \"Barangsiapa yang membawa hewan sembelihan hendaklah dia berihram untuk hajji sekaligus 'umrah kemudian dia tidak bertahallul hingga bertahallul untuk keduanya (hajji dan 'umrah) \". Maka aku tiba di Makkah sedang aku dalam keadaan mengalami haidh sehinga aku tidak melakukan thowaf di Baitulloh dan juga tidak melakuka sa'iy antara bukit Ash-Shafa dan Al Marwah. Lalu aku adukan kondisiku itu kepada Nabi Shallallahu'alaihiwasallam. Maka Beliau bersabda: \"Uraikanlah rambutmu dan sisirlah dan berihramlah untuk hajji dan tinggalkan 'umrah\". Maka kemudian aku laksanakan. Setelah kami selesai menunaikan manasik hajji, Nabi shallallahu 'alaihi wasallam mengutusku bersama 'Abdurrahman bin Abu Bakar menuju Tan'im yang dari tempat itu aku harus memulai 'umrah. Beliau berkata: \"Ini pengganti 'umrahmu\" 'Aisyah radliallahu 'anha berkata: \"Maka orang-orang yang berihram untuk 'umrah melakukan thowaf di Baitulloh dan sa'iy antara bukit Ash-Shafa dan Al Marwah lalu mereka bertahallul kemudian mereka thowaf yang lain lagi setelah kembali dari Mina. Adapun orang-orang yang menggabungkan hajji dan 'umrah mereka hanya melakukan thowaf satu kali\"."},"1455":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ عَنْ ابْنِ جُرَيْجٍ قَالَ عَطَاءٌ قَالَ جَابِرٌ رَضِيَ اللَّهُ عَنْهُأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ أَنْ يُقِيمَ عَلَى إِحْرَامِهِوَذَكَرَ قَوْلَ سُرَاقَةَ وَزَادَ مُحَمَّدُ بْنُ بَكْرٍ عَنْ ابْنِ جُرَيْجٍ قَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا أَهْلَلْتَ يَا عَلِيُّ قَالَ بِمَا أَهَلَّ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَهْدِ وَامْكُثْ حَرَامًا كَمَا أَنْتَ","id":"Telah menceritakan kepada kami [Al Makkiy bin Ibrahim] dari [Ibnu Juraij], ['Atho'] berkata, [Jabir radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam memerintah 'Ali radliallahu 'anhu agar tetap menjaga ihramnya, lalu Beliau menyebutkan ucapan Suraqah. [Muhammad bin Bakar] menambahkan dari [Ibnu Juraij] Nabi shallallahu 'alaihi wasallam bertanya kepadanya ('Ali): \"Wahai 'Ali, bagaimana cara kamu berihram (memulai hajji)?\". Dia menjawab: \"Aku berihram sebagaimana Nabi shallallahu 'alaihi wasallam berihram\". Maka Beliau bersabda: \"Berkurbanlah dan jagalah keadaanmu tetap dalam keadaan berihram\"."},"1456":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ الْهُذَلِيُّ حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا سَلِيمُ بْنُ حَيَّانَ قَالَ سَمِعْتُ مَرْوَانَ الْأَصْفَرَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَدِمَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْيَمَنِ فَقَالَ بِمَا أَهْلَلْتَ قَالَ بِمَا أَهَلَّ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَوْلَا أَنَّ مَعِي الْهَدْيَ لَأَحْلَلْتُ","id":"Telah menceritakan kepada kami [Al Hasan bin'Ali Al Khallal Al Hudzliy] telah menceritakan kepada kami ['Adush Shamad] telah menceritakan kepada kami [Salim bin Hayan] berkata; Aku mendengar [Marwan Al Ashfar] dari [Anas bin Malik radliallahu 'anhu] berkata: \"Ali radliallahu 'anhu tiba di Makkah dari Yaman mendahului Nabi Shallallahu'alaihiwasallam. Beliau bertanya kepadanya: \"Bagaimana cara kamu berihram (memulai hajji)?\". Dia menjawab: \"Aku berihram sebagaimana Nabi shallallahu 'alaihi wasallam berihram\". Maka Beliau bersabda: \"Seandainya aku tidak membawa hewan qurban pasti aku sudah bertahallul\"."},"1457":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَبَعَثَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى قَوْمٍ بِالْيَمَنِ فَجِئْتُ وَهُوَ بِالْبَطْحَاءِ فَقَالَ بِمَا أَهْلَلْتَ قُلْتُ أَهْلَلْتُ كَإِهْلَالِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَلْ مَعَكَ مِنْ هَدْيٍ قُلْتُ لَا فَأَمَرَنِي فَطُفْتُ بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ ثُمَّ أَمَرَنِي فَأَحْلَلْتُ فَأَتَيْتُ امْرَأَةً مِنْ قَوْمِي فَمَشَطَتْنِي أَوْ غَسَلَتْ رَأْسِي فَقَدِمَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فَقَالَ إِنْ نَأْخُذْ بِكِتَابِ اللَّهِ فَإِنَّهُ يَأْمُرُنَا بِالتَّمَامِ قَالَ اللَّهُ{ وَأَتِمُّوا الْحَجَّ وَالْعُمْرَةَ لِلَّهِ }وَإِنْ نَأْخُذْ بِسُنَّةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّهُ لَمْ يَحِلَّ حَتَّى نَحَرَ الْهَدْيَ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Qais bin Muslim] dari [Thoriq bin Syihab] dari [Abu Musa radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam mengutusku kepada suatu kaum di negeri Yaman. Ketika aku sudah kembali aku menemui Beliau ketika Beliau berada di Batha'. Beliau berkata, kepadaku: \"Bagaimana cara kamu berihram (memulai hajji)?\". Aku menjawab: \"Aku berihram sebagaimana Nabi shallallahu 'alaihi wasallam berihram\". Beliau bertanya lagi: \"Apakah kamu ada membawa hewan qurban?. Aku menjawab: \"Tidak\". Maka Beliau memerintahkan aku agar aku melakukan thowaf di Baitulloh dan sa'iy antara bukit Ash-Shafa dan Al Marwah lalu memerintahkan aku pula agar aku bertahallul. Lalu aku temui seorang wanita dari keluargaku lalu dia menyisir rambutku atau membasuh kepalaku. Lalu 'Umar radliallahu 'anhu datang dan berkata: \"Jika kita mengambil pedoman dari Kitab Allah, sesungguhnya Dia memerintahkan kita agar kita menyempurnakannya (hajji dan 'umrah). Allah subhanahu wata'ala berfirman (Qs Al Baqarah ayat 196) yang artinya: (\"Dan semprurnakanlah 'ibadah hajji dan 'umrah kalian karena Allah) \", dan seandainya kita mengambil pedoman dari sunnah Rasulullah Shallallahu'alaihiwasallam, sesungguhnya Beliau tidak bertahallul kecuali setelah menyembelih hewan qurban\". "},"1458":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنِي أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا أَفْلَحُ بْنُ حُمَيْدٍ سَمِعْتُ الْقَاسِمَ بْنَ مُحَمَّدٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَشْهُرِ الْحَجِّ وَلَيَالِي الْحَجِّ وَحُرُمِ الْحَجِّ فَنَزَلْنَا بِسَرِفَ قَالَتْ فَخَرَجَ إِلَى أَصْحَابِهِ فَقَالَ مَنْ لَمْ يَكُنْ مِنْكُمْ مَعَهُ هَدْيٌ فَأَحَبَّ أَنْ يَجْعَلَهَا عُمْرَةً فَلْيَفْعَلْ وَمَنْ كَانَ مَعَهُ الْهَدْيُ فَلَا قَالَتْ فَالْآخِذُ بِهَا وَالتَّارِكُ لَهَا مِنْ أَصْحَابِهِ قَالَتْ فَأَمَّا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرِجَالٌ مِنْ أَصْحَابِهِ فَكَانُوا أَهْلَ قُوَّةٍ وَكَانَ مَعَهُمْ الْهَدْيُ فَلَمْ يَقْدِرُوا عَلَى الْعُمْرَةِ قَالَتْ فَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَبْكِي فَقَالَ مَا يُبْكِيكِ يَا هَنْتَاهُ قُلْتُ سَمِعْتُ قَوْلَكَ لِأَصْحَابِكَ فَمُنِعْتُ الْعُمْرَةَ قَالَ وَمَا شَأْنُكِ قُلْتُ لَا أُصَلِّي قَالَ فَلَا يَضِيرُكِ إِنَّمَا أَنْتِ امْرَأَةٌ مِنْ بَنَاتِ آدَمَ كَتَبَ اللَّهُ عَلَيْكِ مَا كَتَبَ عَلَيْهِنَّ فَكُونِي فِي حَجَّتِكِ فَعَسَى اللَّهُ أَنْ يَرْزُقَكِيهَا قَالَتْ فَخَرَجْنَا فِي حَجَّتِهِ حَتَّى قَدِمْنَا مِنًى فَطَهَرْتُ ثُمَّ خَرَجْتُ مِنْ مِنًى فَأَفَضْتُ بِالْبَيْتِ قَالَتْ ثُمَّ خَرَجَتْ مَعَهُ فِي النَّفْرِ الْآخِرِ حَتَّى نَزَلَ الْمُحَصَّبَ وَنَزَلْنَا مَعَهُ فَدَعَا عَبْدَ الرَّحْمَنِ بْنَ أَبِي بَكْرٍ فَقَالَ اخْرُجْ بِأُخْتِكَ مِنْ الْحَرَمِ فَلْتُهِلَّ بِعُمْرَةٍ ثُمَّ افْرُغَا ثُمَّ ائْتِيَا هَا هُنَا فَإِنِّي أَنْظُرُكُمَا حَتَّى تَأْتِيَانِي قَالَتْ فَخَرَجْنَا حَتَّى إِذَا فَرَغْتُ وَفَرَغْتُ مِنْ الطَّوَافِ ثُمَّ جِئْتُهُ بِسَحَرَ فَقَالَ هَلْ فَرَغْتُمْ فَقُلْتُ نَعَمْ فَآذَنَ بِالرَّحِيلِ فِي أَصْحَابِهِ فَارْتَحَلَ النَّاسُ فَمَرَّ مُتَوَجِّهًا إِلَى الْمَدِينَةِضَيْرِ مِنْ ضَارَ يَضِيرُ ضَيْرًا وَيُقَالُ ضَارَ يَضُورُ ضَوْرًا وَضَرَّ يَضُرُّ ضَرًّا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada saya [Abu Bakar Al Hanafiy] telah menceritakan kepada kami [Aflah bin Humaid]; aku mendengar [Al Qasim bin Muhammad] dari ['Aisyah radliallahu 'anha] berkata: \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam pada bulan haji dan malam-malam bulan hajji serta hari-hari haram haji hingga kami singgah di daerah Saraf. 'Aisyah radliallahu 'anha berkata: \"Maka Beliau keluar menemui para sahabatnya lalu berkata: \"Barangsiapa diantara kalian yang tidak membawa hewan qurban dan ia lebih suka bila menjadikan ihramnya sebagai 'umrah, maka lakukanlah dan barangsiapa yang membawa hewan qurban tidak apa\". 'Aisyah radliallahu 'anha berkata: \"Maka diantara para sahabat Nabi shallallahu 'alaihi wasallam ada yang mengambilnya (apa yang diserukan oleh Beliau) dan ada juga yang meninggalkannya\". 'Aisyah radliallahu 'anha berkata: \"Adapun Nabi shallallahu 'alaihi wasallam dan beberapa orang dari para sahabatnya adalah termasuk orang-orang yang kuat dan mereka membawa hewan qurban maka mereka tidak mengambil ihram mereka sebagai 'umrah\". 'Aisyah radliallahu 'anha berkata: \"Kemudian Rasulullah shallallahu 'alaihi wasallam menemuiku sedangkan aku ketika itu sedang menangis, maka Beliau bertanya: \"Wahai gerangan, apa yang membuatmu menangis,?\" Aku menjawab: \"Aku telah mendengar apa yang anda katakan kepada para sahabat anda sehingga aku terhalang melakukan 'umrah\". Beliau bertanya: \"Memang apa yang sedang kamu alami?\". Aku menjawab: \"Aku tidak shalat\". Beliau berkata: \"Tidak apa, karena kamu hanyalah seorang wanita dari putri-putri Adam yang Allah telah menetapkan untuk mereka ketentuan (maksudnya haidh), maka laksanakanlah hajjimu semoga Allah subhanahu wata'ala memberikan pahala dengannya\". 'Aisyah radliallahu 'anha berkata: \"Maka kemudian kami keluar dalam pelaksanaan hajji Beliau hingga kami tiba di Mina yang ketika itu aku telah kembali suci. Kemudian aku keluar dari Mina lalu menuntaskan manasik di Baitulloh\". 'Aisyah radliallahu 'anha berkata: \"Kemudian aku keluar bersama Beliau pada nafar akhir hingga Beliau sampai di tempat melempar Jumrah dan kamipun ikut berhenti bersama Beliau. Kemudian Beliau memanggil 'Abdurrahman bin Abu Bakar seraya berkata: \"Keluarlah kamu bersama saudaramu ini dari tanah haram dan lakukanlah ihram untuk 'umrah lalu selesaikanlah manasik lalu datanglah kalian berdua kesini karena aku akan menunggu kalian hingga kalian datang\". 'Aisyah radliallahu 'anha berkata; \"Maka kami berdua keluar hingga saat aku sudah selesai (dari 'umrahku) dan menyelesaikan thowafku aku datang menemui Beliau pada waktu sahar (sepertiga akhir malam) lalu Beliau bertanya: \"Apakah kalian sudah selesai?\". Aku menjawab: \"Ya sudah\". Maka Beliau mengumumkan keberangkatan kepada para sahabatnya. Maka orang-orang berangkat dan berjalan menuju Madinah\". Sabda Nabi Shallallahu'alaihiwasallam \"dhair\":. Kata kerja bisa berasal dari \"dhaoro-yadhiiru\" yang kesemuanya memiliki arti: \"membahayakan\" atau \"merugikan\". "},"1459":{"ar":"حَدَّثَنَا عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاخَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا نُرَى إِلَّا أَنَّهُ الْحَجُّ فَلَمَّا قَدِمْنَا تَطَوَّفْنَا بِالْبَيْتِ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَمْ يَكُنْ سَاقَ الْهَدْيَ أَنْ يَحِلَّ فَحَلَّ مَنْ لَمْ يَكُنْ سَاقَ الْهَدْيَ وَنِسَاؤُهُ لَمْ يَسُقْنَ فَأَحْلَلْنَ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا فَحِضْتُ فَلَمْ أَطُفْ بِالْبَيْتِ فَلَمَّا كَانَتْ لَيْلَةُ الْحَصْبَةِ قَالَتْ يَا رَسُولَ اللَّهِ يَرْجِعُ النَّاسُ بِعُمْرَةٍ وَحَجَّةٍ وَأَرْجِعُ أَنَا بِحَجَّةٍ قَالَ وَمَا طُفْتِ لَيَالِيَ قَدِمْنَا مَكَّةَ قُلْتُ لَا قَالَ فَاذْهَبِي مَعَ أَخِيكِ إِلَى التَّنْعِيمِ فَأَهِلِّي بِعُمْرَةٍ ثُمَّ مَوْعِدُكِ كَذَا وَكَذَا قَالَتْ صَفِيَّةُ مَا أُرَانِي إِلَّا حَابِسَتَهُمْ قَالَ عَقْرَى حَلْقَى أَوَ مَا طُفْتِ يَوْمَ النَّحْرِ قَالَتْ قُلْتُ بَلَى قَالَ لَا بَأْسَ انْفِرِي قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا فَلَقِيَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُصْعِدٌ مِنْ مَكَّةَ وَأَنَا مُنْهَبِطَةٌ عَلَيْهَا أَوْ أَنَا مُصْعِدَةٌ وَهُوَ مُنْهَبِطٌ مِنْهَا","id":"Telah menceritakan kepada kami ['Utsman] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah radliallahu 'anha]; \"Kami berangkat bersama Nabi shallallahu 'alaihi wasallam dan setahu kami, tidaklah beliau berangkat melainkan untuk melaksanakan hajji. Ketika kami telah sampai (di Makkah), kami melaksanakan thowaf di Baitulloh, maka kemudian Nabi shallallahu 'alaihi wasallam memerintahkan siapa yang tidak membawa hewan qurban agar bertahallul. Maka orang yang tidak membawa hewan qurban bertahallul begitu juga isteri-isteri Beliau yang tidak membawa hewan qurban mereka bertahallul\". 'Aisyah radliallahu 'anha berkata: \"Kemudian aku mengalami haidh sedangkan aku belum melaksanakan thowaf di Baitulloh. Ketika pada malam saat para hujjaj keluar dari (Makkah setelah hari-hari Tasyriq), 'Aisyah radliallahu 'anha berkata: \"Wahai Rasulullah, orang-orang kembali dengan 'umrah dan hajji sedangkan aku hanya kembali dengan hajji\". Beliau berkata: \"Apakah kamu melaksanakan thowaf pada malam-malam bulan hajji ketika kita sampai di Makkah?\". Aku jawab: \"Tidak\". Beliau berkata: \"Pergilah kamu bersama saudaramu ke Tan'im dan mulailah dari sana berihram untuk 'umrah kemudian tempat kamu begini begini\". Shafiyyah berkata: \"Aku tidak melihat kecuali dia ('Aisyah radliallahu 'anha) telah menjadikan orang-orang tertahan (perjalanan pulangnya) \". Beliau Shallallahu'alaihiwasallam berkata: \"Celaka\" atau \"Apakah kamu tidak thowaf pada hari Nahar\". 'Aisyah radliallahu 'anha menjawab: \"Benar\" Beliau berkata: \"Tidak apa, nafarlah (keluar dari Mina setelah menuntaskan manasik hajji) \". 'Aisyah radliallahu 'anha berkata: \"Kemudian aku menemui Nabi shallallahu 'alaihi wasallam saat Beliau tiba dari Makkah sedangkan aku sudah lebih dulu singgah atau aku baru tiba sedang Beliau sudah singgah dari Makkah."},"1460":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الْأَسْوَدِ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ حَجَّةِ الْوَدَاعِ فَمِنَّا مَنْ أَهَلَّ بِعُمْرَةٍ وَمِنَّا مَنْ أَهَلَّ بِحَجَّةٍ وَعُمْرَةٍ وَمِنَّا مَنْ أَهَلَّ بِالْحَجِّ وَأَهَلَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحَجِّ فَأَمَّا مَنْ أَهَلَّ بِالْحَجِّ أَوْ جَمَعَ الْحَجَّ وَالْعُمْرَةَ لَمْ يَحِلُّوا حَتَّى كَانَ يَوْمُ النَّحْرِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Abu Al Aswad Muhammad bin 'Abdurrahman bin Naufal] dari ['Urwah bin Az Zubair] dari ['Aisyah radliallahu 'anha] berkata: \"Kami berangkat bersama Nabi shallallahu 'alaihi wasallam pada tahun hajji wada' (perpisahan). Diantara kami ada yang berihram untuk 'umrah, ada yang berihram untuk hajji dan 'umrah dan ada pula yang berihram untuk hajji. Sedangkan Rasulullah shallallahu 'alaihi wasallam berihram untuk hajji. Adapun orang yang berihram untuk hajji atau menggabungkan hajji dan 'umrah maka mereka tidak bertahallul sampai hari nahar (tanggal 10 Dzul Hijjah) \". "},"1461":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ مَرْوَانَ بْنِ الْحَكَمِ قَالَ شَهِدْتُ عُثْمَانَ وَعَلِيًّا رَضِيَ اللَّهُ عَنْهُمَاوَعُثْمَانُ يَنْهَى عَنْ الْمُتْعَةِ وَأَنْ يُجْمَعَ بَيْنَهُمَا فَلَمَّا رَأَى عَلِيٌّأَهَلَّ بِهِمَا لَبَّيْكَ بِعُمْرَةٍ وَحَجَّةٍ قَالَ مَا كُنْتُ لِأَدَعَ سُنَّةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِقَوْلِ أَحَدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari ['Ali bin Husain] dari [Marwan bin Al Hakam] berkata: \"Aku menyaksikan ['Utsman] dan ['Ali radliallahu 'anhuma] melarang mengerjakan hajji dengan cara tamattu' dan agar pelaksanaan keduanya digabungkan. Ketika aku melihat 'Ali berihram untuk keduanya (dengan niat atau talbiyyah); \"labbaika bi'umrah wa hajjah (Ya Allah aku penuhi panggilanMu dan aku berniat untuk 'umrah dan hajji), dia berkata: \"Aku tidak akan meninggalkan sunnah Nabi shallallahu 'alaihi wasallam hanya karena perkataan seseorang\"."},"1462":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانُوا يَرَوْنَ أَنَّ الْعُمْرَةَ فِي أَشْهُرِ الْحَجِّ مِنْ أَفْجَرِ الْفُجُورِ فِي الْأَرْضِ وَيَجْعَلُونَ الْمُحَرَّمَ صَفَرًا وَيَقُولُونَ إِذَا بَرَا الدَّبَرْ وَعَفَا الْأَثَرْ وَانْسَلَخَ صَفَرْ حَلَّتْ الْعُمْرَةُ لِمَنْ اعْتَمَرْ قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ صَبِيحَةَ رَابِعَةٍ مُهِلِّينَ بِالْحَجِّ فَأَمَرَهُمْ أَنْ يَجْعَلُوهَا عُمْرَةً فَتَعَاظَمَ ذَلِكَ عِنْدَهُمْ فَقَالُوا يَا رَسُولَ اللَّهِ أَيُّ الْحِلِّ قَالَ حِلٌّ كُلُّهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu Thowus] dari [bapaknya] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Orang-orang (Kaum Jahiliyah) menganggap melaksanakan 'umrah pada bulan-bulan hajji adalah kejahatan yang paling besar di muka bumi dan mereka menjadiikan bulan haram adalah bulan Shafar dan mereka berkata: \"Jika luka sudah sembuh (pada unta setelah melahirkan) dan sisa-sisa pelaksanaan hajji sudah hilang dan bulan Shafar sudah berlalu maka baru dibolehkan 'umrah bagi mereka yang mau ber'umrah\". Kemudian Nabi shallallahu 'alaihi wasallam dan para sahabatnya tiba di Makkah pada hari keempat bulan Dzul Hijjah, mereka bertalbiyyah untuk haji. Kemudian Beliau memerintahkan mereka agar menjadikannya sebagai niat 'umrah. Hal ini menjadi perkara yang besar bagi mereka sehingga mereka bertanya: \"Wahai Rasulullah, apa saja yang halal (dibolehkan)?\". Beliau menjawab: \"Semuanya halal (boleh) \"."},"1463":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَقَدِمْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُ بِالْحِلِّ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsannaa] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Qais bin Muslim] dari [Thoriq bin Syihab] dari [Abu Musa radliallahu 'anhu] berkata: \"Aku mendatangi Nabi Shallallahu'alaihiwasallam \". Lalu Beliau memerintahnya untuk bertahallul\"."},"1464":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَ رَضِيَ اللَّهُ عَنْهُمْ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْيَا رَسُولَ اللَّهِ مَا شَأْنُ النَّاسِ حَلُّوا بِعُمْرَةٍ وَلَمْ تَحْلِلْ أَنْتَ مِنْ عُمْرَتِكَ قَالَ إِنِّي لَبَّدْتُ رَأْسِي وَقَلَّدْتُ هَدْيِي فَلَا أَحِلُّ حَتَّى أَنْحَرَ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada saya [Malik]. Dan diriwaatkan pula. Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dari [Hafshah radliallahu 'anha] isteri Nabi shallallahu 'alaihi wasallam bahwa dia berkata: \"Wahai Rasulullah, bagaimana orang-orang telah bertahallul untuk 'umrah mereka sedang anda malah tidak bertahallul dari 'umrah anda?\". Beliau menjawab: \"Sungguh aku sudah mengikat rambutku dan telah menandai hewan qurbanku dan aku tidak akan bertahallul kecuali setelah menyembelih hewan qurban (pada hari nahar) \". "},"1465":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ أَخْبَرَنَا أَبُو جَمْرَةَ نَصْرُ بْنُ عِمْرَانَ الضُّبَعِيُّ قَالَتَمَتَّعْتُ فَنَهَانِي نَاسٌ فَسَأَلْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا فَأَمَرَنِي فَرَأَيْتُ فِي الْمَنَامِ كَأَنَّ رَجُلًا يَقُولُ لِي حَجٌّ مَبْرُورٌ وَعُمْرَةٌ مُتَقَبَّلَةٌ فَأَخْبَرْتُ ابْنَ عَبَّاسٍ فَقَالَ سُنَّةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي أَقِمْ عِنْدِي فَأَجْعَلَ لَكَ سَهْمًا مِنْ مَالِي قَالَ شُعْبَةُ فَقُلْتُ لِمَ فَقَالَ لِلرُّؤْيَا الَّتِي رَأَيْتُ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepada kami [Abu Jamrah Nashr bin 'Imran Adh Dhuba'iy] berkata: \"Aku mengerjakan haji dengan tamattu' namun orang-orang melarangku maka aku tanyakan hal itu kepada [Ibnu 'Abbas radliallahu 'anhuma]. Maka dia memerintahkan aku (melanjutkan tamattu'). Kemudian aku bermimpi yang dalam mimpiku aku melihat ada seseorang berkata kepadaku; \"hajji yang mabrur dan 'umrah yang diterima\". Lalu hal ini aku kabarkan kepada Ibnu 'Abbas radliallahu 'anhu. Maka dia berkata: \"Sebagai suatu sunnah Nabi Shallallahu'alaihiwasallam \". Lalu dia berkata, kepadaku: \"Berdirilah di hadapanku, karena aku akan memberimu bagian dari hartaku\". Syu'bah berkata: Maka aku tanyakan: \"Mengapa?\". Dia (Abu Hamzah) berkata: \"Karena mimpi yang aku alami itu\"."},"1466":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا أَبُو شِهَابٍ قَالَ قَدِمْتُ مُتَمَتِّعًا مَكَّةَ بِعُمْرَةٍ فَدَخَلْنَا قَبْلَ التَّرْوِيَةِ بِثَلَاثَةِ أَيَّامٍ فَقَالَ لِي أُنَاسٌ مِنْ أَهْلِ مَكَّةَ تَصِيرُ الْآنَ حَجَّتُكَ مَكِّيَّةً فَدَخَلْتُ عَلَى عَطَاءٍ أَسْتَفْتِيهِ فَقَالَ حَدَّثَنِي جَابِرُ بْنُ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُحَجَّ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ سَاقَ الْبُدْنَ مَعَهُ وَقَدْ أَهَلُّوا بِالْحَجِّ مُفْرَدًا فَقَالَ لَهُمْ أَحِلُّوا مِنْ إِحْرَامِكُمْ بِطَوَافِ الْبَيْتِ وَبَيْنَ الصَّفَا وَالْمَرْوَةِ وَقَصِّرُوا ثُمَّ أَقِيمُوا حَلَالًا حَتَّى إِذَا كَانَ يَوْمُ التَّرْوِيَةِ فَأَهِلُّوا بِالْحَجِّ وَاجْعَلُوا الَّتِي قَدِمْتُمْ بِهَا مُتْعَةً فَقَالُوا كَيْفَ نَجْعَلُهَا مُتْعَةً وَقَدْ سَمَّيْنَا الْحَجَّ فَقَالَ افْعَلُوا مَا أَمَرْتُكُمْ فَلَوْلَا أَنِّي سُقْتُ الْهَدْيَ لَفَعَلْتُ مِثْلَ الَّذِي أَمَرْتُكُمْ وَلَكِنْ لَا يَحِلُّ مِنِّي حَرَامٌ حَتَّى يَبْلُغَ الْهَدْيُ مَحِلَّهُ فَفَعَلُوا قَالَ أَبُو عَبْد اللَّهِ أَبُو شِهَابٍ لَيْسَ لَهُ مُسْنَدٌ إِلَّا هَذَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Abu Sihab] berkata: \"Aku menuju Makkah dengan berihram untuk 'umrah sebagai pelaksanaan hajji dengan tamattu'. Maka kami tiba tiga hari sebelum hari Tarwiyah. Maka orang-orang berkata, kepadaku: \"Dari penduduk (rumah-rumah di) Makkah maka hajjimu sekarang sebagai orang Makkah\". Kemudian aku menemui ['Atho'] untuk meminta fatwa darinya. Maka dia berkata; Telah menceritakan kepada saya [Jabir bin 'Abdullah radliallahu 'anhua] bahwa dia pernah melaksanakan hajji bersama Nabi shallallahu 'alaihi wasallam ketika Beliau menggiring hewan qurbannya ketika orang-orang sudah berihram untuk haji secara ifrad, maka Beliau berkata, kepada mereka: \"Halalkanlah ihram kalian ketika sudah thowaf di Baitulloh dan sa'iy antara bukit Ash-Shafa dan Al Marwah dan memotong rambut dan tinggalah (di Makkah) dalam keadaan halal hingga apabila tiba hari Tarwiyah berihramlah untuk hajji dan jadikan apa yang sudah kalian lakukan dari manasik ini sebagai pelaksanaan hajji dengan tamattu'. Mereka bertanya: \"Bagaimana kami menjadikannya sebagai tamattu' sedang kami sudah meniatkannya sebagai ihram hajji?\". Maka Beliau berkata: \"Laksanakanlah apa yang aku perintahkan kepada kalian. Seandainya aku tidak membawa hewan qurban tentu aku akan melaksanakan seperti yang aku perintahkan kepada kalian. Akan tetapi tidak halal bagiku apa-apa yang diharamkan selama ihram ini hingga hewan qurban sudah sampai pada tempat sembelihannya (pada hari nahar) \". Maka orang-orang melaksanakannya\". Berkata, Abu 'Abdullah Al Buklhoriy: \"Abu Syihab tidak memiliki sanad selain jalan ini\"."},"1467":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ الْأَعْوَرُ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَاخْتَلَفَ عَلِيٌّ وَعُثْمَانُ رَضِيَ اللَّهُ عَنْهُمَا وَهُمَا بِعُسْفَانَ فِي الْمُتْعَةِ فَقَالَ عَلِيٌّ مَا تُرِيدُ إِلَّا أَنْ تَنْهَى عَنْ أَمْرٍ فَعَلَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَأَى ذَلِكَ عَلِيٌّ أَهَلَّ بِهِمَا جَمِيعًا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Hajjaj bin Muhammad Al A'war] dari [Syu'bah] dari ['Amru bin Murrah] dari [Sa'id bin Al Musayab] berkata: 'Ali dan 'Utsman radliallahu 'anhuma berbeda pendapat tentang pelaksanaan hajji dengan tamattu' ketika keduanya berada di 'Usfan. ['Ali] berkata: \"Apa yang kamu inginkan sehingga kamu melarang sesuatu yang telah dikerjakan oleh Nabi Shallallahu'alaihiwasallam?\". Ketika 'Ali menyampaikan pendapatnya itu, maka dia memulai ihram dengan menggabungkan keduanya (hajji dan 'umrah). "},"1468":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ قَالَ سَمِعْتُ مُجَاهِدًا يَقُولُ حَدَّثَنَا جَابِرُ بْنُ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاقَالَ قَدِمْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَقُولُ لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ بِالْحَجِّ فَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلْنَاهَا عُمْرَةً","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] berkata; Aku mendengar [Mujahid] berkata; telah menceritakan kepada kami [Jabir bin 'Abdullah radliallahu 'anhua] berkata: \"Kami berangkat menuju Makkah bersama Nabi shallallahu 'alaihi wasallam dan kami mengucapkan talbiyah (niat dalam ihram): \"Labbaikallahumma labbaika bilhajj\" (Ya Allah kami memenuhi panggilanMu untuk berihram hajji). Maka kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan kami, maka kami menjadikannya sebagai ihram untuk 'umrah\"."},"1469":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ قَالَ حَدَّثَنِي مُطَرِّفٌ عَنْ عِمْرَانَ رَضِيَ اللَّهُ عَنْهُ قَالَتَمَتَّعْنَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَ الْقُرْآنُ قَالَ رَجُلٌ بِرَأْيِهِ مَا شَاءَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammam] dari [Qatadah] berkata,, telah menceritakan kepada saya [Muthrrif] dari ['Imran radliallahu 'anhu] berkata: \"Kami melaksanakan hajji dengan cara tamattu' pada masa hidup Rasulullah Shallallahu'alaihiwasallam, Maka turunlah ayat Al Qur'an Al Baqarah ayat 195). Dia ('Imran) bersabda: \"Seseorang berpendapat sesuai kehendak Allah\"."},"1470":{"ar":"حَدَّثَنِي يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ عُلَيَّةَ أَخْبَرَنَا أَيُّوبُ عَنْ نَافِعٍ قَالَ كَانَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاإِذَا دَخَلَ أَدْنَى الْحَرَمِ أَمْسَكَ عَنْ التَّلْبِيَةِ ثُمَّ يَبِيتُ بِذِي طِوًى ثُمَّ يُصَلِّي بِهِ الصُّبْحَ وَيَغْتَسِلُ وَيُحَدِّثُ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَفْعَلُ ذَلِكَ","id":"Telah menceritakan kepada sayai [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Ibnu 'Ulayyah] telah mengabarkan kepada kami [Ayyub] dari [Nafi'] berkata,, bahwa ['Abdullah bin 'Umar radliallahu 'anhua] bila sudah mendekati tanah haram dia berhenti dari membaca talbiyah lalu bermalam di Dzu Thuwa lalu shalat Shubuh disana lalu mandi kemudian menceritakan bahwa Nabiyullah Shallallahu'alaihiwasallam melakukannya seperti itu."},"1471":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَبَاتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذِي طُوًى حَتَّى أَصْبَحَ ثُمَّ دَخَلَ مَكَّةَ وَكَانَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَفْعَلُهُ","id":"Telah menceritakan kepada sayai [Musaddad] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] berkata, telah menceritakan kepada saya [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] berkata: \"Nabi shallallahu 'alaihi wasallam bermalam di Dzu Thuwa sampai pagi lalu memasuki kota Makkah\". Dan Ibnu 'Umar radliallahu 'anhuma juga melakukannya seperti itu. "},"1472":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ قَالَ حَدَّثَنِي مَعْنٌ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْخُلُ مِنْ الثَّنِيَّةِ الْعُلْيَا وَيَخْرُجُ مِنْ الثَّنِيَّةِ السُّفْلَى","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] berkata, telah menceritakan kepada saya [Ma'n] berkata, telah menceritakan kepada saya [Malik] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] berkata; Rasulullah shallallahu 'alaihi wasallam memasuki (kota Makkah) melewati dataran tinggi dan keluar melewati dataran rendah. "},"1473":{"ar":"حَدَّثَنَا مُسَدَّدُ بْنُ مُسَرْهَدٍ الْبَصْرِيُّ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ مَكَّةَ مِنْ كَدَاءٍ مِنْ الثَّنِيَّةِ الْعُلْيَا الَّتِي بِالْبَطْحَاءِ وَخَرَجَ مِنْ الثَّنِيَّةِ السُّفْلَىقَالَ أَبُو عَبْد اللَّهِ كَانَ يُقَالُ هُوَ مُسَدَّدٌ كَاسْمِهِ قَالَ أَبُو عَبْد اللَّهِ سَمِعْتُ يَحْيَى بْنَ مَعِينٍ يَقُولُ سَمِعْتُ يَحْيَى بْنَ سَعِيدٍ يَقُولُ لَوْ أَنَّ مُسَدَّدًا أَتَيْتُهُ فِي بَيْتِهِ فَحَدَّثْتُهُ لَاسْتَحَقَّ ذَلِكَ وَمَا أُبَالِي كُتُبِي كَانَتْ عِنْدِي أَوْ عِنْدَ مُسَدَّدٍ","id":"Telah menceritakan kepada kami [Musaddad bin Musarhad Al Bashriy] telah menceritakan kepada kami [Yaha] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam memasuki kota Makkah dari daerah Kada' melewati dataran yang terletak di Bathha' tinggi dan keluar melewati dataran rendah. Abu 'Abdullah Al Bukhariy berkata: Dahulu dikatakan ia adalah Musaddad sebagai namanya. Abu 'Abdullah Al Bukhariy berkata; Aku mendengar Yahya bin Ma 'in berkata, aku mendengar Yahya bin Sa'id berkata: \"Seandainya aku mendatangi Musaddad di rumahnya lalu aku ceritakan tentulah dia membenarkan hal itu. Dan aku tidak peduli apakah catatanku (kitabku) ada padaku atau pada Musaddad\". "},"1474":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا جَاءَ إِلَى مَكَّةَ دَخَلَ مِنْ أَعْلَاهَا وَخَرَجَ مِنْ أَسْفَلِهَا","id":"Telah menceritakan kepada kami [Al Humaidiy] dan [Muhammad bin Al Mutsanna] keduanya berkata, telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha] bahwa Nabi shallallahu 'alaihi wasallam ketika datang ke kota Makkah, Beliau memasukinya lewat dataran tingginya dan keluar melewati dataran rendahnya."},"1475":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ الْمَرْوَزِيُّ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَامَ الْفَتْحِ مِنْ كَدَاءٍ وَخَرَجَ مِنْ كُدًا مِنْ أَعْلَى مَكَّةَ","id":"Telah menceritakan kepada kami [Mahmud bin Ghoylan Al Marwaziy] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha] bahwa Nabi shallallahu 'alaihi wasallam memasuki (kota Makkah) pada tahun pembebasan dari Kada' dan keluar dari Kudan melalui dataran tinggi kota Makkah. "},"1476":{"ar":"حَدَّثَنَا أَحْمَدُ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنَا عَمْرٌو عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَامَ الْفَتْحِ مِنْ كَدَاءٍ أَعْلَى مَكَّةَقَالَ هِشَامٌ وَكَانَ عُرْوَةُ يَدْخُلُ عَلَى كِلْتَيْهِمَا مِنْ كَدَاءٍ وَكُدًا وَأَكْثَرُ مَا يَدْخُلُ مِنْ كَدَاءٍ وَكَانَتْ أَقْرَبَهُمَا إِلَى مَنْزِلِهِ","id":"Telah menceritakan kepada kami [Ahmad] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepada kami ['Amru] dari [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha] bahwa Nabi shallallahu 'alaihi wasallam memasuki (kota Makkah) pada tahun pembebasan dari Kada' dataran tinggi kota Makkah. Hisyam berkata; Dan 'Urwah melewati keduanya dari Kada' dan Kudan. Namun kebanyakan dari Kada' karena tempat ini yang lebih dekat dengan rumahnya."},"1477":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا حَاتِمٌ عَنْ هِشَامٍ عَنْ عُرْوَةَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ مِنْ كَدَاءٍ مِنْ أَعْلَى مَكَّةَوَكَانَ عُرْوَةُ أَكْثَرَ مَا يَدْخُلُ مِنْ كَدَاءٍ وَكَانَ أَقْرَبَهُمَا إِلَى مَنْزِلِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin 'Abdul Wahhab] telah menceritakan kepada kami [Hatim] dari [Hisyam] dari ['Urwah]; Nabi shallallahu 'alaihi wasallam memasuki (kota Makkah) pada tahun pembebasan dari Kada' dataran tinggi kota Makkah. Dan 'Urwah kebanyakan memasukinya lewat Kada' karena tempat ini yang lebih dekat dengan rumahnya."},"1478":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ مِنْ كَدَاءٍوَكَانَ عُرْوَةُ يَدْخُلُ مِنْهُمَا كِلَيْهِمَا وَكَانَ أَكْثَرَ مَا يَدْخُلُ مِنْ كَدَاءٍ أَقْرَبِهِمَا إِلَى مَنْزِلِهِ قَالَ أَبُو عَبْد اللَّهِ كَدَاءٌ وَكُدًا مَوْضِعَانِ","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Hisyam] dari [bapaknya]; bahwa Nabi shallallahu 'alaihi wasallam memasuki (kota Makkah) pada tahun pembebasan dari Kada'. Dan 'Urwah memasukinya melalui keduanya dan kebanyakan dia memasukinya dari Kada' karena ini tempat yang paling dekat dengan rumahnya. Abu 'Abdullah Al Bukhariy berkata: \"Kuda' dan Kadan adalah dua tempat yang berbeda\"."},"1479":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو عَاصِمٍ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا بُنِيَتْ الْكَعْبَةُ ذَهَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَبَّاسٌ يَنْقُلَانِ الْحِجَارَةَ فَقَالَ الْعَبَّاسُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْعَلْ إِزَارَكَ عَلَى رَقَبَتِكَ فَخَرَّ إِلَى الْأَرْضِ وَطَمَحَتْ عَيْنَاهُ إِلَى السَّمَاءِ فَقَالَ أَرِنِي إِزَارِي فَشَدَّهُ عَلَيْهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Abu 'Ashim] berkata, telah mengabarkan kepada saya [Ibnu Juraij] berkata, telah mengabarkan kepada saya ['Amru bin Dinar] berkata; Aku mendengar [Jabir bin 'Abdullah radliallahu 'anhua] berkata: \"Ketika Ka'bah dibangun (diperbaiki) Nabi shallallahu 'alaihi wasallam dan 'Abbas mengangkut bebatuan, Saat itu Al 'Abbas berkata kepada Nabi shallallahu 'alaihi wasallam: \"Ikatlah kain sarungmu pada lehermu\". Tiba-tiba Beliau tersungkur ke tanah lalu kedua matanya terbelalak menengadah ke arah langit. Lalu Beliau berkata: \"Berikanlah kain sarungku\". Kemudian Beliau mengikatnya kembali dengan kuat."},"1480":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ مُحَمَّدِ بْنِ أَبِي بَكْرٍ أَخْبَرَ عَبْدَ اللَّهِ بْنَ عُمَرَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهُمْ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهَا أَلَمْ تَرَيْ أَنَّ قَوْمَكِ لَمَّا بَنَوْا الْكَعْبَةَ اقْتَصَرُوا عَنْ قَوَاعِدِ إِبْرَاهِيمَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَلَا تَرُدُّهَا عَلَى قَوَاعِدِ إِبْرَاهِيمَ قَالَ لَوْلَا حِدْثَانُ قَوْمِكِ بِالْكُفْرِ لَفَعَلْتُفَقَالَ عَبْدُ اللَّهِ رَضِيَ اللَّهُ عَنْهُ لَئِنْ كَانَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا سَمِعَتْ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أُرَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَرَكَ اسْتِلَامَ الرُّكْنَيْنِ اللَّذَيْنِ يَلِيَانِ الْحِجْرَ إِلَّا أَنَّ الْبَيْتَ لَمْ يُتَمَّمْ عَلَى قَوَاعِدِ إِبْرَاهِيمَ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Salim bin 'Abdullah] bahwa ['Abdullah bin Muhammad bin Abu Bakar] mengabarkan kepada ['Abdullah bin 'Umar] dari ['Aisyah radliallahu 'anhum], isteri Nabi shallallahu 'alaihi wasallam bahwa Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Tidakkah kamu tahu bahwa kaummu ketika membangun Ka'bah mereka menggesernya dari pondasi yang dibangun oleh Nabi Ibrahim Alaihissalam?\". Aku berkata: \"Wahai Rasulullah, mengapa anda tidak mengembalikannya ke posisi yang dibuat Nabi Ibrahim Aalaihissalam?\". Beliau menjawab: \"Seandainya tidak mempertimbangkan masa-masa kaummu yang masih lekat dengan kekufuran tentu aku sudah melakukannya\". Maka 'Abdullah radliallahu 'anhu berkata: \"Sekalipun 'Aisyah radliallahu 'anha mendengar hal ini langsung dari Rasulullah Shallallahu'alaihiwasallam, namun aku tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam meninggalkan 'istilam' terhadap dua rukun yang menghadap (Hajar Aswad) ini, selain memang Baitullah ini tidak disempurnakan pembangunannya di atas pondasi yang dibangun oleh Nabi Ibrahim alaihissalam. "},"1481":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا أَشْعَثُ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْجَدْرِ أَمِنَ الْبَيْتِ هُوَ قَالَ نَعَمْ قُلْتُ فَمَا لَهُمْ لَمْ يُدْخِلُوهُ فِي الْبَيْتِ قَالَ إِنَّ قَوْمَكِ قَصَّرَتْ بِهِمْ النَّفَقَةُ قُلْتُ فَمَا شَأْنُ بَابِهِ مُرْتَفِعًا قَالَ فَعَلَ ذَلِكَ قَوْمُكِ لِيُدْخِلُوا مَنْ شَاءُوا وَيَمْنَعُوا مَنْ شَاءُوا وَلَوْلَا أَنَّ قَوْمَكِ حَدِيثٌ عَهْدُهُمْ بِالْجَاهِلِيَّةِ فَأَخَافُ أَنْ تُنْكِرَ قُلُوبُهُمْ أَنْ أُدْخِلَ الْجَدْرَ فِي الْبَيْتِ وَأَنْ أُلْصِقَ بَابَهُ بِالْأَرْضِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu Al Ahwash] telah menceritakan kepada kami [Asy'ats] dari [Al Aswad bin Yazid] dari ['Aisyah radliallahu 'anha] berkata,, \"Aku bertanya kepada Nabi shallallahu 'alaihi wasallam apakah Hijir Isma'il masuk bagian dari Ka'bah Baitulloh?\". Beliau menjawab: \"Ya benar\". Lalu aku bertanya lagi: \"Mengapa mereka tidak memasukkannya kedalam Ka'bah?\". Beliau menjawab: \"Seseungguhnya kaummu kekurangan biaya\". Aku bertanya lagi: \"Lalu apa alasannya pintu Ka'bah agak tinggi?\". Beliau menjawab: \"Kaummu yang membuatnya seperti itu dengan tujuan mereka bisa memasukkan siapa yang mereka kehendaki dan melarang siapa yang mereka kehendaki. Seandainya bukan karena pertimbangan keberadaan kaummu yang masih lekat dengan jahiliyyah (tentu aku sudah melakukannya) namun aku khawatir hati mereka mengingkarinya bila aku memasukkan Hijir Isma'il ke dalam Ka'bah dan bila aku ratakan pintunya dengan permukaan tanah\". "},"1482":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا حَدَاثَةُ قَوْمِكِ بِالْكُفْرِ لَنَقَضْتُ الْبَيْتَ ثُمَّ لَبَنَيْتُهُ عَلَى أَسَاسِ إِبْرَاهِيمَ عَلَيْهِ السَّلَام فَإِنَّ قُرَيْشًا اسْتَقْصَرَتْ بِنَاءَهُ وَجَعَلْتُ لَهُ خَلْفًاقَالَ أَبُو مُعَاوِيَةَ حَدَّثَنَا هِشَامٌ خَلْفًا يَعْنِي بَابًا","id":"Telah menceritakan kepada kami ['Ubaidullah bin Isma'il] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [bapaknya] dari ['Aisyah radliallahu 'anha] berkata; Rasulullah shallallahu 'alaihi wasallam berkata, kepadaku: \"Seandainya bukan karena zaman kaummu yang masih lekat dengan kekufuran tentu aku sudah membongkar Ka'bah lalu aku bangun kembali diatas pondasi yang dibangun oleh Nabi Ibrahim Alaihissalam karena orang-orang Quraisy telah mengurangi pembangunannya dan aku akan buatkan pintu (dari belakangnya) \". Berkata, [Abu Mu'awiyah] telah menceritakan kepada kami [Hisyam]: istilah Khalfan maksudnya adalah pintu\". "},"1483":{"ar":"حَدَّثَنَا بَيَانُ بْنُ عَمْرٍو حَدَّثَنَا يَزِيدُ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنَا يَزِيدُ بْنُ رُومَانَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهَا يَا عَائِشَةُ لَوْلَا أَنَّ قَوْمَكِ حَدِيثُ عَهْدٍ بِجَاهِلِيَّةٍ لَأَمَرْتُ بِالْبَيْتِ فَهُدِمَ فَأَدْخَلْتُ فِيهِ مَا أُخْرِجَ مِنْهُ وَأَلْزَقْتُهُ بِالْأَرْضِ وَجَعَلْتُ لَهُ بَابَيْنِ بَابًا شَرْقِيًّا وَبَابًا غَرْبِيًّا فَبَلَغْتُ بِهِ أَسَاسَ إِبْرَاهِيمَ فَذَلِكَ الَّذِي حَمَلَ ابْنَ الزُّبَيْرِ رَضِيَ اللَّهُ عَنْهُمَا عَلَى هَدْمِهِ قَالَ يَزِيدُ وَشَهِدْتُ ابْنَ الزُّبَيْرِ حِينَ هَدَمَهُ وَبَنَاهُ وَأَدْخَلَ فِيهِ مِنْ الْحِجْرِ وَقَدْ رَأَيْتُ أَسَاسَ إِبْرَاهِيمَ حِجَارَةً كَأَسْنِمَةِ الْإِبِلِ قَالَ جَرِيرٌ فَقُلْتُ لَهُ أَيْنَ مَوْضِعُهُ قَالَ أُرِيكَهُ الْآنَ فَدَخَلْتُ مَعَهُ الْحِجْرَ فَأَشَارَ إِلَى مَكَانٍ فَقَالَ هَا هُنَا قَالَ جَرِيرٌ فَحَزَرْتُ مِنْ الْحِجْرِ سِتَّةَ أَذْرُعٍ أَوْ نَحْوَهَا","id":"Telah menceritakan kepada kami [Bayan bin 'Amru] telah menceritakan kepada kami [Yazid] telah menceritakan kepada kami [Jarir bin hazim] telah menceritakan kepada kami [Yazid bin Ruman] dari ['Urwah] dari ['Aisyah radliallahu 'anha] bahwa Nabi shallallahu 'alaihi wasallam berkata, kepadanya: \"Seandainya bukan karena keberadaan kaummu yang masih lekat dengan kejahiliyahan, tentu aku sudah perintahkan agar Ka'bah Baitulloh dirabohkan lalu aku masukkan ke dalamnya apa yang sudah dikeluarkan darinya dan aku akan jadikan (pintunya yang ada sekarang) rata dengan permukaan tanah, lalu aku buat pintu timur dan pintu barat dengan begitu aku membangunya diatas pondasi yang telah dibangun oleh Nabi Ibrahim Alaihissalam\". Sabda Nabi shallallahu 'alaihi wasallam inilah yang kemudian dijadikan alasan oleh 'Abdullah bin Az Zubair untuk merabohkannya. Berkata, Yazid: \"Aku melihat Ibnu Zubair ketika merabohkannya lalu membangunnya kembali, dia memasukkan sebagian Hijir Isma'il dan aku melihat pondasi yang dibangun Nabi Ibrahim Alaihissalam berupa bebatuan menyerupai punuk-punuk unta\". Jarir berkata: \"Aku bertanya kepadanya: \"Dimana posisinya?\". Dia berkata: \"Akan kutunjukkan kepadamu sekarang\". Maka aku bersamanya masuk ke dalam Al Hijir lalu dia menunjuk pada suatu tempat seraya berkata; \"Inilah posisinya\". Jarir berkata: \"Kemudian aku mengukur jaraknya dari Al Hijir ternyata kira-kira kurang lebih enam hasta\". "},"1484":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ إِنَّ هَذَا الْبَلَدَ حَرَّمَهُ اللَّهُ لَا يُعْضَدُ شَوْكُهُ وَلَا يُنَفَّرُ صَيْدُهُ وَلَا يَلْتَقِطُ لُقَطَتَهُ إِلَّا مَنْ عَرَّفَهَا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Jarir bin 'Abdul Hamid] dari [Manshur] dari [Mujahid] dari [Thowus] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda pada hari pembebasan kota Makkah: \"Sesungguhnya tanah ini telah diharamkan oleh Allah, maka tidak boleh ditebang pohonnya dan tidak boleh diburu hewan buruannya dan tidak ditemukan satupun barang yang hilang kecuali harus dikembalikan kepada yang mengenalnya (pemiliknya) \""},"1485":{"ar":"حَدَّثَنَا أَصْبَغُ قَالَ أَخْبَرَنِي ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ عَمْرِو بْنِ عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُ قَالَيَا رَسُولَ اللَّهِ أَيْنَ تَنْزِلُ فِي دَارِكَ بِمَكَّةَ فَقَالَ وَهَلْ تَرَكَ عَقِيلٌ مِنْ رِبَاعٍ أَوْ دُورٍ وَكَانَ عَقِيلٌ وَرِثَ أَبَا طَالِبٍ هُوَ وَطَالِبٌ وَلَمْ يَرِثْهُ جَعْفَرٌ وَلَا عَلِيٌّ رَضِيَ اللَّهُ عَنْهُمَا شَيْئًا لِأَنَّهُمَا كَانَا مُسْلِمَيْنِ وَكَانَ عَقِيلٌ وَطَالِبٌ كَافِرَيْنِ فَكَانَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يَقُولُ لَا يَرِثُ الْمُؤْمِنُ الْكَافِرَ قَالَ ابْنُ شِهَابٍ وَكَانُوا يَتَأَوَّلُونَ قَوْلَ اللَّهِ تَعَالَى{ إِنَّ الَّذِينَ آمَنُوا وَهَاجَرُوا ��َجَاهَدُوا بِأَمْوَالِهِمْ وَأَنْفُسِهِمْ فِي سَبِيلِ اللَّهِ وَالَّذِينَ آوَوْا وَنَصَرُوا أُولَئِكَ بَعْضُهُمْ أَوْلِيَاءُ بَعْضٍ }الْآيَةَ","id":"Telah menceritakan kepada kami [Ashbagh] berkata, telah mengabarkan kepada saya [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dari ['Ali bin Husain] dari ['Amru bin 'Utsman] dari [Usamah bin Zaid radliallahu 'anhum] bahwa dia berkata: \"Wahai Rasulullah, dimana anda akan singgah di Makkah ini?\". Beliau berkata: \"Apakah 'Uqail meninggalkan rumah yang luas atau rumah-rumah?\". 'Uqail dan Tholib mendapatkan warisan dari Abu Tholib sedangkan Ja'far dan 'Ali radliallahu 'anhuma tidak mewarisi sedikitpun karena keduanya adalah Muslim sedangkan 'Uqail dan Tholib kafir. Dan adalah 'Umar bin Al Khaththob radliallahu 'anhu berkata: \"Seorang mu'min tidak mewariskan kepada orang yang kafir\". Ibnu Syihab berkata: \"Mereka menafsirkan firman Allah Ta'ala QS Al Anfal ayat 72 (yang artinya): (\"Sesungguhnya orang-orang yang beriman, orang-orang yang berhijrah dan orang-orang yang berjihad dengan harta dan jiwa mereka di jalan Allah dan orang-orang yang memberikan tempat kediaman dan menolong (orang yang berhijrah) mereka itu satu sama lain saling melindungi\"). "},"1486":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أَرَادَ قُدُومَ مَكَّةَ مَنْزِلُنَا غَدًا إِنْ شَاءَ اللَّهُ بِخَيْفِ بَنِي كِنَانَةَ حَيْثُ تَقَاسَمُوا عَلَى الْكُفْرِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah menceritakan kepada saya [Abu Salamah] bahwa [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam berkata, ketika hendak memasuki kota Makkah: \"Tempat singgah kita besok insya Allah di tempat peristirahatan Bani Kinanah saat mereka saling bersumpah setia diatas kekafiran\"."},"1487":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْغَدِ يَوْمَ النَّحْرِ وَهُوَ بِمِنًى نَحْنُ نَازِلُونَ غَدًا بِخَيْفِ بَنِي كِنَانَةَ حَيْثُ تَقَاسَمُوا عَلَى الْكُفْرِ يَعْنِي ذَلِكَ الْمُحَصَّبَ وَذَلِكَ أَنَّ قُرَيْشًا وَكِنَانَةَ تَحَالَفَتْ عَلَى بَنِي هَاشِمٍ وَبَنِي عَبْدِ الْمُطَّلِبِ أَوْ بَنِي الْمُطَّلِبِ أَنْ لَا يُنَاكِحُوهُمْ وَلَا يُبَايِعُوهُمْ حَتَّى يُسْلِمُوا إِلَيْهِمْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَقَالَ سَلَامَةُ عَنْ عُقَيْلٍ وَيَحْيَى بْنُ الضَّحَّاكِ عَنْ الْأَوْزَاعِيِّ أَخْبَرَنِي ابْنُ شِهَابٍ وَقَالَا بَنِي هَاشِمٍ وَبَنِي الْمُطَّلِبِ قَالَ أَبُو عَبْد اللَّهِ بَنِي الْمُطَّلِبِ أَشْبَهُ","id":"Telah menceritakan kepada kami [Al Humaidiy] telah menceritakan kepada kami [Al Walid] telah menceritakan kepada kami [Al Awza'iy] berkata, telah menceritakan kepada saya [Az Zuhriy] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam berkata, sehari setelah hari Nahar ketika Beliau masih di Mina: \" Besok kita akan singgah di tempat peristirahatan Bani Kinanah saat mereka saling bersumpah setia diatas kekafiran\". Tempat yang dimaksud adalah Al Muhashshab. Yang demikian itu karena Suku Quraisy dan Kinanah telah saling berjanji terhadap Bani 'Abdul Mutholib atau Bani Al Mutholib untuk tidak menikah dengan mereka, tidak berjual beli hingga mereka (Bani 'Abdul Mutholib) menyerahkan Nabi shallallahu 'alaihi wasallam kepada mereka (Suku Quraisy dan Kinanah) \". Dan berkata, [Salamah] dari ['Uqail] dan [Yahya bin Adh-Dhahhak] dari [Al Awza'iy] telah mengabarkan kepada saya [Ibnu Syihab] dan keduanya berkata: Bani Hasyim dan Bani Al Mutholib\". Berkata, Abu 'Abdullah Al Bukhariy: \"Bani Al Mutholib sama dengan Bani Hasyim\"."},"1488":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا زِيَادُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُخَرِّبُ الْكَعْبَةَ ذُو السُّوَيْقَتَيْنِ مِنْ الْحَبَشَةِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Ziyad bin Sa'ad] dari [Az Zuhriy] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Yang akan menghancurkan Ka'bah adalah orang-orang yang betisnya kecil berasal dari negeri Habasyah (Eithiophia) \"."},"1489":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا ح و حَدَّثَنِي مُحَمَّدُ بْنُ مُقَاتِلٍ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ هُوَ ابْنُ الْمُبَارَكِ قَالَ أَخْبَرَنَا مُحَمَّدُ بْنُ أَبِي حَفْصَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانُوا يَصُومُونَ عَاشُورَاءَ قَبْلَ أَنْ يُفْرَضَ رَمَضَانُ وَكَانَ يَوْمًا تُسْتَرُ فِيهِ الْكَعْبَةُ فَلَمَّا فَرَضَ اللَّهُ رَمَضَانَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَاءَ أَنْ يَصُومَهُ فَلْيَصُمْهُ وَمَنْ شَاءَ أَنْ يَتْرُكَهُ فَلْيَتْرُكْهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Sihab] dari ['Urwah] dari ['Aisyah radliallahu 'anha]. Dan diriwayatkan pula, telah menceritakan kepada saya [Muhammad bin Muqatil] berkata, telah mengabarkan kepada saya ['Abdullah] dia adalah putra dari Al Mubarak berkata, telah mengabarkan kepada kami [Muhammad bin Abu Hafshah] dari [Az Zuhriy] dari ['Urwah] dari ['Aisyah radliallahu 'anha] berkata: \"Orang-orang melaksanakan shaum hari kesepuluh bulan Muharam ('Asyura') sebelum diwajibkan shaum Ramadhan. Hari itu adalah ketika Ka'bah ditutup dengan kain (kiswah). Ketika Allah subhanahu wata'ala telah mewajibkan shaum Ramadhan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsipa yang mau shaum hari 'asyura' laksanakanlah dan siapa yang tidak mau tinggalkanlah\"."},"1490":{"ar":"حَدَّثَنَا أَحْمَدُ حَدَّثَنَا أَبِي حَدَّثَنَا إِبْرَاهِيمُ عَنْ الْحَجَّاجِ بْنِ حَجَّاجٍ عَنْ قَتَادَةَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي عُتْبَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيُحَجَّنَّ الْبَيْتُ وَلَيُعْتَمَرَنَّ بَعْدَ خُرُوجِ يَأْجُوجَ وَمَأْجُوجَتَابَعَهُ أَبَانُ وَعِمْرَانُ عَنْ قَتَادَةَ وَقَالَ عَبْدُ الرَّحْمَنِ عَنْ شُعْبَةَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى لَا يُحَجَّ الْبَيْتُ وَالْأَوَّلُ أَكْثَرُ سَمِعَ قَتَادَةُ عَبْدَ اللَّهِ وَعَبْدُ اللَّهِ أَبَا سَعِيدٍ","id":"Telah menceritakan kepada kami [Ahmad] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ibrahim] dari [Al Hajjaj bin Hajjaj] dari [Qatadah] dari ['Abdullah bin Abu 'Utbah] dari [Abu Sa'id Al Khudriy radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh pasti akan ada yang berhajji dan 'umrah ke Baitulloh (Ka'bah) setelah keluarnya Ya'juj dan Ma'juj\". Hadits ini dikuatkan oleh [Aban] dan ['Imran] dari [Qatadah] dan berkata, ['Abdurrahman] dari [Syu'bah] berkata: \"Tidak akan terjadi hari qiyamat hingga tidak ada yang berhajji ke Baitulloh (Ka'bah) \". Redaksi hadits yang pertama yang lebih banyak didengar oleh Qatadah dari 'Abdullah dan 'Abdullah mendengarnya dari Abu Sa'id Al Khudriy."},"1491":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا وَاصِلٌ الْأَحْدَبُ عَنْ أَبِي وَائِلٍ قَالَ جِئْتُ إِلَى شَيْبَةَ ح و حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ وَاصِلٍ عَنْ أَبِي وَائِلٍ قَالَ جَلَسْتُ مَعَ شَيْبَةَ عَلَى الْكُرْسِيِّ فِي الْكَعْبَةِ فَقَالَ لَقَدْ جَلَسَ هَذَا الْمَجْلِسَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فَقَالَلَقَدْ هَمَمْتُ أَنْ لَا أَدَعَ فِيهَا صَفْرَاءَ وَلَا بَيْضَاءَ إِلَّا قَسَمْتُهُ قُلْتُ إِنَّ صَاحِبَيْكَ لَمْ يَفْعَلَا قَالَ هُمَا الْمَرْءَانِ أَقْتَدِي بِهِمَا","id":"Telah menceritakan kepada kami ['Abdullah bin 'Abdul Wahhab] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Washil Al Ahdab] dari [Abu Wa'il] berkata; \"Aku menemui [Syaibah] \". Dan diriwayatkan pula, telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Washil] dari [Abu Wa'il] berkata: \"Aku duduk bersama [Syaibah] diatas sebuah kursi di dalam Ka'bah, lalu dia berkata: \"Ini adalah tempat duduknya ['Umar] radliallahu 'anhu yang dia berkata: \"Sungguh aku berusaha keras untuk tidak meninggalkan benda kuning (emas) ataupun benda putih (perak) kecuali aku akan membagikannya\". Aku katakan: \"Kedua sahabatmu (Abu Bakar Ash-Shidiq radliallahu 'anhu dan Nabi Shallallahu'alaihiwasallam) tidak pernah melakukan hal itu!\". 'Umar radliallahu 'anhu berkata: \"Mereka berdua adalah dua orang yang aku ikuti\"."},"1492":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ الْأَخْنَسِ حَدَّثَنِي ابْنُ أَبِي مُلَيْكَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَأَنِّي بِهِ أَسْوَدَ أَفْحَجَ يَقْلَعُهَا حَجَرًا حَجَرًا","id":"Telah menceritakan kepada kami ['Amru bin 'Ali] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami ['Ubaidullah bin Al Akhnas] telah menceritakan kepada saya [Ibnu Abu Mulaikah] dari [Ibnu 'Abbas radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"(Seakan akan aku melihat orang yang akan menghancuirkan Ka'bah), dia orang yang berkulit hitam dan renggang antara kedua kakinya dan dia mengangkat batunya satu persatu\"."},"1493":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَرِّبُ الْكَعْبَةَ ذُو السُّوَيْقَتَيْنِ مِنْ الْحَبَشَةِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] bahwa [Abu Hurairah radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Yang akan menghancurkan Ka'bah adalah orang-orang yang betisnya kecil berasal dari negeri Habasyah (Eithiophia) \"."},"1494":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَابِسِ بْنِ رَبِيعَةَ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُأَنَّهُ جَاءَ إِلَى الْحَجَرِ الْأَسْوَدِ فَقَبَّلَهُ فَقَالَ إِنِّي أَعْلَمُ أَنَّكَ حَجَرٌ لَا تَضُرُّ وَلَا تَنْفَعُ وَلَوْلَا أَنِّي رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَبِّلُكَ مَا قَبَّلْتُكَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari ['Abis bin Rabi'ah] dari ['Umar radliallahu 'anhu] bahwa dia mendatangi Hajar Al Aswad lalu menciumnya kemudian berkata: \"Sungguh aku mengetahui bahwa kamu hanyalah batu yang tidak bisa mendatangkan madharat maupun manfa'at. Namun kalau bukan karena aku telah melihat Nabi shallallahu 'alaihi wasallam menciummu tentu aku tidak akan menciummu\"."},"1495":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِ أَنَّهُ قَالَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيْتَ هُوَ وَأُسَامَةُ بْنُ زَيْدٍ وَبِلَالٌ وَعُثْمَانُ بْنُ طَلْحَةَ فَأَغْلَقُوا عَلَيْهِمْ فَلَمَّا فَتَحُوا كُنْتُ أَوَّلَ مَنْ وَلَجَ فَلَقِيتُ بِلَالًا فَسَأَلْتُهُ هَلْ صَلَّى فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ بَيْنَ الْعَمُودَيْنِ الْيَمَانِيَيْنِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Salim] dari [bapaknya] bahwa dia berkata: \"Rasulullah shallallahu 'alaihi wasallam masuk kedalam Ka'bah bersama Usamah, Bilal, dan 'Utsman bin Tholhah lalu mereka menutup pintunya. Ketika mereka membuka pintunya aku adalah orang pertama yang memasukinya dan aku temui [Bilal] lalu aku tanya; Apakah Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat di dalamnya?\". Dia menjawab: \"Ya, diantara dua tiang Yamani\"."},"1496":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُكَانَ إِذَا دَخَلَ الْكَعْبَةَ مَشَى قِبَلَ الْوَجْهِ حِينَ يَدْخُلُ وَيَجْعَلُ الْبَابَ قِبَلَ الظَّهْرِ يَمْشِي حَتَّى يَكُونَ بَيْنَهُ وَبَيْنَ الْجِدَارِ الَّذِي قِبَلَ وَجْهِهِ قَرِيبًا مِنْ ثَلَاثِ أَذْرُعٍ فَيُصَلِّي يَتَوَخَّى الْمَكَانَ الَّذِي أَخْبَرَهُ بِلَالٌ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِيهِ وَلَيْسَ عَلَى أَحَدٍ بَأْسٌ أَنْ يُصَلِّيَ فِي أَيِّ نَوَاحِي الْبَيْتِ شَاءَ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] apabila mau masuk kedalam Ka'bah dia berjalan menuju arah depan sementara pintu Ka'bah di belakangnya. Maka dia berjalan hingga antara dia dan dinding dihadapannya kira-kira tiga hasta lalu dia shalat ditempat yang pernah [Bilal] kabarkan bahwa Nabi shallallahu 'alaihi wasallam shalat di tempat itu. Dan tidak salah jika seseorang shalat di dalam Ka'bah menghadap kemana saja yang dia mau\". "},"1497":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبِي خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَاعْتَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَافَ بِالْبَيْتِ وَصَلَّى خَلْفَ الْمَقَامِ رَكْعَتَيْنِ وَمَعَهُ مَنْ يَسْتُرُهُ مِنْ النَّاسِ فَقَالَ لَهُ رَجُلٌ أَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكَعْبَةَ قَالَ لَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Khalid bin 'Abdullah] telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari ['Abdullah bin Abu Awfa] berkata; Rasulullah shallallahu 'alaihi wasallam melaksanakan thowaf di Ka'bah lalu shalat dua raka'at di belakang maqam Ibrahim dan bersama Beliau ada orang yang melindungi Beliau dari orang-orang Quraisy. Berkata, seseorang kepada 'Abdullah bin Abu Awfa: \"Apakah Rasulullah shallallahu 'alaihi wasallam masuk ke dalam Ka'bah?\". Dia menjawab: \"Tidak\"."},"1498":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ حَدَّثَنَا عِكْرِمَةُ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا قَدِمَ أَبَى أَنْ يَدْخُلَ الْبَيْتَ وَفِيهِ الْآلِهَةُ فَأَمَرَ بِهَا فَأُخْرِجَتْ فَأَخْرَجُوا صُورَةَ إِبْرَاهِيمَ وَإِسْمَاعِيلَ فِي أَيْدِيهِمَا الْأَزْلَامُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاتَلَهُمْ اللَّهُ أَمَا وَاللَّهِ لَقَدْ عَلِمُوا أَنَّهُمَا لَمْ يَسْتَقْسِمَا بِهَا قَطُّ فَدَخَلَ الْبَيْتَ فَكَبَّرَ فِي نَوَاحِيهِ وَلَمْ يُصَلِّ فِيهِ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami [Ayyub] telah menceritakan kepada kami ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Rasulullah shallallahu 'alaihi wasallam ketika didahului oleh bapakku memasuki Ka'bah yang didalamnya terdapat patung-patung, Beliau memerintahkan agar patung-patung tersebut dikeluarkan. Lalu mereka mengeluarkan patung berbentuk Nabi Ibrahim dan Nabi Isma'il yang di tangan keduanya ada azlam (panah untuk mengundi nasib). Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga Allah membinasakkan mereka. Padahal, sungguh mereka mengetahui bahwa keduanya tidak pernah mengundi nasib dengan azlam sekalipun\". Kemudian Beliau masuk kedalam Ka'bah lalu bertakbir pada sisi-sisinya dan tidak shalat didalamnya."},"1499":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ هُوَ ابْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ فَقَالَ الْمُشْرِكُونَ إِنَّهُ يَقْدَمُ عَلَيْكُمْ وَقَدْ وَهَنَهُمْ حُمَّى يَثْرِبَ فَأَمَرَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَرْمُلُوا الْأَشْوَاطَ الثَّلَاثَةَ وَأَنْ يَمْشُوا مَا بَيْنَ الرُّكْنَيْنِ وَلَمْ يَمْنَعْهُ أَنْ يَأْمُرَهُمْ أَنْ يَرْمُلُوا الْأَشْوَاطَ كُلَّهَا إِلَّا الْإِبْقَاءُ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad] dia adalah putra dari Zaid dari [Ayyub] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya datang mengunjungi Ka'bah\". Kaum Musyrikin berkata: \"Dia datang kepada kalian padahal mereka telah dilemahkan fisik mereka oleh penyakit demam yang melanda kota Yatsrib\". Maka Nabi shallallahu 'alaihi wasallam memerintahkan para sahabatnya agar berlari-lari kecil pada tiga putaran pertama dan berjalan biasa antara dua rukun (sudut) dan tidak ada yang menghalangi Beliau bila memerintahkan mereka agar berlari-lari kecil untuk semua putaran, namun hal itu tidak lain kecuali sebagai kemurahan Beliau kepada mereka\"."},"1500":{"ar":"حَدَّثَنَا أَصْبَغُ بْنُ الْفَرَجِ أَخْبَرَنِي ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ يَقْدَمُ مَكَّةَ إِذَا اسْتَلَمَ الرُّكْنَ الْأَسْوَدَ أَوَّلَ مَا يَطُوفُ يَخُبُّ ثَلَاثَةَ أَطْوَافٍ مِنْ السَّبْعِ","id":"Telah menceritakan kepada kami [Ashbagh bin Al Faraj] telah mengabarkan kepada saya [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dari [Salim] dari [bapaknya] radliallahu 'anhu berkata,: \"Aku melihat Rasulullah Shallallahu'alaihiwasallam tatkala datang ke Makkah (melaksanakan haji atau 'umrah) bila menyentuh sudut Al Hajar Al Aswad ketika melaksanakan thawaf qudum, Beliau berlari-lari kecil pada tiga kali putaran dari tujuh putaran\"."}};
